window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-017.json"] = [{"name":"扁嘴翡翠","english_name":"Flat-billed Kingfisher","scientific_name":"Todiramphus recurvirostris","overview":"扁嘴翡翠（英文名：Flat-billed Kingfisher，学名：Todiramphus recurvirostris），是佛法僧目翠鸟科林翡翠属的鸟类。体型紧凑，拥有相对较短、扁平的喙。上体呈深蓝色，翅膀蓝绿色，背部略深，头部上方有一顶蓝色的冠羽，眼前部为淡黄色，眼睛黑色，腿灰黑色。胸前腹部分别为白色或橙色，具有独特的白领和白眉。分布于萨摩亚的Savaii、Upolu及其周边小岛。","appearance":"扁嘴翡翠的嘴粗长而扁平，基部宽大，略向上翘，两侧无鼻沟，翼圆，第1片初级飞羽与第7片初级飞羽长度相当或略短，第2、3、4片初级飞羽几乎等长；初级飞羽基部有白色斑点，尾部圆形。体长22厘米，雄雌外观相似，亚种间存在细微差异，如体色深浅和嘴的形状。","call":"其鸣叫特征为一系列短促、尖锐的‘kik’音符，声音略显单调和急促。","habits":"栖息于茂密的森林、次生林、农耕区甚至城市公园和花园，常见于低地至山脚地带，高达1,200米。它们单独或成对活动，以昆虫、小脊椎动物和果实为食，觅食行为可能与白眉翡翠类似。","breeding":"在土崖壁或河流堤坝上挖掘隧道式洞穴筑巢，巢穴深约60厘米，宽20厘米，高10厘米，呈椭圆形，内部无铺垫物，卵直接产于巢底，大小约为29.4×26.2毫米，纯白色。","identification":"与白领翡翠相比，扁嘴翡翠体型较小，侧翼颜色更深，嘴更短且扁平。鸣叫声类似，但更为短促。","protection":"IUCN：LC（无危）","distribution":"主要分布在萨摩亚群岛的Savaii、Upolu和周边小岛，包括Fanuatapu、Manono和Namua。在Nu’utele和Apolima岛上似乎未见其踪迹。","other":"在O-le-Pupu-Pue国家公园（Upolu）等保护区可见其身影，种群密度在农业区最高。"},{"name":"冠翡翠","english_name":"Cinnamon-banded Kingfisher","scientific_name":"Todiramphus australasia","overview":"冠翡翠（英文名：Cinnamon-banded Kingfisher，学名：Todiramphus australasia），是佛法僧目翠鸟科林翡翠属的鸟类。宽广的肉桂色眉纹和颈圈，宽阔的黑色眼线和深色顶冠。分布于印尼的小巽他群岛和塔宁巴尔群岛，偏好森林和森林边缘地带。","appearance":"成年冠翡翠长约21厘米，雌鸟体重39-55克，雄鸟体重28-58克。头部有鲜艳的桔红色帽状羽毛延伸至眼眉处，脸颊覆盖黑色面具直达颈部，下颏白色，喉咙及颈侧为浅橙色。颈上部肉桂橙色，背部和肩部油绿色，腰部蓝绿色，尾端亮蓝色，双翼绿色，尾为蓝绿色，翼角下方有黑色斑点。上颌骨棕黑色，下颌骨淡黄色，虹膜褐色，腿黑色。幼鸟类似成年雌鸟，但胸部有黑色镶边，嘴苍白色。","call":"能发出快速下降的颤音‘keeeerrrrer’，时长2-3秒，还有尖锐的‘krrrreee-kreeee’声和吠叫。","habits":"栖息于原始森林、高大的次生林、森林边缘、季风林、开阔森林，甚至村庄和耕地上有遮荫的树林，偏好有闭合树冠的环境。以昆虫及其幼虫为主食，捕食方式多样。","breeding":"已知会在土崖壁或河流堤坝上挖掘隧道式巢穴，产卵季节通常在5月和6月，卵呈纯白色，大小约29.4x26.2毫米。","identification":"与白眉翡翠和白领翡翠的区别在于其近乎赤褐色的下体和宽广的眉纹。","protection":"IUCN：LC（无危）。在北努沙登加拉EBA、苏姆巴EBA、帝汶和韦塔EBA及班达海岛屿EBA有分布。因栖息地丧失和退化而处于潜在脆弱状态。","distribution":"分布于澳新界的印尼小巽他群岛和塔宁巴尔群岛（印尼摩鹿加群岛南部）。","other":"需要更多关于其生物学、生态学和现状的紧急信息。"},{"name":"博拉翡翠","english_name":"Chattering Kingfisher","scientific_name":"Todiramphus tutus","overview":"博拉翡翠（英文名：Chattering Kingfisher，学名：Todiramphus tutus），是佛法僧目翠鸟科林翡翠属的鸟类。常见于库克群岛和法属波利尼西亚的社会群岛。体型较小，长约22厘米，以蓝白相间的羽毛著称，头部深蓝绿色，额部及两侧有明显的白色条纹，下体洁白。分布于热带湿润低地森林和山地森林。","appearance":"博拉翡翠身长22厘米，性别相似。头部深蓝绿色，额头、眉部及颈部白色，眼先黑色，脸颊绿黑色。下体白色，颈部有黑色窄线。翕、肩胛深蓝绿色，双翼、尾部暗绿蓝色。上喙黑色，下喙浅黄色至象牙色，尖端及边缘暗色。虹膜深棕色，腿脚黑色。幼鸟体羽暗绿，眼眉细条绿色和白色，喉咙及下颏有细黑纹，胸腹部强烈黑白条纹。","call":"发出快速重复的'kee-kee-kee-kee'声，有时变为连续的嘎嘎声，还有'ke-kow, ke-kow, ke-kow'声，以及各种尖叫、咯咯声和轻笑声。","habits":"栖息于原始森林，尤其偏好高海拔溪流附近，也能适应次生林、老种植园、带树的耕地和花园。单独或成对活动，主要捕食昆虫、蜘蛛、蚯蚓、淡水虾、小鱼和小型爬行动物。","breeding":"在12月至1月间繁殖，于腐木中挖巢。每窝产两枚白色卵。","identification":"与塔希提翡翠区别在于完整的白色领圈和更明亮、淡色的羽毛。幼鸟与成鸟的区别在于胸腹部的强烈黑白条纹。","protection":"IUCN：NT（近危）。在某些岛屿上普遍或丰富，但在人类影响较大的地方数量减少。","distribution":"分布于太平洋的库克群岛中部和东部，以及法属波利尼西亚的社会群岛。","other":"曾被误认为在塔希提岛存在，实际在该岛罕见且局部。"},{"name":"库克岛翡翠","english_name":"Mewing Kingfisher","scientific_name":"Todiramphus ruficollaris","overview":"库克岛翡翠（英文名：Mewing Kingfisher，学名：Todiramphus ruficollaris），是佛法僧目翠鸟科林翡翠属的鸟类。是翠鸟科林翡翠属的物种，仅见于库克群岛的Mangaia岛。这种美丽的鸟拥有蓝绿色的羽毛，头上有明显的黄橙色带纹，眼睛黑色，眼眉黄色，橙色领带状花纹延伸至胸部。下体白色，嘴黑色，强壮有力。","appearance":"库克岛翡翠体型长约19-22厘米，头部较大，喙呈黑色，粗长似凿，基部宽大。上体蓝绿色，翅膀和尾巴颜色更深，胸前有强烈的橙色斑纹，雌鸟橙色会扩展至胸部。嘴基部淡粉色或灰色，脚黑灰带浅黄底色。幼鸟特征与成鸟相似，但细节略有差异。","call":"库克岛翡翠发出响亮的“kek-kek-kek-kek”叫声，不同于博拉翡翠的噪音式鸣叫。","habits":"库克岛翡翠偏好珊瑚石灰岩平台上的密集原生森林环境，以虫类、节肢动物、小鱼、蜥蜴等为食，捕食方式多样，从地面到树冠层均有其活动。飞行特点灵活，活动范围广泛。","breeding":"繁殖期在11月至1月，以一对或三人为单位筑巢，巢穴位于树干腐朽处，深度可达数米。每窝产卵2-3枚，白色，孵化期21-23天，由成鸟轮流孵卵和喂养幼鸟，幼鸟离巢期约为26天。","identification":"与博拉翡翠相比，库克岛翡翠具有橙色而非白色的眉纹和面部斑纹，叫声亦有明显区别。","protection":"IUCN：LC（无危）。受栖息地丧失、外来物种竞争和捕食威胁，但近年来种群似乎稳定。","distribution":"库克岛翡翠仅分布于太平洋中的Mangaia岛，属于库克群岛的东南部。","other":"库克岛翡翠曾被认为是博拉翡翠的亚种，但分子研究支持其独立物种的地位。"},{"name":"塔希提翡翠","english_name":"Society Kingfisher","scientific_name":"Todiramphus veneratus","overview":"塔希提翡翠（英文名：Society Kingfisher，学名：Todiramphus veneratus），是佛法僧目翠鸟科林翡翠属的鸟类。塔希提翡翠在法国波利尼西亚社会群岛特有的翠鸟科鸟类。栖息在热带湿润的低地森林和山地森林中。","appearance":"塔希提翡翠体长约21厘米。成年雄鸟的上半身呈暗橄榄色，头部偏蓝绿色，眼后有一块蓝绿色区域，耳羽盖同样蓝绿色。下半身为白色，胸带宽度可变，锈色。雌鸟上半身为暗褐色，有明显的褐色胸带。幼鸟喉部、胸部有深褐色条纹，侧面和腹部淡黄色。喙粗长，黑色；虹膜深棕色；腿脚黑色。","call":"塔希提翡翠发出类似噼啪声的‘kikikikiki’叫声，与林翡翠的‘kikikiki扣’有所区别。","habits":"塔希提翡翠栖息于低地森林，偏好林地、花园和种植园环境，活动高度从地面至海拔1700米。主要以无脊椎动物为食，如蟋蟀、蜘蛛、蝎子、蜗牛，也会捕食小鱼、小蛇和蜥蜴。","breeding":"在树干上挖掘巢穴，离地高度可达11米。繁殖期为10月至12月，每次产卵3枚，卵近圆形，纯白色。","identification":"与林翡翠的区别在于塔希提翡翠的雄鸟有蓝色上半身，雌鸟有明显的褐色胸带，叫声也有所不同。","protection":"IUCN：NT（近危）","distribution":"仅分布于社会群岛的Moorea和Tahiti两个岛屿。","other":"塔希提翡翠的学名由Todus和古希腊语rhamphos（意为喙）组合而成，特指其独特的喙形。"},{"name":"土岛翡翠","english_name":"Mangareva Kingfisher","scientific_name":"Todiramphus gambieri","overview":"土岛翡翠（英文名：Tuamotu Kingfisher，学名：Todiramphus gambieri），是佛法僧目翠鸟科林翡翠属的鸟类。法属波利尼西亚土阿莫土群岛特有的小型翠鸟，现存仅一个亚种——格特鲁德亚种（T. g. gertrudae）。其指名亚种（T. g. gambieri）自1922年前已灭绝。该鸟体长约20厘米，头部及颈部呈淡黄褐色，头顶具可变范围的蓝色，上体蓝或蓝绿并带紫色晕染，喉胸奶油至淡橙色，喙黑上黄下，极为艳丽。仅分布于尼奧岛（Niau）26 km²的狭小区域，全球成鸟不足90只，被IUCN列为极危物种。","appearance":"体长20厘米。格特鲁德亚种（gertrudae）：头颈部呈淡黄褐色，头顶具深浅不一的蓝色斑块，自眼向后延伸一条蓝色线；上体蓝或蓝绿，翼与尾覆羽带较深的紫色晕染；颈侧及胸侧为淡橙色至奶油色；上喙黑色，下喙淡粉杏至黄色，边缘及尖端带黑；虹膜深褐；腿脚黑色。幼鸟尚无描述。雌雄外形相似，未记载性别差异。","call":"目前尚无对其鸣唱或叫声的描述。","habits":"主要栖息于尼奧岛的林地、椰子种植园及村落花园，偶入森林。被认为留鸟，不迁徙。以昆虫及其幼虫（如甲虫）为主食，亦捕食小型蜥蜴；低潮时会在礁池捕小鱼。","breeding":"繁殖期记录为9月，亦可能在5–6月产卵。巢穴为在枯死椰树或树上腐烂椰果中挖掘的洞穴；有报告称在椰棕中垫草及茎作巢，需进一步核实。10月曾见亲鸟喂食雏鸟，其余繁殖细节未知。","identification":"与同属其他物种相比，土岛翡翠体型小、头颈部黄褐与头顶蓝色对比明显，下喙黄基部黑端，翼尾具紫色晕染。指名亚种与格特鲁德亚种仅在羽色深浅等细微处有别，且相距1 400 km以上，无中间种群。","protection":"IUCN: CR（极危）","distribution":"繁殖区：尼奧岛（Niau Island），位于土阿莫土群岛西北部。非繁殖区：无迁徙记录。指名亚种历史上分布于芒阿雷瓦岛（Mangareva Island，土阿莫土群岛东部），现已灭绝。","other":"系统分类长期存疑，曾被视作与白眉翡翠等构成复合种，或与博拉翡翠及库克岛翡翠合并或拆分；DNA研究尚缺，需进一步澄清。因鼠类夜间捕食雌鸟、猫捕食幼鸟，雌鸟与幼鸟存活率显著低于雄鸟。曾建议将其迁地保护至邻近岛屿，并建立长期监测计划。尼澳岛翡翠目前视为其亚种。"},{"name":"尼澳岛翡翠","english_name":"Niau Kingfisher","scientific_name":"Todiramphus gertrudae","overview":"尼澳岛翡翠（英文名：Niau Kingfisher，学名：Todiramphus gertrudae），是佛法僧目翠鸟科林翡翠属的独特翠鸟，仅见于法属波利尼西亚土阿莫土群岛西部的尼澳岛。拥有鲜艳的蓝绿色羽毛，头部呈淡橙色至奶油色，体型约为20厘米。此物种在历史上曾广泛分布于多个岛屿，但目前仅存于面积仅为26平方公里的单一岛屿。","appearance":"尼澳岛翡翠的成鸟具有明显的外观特征，头部和颈部呈淡黄色，头顶可见蓝色，眼睛后方有一条蓝色线条；上身蓝绿相间，翅膀和尾巴带有深紫色调；颈侧和胸部颜色由浅橙色渐变为奶油色。喙部上颌黑色，下颌呈浅粉至黄色，边缘及尖端为暗色；虹膜深棕色；腿和脚黑色。幼鸟特征未详细描述。","habits":"栖息于林地、椰子种植园和乡村花园，偶尔出现在森林中。主要以昆虫和幼虫为食，如甲虫；也会捕食小型蜥蜴，低潮时会在礁石池塘捕捉小鱼。在死椰子树或腐烂的椰子上挖掘巢穴，有报告称其巢穴由草和茎构成，位于椰子树上，需进一步确认。","breeding":"繁殖季节可能在九月，也可能在五月到六月。记录显示，十月时已开始喂养雏鸟。关于繁殖的其他信息较少。","identification":"尼澳岛翡翠与同属其他物种的区别在于其独特的颜色组合和分布区域，特别是在头部和颈部的色彩以及蓝绿色的背部。此外，它的体型和鸣叫也可能用于辨识。","protection":"IUCN：CR（极危）。此物种适应了在商业椰子种植园中觅食和筑巢，但由于鼠类和猫的捕食，成年雌鸟和幼鸟的存活率较低。建议将部分群体迁移到相邻岛屿。自2005年起，其状态从易危升级为极危。","distribution":"太平洋：Niau（土阿莫土群岛西部，波利尼西亚东部）。","other":"尼澳岛翡翠的总人口数量估计在2009年为135只，相当于不足90只成熟个体。近年来的人口调查表明，其数量显著低于先前的估计。现为土岛翡翠亚种。"},{"name":"马克岛翡翠","english_name":"Marquesan Kingfisher","scientific_name":"Todiramphus godeffroyi","appearance":"马克萨斯翡翠体长约21厘米，其最显著的特征是白色的冠、颈和下体，以及通过眼睛的暗色面具，继续为蓝黑色条纹，薄带横过颈背。上背部有一个特征性的浅黄色三角形，其余上体、翅膀和尾巴呈明亮的蓝色。喙上部为黑色，下部为淡黄色至淡角质色，尖端和边缘为深色；虹膜为深棕色；腿和脚为黑色。幼鸟的冠部为蓝绿色，头部侧面和胸部为黑色，上体为绿蓝色。","call":"发出短暂重复的“kiau”声，逐渐发展成类似笑声的叽叽喳喳。","habits":"偏好密集潮湿的低地森林，常见于溪流附近。以昆虫为主食，如甲虫和大型蚱蜢，以及小型蜥蜴；可能也会捕食一些鱼类。在树叶间捕食，或从栖木上俯冲到地面或水面捕食。","breeding":"繁殖期在9月至次年1月，在Hiva Oa岛发现繁殖记录。在旧芒果树的洞穴或腐朽的螺旋松树（Pandanus）树干中的空洞筑巢，巢孔直径3.5厘米，高度2至5米。在枯死的椰子树桩上也有发现巢穴，高度7米。","identification":"马克萨斯翡翠在其分布范围内独一无二，可以通过其大部分白色的体羽和穿过眼睛的细黑线以及蓝黑色的颈背带进行识别。","protection":"IUCN：CR（极危）","distribution":"马克萨斯翡翠仅限于马尔克斯群岛的Hiva Oa和Tahuata岛（后者可能存在），在其他马尔克斯群岛岛屿上的报道可能是错误的。","other":"全球估计数量在260至320只成熟个体之间，由于栖息地退化和外来物种的捕食，种群数量正在下降。"},{"name":"红背翡翠","english_name":"Red-backed Kingfisher","scientific_name":"Todiramphus pyrrhopygius","overview":"红背翡翠（英文名：Red-backed Kingfisher，学名：Todiramphus pyrrhopygius），是佛法僧目翠鸟科林翡翠属的鸟类。树栖型翠鸟，以蓝绿白相间羽毛和醒目的栗色臀部为显著特征。广泛分布于澳大利亚大陆的干旱地带，除塔斯马尼亚岛及东南部与西南部部分地区。","appearance":"红背翡翠长约22厘米，雄鸟重45-70克，雌鸟重41-62克。头部有绿色条纹冠，雄鸟额头及眉毛白色，眼周黑带延伸至颈部，肩部和背部上段绿色，腰至尾部为鲜明的红褐色。尾羽浅黄红，中央部分绿色，末端深蓝。雌鸟颜色稍暗淡，翅膀偏蓝绿，白色区域泛黄。幼鸟类似雌鸟，但颈部和胸部更显红褐色斑点。","call":"发出下降式哀婉哨声“kee-ip”，每数秒重复一次，形成连续系列。繁殖期间发出尖锐警报声和鹦鹉般叽叽喳喳叫声。","habits":"栖息于干旱森林、灌木丛，甚至接近无树地带，远离水源。观察并从树梢或电线俯冲捕食，然后返回栖息地。主要食物为昆虫、蜘蛛、小型脊椎动物等。","breeding":"繁殖季为8月至翌年2月，筑巢于河岸或水坝土壁，挖凿洞穴，高离地面2米左右，洞深平均28厘米，直径6厘米。每窝产卵2-6枚，孵化期20-23天，育雏期26-30天。","identification":"与相似物种区分在于灰纹冠部（蓝绿在白眉翡翠中）、飞行时全蓝的上翼以及明显的红褐色臀部。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚大陆，除塔斯马尼亚州、极西南与东南部。夏季访问东南部，其余区域全年留驻。","other":"适应性强，依赖异常降雨模式迁徙，可能影响其分布密度。"},{"name":"黄嘴翡翠","english_name":"Yellow-billed Kingfisher","scientific_name":"Syma torotoro","overview":"黄嘴翡翠（英文名：Yellow-billed Kingfisher，学名：Syma torotoro），是佛法僧目翠鸟科黄嘴翡翠属的鸟类。中型翠鸟科鸟类，广泛分布在新几内亚和澳大利亚东北部的低地。其最显著的特征是橙色头部、亮黄色的喙，以及在新几内亚雨林中的活跃身影。","appearance":"黄嘴翡翠体长约20厘米，雄鸟体重32-50克，雌鸟30-52克。雄鸟头部和颈部呈鲜红色，眼周和眼圈黑色，颈侧黑色，肩部深绿色。背部蓝绿色，尾部蓝紫色。雌鸟与雄鸟相似，但冠部有黑色斑块，下体颜色较淡。幼鸟似雌鸟，但冠羽有红边，眼周黑色面积大，嘴灰黑色。喙粗长，基部宽，尖端直，两侧无鼻沟；翼圆，初级飞羽基部有白色斑；尾圆形。","call":"鸣叫为响亮、连续的哨音颤鸣，类似邮差的哨声，主要在繁殖季节发出。","habits":"黄嘴翡翠栖息于雨林、季风林及森林边缘地带，常见于海拔500米以下。独居或成对活动，以昆虫、蚯蚓、小蛇和蜥蜴为食，常在树叶或泥土中寻找猎物。","breeding":"繁殖期在澳大利亚的昆士兰为11月至1月，在新几内亚可能为8月至3月。巢穴通常是在树蚁丘中挖掘，由两性共同完成，深度可达12厘米，宽度约9.5厘米。每窝产卵3-4枚，无壳纹的白色卵，由双亲轮流孵化。","identification":"与其他翠鸟相比，黄嘴翡翠的黄色喙和橙色头部是明显区别。雌雄差异在于雌鸟的冠部有黑色斑块。","protection":"IUCN：LC（无危）。黄嘴翡翠分布广泛，数量稳定，无严重威胁。","distribution":"分布于新几内亚及其周边岛屿，向南延伸至澳大利亚的东北部，包括昆士兰州北部和卡奔塔利亚半岛。","other":"黄嘴翡翠能够在一定程度的人类改造环境中生存，如成熟的人工林和森林边缘地带。"},{"name":"山黄嘴翡翠","english_name":"Mountain Kingfisher","scientific_name":"Syma megarhyncha","overview":"山黄嘴翡翠（英文名：Mountain Kingfisher，学名：Syma megarhyncha），是佛法僧目翠鸟科黄嘴翡翠属的鸟类。体型较大，以亮橙色头部和身体、蓝色背部和尾巴、鲜艳的黄色喙以及头后部的黑色标记为显著特征。主要分布在新几内亚高地，除了休恩半岛，常见于海拔1200至2400米的地区。","appearance":"雄性山黄嘴翡翠体长约24厘米，体重52至60克。头部和下体为棕红色，背部和翅膀上覆羽呈绿蓝色，尾部深蓝色，喙鲜黄色，尖端有暗色边缘。雌鸟头顶黑色，颈侧和下体颜色较淡。幼鸟喙灰黑色，眼周黑色区域较大，脸颊和胸部有暗色羽尖。喙粗长，翼圆，初级飞羽基部有白色斑点，尾圆形。","call":"发出一系列响亮的音符，先是上升，然后下降，最后以颤音结束，持续数秒，与黄嘴翡翠的叫声相似。","habits":"栖息于山地森林和次生植被中，主要在1200至2400米的海拔范围内，偶尔降至760米。偏好独居或成对活动，以昆虫、幼虫和小型蜥蜴为食，长时间停栖在中上层树冠，随后俯冲捕食。","breeding":"繁殖期在11月至1月间，筑巢于土崖壁或河岸的隧道式洞穴中，深度约9至12厘米，宽度9.5厘米，有时在树干上钻洞作巢，离地约3米。","identification":"与黄嘴翡翠极为相似，但体型更大，喙更长，且多数个体头部上方有暗色斑点。雌鸟头顶黑色，颈侧斑块相连。通过大小、喙的长度和头部上方的暗色标记来区分。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚岛，包括西新几内亚和巴布亚新几内亚，常见于新几内亚高地，除休恩半岛外。","other":"该物种与黄嘴翡翠关系密切，曾被认为是同一种，有记录显示两者能杂交。"},{"name":"红头小翠鸟","english_name":"African Dwarf Kingfisher","scientific_name":"Ispidina lecontei","overview":"红头小翠鸟（英文名：African Dwarf Kingfisher，学名：Ispidina lecontei），是佛法僧目翠鸟科小翠鸟属的鸟类。是最小的翠鸟之一，主要栖息于非洲热带雨林地区。以其鲜艳的橙色头部、腹部和喙部，以及独特的紫色耳斑和白色的喉部而闻名。","appearance":"红头小翠鸟身长仅约10厘米，雄鸟体重9-11克，雌鸟体重9.5-12克。其额部为黑色，头部呈现红色，后颈和背部呈紫丁香色，后颈两侧各有白色斑点。翕、背、尾部为蓝紫色，尾羽和翅膀颜色更深。下颏和喉咙为白色，胸腹及翼下为黄红色。喙部红色，虹膜深褐色，腿亦为红色。幼鸟前额黑色，头和翼为蓝黑色，背部和尾巴为亮蓝色，腹部灰白红色，腹部边缘浅黄色。嘴部黑色，带有白色边缘，下颌至嘴基部红色。","call":"其叫声为尖锐的吱吱声。","habits":"红头小翠鸟栖息于热带雨林和密林环境中，也出现在如油棕树种植园等半开放地带，分布海拔自海平面至1400米。它主要以昆虫为食，包括蜻蜓、甲虫、蚂蚁和苍蝇，偏好行军蚁。捕食方式多样，既可在树叶中也可在泥土中寻觅猎物。","breeding":"繁殖期间，红头小翠鸟会进行特殊的嬉水行为，两只鸟面对面站立，距离不超过50厘米，嘴部几乎垂直，进行二重唱式的呼唤。筑巢于土崖或河岸的堤坝上，挖掘约15厘米长、5厘米高的隧道式巢穴，卵直接产于巢穴地面。","identification":"与非洲侏儒翠鸟相比，红头小翠鸟具有明显的橙色冠羽，这是辨识的重要特征。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的塞拉利昂至加纳，尼日利亚南部至苏丹西部南部，乌干达和刚果民主共和国中部，以及安哥拉中部。","other":"红头小翠鸟由美国鸟类学家约翰·卡辛于1856年首次描述，种小名以昆虫学家约翰·劳伦斯·莱孔特的名字命名。"},{"name":"粉颊小翠鸟","english_name":"African Pygmy Kingfisher","scientific_name":"Ispidina picta","overview":"粉颊小翠鸟（英文名：African Pygmy Kingfisher，学名：Ispidina picta），是佛法僧目翠鸟科小翠鸟属的鸟类。体型小巧，宝石般亮丽，常见于非洲热带地区的林地。其最显著的外部特征是橙色面部与紫丁香色颊斑，以及狭窄的深蓝色额顶冠。广泛分布于非洲南部，偏好林地、灌木丛及某些森林地带。","appearance":"成年粉颊小翠鸟长约12厘米，雄鸟体重11-16克，雌鸟体重9-15克。额顶冠羽毛呈蓝黑色光泽，眼眉红色，脸颊紫丁香色，颈部两侧有白色或浅黄色斑点，翕、背、尾部蓝紫色，翅膀和尾巴黑色。下颏和喉咙白色，翼有黄红色调。嘴、虹膜和腿分别为红色、深棕色和橙红色。幼鸟羽色较暗，翅膀和背部淡蓝色，嘴尖带黄色，腿粉红色。","call":"发出尖锐的‘tsip’声，通常在飞行中鸣叫，也有延长的高音颤音。","habits":"栖息于多种环境，包括干燥草原、灌木丛、河流附近的密植草原、沼泽森林、常绿森林、种植园、农田、花园和草地，分布海拔可达2000米。以昆虫为主食，包括草蜢、蛾类、甲虫等，偶尔捕食蜘蛛、小型节肢动物、小青蛙和蜥蜴。在低枝上静候猎物，有时跟随蚂蚁群捕食逃跑的昆虫。","breeding":"繁殖期因纬度而异，筑巢于土崖或河流堤坝，巢穴长达30-60厘米，雌雄共同挖掘。每窝产卵3-6枚，双方共同孵化和喂养幼鸟。","identification":"与红头小翠鸟相似，但后者冠羽不黑；与冠翠鸟相比，体型更小，脸部橙色更多，偏好高地环境。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲南部，包括南至南非、东至肯尼亚、北至刚果民主共和国。部分亚种有季节性迁徙，冬季可北迁至赤道附近。","other":"在津巴布韦和南非，夜间迁徙时易受建筑物撞击影响，已成功在圈养环境下繁殖。"},{"name":"马岛小翠鸟","english_name":"Madagascar Pygmy Kingfisher","scientific_name":"Corythornis madagascariensis","overview":"马岛小翠鸟（英文名：Madagascar Pygmy Kingfisher，学名：Corythornis madagascariensis），是佛法僧目翠鸟科科里翠鸟属的鸟类。仅见于马达加斯加岛，尤其在东部和北部雨林较为常见，偶尔也在西部落叶森林中出现。以其小巧的体型和几乎荧光橙色的外观而引人注目。","appearance":"马岛小翠鸟体长约13厘米，雄鸟体重介于17至21克之间，雌鸟体重约17至22克。其头部顶部全为鲜红色，下颏、喉咙、胸部、腹部及尾下覆羽为白色，颈侧各有长方形的白色斑点。下背部、尾部、脸颊后方及颈部呈现出强烈的紫罗兰色。喙、虹膜及腿均为鲜艳的橙红色。幼鸟颜色较暗淡，紫罗兰色较浅，喙为黑色，尖端泛白。","call":"马岛小翠鸟会发出高音的“treet treet”声，当受惊扰时，则会发出尖锐的“chweip”或“treeeee”声。","habits":"马岛小翠鸟偏好居住在森林环境中，常栖息于低枝上，长时间静止不动，伺机捕食，主要以青蛙为食，也会捕食昆虫如蚱蜢、甲虫、蠼螋、蚂蚁及幼虫，蜘蛛、虾及小型蜥蜴和变色龙也是其食物来源。它们会在浓密的灌木丛中观察猎物，然后快速俯冲捕捉。","breeding":"马岛小翠鸟会在土崖壁或河流堤坝上挖掘隧道式巢穴，直径约为30至35厘米长，雌鸟通常在11月产卵，洞穴内部不铺设任何材料，卵直接产在巢穴地面上。","identification":"马岛小翠鸟与马岛翠鸟的区别在于前者具有橙色的上体和喙，而后者主要在湿地中发现。","protection":"IUCN：LC（无危）","distribution":"马岛小翠鸟主要分布在非洲的马达加斯加岛，除了中部和远南部以外的地区。","other":"历史上曾被归入Ceyx和Ispidina属，但基于分子系统发育关系的研究，现在认为它更适合作为Corythornis属的一员。"},{"name":"白腹翠鸟","english_name":"White-bellied Kingfisher","scientific_name":"Corythornis leucogaster","overview":"白腹翠鸟（英文名：White-bellied Kingfisher，学名：Corythornis leucogaster），是佛法僧目翠鸟科科里翠鸟属的鸟类。美丽的翠鸟科鸟类，体长约13厘米，体重约为14.5克。其显著特征为腹部中央有一条贯穿至尾下的白色条纹。分布于非洲中部及西部的雨林地带，栖息于河流和水池附近。","appearance":"白腹翠鸟体羽色彩鲜艳，上体呈深蓝色，腹部除了一条醒目的白色条纹外，其余部分为赤褐色。头部蓝色，脸颊红色，尾羽群青色并带有光泽。嘴部为红橙色，虹膜深棕色，腿部红色。雌雄外观相似。嘴部粗直且长，翼尖长，尾部较短，头大颈短，足细弱，趾部部分并连。","call":"发出尖锐的‘tshik’声，通常在飞行中鸣叫。","habits":"偏好栖息在有灌木丛或稀树的干燥森林、红树林、河流、沼泽、湖泊、花园、椰子种植园和池塘旁。单独生活，以小鱼为主食，也会捕食昆虫、水生无脊椎动物、蜘蛛蟹、蚯蚓、青蛙、蝌蚪和蜥蜴。具有优秀的水中视力，擅长潜水捕鱼。","breeding":"在土崖或河岸挖掘隧道式巢穴，通常不铺设巢材，直接在洞穴地面产卵。每窝产卵两枚，卵色纯白，孵化期约21天，由雌雄双方共同孵卵和喂养雏鸟。","identification":"通过腹部的白色条纹与其他类似翠鸟区分，与冠翠鸟的区别在于栖息环境，白腹翠鸟更倾向于森林环境。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部和西部，具体包括喀麦隆、加蓬等地的雨林区域。","other":"由英国动物学家Louis Fraser于1843年首次正式描述，归类于翠鸟科的Alcedininae亚科。"},{"name":"冠翠鸟","english_name":"Malachite Kingfisher","scientific_name":"Corythornis cristatus","overview":"冠翠鸟（英文名：Malachite Kingfisher，学名：Corythornis cristatus），是佛法僧目翠鸟科科里翠鸟属的鸟类。色彩艳丽的小型湿地翠鸟，广泛分布于非洲南部撒哈拉以南地区。其最显著的外部特征是头部的短小黑蓝相间的羽冠，上体呈现亮丽的金属蓝色，脸部、脸颊和下体为赤褐色，喉部和颈侧有白色斑块。成年个体的喙为鲜红色，幼鸟喙为黑色。性别相似，但幼鸟较成鸟暗淡。","appearance":"体长约13厘米，体重12至19克。两性皆有橙色眉纹，长额冠羽形成有黑、浅绿蓝相间条带的冠羽；颈侧白条；后颈和上体为深蓝宝色；下体橙红至赤褐色，腹部为淡黄色或白色；眼睛为深棕色；喙、腿和脚为红色。幼鸟较暗淡，黑色翼覆羽，赤褐色部分泛棕色，喙和腿为黑色。成年后，喙变为鲜红色。","call":"发出尖锐重复的‘seek, seek’或‘seek, seek, seek’声；伴侣间会使用二重唱‘ii-tiii-cha-cha, chui chui tuiichui chui’，结尾带有咯咯笑声。","habits":"栖息于几乎所有有水的环境，包括溪流、河流、湖泊、稻田、泻湖等。常长时间静坐不动，然后突然俯冲入水捕食。偏好在小水域活动，可能因为筑巢需求。分布区从低海拔到肯尼亚的3000米高度都有记录。","breeding":"繁殖期在西非为4月至12月，中非为6月至10月，乌干达为3月、5月、7月、10月和11月，肯尼亚南部和坦桑尼亚东部为4月至5月、7月、10月和12月。巢穴建在河岸、路堑、坑洞、土丘、倒木根部土壤或土豚洞穴侧边，隧道长25至125厘米，每窝产卵3至6枚，孵化期14至16天，幼鸟在巢内停留22至25天。","identification":"与非洲侏儒翠鸟类似但体型较大，面部橙色较少，偏好水生环境。与白腹翠鸟相比，冠羽更淡且条纹更明显，下体更多赤褐色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲撒哈拉以南的广大地区，除索马里、肯尼亚、纳米比亚和博茨瓦纳的部分干旱地区。在肯尼亚的记录高达3000米，在埃塞俄比亚为2720米。","other":"在一些地方，如利比里亚的蒙罗维亚，甚至能在城市花园中找到它们的身影。"},{"name":"马岛翠鸟","english_name":"Malagasy Kingfisher","scientific_name":"Corythornis vintsioides","overview":"马岛翠鸟（英文名：Malagasy Kingfisher，学名：Corythornis vintsioides），是佛法僧目翠鸟科科里翠鸟属的鸟类。小型而美丽的湿地翠鸟。广泛分布于非洲东部的马达加斯加、科摩罗群岛及马约特岛。以水边环境为栖息地，包括河流、湖泊、稻田和海岸。其显著特征为蓝绿色的上体，橙色的下体，以及黑色带红基的喙。","appearance":"体型小，约13厘米长，雄鸟重16-21克，雌鸟重18-22克。头部前额至冠部呈淡绿蓝色，带黑色条纹；背部、翅膀和尾部为深蓝宝石色，背部和臀部则更偏浅的天蓝色；喉咙和颈部有一块白色，脸颊及下体为赤褐色，腹部颜色较浅；喙为黑色，基部暗红；眼睛深棕色，腿和脚橙红色。幼鸟色泽较暗，上体带有黑色斑点，胸部和腹部呈淡黄色。johannae亚种颜色更淡，偏绿蓝。","call":"发出尖锐的高音‘seek’声，快速重复，尤其在飞行中，或起飞时发出非常尖锐的‘treeeeee’声。","habits":"偏好河流、溪流、湖泊、沼泽、红树林、海岸潮汐池等地，也见于稻田和椰子种植园，通常靠近树木或芦苇丛，甚至在离淡水远的干旱沿海灌木中。海拔高度从海平面至1800米。以小鱼、青蛙、甲壳类、水生和陆生昆虫为食，如蚱蜢、蝽象、苍蝇和甲虫。捕食时静坐于低处的栖木上，发现猎物后迅速潜入水中或地面捕捉，然后返回栖木反复敲打猎物。","breeding":"繁殖季节在马达加斯加为9月至次年4月，在科摩罗群岛始于10月。雌雄共筑巢，挖掘5厘米宽、40厘米长的隧道，末端有巢室，位于河岸或土堤。每窝产卵3-6枚，双方轮流孵化和育雏，但具体孵化和离巢时间未知。","identification":"与马岛小翠鸟的区别在于上体蓝色和较暗的喙。前者偏好湿地，后者则常见于森林环境。","protection":"IUCN：LC（无危）。在马达加斯加分布广泛且数量相对较多，出现在多种生境中，如Ranomafana国家公园和Perinet特殊保护区。在科摩罗群岛的具体数据不多，但认为数量合理。","distribution":"分布于马达加斯加、科摩罗群岛（包括Grand Comoro）和马约特岛。在马达加斯加可见于各种生境，从海平面至1800米高度。在科摩罗群岛，尤其是Grand Comoro岛上，可见于海岸和火山湖附近。","other":"属于佛法僧目翠鸟科科里翠鸟属。"},{"name":"小蓝翠鸟","english_name":"Cerulean Kingfisher","scientific_name":"Alcedo coerulescens","overview":"小蓝翠鸟（英文名：Cerulean Kingfisher，学名：Alcedo coerulescens），是佛法僧目翠鸟科翠鸟属的鸟类。原生于印尼的部分地区。以全身金属蓝的外观而著称，与常见的翠鸟相似，但腹部为白色而非橙色。雄鸟比雌鸟更显蓝色，雌鸟的羽毛略带绿色。","appearance":"这种小型翠鸟体长约13厘米，头部和上体呈现海蓝色，颈部侧面和喙基部有白色斑块，尾部银蓝色，胸部有一条明显的蓝色宽带。雄鸟的上体颜色更为鲜艳，雌鸟则偏绿，幼鸟下体灰白，胸带不明显。嘴黑色，虹膜深褐色，腿和脚为棕红色。翼下白色，嘴粗直且长，翼尖长，尾短圆，体羽色彩艳丽。","call":"发出高音重复的“ti ti ti”声，或飞行中的两音节“tew-tew”叫声。","habits":"小蓝翠鸟常见于河流、运河、水库、湿地、河口、湖泊、红树林、鱼塘及灌溉稻田等水域附近，栖息地海拔从海平面至800米。它通常单独活动，常坐在低矮的枝头俯瞰水面或泥滩，然后潜入水中捕食，也会从开阔水域的空中悬停捕食，主要以小鱼、甲壳类和水生昆虫为食。","breeding":"小蓝翠鸟在土崖壁或田野、小溪堤坝上挖掘隧道式洞穴作巢，巢穴内部无铺垫物，直接在地面产卵。每窝产卵6至7枚，卵色纯白，大小约28毫米×18毫米，每年繁殖1至2次，孵化期约21天，雌雄共同孵化，雌鸟负责喂养雏鸟。","identification":"与常见的翠鸟相比，小蓝翠鸟的腹部为白色，而后者为橙色。此外，雌雄小蓝翠鸟在颜色上有细微差异，雌鸟羽毛略带绿色。","distribution":"分布于印尼的苏门答腊南部、爪哇、巴厘岛、康厄安群岛、龙目岛至弗洛勒斯岛的小巽他群岛西部和中部。"},{"name":"蓝带翠鸟","english_name":"Javan Blue-banded Kingfisher","scientific_name":"Alcedo euryzona","overview":"蓝带翠鸟（英文名：Javan Blue-banded Kingfisher，学名：Alcedo euryzona），是佛法僧目翠鸟科翠鸟属的珍稀鸟类，体型较小，以森林中的溪流和河流为栖息地，分布于印度尼西亚的爪哇岛。其最显著的特征是银蓝色背部和尾部，宽阔的蓝绿色胸带，以及白色的喉部。雄鸟腹部白色，喙全黑；雌鸟腹部橙色，下喙基部红色。因栖息地破坏而极度濒危。","appearance":"蓝带翠鸟体长约20厘米，重34至38克。雄鸟背部黑色，点缀翠蓝色羽毛，脸部下方有大片白色斑块。胸腹橙黄色，肩胛、尾巴及翅膀上有鲜明的天蓝色斑块，与黑色身体形成对比。腿爪橙红，虹膜深棕。雌鸟深褐色，无蓝色胸带，腹部、脖子、小尾巴及翼下橙红色。颌骨灰黑，下部红橙色。喙粗直，长而坚实，呈圆脊形，翼尖长，尾短圆，体羽鲜艳，具蓝绿光泽。头大颈短，翼短圆，尾短，嘴长尖，脚短，趾细弱，第4趾与第3趾大部分并连。","call":"发出刺耳的叫声，类似于普通翠鸟的叫声。","habits":"栖息于热带湿润低地森林、红树林及河流边，偏好隐蔽的中型永久性溪流，活动范围在海平面至1250米高度。以小鱼为主食，兼食甲壳类、水生昆虫及其幼虫，偶尔捕食小型蛙类和少量水生植物。眼睛能在水中迅速调整视角，捕鱼技巧高超。","breeding":"在土崖壁或堤坝挖掘隧道式巢穴，卵直接产在巢穴地面，每窝产卵6至7枚，纯白色，孵化期约21天，雌雄共同孵卵喂雏。","identification":"与普通翠鸟相比，整体色彩较暗淡，缺乏眼后明亮的橙白色斑块。雌鸟的橙色腹部和红基下喙区分为蓝带翠鸟与其它同属物种。","protection":"IUCN：CR（极危）","distribution":"分布于印度尼西亚的爪哇岛，繁殖区域与非繁殖区域一致。","other":"与马来蓝带翠鸟曾被认为是同一物种，后基于形态差异被区分为两个独立物种。"},{"name":"亮蓝翠鸟","english_name":"Shining-blue Kingfisher","scientific_name":"Alcedo quadribrachys","overview":"亮蓝翠鸟（英文名：Shining-blue Kingfisher，学名：Alcedo quadribrachys），是佛法僧目翠鸟科翠鸟属的鸟类。体长约16厘米的小型翠鸟，背部具金属光泽的深蓝至紫色羽毛，腹部栗红，雌雄差异仅见于雌鸟下喙基部呈暗红色。该鸟主要分布于西非至中非的森林溪流、红树林及低地水域，通常单独活动，行踪隐秘。","appearance":"成鸟背部呈亮紫色或钴蓝色，随地理变异；头、翼黑色而闪极蓝光；尾蓝黑色；颏喉乳白，胸侧具紫色小领环，余下体羽橙栗色；眼虹膜暗褐；嘴全黑；脚橙红。雌鸟仅在嘴基部具暗红斑。幼鸟头顶色淡，下体橙栗色亦较浅，胸部有暗色横斑，嘴端具白斑。指名亚种背部紫蓝，亚种guentheri背部为更亮的钴蓝，腰淡天蓝色。","call":"飞行时发出尖锐的“cheet”；另有连续的高音“seet-seet-seet-seet”。巢雏受惊时会发出“嘶嘶”声。","habits":"栖于沿海泻湖、河口、红树林，以及森林、稀树草原和农田中的芦苇丛、纸莎草沼泽、溪流、河湖、池塘、水库等；海拔记录至1800米。基本留鸟，但局部地区有季节性数量变化，如尼日利亚拉各斯3–5月缺记录，亦可见幼鸟扩散导致的偶发移动。觅食时停栖于水边芦苇或低枝，距水面1–2米，见猎物后垂直俯冲入水，捕获后返回原枝。主食6厘米以下小鱼，亦食水生昆虫幼虫及小蟹。","breeding":"繁殖期各地差异：尼日利亚9月，喀麦隆11月，加蓬12–3月，刚果3月，乌干达12月、2月及4–7月（高峰5月），东北扎伊尔10月。配偶共同在垂直溪岸或沙坑侧壁挖掘长约40厘米的隧道巢，巢址可距溪流达1公里。每窝4–6枚卵，其余繁殖细节未见报道。","identification":"体型大于普通翠鸟，嘴全黑；与暗色喙部的幼年普通翠鸟区别在于面部无橙色。亚种guentheri背部更亮且腰淡蓝色，易与指名亚种区分。","protection":"IUCN: LC（无危）","distribution":"繁殖区：西非塞内冈比亚向东至尼日利亚尼日尔河以西；东南尼日利亚向东至南苏丹极南部及乌干达维多利亚湖地区，向南至北安哥拉及西北赞比亚。","other":"近期分子研究表明，亮蓝翠鸟与半领翠鸟亲缘关系最近，二者共同构成普通翠鸟与小蓝翠鸟的姊妹群。"},{"name":"蓝耳翠鸟","english_name":"Blue-eared Kingfisher","scientific_name":"Alcedo meninting","overview":"蓝耳翠鸟（英文名：Blue-eared Kingfisher，学名：Alcedo meninting），是佛法僧目翠鸟科翠鸟属的鸟类。体型小巧的翠鸟科翠鸟属鸟类。其最显著的特征为深蓝色的外观和橙色的眼前斑点，以及颈部两侧的白色耳簇。该物种分布于亚洲的印度次大陆至东南亚一带，偏好栖息于浓荫覆盖的森林小溪旁。","appearance":"蓝耳翠鸟全长约16厘米，雄鸟头部和颈部呈超群的钴蓝色，带有更深的蓝色条纹，形成鳞片般的外观。背部、翅膀和尾巴为光泽的深蓝色，背部中央有一条较浅的蓝色带。下巴和喉咙为白色，腹部为深橙色。雄鸟的喙为黑色，基部带有红棕色，雌鸟喙几乎全红。幼鸟上体颜色较暗，脸颊和耳羽呈锈色，与普通翠鸟相似。","habits":"蓝耳翠鸟居住在森林中被良好遮蔽的水道附近，主要以鱼类、甲壳类和昆虫为食，包括蜻蜓幼虫。它会在水边枝头停留，通过点头和摆尾寻找猎物，然后垂直潜水捕食，随后返回枝头敲击猎物，准备吞食。有时会飞掠水面捕食空中昆虫。","breeding":"繁殖季节在印度北部为4月至6月，南部为1月，马来西亚半岛为5月至6月，苏门答腊为4月，婆罗洲为12月至8月。它们在倾斜或垂直的土岸挖掘巢穴，长度30至100厘米，宽5厘米，最终形成一个直径12至14厘米、高10至12厘米的巢室。一窝通常产3至7枚蛋，双亲共同孵化和喂养幼鸟。孵化期约为21天，幼鸟离巢期约为23天。","identification":"蓝耳翠鸟与普通翠鸟的区别在于蓝耳翠鸟没有橘色的贯眼纹，眼后有蓝色耳斑；背部为亮丽的蓝色，而非绿色；在中国极为罕见。","protection":"IUCN：LC（无危）","distribution":"分布于印度至东南亚，包括尼泊尔、不丹、孟加拉国、缅甸、泰国、柬埔寨、越南和马来西亚等地。在中国，仅限于云南省勐腊县。"},{"name":"普通翠鸟","english_name":"Common Kingfisher","scientific_name":"Alcedo atthis","overview":"普通翠鸟（英文名：Common Kingfisher，学名：Alcedo atthis），是佛法僧目翠鸟科翠鸟属的鸟类。俗名: 翠鸟、鱼狗、打鱼郎、钓鱼郎、刁鱼郎、小翠，又名翠鸟、鱼狗、打鱼郎等。体型小巧，上体蓝绿色，中央有一条蓝色带纹，下体橙棕色。广泛分布于欧亚大陆、东南亚、印度尼西亚至新几内亚，以及非洲北部、新几内亚东部、俾斯麦群岛和所罗门群岛。对生态环境要求较高，是环境指示物种。","appearance":"普通翠鸟体长16-18厘米，体重23-45克（雄鸟），30-35克（雌鸟）。雄鸟具有橘红色眉纹、黑色眼纹、橘红色耳羽，白色颈带，上体和尾部亮湛蓝色，翅膀暗绿带浅蓝斑点，下体橘红色；喙黑色，基部红色；虹膜深褐色；腿和脚橙红色。雌鸟与雄鸟相似，但下颌橙红色，顶端黑色。幼鸟较成鸟暗淡，背部更绿，腹部颜色较浅，胸部有灰暗条纹，喙黑色，腿和脚黑色。","call":"飞行中发出短促尖锐的‘chee, chee’声，警戒时声音更粗糙‘tjii’，威胁时发出刺耳的‘kritritrit’声，广告叫声‘tee titi titi titi’，雌鸟乞食声‘chee chee’，兴奋叫声‘tsuk tsuk’，雏鸟最初发出哀怨的‘cheep cheep’声，10天后变为持续音，离巢时变为尖锐的‘zipp’或‘tschick’。","habits":"栖息于有小鱼的淡水或咸水环境，偏好河流、溪流、运河和池塘。冬季向沿海迁移，常见于河口、港口和岩石海岸。以鱼为主食，也捕食水生昆虫、甲壳类、两栖动物等。潜水捕食，视觉适应水中猎物。每日需摄取相当于体重60%的食物。","breeding":"繁殖期3月至8月，筑巢于河岸、采石场、沙坑等地的垂直土壁，隧道长50-90厘米，终室宽9-17厘米。每窝产3-10枚光滑白蛋，平均6-7枚。双亲白天轮流孵卵，夜间由雌鸟孵卵，孵化期19-21天。幼鸟孵化后24-25天离巢，每年可育1-2窝，有时3-4窝。","identification":"普通翠鸟的橘黄色条带横贯眼部及耳羽为其显著识别特征，可借此与白胸翡翠及斑鱼狗区分。","protection":"IUCN：LC（无危）。已列入中国《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"广泛分布于欧亚大陆、东南亚、印度尼西亚至新几内亚，以及非洲北部、新几内亚东部、俾斯麦群岛和所罗门群岛。在中国大陆分布于海南、东北、华东、华中、华南及西南地区。","other":"对环境污染敏感，是水质健康的重要指标。"},{"name":"半领翠鸟","english_name":"Half-collared Kingfisher","scientific_name":"Alcedo semitorquata","overview":"半领翠鸟（英文名：Half-collared Kingfisher，学名：Alcedo semitorquata），是佛法僧目翠鸟科翠鸟属的鸟类。中等体型的翠鸟，广泛分布在非洲东部和南部。其特征显著，包括交替的深蓝和亮蓝色条纹装饰的头部，以及一侧颈部的奶油色斑纹形成半领状。该鸟主要栖息于河流、溪流和水体丰富的环境，以鱼类为食。","appearance":"体长约18厘米，体重介于35至40克之间。雄鸟的黑眼先上方有一道浅色线，颈侧有半圈奶油色斑纹。头顶部有黑色与亮钴蓝色条纹，额前有灰绿色斑纹，颈部亮蓝色。后颈、背部和尾部呈现亮丽的钴蓝色，尾部带紫色光泽。翅膀呈深蓝色，肩部蓝绿色。下颏黄色，喉部白色，其余下体赭色。两侧胸部有深蓝色斑点。雌鸟与雄鸟相似，但雌鸟下颌基部有红色。幼鸟体羽较深，胸前有暗条纹，腿暗红色。嘴长而坚，翼尖长，尾短圆，体羽鲜艳。","call":"会发出尖锐的‘seet’声。","habits":"偏好栖息在有密集水边植被的河流、溪流和湖泊附近，偶尔出现在沿海泻湖和河口。善于潜水捕食，主要以小鱼为食，也会捕食螃蟹、青蛙、水生昆虫及其幼虫。有时会在低枝上等候，然后急速潜入水中捕获猎物。","breeding":"筑巢于河岸边，通常在堤岸上挖掘垂直洞穴。产卵数量一般为3至4枚，雌雄双方共同参与孵化，但幼鸟喂养主要由雌鸟承担。幼鸟大约27天后离开巢穴，很快就能飞行。","identification":"与冠翠鸟相比，体型更大，且具有黑色的喙。幼鸟与冠翠鸟幼鸟相似，但半领翠鸟幼鸟面部颜色较深，无橙色部分。","protection":"IUCN：LC（无危）","distribution":"分布于埃塞俄比亚和相邻的苏丹东南部，从安哥拉向东至坦桑尼亚，南至纳米比亚东北部、博茨瓦纳东部和南非东北部与南部。在非洲南部和东部广泛分布。","other":"在某些地区，如南非的纳塔尔海岸，由于污染、河流淤积和栖息地丧失，半领翠鸟的数量有所下降。"},{"name":"斑头大翠鸟","english_name":"Blyth's Kingfisher","scientific_name":"Alcedo hercules","overview":"斑头大翠鸟（英文名：Blyth's Kingfisher，学名：Alcedo hercules），是佛法僧目翠鸟科翠鸟属的鸟类。翠鸟属的最大成员，身长22至23厘米，以深蓝色上体、黑色头部和亮丽的钴蓝色翼部为显著特征。分布于喜马拉雅山脉东段至越南中部的热带森林地带，常见于遮荫的山涧旁。","appearance":"雄鸟头部羽毛呈黑色，尖端泛蓝光，面颊至颈项为淡黄白色，背部至尾上覆羽为耀眼的钴蓝色，翼部及肩羽为深绿黑色，翼上覆羽点缀着钴蓝色。下体以栗色为主，胸部有一块深蓝黑色斑。雌鸟下颌基部红色。幼鸟的羽毛特征尚未详述。","call":"发出响亮而沙哑的‘pseet’声，较之于普通翠鸟，叫声更为粗犷。","habits":"栖息于深谷中的溪流与小河，以及常绿森林或邻近农地的森林水道。活动于海拔200至1200米间，主要集中在400至1000米。主要以鱼类为食，也会捕食昆虫，常从隐蔽的灌木上俯冲入水捕食。","breeding":"繁殖期主要在4月至5月，巢筑于溪流边的泥岸或森林峭壁的隧道末端，巢室宽15至20厘米，高10至13厘米。每窝产卵4至6枚，双亲共同孵化。","identification":"与普通翠鸟相比，斑头大翠鸟体型更大，没有橙色的贯眼纹，且拥有更重的全黑色喙。","protection":"IUCN：NT（近危）, 中国国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"分布于东洋界，自尼泊尔东部至越南中部。在中国，可见于西藏、云南、海南、广西、广东、江西、福建等地。","other":"该物种密度较低，面临栖息地退化和人为干扰的威胁。"},{"name":"马来蓝带翠鸟","english_name":"Malaysian Blue-banded Kingfisher","scientific_name":"Alcedo peninsulae","overview":"马来蓝带翠鸟（英文名：Malaysian Blue-banded Kingfisher，学名：Alcedo peninsulae），是佛法僧目翠鸟科翠鸟属的小型鸟类。主要分布在远东地区的缅甸南部、马来半岛、苏门答腊岛和婆罗洲。马来蓝带翠鸟以其独特的蓝绿色带状标记和白色胸部而著称，雄鸟尤为显著。","appearance":"马来蓝带翠鸟体长约17至20.5厘米，翼展79至92毫米，尾长35至40毫米，喙长45至50.8毫米，跗跖长度11.9至13.7毫米，体重在40.6至48.5克之间。成鸟具有白色的喉部和颈部，连接到狭窄的红褐色颈环，头部、翅膀和上尾覆羽呈蓝黑色，背部为淡银蓝色，与其余部分形成鲜明对比。雄鸟拥有宽广的蓝胸带，雌鸟则为暗红色下体，缺乏胸带，脸颊比头顶更亮蓝色。雌鸟还具有更广泛的红褐色眼区和较暗的翅膀与头部。幼鸟类似成鸟，但颜色较暗淡，雄鸟幼鸟腹部带有红褐色色调。","call":"马来蓝带翠鸟发出尖锐的叫声，类似于普通翠鸟的叫声。","habits":"马来蓝带翠鸟居住在岩石边、流动的溪流和河流旁的常绿和半常绿森林中，偏好中等大小、隐蔽的缓慢流动的永久性溪流，周围有树木和自然植被覆盖的河岸。它们偶尔出现在混合落叶林、后红树林和沿海沼泽。马来蓝带翠鸟主要在低地发现，但在马来西亚半岛的山地雨林中高达900米，在婆罗洲达到1400米。","breeding":"繁殖活动通常发生在1月至3月间，但繁殖季节可能延长至1月中旬至8月中旬。巢穴通常位于森林中的溪流岸边，有时会在溪流岸边挖掘巢穴。每窝产3至5枚白色蛋。","identification":"马来蓝带翠鸟与普通翠鸟和蓝耳翠鸟相似，但整体颜色更暗淡，缺乏橙色眼后斑块和红色喙基部，且没有明亮的蓝色。雌性马来蓝带翠鸟与这两种翠鸟的雌鸟共享红褐色下体和明显的白色颈闪，但马来蓝带翠鸟的背部为醒目的淡蓝色，与深色上体形成鲜明对比。","protection":"IUCN：NT（近危）","distribution":"马来蓝带翠鸟主要分布在缅甸南部、马来半岛、苏门答腊岛和婆罗洲。在马来西亚半岛，它们被发现在海拔高达900米的山地雨林中，而在婆罗洲，高度可达1400米。","other":"马来蓝带翠鸟曾被认为是蓝带翠鸟的一个亚种，但现在被认为是一个独立物种。"},{"name":"三趾翠鸟","english_name":"Black-backed Dwarf Kingfisher","scientific_name":"Ceyx erithaca","overview":"三趾翠鸟（英文名：Black-backed Dwarf Kingfisher，学名：Ceyx erithaca），是佛法僧目翠鸟科三趾翠鸟属的鸟类。俗名: 小黄鱼狗，也被称为黑背翠鸟、东方侏翠鸟，俗称小黄鱼狗。这种小型翠鸟拥有鲜艳的色彩和红色的长喙，其上体呈深蓝色，腹部橙色，头部有紫红色冠羽。常见于东南亚的干燥山溪边，有时远离水源。飞行迅速直接，善于在浓密的植被中穿梭，发出尖锐的高音叫声。","appearance":"三趾翠鸟体型小巧，长度介于12.5至14厘米，体重雄鸟14-21.5克，雌鸟14-16克。头部有黑色斑点，颈部两侧蓝白相间，头顶紫红色，背部与翅膀深蓝色；下巴和喉咙白色，其余腹部淡橙色；虹膜深棕色；喙、腿脚红色。幼鸟色泽较暗淡，少紫红色，下巴、喉咙和腹部白色，喙黄橙色，顶端淡色；背部仅肩羽和翼覆羽蓝色。","call":"三趾翠鸟发出尖锐的高音\"tsriet-tsriet\"或柔和的\"tjie-tjie-tjie\"叫声，通常在飞行中发出。","habits":"三趾翠鸟栖息于落叶和常绿原始、次生森林，以及河流附近的湿地，偏好在小溪旁或池塘附近活动，但也常见于远离水源的地带。它们活跃在低地至海拔1300米的高度，以昆虫为主食，如螳螂、蚱蜢、苍蝇、水甲虫、飞蚁、石蛾；偶尔捕食蜘蛛、蠕虫、小蟹、鱼、蛙和蜥蜴。独居捕食，从低矮的栖木上飞出，捕食地面或树叶中的猎物。","breeding":"繁殖期在印度南部为7月至9月，在斯里兰卡为2月至7月，在印度东北部为4月至5月，在马来半岛为3月至7月，在苏门答腊为3月，在爪哇为12月至5月。在溪岸、路基、陆地白蚁巢或倒木根部土壤中筑巢，挖掘15至100厘米长的隧道，直径3.8至4.5厘米，末端为无衬垫的巢室。每窝产3至7枚蛋，孵化期约17至18天。","identification":"三趾翠鸟与同属的其他种类相比，具有独特的紫红色头部、深蓝色背部和橙色腹部。成鸟的特征明显，幼鸟色泽较为暗淡，但头部的紫红色减少，下巴、喉咙和腹部白色，喙色为黄橙色。","protection":"IUCN：NT（近危）","distribution":"分布于印度次大陆至中国东南部，中南半岛和泰国。在印度东部、孟加拉国、印度东北部、缅甸、中国极南地区、老挝、柬埔寨和泰国等地繁殖。部分鸟群冬季迁往马来半岛和苏门答腊。","other":"曾被认为与棕背三趾翠鸟为同一物种的不同形态，但分子遗传研究表明两者为独立物种。"},{"name":"菲律宾三趾翠鸟","english_name":"Philippine Dwarf Kingfisher","scientific_name":"Ceyx melanurus","overview":"菲律宾三趾翠鸟（英文名：Philippine Dwarf Kingfisher，学名：Ceyx melanurus），是佛法僧目翠鸟科三趾翠鸟属的鸟类。体型小巧、色彩鲜艳的翠鸟，广泛分布于菲律宾的多个岛屿，如吕宋岛、波利略群岛、卡坦端内斯、巴西兰、萨马岛、莱特岛和棉兰老岛。其自然栖息地为热带湿润低地森林，但面临着严重的栖息地丧失威胁。","appearance":"菲律宾三趾翠鸟身长约为12厘米，体重约16.4克，全身覆盖着橙红色的羽毛，头部、前额、颈部、胸部和背部带有橙红色，颈后两侧有白色长斑，翅膀呈灰褐色，羽毛边缘深蓝色，下体腰部和腹部白色，尾羽橙红色，颏喉白色，耳羽紫红色，具有光泽。虹膜为棕色，嘴和脚为鲜红色。独特的三趾特征，尾巴比喙短，翼形尖长，羽色非黑白。喙粗直且长，鼻沟不明显，翼尖长，第1片初级飞羽稍短，第3、4片最长，尾短圆，体羽色彩艳丽。","call":"发出高音的虫鸣般的叫声，被描述为‘zeeep’声，几乎听不见。","habits":"栖息于低地的原始森林和次生林，海拔高度可达750米，偏好雨水充沛的环境，常见于河流附近。单独或成对活动，以昆虫、蜘蛛、蝎子、蜗牛等为食，偶尔也会捕食小型水生动物。不捕鱼，有时会捕捉小型蛙类。","breeding":"在土崖壁或河堤挖掘隧道式洞穴筑巢，巢穴内不铺设任何衬垫物，卵直接产在巢穴地面。也有在树干上钻洞筑巢的记录。","identification":"与双色三趾翠鸟相似，但从正面或下方观察时，菲律宾三趾翠鸟缺乏明亮的蓝色头部和背部。与C. erithaca motleyi相比，其下体颜色更暗淡，银翠鸟下方为蓝白相间，上方主要为深蓝色，而C. lepida上体也为蓝色。","protection":"IUCN：VU（易危）","distribution":"分布于菲律宾的吕宋岛、波利略群岛、卡坦端内斯、巴西兰、萨马岛、莱特岛和棉兰老岛。在吕宋岛的奎松国家公园、北锡亚里山脉国家公园和比科尔国家公园有记录。在棉兰老岛的希尔龙-希尔龙保护区也有记录。","other":"面临的主要威胁是森林的大规模砍伐，用于农业、木材生产和采矿活动。"},{"name":"小三趾翠鸟","english_name":"Sulawesi Dwarf Kingfisher","scientific_name":"Ceyx fallax","overview":"小三趾翠鸟（英文名：Sulawesi Dwarf Kingfisher，学名：Ceyx fallax），是佛法僧目翠鸟科三趾翠鸟属的鸟类。体型微小，与三趾翠鸟相似。其显著特征包括大型胡萝卜橙色的喙、蓝鳞状的冠羽、紫颊、白色喉部和颈部条纹、橙色下体、紫红色的背羽和鲜明的亮蓝色臀部与尾羽。该物种特有于印尼苏拉威西岛，栖息于低地森林，面临严重的栖息地丧失威胁。","appearance":"小三趾翠鸟体型娇小，约12厘米长，体重18克。头部黑色额前，带蓝色尖端；脸颊呈淡紫色，颈侧有白色斑点；背部暗红棕色，翅膀覆羽和肩羽同色；背部下半部及臀部、尾羽上覆羽为鲜艳的蓝色；主翼羽和尾羽黑色；喉部白色，胸部深橙色，向腹部渐变为浅色。虹膜深棕色，喙、腿和足均为红色。幼鸟颜色较暗淡，喙为黑色，末端淡色。","call":"小三趾翠鸟发出轻柔、重复、极高音调的‘seee’声或类似‘siiiiiiiiit ... siiuiiiiiit...siiiii’的啾啾声。","habits":"栖息于低地和山地原始森林，偶尔出现在被选择性砍伐的次生林、种植园甚至以Macaranga sp.和Piper aduncum为主的次生灌木丛中。活动范围从海岸至海拔1000米，主要在600米以下，不依赖水源。","breeding":"在土崖或河堤上挖掘隧道式巢穴，深约25厘米，宽13-15厘米，直径5-7厘米。巢穴通常无铺垫物，雌鸟产3至7枚卵，直接在巢穴地面孵化。","identification":"独特的第四趾退化，与同域内的其他翠鸟种类有明显的色彩差异。","protection":"IUCN：LC（无危）","distribution":"分布在苏拉威西岛、Lembeh岛（东北半岛以东）和Buton岛（苏拉威西东南部外海）。","other":"自然栖息地遭受严重破坏，导致种群数量急剧减少。"},{"name":"摩鹿加三趾翠鸟","english_name":"Moluccan Dwarf Kingfisher","scientific_name":"Ceyx lepidus","overview":"摩鹿加三趾翠鸟（英文名：Moluccan Dwarf Kingfisher，学名：Ceyx lepidus），是佛法僧目翠鸟科三趾翠鸟属的鸟类。体型小巧、色彩斑斓的翠鸟，拥有鲜艳的橙色喙与腹部，头部斑点蓝中带黑，背部呈深蓝，配以电蓝色条纹，颈部有白色标记，喙基橙色，幼鸟色泽稍暗。该鸟种主要分布在印尼摩鹿加群岛，生性孤僻，栖息于低地至山麓的森林底层，偶尔在森林溪流边活动。","appearance":"摩鹿加三趾翠鸟体长约14厘米，雄鸟体重11-21克，雌鸟13-24克。雌雄同形同色，成鸟头顶橙色并带有黑色斑点，前额、顶冠、颧、脸颊、颈后蓝色泛黑光，每根羽毛都显现出亮蓝色。颈侧有一白色三角区，披风、肩胛、翅膀蓝黑有光泽，背部、尾部亮蓝色。下颏和喉咙白色或微黄色，胸腹亮橙色，尾端黑色，喙红色，虹膜深棕色，腿橙黄色，仅有三个趾。幼鸟蓝色略淡，喙基橙色。","call":"发出尖锐高音的‘tseeeeet’叫声，音调约6.5-7.5kHz，有时为下降的嗡嗡声，持续0.4-0.5秒，间隔不规律。","habits":"栖息于热带雨林、季风次生林、沿江中下游，分布于海平面至海拔1300米的区域。捕食时快速振翅，主要以昆虫为食，如蜻蜓和其他昆虫。偏好在森林溪流中活动。","breeding":"繁殖期随地区不同而异，通常在土崖壁或河流堤坝挖掘洞穴作为巢穴，直接产卵于地面，每窝产卵两枚。","identification":"与普通翠鸟和天蓝翠鸟相比，体型更小，喙橙色，颈部有白色标记，幼鸟上部颜色更深，喙基部暗色。","protection":"IUCN：LC（无危）","distribution":"主要分布于印尼摩鹿加群岛，包括Ambon、Seram、Saparua、Seram Laut、Kasiui、Watubela、Obi、Bisa、Bacan、Ternate、Halmahera、Tidore、Morotai等岛屿。","other":"曾被分类为广泛分布的物种群的一部分，后分子分析显示其与其他种类有显著遗传差异，现独立为种。"},{"name":"双色三趾翠鸟","english_name":"Dimorphic Dwarf Kingfisher","scientific_name":"Ceyx margarethae","overview":"双色三趾翠鸟（英文名：Dimorphic Dwarf Kingfisher，学名：Ceyx margarethae），是佛法僧目翠鸟科三趾翠鸟属的鸟类。具有三趾，上体深蓝色，下体橙色鲜明，喙与腿鲜红，喉部白色，脸颊后方有白斑，头侧有橙色斑点。曾被认为灭绝于宿务岛，近期又得以重新发现。","appearance":"成年双色三趾翠鸟体长约14.5厘米，体重介于15.7至23克之间。头部、背部、臀部、翅膀和尾羽上覆羽的颜色从电光蓝到亮金属钴蓝不等，有时混有黑色。飞行羽黑色，次级飞羽边缘蓝色。喉部淡黄色至白色，胸部及腹部橙黄色，向后渐淡。喙、腿及脚呈红橙至深红色，眼睛棕至深棕色。幼鸟上体有更多黑色。与和Ceyx mindanensis的区别在于缺乏粉玫瑰色的冠羽和胸部，且上体颜色较暗淡。","call":"发出高音金属质感的“pe-teeeet pe-teeeet”声，通常在停栖时鸣叫。","habits":"栖息于低地和山脚森林，飞行迅速，以昆虫和虫蛹为食。不同于其近缘物种，如菲律宾三趾翠鸟和南方银色翠鸟，它们不在水中捕鱼，而仅用水清洁羽毛。","breeding":"相关信息未提供。","identification":"与菲律宾三趾翠鸟相似，但双色三趾翠鸟具有明亮的蓝色头部和背部，而无粉玫瑰色的冠羽和胸部。与和Ceyx mindanensis的区别在于色彩差异。","protection":"IUCN：LC（无危）。物种分布范围估计为116,000平方公里，但由于持续的栖息地破坏，局部数量可能正在下降。","distribution":"分布于菲律宾的米沙鄢群岛西部、Camaguin Sur、棉兰老岛南部以及苏禄群岛，包括Banton、Tablas、Romblon、Sibuyan、Semirara、Negros、Cebu、Olango、Siquijor、Mindanao、Basilan、Malamaui和Sulu群岛中的Jolo、Tawitawi和Bongao。","other":"曾被归为变色矮翠鸟的15个公认亚种之一。2013年的一项分子系统发育研究发现，岛屿亚种间存在显著分化，因此变色矮翠鸟被拆分为多个物种，包括双色三趾翠鸟在内的12个亚种被提升为独立物种。同时，变色矮翠鸟更名为摩鹿加三趾翠鸟。"},{"name":"苏拉三趾翠鸟","english_name":"Sula Dwarf Kingfisher","scientific_name":"Ceyx wallacii","overview":"苏拉三趾翠鸟（英文名：Sula Dwarf Kingfisher，学名：Ceyx wallacii），是佛法僧目翠鸟科三趾翠鸟属的鸟类。原被视为变异性三趾翠鸟的亚种之一，2013年分子系统学研究确认其独立物种地位，分布于印尼苏拉群岛，栖息于低地湿润森林。","appearance":"体型较小，喙全橙色，上体深蓝，背部有浅蓝色条纹，喉部白色，腹部橙色。颈侧有橙色斑块，前额橙色。与蓝耳翠鸟和普通翠鸟相比，体形更小，喙色一致，上体颜色更深的黑蓝。","call":"发出极高音调、尖锐的‘tseeeeip’叫声，符合矮型翠鸟叫声特征。","habits":"栖息于森林下层，活动范围至少可达海拔500米。与蓝耳翠鸟和普通翠鸟有重叠分布，但通过体型、喙色和上体色彩加以区分。","identification":"与蓝耳翠鸟和普通翠鸟相比，苏拉三趾翠鸟更小，喙色全橙，上体色彩更深。","protection":"IUCN：NT（近危）。估计成熟个体数量在2500至10,000之间，总体分布范围4700平方公里，数量疑下降，主要威胁来自伐木活动导致的生境丧失。","distribution":"分布于苏拉群岛（Seho, Taliabu, Mangole, Sanana），位于印尼东部，靠近苏拉威西岛。","other":"曾被认为是变异性三趾翠鸟的15个公认亚种之一，现已确认独立物种地位。"},{"name":"布鲁三趾翠鸟","english_name":"Buru Dwarf Kingfisher","scientific_name":"Ceyx cajeli","overview":"布鲁三趾翠鸟（英文名：Buru Dwarf Kingfisher，学名：Ceyx cajeli），是佛法僧目翠鸟科三趾翠鸟属的鸟类。仅见于印尼的布鲁岛。其最显著的特征是拥有鲜亮的橙色喙部和额斑，以及蓝橙相间的羽色。","appearance":"该鸟体长约14厘米，上体呈深蓝色，背部、臀部和上尾覆羽则为明亮的淡蓝色，形成鲜明对比。头部主要为深蓝，冠部点缀着微小的电蓝色斑点。耳羽后方有一片橙白相间的区域紧邻颈背，面颊部为深橙色，下体为鲜艳的橙色，与白色喉部形成鲜明界限。喙部粗壮且鲜红。","call":"该鸟的叫声尚未被描述。","habits":"布鲁三趾翠鸟栖息于森林下层，有时靠近溪流。它在布鲁岛上是唯一具有橙色喙的翠鸟种类。","breeding":"关于生长繁殖的信息尚不明确。","identification":"与当地其他翠鸟相比，布鲁三趾翠鸟的橙色下体是其独特的识别特征，除了与暗喙普通翠鸟的区分之外。","protection":"IUCN：NT（近危）","distribution":"布鲁三趾翠鸟分布于印尼的布鲁岛（位于摩鹿加群岛中西部），其生境为亚热带或热带湿润低地森林。","other":"2013年的一项分子系统发育研究发现，大部分岛屿亚种已显著分化，因此原本的摩鹿加三趾翠鸟被拆分，包括布鲁三趾翠鸟在内的12个亚种被提升至物种级别。"},{"name":"巴布亚三趾翠鸟","english_name":"Papuan Dwarf Kingfisher","scientific_name":"Ceyx solitarius","overview":"巴布亚三趾翠鸟（英文名：Papuan Dwarf Kingfisher，学名：Ceyx solitarius），是佛法僧目翠鸟科三趾翠鸟属的小型鸟类。其显著特征包括深蓝色头部和翅膀、醒目的浅蓝色背部斑块以及橙色腹部。分布于西部帕皮安群岛、新几内亚、阿鲁群岛及D'Entrecasteaux群岛的低地和山脚森林内部。","appearance":"体型小巧，长约12厘米，体重11至24克。成鸟拥有深蓝色上体，背侧颜色更浅，翼上覆羽有闪光般的淡蓝色斑点；下体呈蜜金色，喙黑色，腿和脚黄色。雌鸟比雄鸟略显暗淡，但在野外难以区分。幼鸟比成鸟更加暗淡，胸部可能有暗色鳞片状斑纹。","call":"发出高音调的“cheep！”叫声，类似于快速重复的尖锐‘tseet’或‘ss’声，无论静止还是飞行中都能听到，与蓝翠鸟和某些鹦鹉（Micropsitta）的叫声相似。","habits":"栖息于低地和山脚森林内部，不依赖水体，飞行速度快，如同蓝色子弹。其生活方式神秘，极难观察到。","identification":"与蓝翠鸟相比，巴布亚三趾翠鸟体型更小，胸部两侧无蓝色，且不靠近水域。与蓝翠鸟相比，体型较小，上体颜色更均匀。","protection":"IUCN：LC（无危）物种广泛分布，许多地区常见。在新几内亚大陆的密度估计为每10公顷一只鸟，但在Crater Mountain野生动物管理区的记录显示密度可达36只/平方公里。","distribution":"分布于西帕皮安群岛（四王群岛）、阿鲁群岛、Biak和Yapen岛（鸟头湾）、新几内亚、Karkar岛及D'Entrecasteaux群岛。","other":"曾被认为是Variable Dwarf Kingfisher的15个亚种之一，2013年分子系统发育研究将其独立为物种，同时将Variable Dwarf Kingfisher更名为摩鹿加三趾翠鸟。"},{"name":"马努斯三趾翠鸟","english_name":"Manus Dwarf Kingfisher","scientific_name":"Ceyx dispar","overview":"马努斯三趾翠鸟（英文名：Manus Dwarf Kingfisher，学名：Ceyx dispar），是佛法僧目翠鸟科三趾翠鸟属的鸟类。原被认为是变异性三趾翠鸟的15个亚种之一，但2013年的一项分子系统发育研究发现，岛屿上的多数亚种已显著分化，因此包括马努斯三趾翠鸟在内的12个亚种被提升至物种级别，而原变异性三趾翠鸟更名为摩鹿加三趾翠鸟。该物种仅见于阿德默勒尔蒂群岛的马努斯岛，位于新几内亚东北部的俾斯麦群岛中北部。","appearance":"这是一种小型的蓝橙色三趾翠鸟，拥有鲜艳的蜡状橙色喙，姜黄色的下体，白色喉部，蓝色上体带有醒目的白色颈斑。雌鸟头部呈亮橙色而非蓝色，头顶蓝色。其体型小于普通翠鸟，喙完全红色。","call":"鸣声为高音、微弱的重复哨声，通常在飞行中发出，与梅拉尼西亚其他小翠鸟的鸣声几乎相同。","habits":"栖息于森林环境，不一定靠近水源，能适应种植园和退化森林。未观察到其特定的迁徙行为，飞行特点未知。","breeding":"关于繁殖行为的信息有限，具体繁殖期、求偶、营巢、交配、产卵、孵化和育雏细节尚待研究。","identification":"与普通翠鸟的区别在于体型更小和完全红色的喙。在曼努斯岛范围内无其他同类物种。","protection":"IUCN：NT（近危）。马努斯三趾翠鸟因栖息地持续破坏导致数量局部下降，岛上低地大面积森林已被砍伐或处于砍伐特许权之下，沿海地区的森林正遭受轮作耕种侵蚀。","distribution":"该物种仅分布于澳新界，具体为马努斯岛（新几内亚东北阿德默勒尔蒂群岛，俾斯麦群岛中北部）。","other":"由于生态和行为信息的缺乏，急需对该物种进行深入研究。"},{"name":"新爱岛三趾翠鸟","english_name":"New Ireland Dwarf Kingfisher","scientific_name":"Ceyx mulcatus","overview":"新爱岛三趾翠鸟（英文名：New Ireland Dwarf Kingfisher，学名：Ceyx mulcatus），是佛法僧目翠鸟科三趾翠鸟属的鸟类。体型小巧，色彩蓝橙相间，以新爱尔兰岛及周边岛屿为其独特分布地。其显著特征包括全黑喙、姜黄色腹部、白色喉部和蓝色上体，带有醒目的白色颈斑。在密林中生活，常见于溪流池塘附近。","appearance":"成鸟长约14厘米，体重15.5至21.6克，拥有三趾。上体明亮紫蓝，冠羽和翼盖有淡蓝斑点，背部及臀部颜色略深。头部具橙色眉纹、耳后白色斑块和淡黄色喉部，其余下体为橙色。喙全黑。幼鸟色泽较暗淡。","call":"鸣声为高音调、微弱的重复哨音，与同属其他物种极为相似，常在飞行中发出。","habits":"栖息于成熟森林，偏好靠近水源的环境。飞行轻盈，活动范围广泛，善于在陆地和水域之间穿梭，主要以小鱼、昆虫为食。","breeding":"具体繁殖信息不详，一般于繁殖季节内，会筑巢、产卵并孵化。","identification":"与地理上远离的摩鹿加三趾翠鸟有相似之处，但可通过体型、颜色细节和分布地加以区分。与布岛乌鸦和瓜岛三趾翠鸟相比，后者的下颌基部呈橙色，而前者的头部更暗，带有蓝色斑点。","protection":"IUCN：LC（无危）；然而，由于其分布范围相对较小（约8800平方公里），若证实数量下降，未来可能上调保护等级。","distribution":"分布于澳新界，包括Lavongai（新汉诺威）、新爱尔兰岛、Dyaul（新爱尔兰西部南部）、Tabar和利希尔岛（新爱尔兰中部北部，俾斯麦群岛东北部）。","other":"目前全球状况稳定，但在特定区域内较为隐秘，通常通过鸣叫被发现。"},{"name":"新英岛三趾翠鸟","english_name":"New Britain Dwarf Kingfisher","scientific_name":"Ceyx sacerdotis","overview":"新英岛三趾翠鸟（英文名：New Britain Dwarf Kingfisher，学名：Ceyx sacerdotis），是佛法僧目翠鸟科三趾翠鸟属的鸟类。以其深紫蓝色上体和鲜艳橙色下体为显著特征，颈侧有白色斑点，腿脚呈亮橙色。分布于新不列颠岛及附近岛屿，包括Umboi、Lolobau和Watom。","appearance":"体长约14厘米，体重17至20.5克。成鸟上体呈紫色蓝色，冠羽和翼覆羽点缀淡蓝斑点，背部和臀部颜色稍明亮；头部有小而暗橙色眉纹，耳后有白色斑块，喉部淡黄色，其余下体为浅橙色，向后渐淡；上喙黑色带红，下喙暗橙红色；眼睛深棕色。幼鸟整体色泽较暗淡。","call":"发出特有的高音哨声，通常在飞行中发出，类似“tzzeep”。成对时会合唱，产生一系列较短且更安静的双音节声，如“see-see, see-see...”。","habits":"偏好成熟且密集的次生林环境，常低飞。在新不列颠岛的低地较为常见，但在西新不列颠岛的Nakanai山脉中仅罕见或偶见。","breeding":"具体繁殖信息不详，但一般翠鸟科鸟类会在繁殖季节营巢、求偶、产卵及育雏。","identification":"与普通翠鸟相比体型较小，且喙部为红色而非黑色，是其范围内唯一的小型翠鸟。","protection":"IUCN：LC（无危）。在新不列颠岛和新爱尔兰地区的特有种，虽然面临栖息地破坏导致的局部数量下降，但目前认为其种群相对稳定。","distribution":"分布于新不列颠岛及附近岛屿，包括Umboi、Lolobau和Watom。在新不列颠岛的低地广泛分布。","other":"关于其生态和行为的信息亟需更多研究。"},{"name":"所罗门三趾翠鸟","english_name":"North Solomons Dwarf Kingfisher","scientific_name":"Ceyx meeki","overview":"所罗门三趾翠鸟（英文名：North Solomons Dwarf Kingfisher，学名：Ceyx meeki），是佛法僧目翠鸟科三趾翠鸟属的鸟类。分布于所罗门群岛的布卡岛、布干维尔岛、舒瓦瑟尔岛和圣伊莎贝尔岛，具有鲜明的上部暗绿蓝色和下部淡色对比。其头部黑色，冠部点缀明亮的蓝点，背部有亮蓝色条纹，腹部奶油白色，喉部纯白，腿黄色。在所罗门群岛中是特有种，与其它三趾翠鸟相比，其体型较小，颜色对比强烈。","appearance":"这种翠鸟体型小巧，长约14厘米，具有三个脚趾。上部为深蓝色至蓝黑色，下部为淡黄褐色至浅黄色，喉部变为白色。头部呈黑色，冠部有亮蓝色斑点，背部有一条鲜亮的蓝色彩带延伸到尾羽覆羽。翅膀为深蓝黑至黑色，带有亮蓝色斑点。尾巴短小，蓝黑色。喙全黑，腿和脚为黄色。","call":"鸣叫为高音的单一声调‘tseee’哨声，通常在飞行或警戒时发出，类似于其它美拉尼西亚地区的三趾翠鸟复合种群的叫声。","habits":"主要栖息于成熟的低地雨林和茂密的次生林中，偏好靠近溪流的环境，活动于树冠下层。以昆虫为主食，具体食性和觅食生态细节尚不清楚。","breeding":"繁殖季节可能在9月初，巢穴建在溪边的土岸中，已知巢中有两枚卵和一只即将离巢的幼鸟。卵为纯白色，近似球形，大小约为20 x 17毫米。","identification":"与巴布亚三趾翠鸟和新爱岛三趾翠鸟相似，但所罗门三趾翠鸟上部颜色更深，下部颜色更浅。此外，其体型介于巴布亚三趾翠鸟和其它所有三趾翠鸟之间，足部颜色为黄色而非珊瑚红色。","protection":"IUCN：LC（无危）","distribution":"分布于所罗门群岛北部和中部的布卡岛、布干维尔岛、舒瓦瑟尔岛和圣伊莎贝尔岛。","other":"虽然目前全球不被视为受威胁物种，但作为范围受限的物种，它可能对栖息地的丧失和改变较为敏感。"},{"name":"新乔岛三趾翠鸟","english_name":"New Georgia Dwarf Kingfisher","scientific_name":"Ceyx collectoris","appearance":"新乔岛三趾翠鸟体型小巧，上体呈现深紫色，下体为鲜明的姜黄色，其喙为亮丽的橙色，喉部洁白，颈部有一个独特的橙白色斑点。与常见的翠鸟相比，其体型更小，上体颜色更深，喙完全为红色。","call":"鸣叫声几乎与梅拉尼西亚地区的其他矮翠鸟相同，是一种高音、微弱而重复的哨声，通常在飞行时发出。","habits":"新乔岛三趾翠鸟栖息于森林中，不仅限于水边环境，能适应种植园和退化森林。关于其具体的生活习性，如迁徙、飞行特点和食物偏好，目前资料有限。","breeding":"关于新乔岛三趾翠鸟的繁殖行为、筑巢、交配、产卵和育雏等细节，现有资料不足。","identification":"与普通翠鸟的区别在于体型更小，上体颜色偏深紫色，且喙为全红。在分布范围内，没有其他矮翠鸟种类与其混淆。","protection":"IUCN：LC（无危）。新乔岛三趾翠鸟在多个区域被描述为常见，拥有数个大型亚种群，每平方公里记录总数约为23至63只。种群趋势难以确定，因对其生态和行为了解不足。","distribution":"该物种分布于所罗门群岛中西部的新乔治亚岛群，从Vella Lavella至Nggatokae（=Gatukai）。"},{"name":"马莱塔三趾翠鸟","english_name":"Malaita Dwarf Kingfisher","scientific_name":"Ceyx malaitae","overview":"马莱塔三趾翠鸟（英文名：Malaita Dwarf Kingfisher，学名：Ceyx malaitae），是佛法僧目翠鸟科三趾翠鸟属的小型森林翠鸟。分布于所罗门群岛的马莱塔岛，以暗紫色蓝上部和深红橙下部为显著特征。","appearance":"体型小，约14厘米，重17至18.7克。头部黑色，顶冠点缀亮蓝色斑点，背部具有一条明亮的蓝色条纹延伸至上尾覆羽。上体呈深紫蓝色，下体深红橙色。喙基部橙色，其余黑色；腿和脚橙红色。成年鸟比幼鸟色彩更鲜艳，幼鸟较为暗淡。某些个体具白色眉纹，上体和下体颜色较淡，虹膜深棕色，上喙黑色，下喙黄橙色渐变为灰色近端，脚和跗跖鲜黄橙色。","habits":"栖息于森林环境，偏好湿润低地森林。关于其生活习性的具体信息有待进一步研究。","identification":"与布岛乌鸦和新爱岛三趾翠鸟的区别在于后者具有全黑的喙。新英岛三趾翠鸟的新不列颠亚种整个下喙为橙色，而马莱塔三趾翠鸟具有双色喙。与瓜岛三趾翠鸟的区分在于下喙的颜色差异，以及白色眉纹的存在。","protection":"IUCN：LC（无危）","distribution":"分布于所罗门群岛的马莱塔岛，为该地区的特有种。","other":"曾被认为是的一个亚种，但分子分析支持其独立物种的地位。Clements和IOC已将其合并入瓜岛三趾翠鸟"},{"name":"瓜岛三趾翠鸟","english_name":"Guadalcanal Dwarf Kingfisher","scientific_name":"Ceyx nigromaxilla","overview":"瓜岛三趾翠鸟（英文名：Guadalcanal Dwarf Kingfisher，学名：Ceyx nigromaxilla），是佛法僧目翠鸟科三趾翠鸟属的鸟类。以深紫色上体和鲜艳橙色下体为特征，颈部有白色斑点，腿脚鲜橙。黑色喙基部带红色。偏好成熟密集的次生林，常低枝栖息。其独特之处在于缺乏多数同类所具的亮蓝色背部条纹，喙下颌双色，远端黑近端红。该物种在瓜达尔卡纳尔岛和马莱塔岛（所罗门群岛）特有，自然栖息于热带湿润低地森林。","appearance":"体长约14厘米，体重17至18.7克。上体深紫蓝，下体橙红，颈部有白色斑点。喙黑色，基部红色。腿脚橙红。成鸟头部黑色，冠部有蓝色斑点，背部至尾羽覆羽有亮蓝色条纹。幼鸟色彩较淡。两性相似。","call":"鸣叫为高音尖锐、短促下滑的哨声，通常在飞行中发出，频带约6.5至8.5千赫兹，音符持续约0.2秒，速率约为每秒1至2个音符。","habits":"栖息于低地和山麓的原始森林和密闭次生植被中，常见于林下层。海拔记录最高至1,320米。生活方式定居，几乎全年在同一区域内活动。饮食主要由昆虫构成，具体食性和觅食生态知之甚少。","breeding":"繁殖生态知之甚少。已知雌鸟卵巢尺寸在繁殖季节会增大，但确切的繁殖期和繁殖行为细节尚不清楚。","identification":"与普通翠鸟的区别在于体型更小和喙基部的红色。在所罗门群岛范围内无其他矮翠鸟共存，易于辨识。","protection":"IUCN：LC（无危）。但鉴于其岛屿特有性和潜在的小范围，对栖息地变化的脆弱性使得其保护状态值得关注。","distribution":"分布于所罗门群岛的瓜达尔卡纳尔岛和马莱塔岛。","other":"曾被认为是摩鹿加三趾翠鸟的15个亚种之一，分子遗传学研究证实其独立物种地位。2023年，马莱塔三趾翠鸟被归入其亚种。"},{"name":"马基拉三趾翠鸟","english_name":"Makira Dwarf Kingfisher","scientific_name":"Ceyx gentianus","overview":"马基拉三趾翠鸟（英文名：Makira Dwarf Kingfisher，学名：Ceyx gentianus），是佛法僧目翠鸟科三趾翠鸟属的小型鸟类，特有于所罗门群岛的马基拉岛。以独特的深紫蓝色上体和洁净的白色下体而闻名，拥有醒目的白色颈斑和明亮的橙色腿脚。该鸟种的分布局限于成熟的森林环境，而非紧邻水源地带。","appearance":"马基拉三趾翠鸟体长约14厘米，体重介于22至24.8克之间。其特征在于健壮的全黑色刀状喙，深紫蓝色的上体，尤其是闪耀着超群青色的背部，以及白色的眉纹和耳羽斑点。该物种是摩鹿加三趾翠鸟种群中的特例，是唯一一个完全缺乏橙色羽毛的成员，与小翠鸟相似，但区别在于胸部两侧和胁部没有蓝色。","call":"发出尖锐的单音哨声，通常在飞行中或停歇时发出，‘tzzeep’声可以重复数次，节奏稳定或偶尔加速。这种叫声与摩鹿加三趾翠鸟种群中的其他梅拉尼西亚矮翠鸟类似。","habits":"偏好成熟森林，不一定靠近水源，常在低处栖息。关于其迁徙、飞行特点、活动范围和觅食方式的信息未详。","breeding":"关于繁殖习性的具体信息未提及。","identification":"与小翠鸟的区别在于橙色的腿脚和胸部缺乏蓝色。在摩鹿加三趾翠鸟种群中，通过完全缺乏橙色羽毛和特定的头部标记来辨认。","protection":"IUCN：LC（无危）。此物种为限制分布种，仅见于所罗门群岛东部生物地理区。其全球数量估计在1万至3万成熟个体之间，当前面临的威胁不显著。尽管存在持续的农业和工业伐木导致的森林破坏，但其影响程度较低，且该物种似乎能容忍一定程度的生境退化。","distribution":"仅分布于所罗门群岛的马基拉岛（San Cristobal），属于澳大利亚新几内亚地区。","other":"曾被认为是变种矮翠鸟的15个公认亚种之一。2013年的一项分子系统发育研究发现，大多数岛屿亚种已显著分化，因此变种矮翠鸟被拆分为多个物种，包括马基拉三趾翠鸟在内的12个亚种被提升为独立物种。同时，变种矮翠鸟更名为摩鹿加三趾翠鸟。"},{"name":"蓝胸翠鸟","english_name":"Indigo-banded Kingfisher","scientific_name":"Ceyx cyanopectus","overview":"蓝胸翠鸟（英文名：Indigo-banded Kingfisher，学名：Ceyx cyanopectus），是佛法僧目翠鸟科三趾翠鸟属的鸟类。拥有深宝石蓝色的头部、背部与翅膀，点缀着黑色斑点与纵纹。下体呈橙黄色，胸部特有蓝色，颈部两侧有桔黄色斑块。眼先、鸟喙、腿爪均为桔红色。分布于菲律宾北部和中部岛屿，包括吕宋岛、民都洛和米沙鄢群岛西部，常见于河流与溪流附近的森林地带。","appearance":"蓝胸翠鸟体型小巧，长约13厘米，重约16.5克。雄鸟的冠、脸颊和后颈为黑色，带超蓝色尖端；前额有一红斑，颈侧白色，后方转为红褐色；肩羽、翅膀与尾巴为黑蓝色，翼覆羽尖端明亮的蓝色，背部、腰部与尾上覆羽闪耀蓝色；下巴白色，喉部淡红褐色，至胸部与腹部颜色加深；胸部有两条钴蓝色的横带，向两侧延伸。雌鸟单条胸带，通常中间断开。幼鸟下体橙红褐色，胸侧有紫色蓝色斑块，下颌骨棕色，常有白色尖端。","call":"蓝胸翠鸟发出薄而高音的单音节叫声，以及在手中时会发出连续的高音、喷嚏似的轻微吱吱声。","habits":"栖息于河流和溪流旁，偏好植被密集的岸线，也可见于海岸附近的尼帕棕榈沼泽和红树林。活动范围从海平面至海拔1500米。以小鱼、水生昆虫及其幼虫为食，常在岩石和悬垂植被上停留，陡峭潜入水中捕食，而后返回原位击打猎物。","breeding":"繁殖季节在3月至5月，筑巢于河岸的隧道中，具体繁殖行为资料有限。","identification":"与普通翠鸟相比，蓝胸翠鸟缺少脸颊上的橙色，且至少部分侧面带有蓝色。两性差异在于胸带的完整性和数量。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾的吕宋岛、波利略、阿拉巴特、卡坦端内斯、民都洛、马林杜克、西布延、马斯巴特和蒂奥岛（北菲律宾）；班乃岛、内格罗斯和宿务（中菲律宾）。","other":"蓝胸翠鸟与南部银色翠鸟构成超种群，可能在宿务岛上已灭绝。"},{"name":"银翠鸟","english_name":"Southern Silvery Kingfisher","scientific_name":"Ceyx argentatus","overview":"银翠鸟（英文名：Southern Silvery Kingfisher，学名：Ceyx argentatus），是佛法僧目翠鸟科三趾翠鸟属的小型鸟类，分布于菲律宾中南部的棉兰老岛、巴西兰省、迪纳加特群岛和锡亚高岛。以其独特的黑白相间羽毛和亮丽的橙红色腿闻名。","appearance":"银翠鸟身长约14厘米，重约18.8至23.8克。头部黑色，前额和颈部有白色或蓝白色的斑点，翅膀、肩胛和尾巴黑色，中央翼羽上有白色斑点。背部、臀部和尾上覆羽呈淡天蓝色，喉咙白色，胸部蓝黑色，腹部白色。鸟喙黑色，虹膜深棕色，腿和脚橙红色。幼鸟前额和颈部斑点较浅，上胸呈奶油色。","call":"鸣声为柔和的高音‘wheeet’，通常在飞行中发出。","habits":"栖息于低海拔的原始或次生雨林中的溪流、小河和池塘旁，偏好树木茂密的河岸和浓密的悬垂植被。主要在1000米以下活动，偶尔可达1120至1350米高度。以小鱼和螃蟹为食，也会捕食昆虫。常在溪边灌木低枝或岩石上停歇，俯冲入水捕捉猎物。","breeding":"繁殖季节不详，已知幼鸟出现在4月至5月。巢穴可能位于溪流边的土壁上，具体细节未知。每窝产卵数量和孵化期未有详细记录。","identification":"与北银翠鸟的区别在于其蓝白色喉咙、脸颊和腹部，而北银翠鸟的相应部位为奶油色。","protection":"IUCN：NT（近危）","distribution":"主要分布于棉兰老岛、巴西兰省、迪纳加特群岛和锡亚高岛，均为菲律宾中南部的岛屿。","other":"银翠鸟面临森林砍伐和河流污染导致的栖息地丧失威胁，人口数量估计在1500到7000只成熟个体之间，且正在快速减少。"},{"name":"北银翠鸟","english_name":"Northern Silvery Kingfisher","scientific_name":"Ceyx flumenicola","overview":"北银翠鸟（英文名：Northern Silvery Kingfisher，学名：Ceyx flumenicola），是佛法僧目翠鸟科三趾翠鸟属的小型鸟类，以深蓝色为主色调，下腹部带紫罗兰色，喉咙呈奶油色，胸前有白色斑点，两颊后方有乳白色斑块，鼻孔后方有橙色斑点，腹部雪白，背部至尾部有一条淡银蓝色条纹，头翼上点缀着白色斑点，腿脚鲜红。该物种仅分布于菲律宾中部的森林低地河流附近，包括薄荷省、莱特岛和萨马岛。曾与银翠鸟视为同一物种。","appearance":"体型小，约14厘米，体重14.7至20.5克。整体呈深蓝色，下腹部更偏紫罗兰色，腹部纯白，上胸部有白色，喉部及下巴呈浅黄色；头部主要为黑色，眼下方有浅黄色斑点，颈部有亮色斑纹，头部两侧有形成条纹状眉线的白色斑点；背部黑色，除从臀部至肩部有银色斑纹及中覆羽尖端的珍珠白色；喙黑色，虹膜深棕色，腿脚鲜艳红色。幼鸟可能与成鸟相似，但细节上有所不同。","call":"发出简单高音的‘tseep’声，常在飞行中鸣叫。","habits":"栖息于热带湿润低地森林中的河流与溪流边，依赖于低海拔的森林河流，能够容忍次生林和选择性砍伐的森林，甚至椰子种植园内的河岸植被，靠近森林边缘。","breeding":"关于繁殖的信息有限，有记录显示雌鸟卵巢在五月增大，七月有幼鸟，但具体繁殖细节未知。","identification":"与银翠鸟相比，北银翠鸟具有奶油色的喉咙、脸颊和腹部，而银翠鸟的相应部位为蓝白色。","protection":"IUCN：NT（近危）","distribution":"分布于菲律宾中部的薄荷省、莱特岛和萨马岛。","other":"面临的主要威胁是栖息地丧失，包括森林被大量清除、农业用地转换和采矿活动，以及河流污染和土壤侵蚀等。"},{"name":"蓝翠鸟","english_name":"Azure Kingfisher","scientific_name":"Ceyx azureus","overview":"蓝翠鸟（英文名：Azure Kingfisher，学名：Ceyx azureus），是佛法僧目翠鸟科三趾翠鸟属的鸟类。色彩鲜艳的小型翠鸟，以其亮丽的蓝色和橙色羽毛著称。广泛分布于澳大利亚北部和东部、塔斯马尼亚、新几内亚低地及其邻近岛屿，远至北摩鹿加群岛和罗曼岛。常栖息于河流、湖泊及沼泽地带。","appearance":"蓝翠鸟长约18厘米，翼展25-29厘米，重约40克。头部和背部羽毛呈现深邃的蓝色光泽，胸腹部为鲜亮的桔红色，翅膀间点缀着黑色。后颈和喉部有显著的白色斑点，嘴长而粗直，尖锐，腿脚橙红色。雌鸟相比雄鸟略显暗淡，雏鸟色泽较淡，嘴端有较大的白色尖端。亚种在大小和颜色上有细微差异。","call":"发出尖锐、高音的'pseet'声，尤其是在飞行中，繁殖期间会发出连续的高音哨声。","habits":"偏好沿海木本水道、红树林、淡水溪流、湖泊和森林中的小溪。主要食物为小鱼，也会捕食甲壳类、水生昆虫、蜘蛛、小型两栖动物。常在离水面1-10米的枝头上守候，然后突然俯冲入水抓取猎物，有时会在空中盘旋后再潜入水中。","breeding":"繁殖季节为9月至翌年4月在澳大利亚北部，8月至翌年2月在南部。在河边或湖岸的土堤上挖掘巢穴，产卵4-7枚，通常为5或6枚，孵化期20-22天，双亲共同育雏，持续21-35天。","identification":"与白眉翡翠相比，体型更小，蓝翠鸟的蓝更为鲜艳，腹侧有明显的紫罗兰色调。","protection":"IUCN：LC（无危）","distribution":"分布在澳大利亚北部和东部、塔斯马尼亚、新几内亚低地及周边岛屿，北至摩鹿加群岛北部和罗曼岛。","other":"尽管数量有所下降，但由于分布广泛，目前仍处于IUCN红名单上的无危级别。"},{"name":"俾岛翠鸟","english_name":"Bismarck Kingfisher","scientific_name":"Ceyx websteri","overview":"俾岛翠鸟（英文名：Bismarck Kingfisher，学名：Ceyx websteri），是佛法僧目翠鸟科三趾翠鸟属的鸟类。中等体型，蓝绿与白色相间，拥有厚重的黑色大喙。头顶至背部蓝绿色，胸前有蓝色带状斑，腹部奶油白色，颈部有显著白色斑块。分布于巴布亚新几内亚的俾斯麦群岛，包括Lavongai（新汉诺威）、新爱尔兰、Lihir、Umboi和新不列颠岛。","appearance":"俾岛翠鸟体长约22厘米，雄鸟体重54-57克，雌鸟67克。两性均有白色眼眉，大的奶油白色颈环，头部和上体呈蓝绿色，胸部有蓝绿色斑块；腹部奶油白色，胸有淡橙色晕染；喙黑色，尖端白色；虹膜黑色；腿和脚灰褐色。雌鸟胸部斑块不明显，腹部可能更偏黄褐色。雏鸟描述未详。","call":"发出响亮的哨声，比普通翠鸟的叫声更为洪亮有力，少有嘶嘶声。","habits":"栖息于低地森林中的溪流和河流，偏好水流缓慢的水道；有时出现在森林边缘的湖泊，但不会出现在开阔的芦苇丛或沼泽地带。活动范围从海平面到约250米高度。以鱼、小龙虾、虾、昆虫及其幼虫为食，常在近水面的枯木枝上守候，然后潜入水中捕食。","breeding":"有记录显示，11月在Lihir岛上发现正在筑巢的雌鸟。关于繁殖的其他信息尚不清楚。","identification":"与普通翠鸟相比，体型较大，下体颜色为奶油白色而非橙色；与小翠鸟相比，体型更大，喙更粗壮。与矮翠鸟的区别在于体型更大，喙更厚重，上体纯蓝无白色斑点。与其他蓝白翠鸟的区别在于后颈蓝色，无黑色面罩。","protection":"IUCN：VU（易危）","distribution":"分布于俾斯麦群岛，包括新汉诺威（Lavongai）、新爱尔兰、Lihir（新爱尔兰北中部）、Umboi（新不列颠西部）和新不列颠岛（东部）。","other":"由于栖息地的严重破坏和退化，种群数量估计较小且可能在下降。在新不列颠岛，大面积的原始森林已被砍伐或计划清除，以种植商业油棕榈。"},{"name":"小翠鸟","english_name":"Little Kingfisher","scientific_name":"Ceyx pusillus","overview":"小翠鸟（英文名：Little Kingfisher，学名：Ceyx pusillus），是佛法僧目翠鸟科三趾翠鸟属的小型鸟类。广泛分布于澳新界，包括印尼摩鹿加群岛、新几内亚、澳大利亚北部、俾斯麦群岛和所罗门群岛。以其深蓝色上体和纯白色下体为显著特征。","appearance":"小翠鸟体型小巧，长度约11.5至13厘米，雄鸟体重10-15克，雌鸟体重10-14克。它们拥有深蓝色的背部和头部，搭配雪白的胸部。其喙厚重，尾巴短小。脚为暗棕色，一趾向后，两趾向前。雌雄皆有大而白色的前额和颈部斑纹，胸部两侧有黑色羽毛构成的界线。嘴粗直且长，翼尖长，尾短而圆。","call":"小翠鸟发出高音调的‘tsee’或‘peep’声，通常在飞行中重复鸣叫；在巢穴附近会发出其他类型的‘tick’声；幼鸟则有‘churr’或‘buzz’的叫声；当父母面对入侵者时，会发出尖锐的警告声。","habits":"小翠鸟栖息于沿海红树林、池塘、溪流、森林和沼泽地带，海拔高度可达750米。它们偏好孤独，常独自栖息于近水边的树枝或岩石上，以小鱼、甲壳类、水生昆虫及其幼虫为食。在捕食时，小翠鸟能迅速调整水中视角，提高捕鱼效率。","breeding":"小翠鸟在河流岸边、红树林根部、白蚁巢穴等处挖掘巢穴，巢穴长度可达15厘米，宽度13厘米。繁殖季节因地区而异，产卵期在昆士兰为10月至次年4月，在新几内亚和巴布亚新几内亚为1月至4月。每窝产卵3-5枚，大小约为17毫米×14毫米，父母双方共同参与喂养幼鸟。","identification":"小翠鸟与其他翠鸟相比，体型最小，上体深蓝色，下体纯白色，具有明显的白色前额和颈部斑纹。不同亚种间在蓝色的亮度和胸部侧面的颜色上有细微差异。","protection":"IUCN：LC（无危）。虽然全球数量趋势下降，但小翠鸟总体上并不受威胁。然而，某些亚种可能受到红树林砍伐的影响，尤其是Guadalcanal亚种（ aolae）已有数十年未有记录。","distribution":"小翠鸟分布于澳新界，包括印尼摩鹿加群岛、新几内亚、澳大利亚北部、俾斯麦群岛和所罗门群岛。在澳大利亚，主要分布在北部昆士兰和北领地沿海地区；在新几内亚，分布于沿海地区；在所罗门群岛，分布于沿海及内陆红树林。","other":"小翠鸟有九个公认的亚种，各自分布于不同的地理区域，展现出一定的生态适应性。"},{"name":"桑岛小三趾翠鸟","english_name":"Sangihe Dwarf Kingfisher","scientific_name":"Ceyx sangirensis","overview":"桑岛小三趾翠鸟（英文名：Sangihe Dwarf Kingfisher，学名：Ceyx sangirensis），是佛法僧目翠鸟科三趾翠鸟属的鸟类。拥有鲜明的多色羽毛和大型橙胡萝卜色的喙，被认为是亚洲乃至全球最濒危的鸟类之一，自20世纪下半叶以来未有确切记录。","appearance":"体型极小，色彩斑斓，具有大而醒目的橙胡萝卜色喙。头顶蓝鳞状，脸颊呈紫色，喉部白色，颈部有白色条纹，腹部橙色，背部紫红色至棕褐色，臀部和尾巴亮蓝色。幼鸟较为暗淡，喙尖黑色。","call":"发出安静、细薄且非常高音的‘tseeee’叫声。","habits":"生活在低地森林的下层，偏好热带干燥森林，非依赖水源。有关其具体生态习性的知识非常有限。","breeding":"关于繁殖行为的知识完全缺失。","identification":"在桑吉尔群岛上独一无二，与蓝耳翠鸟、普通翠鸟的区别在于上体颜色和喙色，且栖息地选择有所不同。","protection":"IUCN：CR（极危）","distribution":"仅分布于印度尼西亚北部的桑吉尔群岛，可能已灭绝。","other":"最后一次被证实记录是在20世纪下半叶，之后的调查均未能再次发现其踪迹。"},{"name":"棕背三趾翠鸟","english_name":"Rufous-backed Dwarf Kingfisher","scientific_name":"Ceyx rufidorsa","overview":"棕背三趾翠鸟（英文名：Rufous-backed Dwarf Kingfisher，学名：Ceyx rufidorsa），是佛法僧目翠鸟科三趾翠鸟属的鸟类。广泛分布于东南亚的低地森林中，常见于溪流和小池塘附近。以鲜艳的粉红、橙色、黄色和蓝紫色羽毛著称，背部明亮多彩，与近缘三趾翠鸟有显著区别。","appearance":"该物种体型微小，总长12.5至14.5厘米，翼展55至64.5毫米，尾长21至30毫米。头部带有亮丽的紫罗兰色，颈部两侧有明显的白色斑块。上体呈现变化的蓝黑色至亮紫色，下体为鲜艳的铬黄色。嘴部珊瑚红色，尖端黄色，随年龄增长变为深红色。虹膜呈深棕色，裸露的面部皮肤为灰色。腿部、脚和爪子同样为珊瑚红色。雄鸟平均比雌鸟稍大。","call":"发出高音的尖叫和细薄的哨声，常以双音节形式出现。","habits":"栖息于茂密植被的阴暗处，如红树林、河流边缘、过度生长的地带或深低地和山麓森林。既可在水边也可远离水源，当靠近水源时，常出现在浅林溪和小水潭附近。活跃于海拔1300米以下的地区，尤其在砂拉越低于300米的区域最为常见。在泰国马来半岛、苏门答腊、婆罗洲等地的低地森林中都有记录。","breeding":"筑巢于土穴或朽木中，繁殖期在雨季之后，具体时间因地区而异。通常产卵2至4枚，由双方共同孵化，孵化期约21天。幼鸟孵化后裸身，逐渐长出羽毛。","identification":"与三趾翠鸟相比，其背部颜色更偏向红褐色，缺乏蓝色，且具有独特的黄色下体。与菲律宾三趾翠鸟的区别在于后者具有较暗的下体，两者在分布上接近但不重叠。","protection":"IUCN：LC（无危）","distribution":"分布于泰国南部马来半岛、大巽他群岛、小巽他群岛至菲律宾西部和西南部。","other":"在新加坡已绝迹，但在印度尼西亚龙目岛最近有少量记录。"},{"name":"侏绿鱼狗","english_name":"American Pygmy Kingfisher","scientific_name":"Chloroceryle aenea","overview":"侏绿鱼狗（英文名：American Pygmy Kingfisher，学名：Chloroceryle aenea），是佛法僧目翠鸟科绿鱼狗属的鸟类。体型小巧，长约13厘米，重量介于10至16克之间，分布于中美洲至南美洲北部，自墨西哥南部直至阿根廷北部，栖息于森林中的溪流、池塘、河流和红树林地带。","appearance":"雄鸟特征明显，头部有深绿色光泽并带有金色，尾巴蓝绿色，眼先黑色，喉部有一红领，胸部和两侧红色，腹部白色，翅膀下部橙色。雌鸟有深绿色胸带，幼鸟颜色较淡，翅膀有更多斑点，半成鸟胸部和两翼有深绿色条纹。嘴长而侧扁，峰脊圆，翼尖，第1枚初级飞羽较第2枚短，第2或3枚最长，尾长于嘴。","call":"发出弱而重复的“tik”声或“dzit, tsweek”声，有时快速连成串，类似颤音或叽叽喳喳的叫声。其歌可能是一系列悦耳的啾啾声。","habits":"偏好阴暗环境，栖息于密集的森林、溪流、河流、池塘、沼泽和红树林，海拔高度可达2600米。以小鱼、蝌蚪、青蛙和大型昆虫为食，善于从低处俯冲捕鱼，偶尔也会在空中捕捉昆虫，但此行为未经证实。通常栖息在低矮的树枝上，频繁点头和摇晃尾巴。","breeding":"繁殖季节在萨尔瓦多和苏里南为5月，在特立尼达从5月至9月。巢穴位于河岸、土堆、砂坑、道路切割、白蚁丘或倒下的树木根部，长度约为30至40厘米。每窝产卵3至4枚，孵化期和雏鸟成长时间未知。","identification":"与绿鱼狗相比，体型更小，约为其一半，通过锈色下体和不太明显的浅色颈圈容易区分，绿鱼狗颈圈明亮白色。雌鸟具有狭窄的绿色胸带，雄鸟则无。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，从墨西哥南部直至阿根廷北部，包括哥伦比亚、委内瑞拉、圭亚那、亚马逊地区的巴西、秘鲁、玻利维亚，范围略延伸至巴拉圭和阿根廷，以及特立尼达岛。","other":"物种内部有两种亚种，stictoptera亚种在次级飞羽上有明显的白点线，与指名亚种在中部哥斯达黎加有过渡地带。"},{"name":"棕腹绿鱼狗","english_name":"Green-and-rufous Kingfisher","scientific_name":"Chloroceryle inda","overview":"棕腹绿鱼狗（英文名：Green-and-rufous Kingfisher，学名：Chloroceryle inda），是佛法僧目翠鸟科绿鱼狗属的鸟类。背部呈鲜艳的绿色，腹部为统一的赤褐色，这一独特的色彩组合使它在众多翠鸟中脱颖而出。分布于中美洲的尼加拉瓜至巴拿马，南美洲的绝大部分国家，除了阿根廷、智利和乌拉圭。","appearance":"成年棕腹绿鱼狗长约24厘米，雄鸟体重40-60克，雌鸟53-62克。雄鸟具有光泽的深绿色上部，黄色喉部逐渐过渡到赤褐色喉咙，余下的下部为深赤褐色。雌鸟在胸部有一条宽阔的绿色带纹，上面点缀着白色斑点，前额白色，比雄鸟更显眼。幼鸟类似雌鸟，但其上部斑点更为明显，两性皆有绿色的胸部带纹，雄鸟的较为窄细。","call":"发出尖锐、高音的‘week week week’声，以及一系列多样的叫声，包括‘chip-chip-chip’、‘drrrt’、‘trit-trit-trit’和‘too-too-too-too’。","habits":"栖息于溪流、河流、森林沼泽和红树林，偏好植被茂密的河岸而非开阔的河岸线。通常独居，从低处的枝头俯冲入水捕食，偏爱隐蔽的栖息地，饮食以小型鱼类、螃蟹、虾和水生昆虫为主。","breeding":"繁殖季节因地区而异，北部巴西为7月至11月，巴拿马可能包括2月。在土质河岸挖掘隧道作为巢穴，末端有巢室，每次产卵3-5枚，孵化和雏鸟成长期未知。","identification":"与美国侏儒翠鸟最为相似，但体型几乎为其两倍，且缺乏后者白色的下腹部。雌雄间主要区别在于雌鸟的绿色胸带和更明显的白色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的东南尼加拉瓜至巴拿马，南美洲除阿根廷、智利和乌拉圭外的所有国家，包括哥伦比亚西部、厄瓜多尔西北部，以及巴西东南部。"},{"name":"绿鱼狗","english_name":"Green Kingfisher","scientific_name":"Chloroceryle americana","overview":"绿鱼狗（英文名：Green Kingfisher，学名：Chloroceryle americana），是佛法僧目翠鸟科绿鱼狗属的鸟类。体型较小，雄鸟体重约29-40克，雌鸟略重，可达33-55克。主要分布于美国南部至阿根廷北部的广大区域，常见于河流和淡水湖泊附近。绿鱼狗以其独特的绿色外表和长喙著称。","appearance":"绿鱼狗体长约20厘米，雄鸟的头部前端为黑色，头顶深绿色带金属光泽。翅膀上的羽毛点缀着白色斑点，下颌和喉咙为白色，间杂绿色条纹，腹部鲜红，中央带有白色。雌鸟的喉咙呈奶油色或淡黄色，上胸金绿色，腹部浅黄。成鸟的嘴为黑色，虹膜深棕色，腿脚深灰色。雌鸟体形较雄鸟大，嘴长而侧扁，翼尖，第一枚初级飞羽较第二枚短，第二或第三枚最长，尾长过嘴。","call":"绿鱼狗发出的叫声被形容为两块鹅卵石相撞的声音，通常为单声或双声。另一种叫声则被描述为刺耳的、嗡嗡的责骂声，不同的文献中将其描述为'tsheersh', 'tseelp'或'zchrrk'。","habits":"绿鱼狗偏好栖息在河流、湖泊和池塘的树木覆盖的岸边，尤其喜欢靠近水面的低矮植被。它们的活动范围可延伸至1公里以上的河流。绿鱼狗以小型鱼类为主食，偶尔也会捕食甲壳类和水生昆虫。它们擅长俯冲潜水捕食，有时会在空中悬停定位目标。","breeding":"绿鱼狗的繁殖期随地理位置而异。在北美洲的繁殖期从春季开始，至夏季结束。在南美洲，繁殖期可延长至冬季。它们在河岸的泥土堤坝上挖掘巢穴，长度可达1米，巢室内无衬垫。每窝产卵数量从2至6枚不等，孵化期约为19至21天。雏鸟在26至27天后离巢。","identification":"绿鱼狗与Ceryle amazona在外表上有相似之处，但亚马逊翠鸟体型更大，头部有明显的冠羽，尾部外侧无明显白色标记。与绿鱼狗相比，棕腹绿鱼狗体型更大，下体几乎全为红褐色。绿鱼狗的亚种之间在上体绿色的深浅、翅膀和尾部白色标记的多少、侧腹斑点的大小和胸带是否完整上存在差异。","protection":"IUCN：LC（无危）","distribution":"绿鱼狗分布于北美、中美和南美的广阔区域，从美国西南部至阿根廷北部。在中美洲和南美洲，它们的栖息地从平原延伸至海拔1500米的高度，甚至在墨西哥达到2800米的高海拔。","other":"尽管绿鱼狗的种群估计约有2000万成熟个体，但被认为正在减少。目前尚未确定具体的威胁因素。"},{"name":"亚马逊绿鱼狗","english_name":"Amazon Kingfisher","scientific_name":"Chloroceryle amazona","overview":"亚马逊绿鱼狗（英文名：Amazon Kingfisher，学名：Chloroceryle amazona），是佛法僧目翠鸟科绿鱼狗属的鸟类。分布自墨西哥南部至阿根廷中部，生活在热带低地的大河流和宁静的泻湖周边，以其独特的青铜绿色外观和优秀的潜水捕鱼技巧著称。","appearance":"身长约30厘米，雄鸟体重介于98至121克，雌鸟体重125至140克。成年雄鸟上部呈深绿带青铜光泽，具白色颈环，胸部红褐色与绿色对比鲜明，腹部白色，两侧有深绿色条纹。雌鸟胸部白色，边缘有绿色羽毛，延伸至腹部。嘴黑色，基部有黄色斑点，虹膜深褐色，腿脚暗灰色。","call":"发出响亮、刺耳、重复的‘tek’或‘klek’声，还有短促的‘chrit’声，有时连成一串，类似蛙鸣，另有加速的清晰音节‘see see see...su su su su’，可能是问候或警报叫声。","habits":"栖息于大型河流、平静的湖泊和林地边缘，偏好开阔地带而非密林，主要在低于1200米高度处活动，偶尔可达1780或2500米。以鱼类为主食，善于俯冲潜水捕食，也能在空中悬停锁定目标。","breeding":"繁殖季节随地理位置而异，筑巢于河岸或土崖壁上的隧道式洞穴，巢穴长约1.6米，直径8-10厘米，巢室宽25厘米，长45厘米，高16厘米。每窝产3-4枚卵，孵化期约22天，雏鸟29至30天后离巢。","identification":"与同属其他翠鸟相比，亚马逊绿鱼狗体型更大，上部颜色更接近青铜绿，具有明显的白色颈环，雄鸟胸部红褐色，雌鸟胸部白色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从墨西哥南部至阿根廷中部，包括哥伦比亚、委内瑞拉等国。"},{"name":"冠鱼狗","english_name":"Crested Kingfisher","scientific_name":"Megaceryle lugubris","overview":"冠鱼狗（英文名：Crested Kingfisher，学名：Megaceryle lugubris），是佛法僧目翠鸟科大鱼狗属的鸟类。又名: 花斑钓鱼郎，此鸟种以粗壮体型、显著的冠羽和黑白相间的羽毛著称。分布于远东地区，自阿富汗东北部至越南中部和日本，常栖息于山麓、小山丘或平原森林中的清澈河流与溪流旁。","appearance":"冠鱼狗身长38至43厘米，体重230至280克，拥有独特的大型身躯与长冠羽毛。成年雄鸟头顶有白色眉斑，冠羽黑灰带白点，两片短白羽在竖立时形成特色；颈侧有黑底白点的颈环，背部黑白色条纹密集，尾巴黑色伴以6至8道白条，下体白色，胸带混有黑点和红橙色羽毛，两侧有灰色条纹；喙基部淡蓝，尖端微黄；虹膜深棕色；腿脚暗橄榄灰。雌鸟相似，但胸部无红褐色，翼下覆羽呈鲜艳粉肉桂色。幼鸟似雌鸟，颈部、胸部、侧腹及尾下覆羽泛淡红褐色。","call":"飞行中发出响亮的“ket ket”声，亦会发出深沉的‘ping’音，配对鸟儿间有低沉的嘶哑叫声，以及嘈杂的磨擦声。","habits":"偏好位于森林山区或山麓的湍急河流，基底为岩石或砾石，偶尔出现在宽阔的河流口。在日本和喜马拉雅山脉，冬季会向低地迁移以避开冰冻河流，但在北海道的热泉周围，部分鸟群全年驻留。在香港曾为繁殖鸟，现仅作为迁徙过客。食谱主要包括15至18厘米长的鱼和淡水蟹，从高处俯冲入水捕捉猎物，偏好湍急水域，捕食较大猎物。","breeding":"繁殖季节在尼泊尔为3月至6月，在中国为4月，在日本为4月至7月。单个领地可能覆盖4平方公里。在垂直的河岸挖掘巢穴，通常选择沙质、至少2米高的位置，距水源可达1.5公里；巢穴由双方共同挖掘，长度2至3米，宽10至15厘米，末端扩展成30至50厘米宽的巢室；在喀什米尔，一对鸟在20小时内挖掘了1米长的隧道。每窝产卵4至7枚，通常4至5枚，仅雌鸟孵卵，幼鸟在约40天后离巢。","identification":"与斑鱼狗相比，冠鱼狗具有更大的冠羽和缺失的白眉纹，是主要的辨识特征。雌雄个体区分较为困难，主要通过冠羽的大小和颜色差异识别。","protection":"IUCN：LC（无危）。在某些地区广泛且常见，但20世纪在北海道和香港的数量急剧下降，原因可能是森林砍伐和人类干扰。","distribution":"冠鱼狗主要分布在喜马拉雅山脉北部印度、孟加拉国、北印支、东南亚及日本的山河与山麓地带。在中国东部地区广泛分布。","other":"与普通翠鸟在共存区域的生态位分化明显，偏好更快流速的水域，从更高位置潜水，捕食更深水域的较大猎物。"},{"name":"大鱼狗","english_name":"Giant Kingfisher","scientific_name":"Megaceryle maxima","overview":"大鱼狗（英文名：Giant Kingfisher，学名：Megaceryle maxima），是佛法僧目翠鸟科大鱼狗属的鸟类。是非洲最大的翠鸟科物种之一，广泛分布于撒哈拉沙漠以南的非洲大陆。其特征包括头部的羽冠、黑白相间的上体以及独特的胸部斑纹，雌雄具有明显差异。雄鸟胸部带有栗色条带，而雌鸟腹部呈栗色，胸部则带有白色斑点。","appearance":"大鱼狗体长42-46厘米，体重可达275-426克。雄鸟额部、头顶和后颈黑色，带有小白点；雌鸟腹部栗色，胸部黑色并有白色斑点。背部、腰部和尾下覆羽为灰黑色，各羽具白色斑点。翅膀黑色，初级飞羽具白色圆斑，次级飞羽具白色横斑。嘴角黑色，上嘴基部和尖端淡绿褐色。虹膜呈暗褐色，脚为肉褐色。喙大且尖锐，像矛一样侧扁，翼尖，第1枚初级飞羽较短，第2或3枚最长；尾较长于嘴，头大颈短，翼短圆，尾短小。","call":"大鱼狗发出响亮的、粗哑的、快速重复的‘kek’和‘kakh’叫声，特别是在受到惊扰时。此外，还有类似‘kah, kah, kah’的问候叫声，以及飞行中的‘kee-ou, kee-kee-ou’叫声。","habits":"大鱼狗栖息于大型河流、湖泊、海岸线、红树林、河口和盐水沼泽等地，以鱼、蟹、蛙和无脊椎动物为食。它们通常从俯瞰的枝头或隐蔽的岩石上扫描猎物，然后潜水捕捉，有时会在开放水域上方盘旋。大鱼狗在清晨、傍晚和夜晚最为活跃。","breeding":"大鱼狗的繁殖期因地区而异，通常在11月至翌年2月间。它们是单配制的，巢穴通常位于河流、悬崖或水坝溢洪道的岸边，由双方挖掘。巢穴深度可达1.8米，直径20-60厘米。每窝产卵3-5枚，双方轮流孵化，平均孵化期约为22-24天。雏鸟在37天左右离巢。","identification":"雄鸟与雌鸟在胸部斑纹上有明显区别，雄鸟胸部有栗色带，雌鸟腹部为栗色。森林亚种（M. m. gigantea）比指名亚种（M. m. maxima）颜色更深，上体斑点较少，下体条纹更重。","protection":"IUCN：LC（无危）","distribution":"大鱼狗广泛分布于非洲，包括撒哈拉沙漠以南的大部分地区，从塞内加尔到埃塞俄比亚，南至南非。在坦桑尼亚，它们的分布高度可达1600米。","other":"大鱼狗可能受到来自邻近农田流入河流的农药影响，被认为是某些鳟鱼养殖场的害鸟。"},{"name":"棕腹鱼狗","english_name":"Ringed Kingfisher","scientific_name":"Megaceryle torquata","overview":"棕腹鱼狗（英文名：Ringed Kingfisher，学名：Megaceryle torquata），是佛法僧目翠鸟科大鱼狗属的鸟类。体型较大的翠鸟科大鱼狗属鸟类。以其异常巨大的喙和喧闹的叫声著称。羽毛呈蓝灰，头部有蓬松的羽冠，颈部有一圈白色的项圈，腹部红棕色。雄鸟和雌鸟外观相似，但雌鸟的胸部有一条蓝灰色的宽带，与白色的下部形成对比。常见于北美至南美的淡水环境。","appearance":"成年棕腹鱼狗体长可达38-42厘米，体重在305-341克之间。羽毛以蓝色为主，头部羽冠竖立形成小尖峰，喙力强大，长度可达8厘米。雄鸟腹部几乎全为红棕色，雌鸟下体板栗色，红区略少，胸部有较宽的灰带。喙和脚均为黑褐色。嘴粗直，长而坚固，翼尖长，第1片初级飞羽稍短，第3、4片最长；尾短圆，头大颈短，翼短圆，尾亦短小；嘴形长大而尖，脚甚短，趾细弱，第4趾与第3趾大部分并连，与第2趾仅基部并连。","call":"棕腹鱼狗的叫声比白腹鱼狗更为响亮和低沉，被捕获的幼鸟会发出尖叫，通常发出klek或kek的叫声。当受到人类干扰或其他惊扰时，也会发出同样的叫声。成鸟在巢穴中会发出柔和的klek声，用于与正在孵化的伴侣沟通。","habits":"棕腹鱼狗常见于沿海和内陆地区的河流沿岸。它们偏好红树林、稻田和城市边缘地带。大部分时间栖息在临水面5至10米高的枯树、岩石、河流和小溪上，有时会在电线杆上等待猎物。食物以小鱼为主，偶尔也会捕食甲壳类、水生昆虫幼虫、小型蛙类和少量水生植物。","breeding":"棕腹鱼狗在土崖壁或田野、小溪的堤坝上用嘴挖掘隧道式洞穴作巢，巢穴内通常不铺设垫物，卵直接产在巢穴地面。每窝产卵4-5枚，卵色纯白，大小约28毫米×18毫米。孵化期约34至37天，由雌雄双方共同喂养雏鸟，主要食物为鱼类。","identification":"与白腹鱼狗相比，棕腹鱼狗显得更大，具有红棕色的腹部，庞大的喙，以及蓝色的背部。雄鸟与雌鸟在颜色上有细微差异，雄鸟腹部全为红棕色，雌鸟胸部有一条蓝灰色的宽带。","protection":"IUCN：LC（无危）","distribution":"分布于北美西南部至南美洲火地群岛，包括美国南部、中美洲和南美洲的广阔区域。"},{"name":"白腹鱼狗","english_name":"Belted Kingfisher","scientific_name":"Megaceryle alcyon","overview":"白腹鱼狗（英文名：Belted Kingfisher，学名：Megaceryle alcyon），是佛法僧目翠鸟科大鱼狗属的鸟类。广泛分布于北美洲，其显著特征是厚实的身体和大头，以及独特的蓝灰和白色羽毛组合，雌鸟还带有额外的锈色腹部条带。该鸟主要栖息于淡水环境，如溪流、湖泊和河口地带。","appearance":"白腹鱼狗体长介于28至35厘米，翼展可达48至58厘米，体重约140至170克。其头部呈深蓝色，具有一顶蓬松的羽冠，眼先为白色，脸颊黑色，拥有一个明显的白色颈环，背、翅及尾部呈现深棕色，背部羽毛上有鳞片状斑点，腹部和尾下覆羽纯白，有时带淡黄色、粉红或黄色调。雌鸟在腹部的灰带之上有一红色带。嘴长而侧扁，翼尖，第1枚初级飞羽较第2枚短，第2或3枚最长，尾比嘴长。体羽黑白斑驳，雌雄差异在于雌鸟腹部的红色带叠加在灰带上。","call":"白腹鱼狗在受到威胁或与伴侣互动时，会发出清晰的鸣叫声，作为警告信号。其鸣声类似于振动机械的敲击声，这种声音在两个伴侣间表现为短促的尖叫威胁。","habits":"白腹鱼狗栖息于各种水生环境，包括湖泊、山涧、海岸、红树林、海湾、沼泽、河流、水库和宁静的海面。它们的领地意识强烈，主要通过声音命令或叫声来防御领域。白腹鱼狗主要以鱼类为食，尤其偏好鳟鱼、杜父鱼和大西洋鲑鱼，但在鱼类稀缺时也会摄食软体动物、甲壳类、水生昆虫、两栖动物、爬行动物、其他鸟类的幼鸟、小型哺乳动物和浆果。它们能够在北美严寒的冬季生存。","breeding":"在繁殖季节，白腹鱼狗夫妇会积极捍卫自己的领地，尤其是雄鸟。配偶关系确立后，雄鸟会为雌鸟献歌并提供食物。它们会在松软的砂土或黏土层中挖掘长达80厘米的巢穴，通常位于捕鱼区附近。雌鸟产卵6至8枚，孵化期为22至24天，父母双方都会参与孵卵。幼鸟大约在第28天离巢，但仍与父母共同生活约三周。","identification":"白腹鱼狗与其他翠鸟科鸟类的区别在于其较大的体型、独特的蓝灰和白色羽毛组合，以及雌鸟特有的腹部锈色带。与雄鸟相比，雌鸟的腹部具有更鲜明的红色带。","protection":"IUCN：LC（无危）","distribution":"繁殖区广泛分布在北美洲，包括加拿大、阿拉斯加和美国大部分地区。冬季迁徙至中美洲和南美北部，偶尔访问哥伦比亚、委内瑞拉和圭亚那的北部地区。在迁徙过程中，可能出现在太平洋岛屿、加那利群岛、阿苏雷斯群岛、克拉里昂岛，以及罕见地出现在厄瓜多尔、格陵兰、爱尔兰、荷兰、葡萄牙和英国。","other":"白腹鱼狗在北美的分布广泛，但会离开其北部栖息地当水面冻结时。在温暖地区，它们全年居住。"},{"name":"斑鱼狗","english_name":"Pied Kingfisher","scientific_name":"Ceryle rudis","overview":"斑鱼狗（英文名：Pied Kingfisher，学名：Ceryle rudis），是佛法僧目翠鸟科鱼狗属的鸟类。以其独特的飞行和捕鱼技巧著称。分布于非洲、中东至东南亚地区，常见于湖泊、河口、红树林及近水地带。雄鸟有双黑胸带，雌鸟则为单个断裂的胸带。","appearance":"斑鱼狗长约25-30.5厘米，重约68-110克，具黑白相间的羽毛，雄鸟头顶和冠羽黑色，眼上有一条白色条纹，眼带至颈后黑色，喉部和颈圈白色；背部黑色，边缘白色，臀部黑白相间，翼上有白色斑块；下身白色，有两道黑色胸带，上部较宽，下部较窄。雌鸟仅有一条较窄的胸带。幼鸟类似雌鸟，但头部、颏部、喉部和胸部的羽毛边缘呈棕色。喙几乎全黑，虹膜深褐色，腿和脚黑色。","call":"发出尖锐的‘kwik-kwik’或‘chirruk, chirruk’警戒叫声，以及低沉的‘trrr trrr trrr’报警声。还有急促重复的‘preepreepreepree’遇险叫声，以及‘tréétiti, tréétiti’接触叫声。","habits":"斑鱼狗栖息于各种水边环境，包括湖泊、大河、河口、沿海泻湖、红树林和沙滩海岸。它们通常成对或小群体活动，偏好在树、芦苇、围栏、电线杆、小屋等人造物体附近筑巢。活动范围广泛，从海岸到海拔2500米的高度都有其踪迹。食物主要为鱼类，也包括甲壳类、水生昆虫及其幼虫，偶尔啄食小型蛙类和少量水生植物。","breeding":"繁殖季节在不同地区有所不同，如土耳其的8-9月，印度北部的3-6月，南印度和斯里兰卡的3-5月。繁殖期在水边土堤上挖掘巢穴，巢穴深度可达2.5米，末端有室状空间。每窝产卵1-7枚，通常4-5枚，每天产一枚，孵化期18天。雌鸟主要负责夜间和白天大部分时间的孵化和育雏，雄鸟和辅助者参与喂养巢中幼鸟。幼鸟出生时盲且裸体，23-26天后离巢，再过14天可自行捕鱼。","identification":"与冠鱼狗相比，斑鱼狗体型较小，头部和胸部斑纹更明显，冠羽不竖立。雄鸟有双胸带，雌鸟为单一断裂的胸带。","protection":"IUCN：LC（无危）","distribution":"斑鱼狗广泛分布于非洲、东洋界和中东地区，包括亚洲的南部，从土耳其到印度再到中国。在中国大陆，主要分布在平原地区。","other":"斑鱼狗是全球数量最多的三种翠鸟之一，适应性强，能够在多种水体环境中生存，包括受人类活动影响的区域。"},{"name":"杂色短尾鴗","english_name":"Cuban Tody","scientific_name":"Todus multicolor","overview":"杂色短尾鴗（英文名：Cuban Tody，学名：Todus multicolor），是佛法僧目短尾鴗科短尾鴗属的鸟类。体型小巧、色彩斑斓的鸟类，仅见于古巴及其邻近岛屿。其头部相对于身体显得较大，拥有闪亮的绿色背部、黄色超眼纹、红色喉部、粉红侧翼、白色腹部和鲜黄臀部，是短尾鴗属中最鲜艳的成员。","appearance":"杂色短尾鴗体长约 10 厘米，体重约 5.9 克。头部比例大，喙细长扁平。上体呈绿宝石光泽，下体颜色多样，包括红喉、粉侧翼、白腹和黄臀。雄雌相似，但雌鸟平均色泽稍暗。幼鸟羽毛较为暗淡，腿部颜色较灰，喉部红色羽较少。","call":"常发出快速的“chuk, chuk, chuk, chuk”声，每秒约7至10个音节，每组含1至10个音符，连贯而急促。此外，也有柔和的‘pprreeee-pprreeee’叫声，这是其得名‘Pedorrera’的由来。","habits":"栖息于干低地、常绿林、沿海植被及河流附近，偏好低至中层的树林。以昆虫为主食，偶尔食用小果实、蜥蜴和蜘蛛。它们成对活动，翅膀振动声在求偶飞行中扮演角色。","breeding":"繁殖期，它们在泥岸挖掘约30厘米长的隧道作为巢穴，有时也会利用朽木或树洞。巢壁与蛋室覆盖着粘稠物质混合草、苔藓、藻类、羽毛等。每窝产3至4枚卵，双亲共同孵化。","identification":"是古巴境内唯一的短尾鴗，不易与其它物种混淆。色彩丰富，尤其是独特的红色喉部和黄色面部特征，使其易于识别。","protection":"IUCN：LC（无危）","distribution":"全年居住于古巴及周边岛屿，分布于东部和西部两个不同群体。","other":"参与混种群落活动，是獴和人类在贫困地区猎食的对象。"},{"name":"阔嘴短尾鴗","english_name":"Broad-billed Tody","scientific_name":"Todus subulatus","overview":"阔嘴短尾鴗（英文名：Broad-billed Tody，学名：Todus subulatus），是佛法僧目短尾鴗科短尾鴗属的鸟类。体型小巧，色彩鲜艳，头部较大，喙长且扁平，尾巴短小。在多米尼加共和国和海地的低海拔森林中可见其身影，与同岛的狭嘴短尾鴗生态位有所区分。","appearance":"阔嘴短尾鴗的上体呈现明亮的绿色，喉部与两侧有红色斑纹，下体通常带有淡黄色或粉白色。雄雌相似，但幼鸟喉部为淡黄色，略带红色，且下喙全红，与狭嘴短尾鴗的黑尖区别明显。","call":"其最常见的鸣声为快速连续的‘weep’或‘whip’声，每秒约两声，与狭嘴短尾鴗的‘chik-zhwik’和急促的嗡嗡声不同。","habits":"栖息于低至1700米的干燥林地，偏好旱生灌木丛、仙人掌和龙舌兰丛生的环境，以及荫蔽的咖啡种植园和松树林。不迁徙，占据极小领地，常在枝干间跳跃觅食昆虫。","breeding":"繁殖季从四月至七月，一窝产卵1至4枚，孵化期约2到3周。幼鸟需三周左右才能离巢独立。","identification":"与狭嘴短尾鴗相比，阔嘴短尾鴗的下体有黄色色调，下喙全红，活动高度较高，且叫声不同。","protection":"IUCN：LC（无危）","distribution":"分布于多米尼加共和国和海地的低海拔地区，尤其在干旱森林和咖啡种植园中常见。","other":"与狭嘴短尾鴗在特定的松树林和红树林中共存，但地理分布上多有分离。"},{"name":"狭嘴短尾鴗","english_name":"Narrow-billed Tody","scientific_name":"Todus angustirostris","overview":"狭嘴短尾鴗（英文名：Narrow-billed Tody，学名：Todus angustirostris），是佛法僧目短尾鴗科短尾鴗属的小型、色彩鲜艳的鸟类。偏好高海拔湿润林地，但在咖啡种植园也能发现其踪迹。该物种仅限于多米尼加共和国和海地所在的希斯帕尼奥拉岛，且多见于海拔700米以上的地区。","appearance":"狭嘴短尾鴗体型小巧，头部较大，喙长而尾短，上体呈明亮的绿色，喉部和两侧红色鲜明，腹部白色，两胁呈深红色或粉红色，下腹及尾下覆羽为鲜亮的硫磺黄色。喙的上颚为黑色或褐色，下颚红色，尖端稍暗。","call":"鸣声包括快速的‘chip-zhwik’声，第二音节略微上扬，以及约每秒14个音符的快速嗡嗡声，与阔嘴短尾鴗的‘weep’或‘whip’声不同。","habits":"栖息于海拔900至2400米的密集湿林和森林中，以昆虫为主要食物来源，偏好在森林树冠层高处觅食，也会在咖啡园的低矮灌木丛中活动。","breeding":"繁殖季节一般在4月至7月之间，巢穴由双方共同挖掘，位于土岸中，深度约30厘米。每次产卵1至4枚光滑的白蛋，双亲轮流孵卵。","identification":"与阔嘴短尾鴗相比，狭嘴短尾鴗下颚通常有黑尖，下体更白，且活动于较高海拔。","protection":"IUCN：LC（无危）","distribution":"分布于希斯帕尼奥拉岛，包括多米尼加和海地，主要栖息于海拔700米以上的地区。","other":"狭嘴短尾鴗与阔嘴短尾鴗虽在地理上重叠，但生态位分离明显，前者偏好更高海拔，后者则多见于低地。"},{"name":"短尾鴗","english_name":"Jamaican Tody","scientific_name":"Todus todus","overview":"短尾鴗（英文名：Jamaican Tody，学名：Todus todus），是佛法僧目短尾鴗科短尾鴗属的小巧宝石般的鸟类。亦被称为rasta bird、robin和robin redbreast，仅分布于牙买加。其特征包括大头、长喙和短尾，上体闪耀着绿色光泽，喉部鲜红，腹部呈绿黄色。","appearance":"短尾鴗体长约9-10.8厘米，雄鸟体重5.5-7.2克，雌鸟6.4-6.5克。上体鲜艳绿色，具小蓝灰色耳侧斑块；喉部红色，胸部两侧黄绿色，腹部绿色带黄；两胁有稀疏粉色；虹膜颜色变化，从白色至板岩色；上喙黑色，下喙红色。与同属其他物种在外观上有明显区别。","call":"短尾鴗在繁殖季节会发出响亮的‘beep’声和快速、沙哑的喉音‘frrrup’，以及在受惊时发出尖锐的‘cheep’声。飞行时翅膀产生独特的嗡嗡声。","habits":"广泛分布于潮湿、湿润和干燥森林，尤其在山林中最为常见。偏好原生和次生林地，如红树林、低地干林、山地森林、中海拔云雾林。在蓝山地区，1500米以上较为罕见。人工移植实验显示，它们能跨越城市周边发展区和铝土矿开采区返回家园。","breeding":"繁殖期为12月至7月。在垂直土岸挖掘巢穴，平均高度3.9厘米，宽度3.5厘米，距地面平均1.3米。巢穴靠近地面或岩石露出层上方的薄土层中。每次产卵1-4枚白色蛋，平均产卵量2.8枚，卵尺寸约为16.1×13.3毫米。","identification":"与杂色短尾鴗相比，腹部为绿黄色而非白色，胁部粉色较少，无黄色眉纹，翅膀和尾巴无蓝色。与波多黎各短尾鴗的区别在于胸部颜色和胁部粉色程度。","protection":"IUCN：LC（无危）","distribution":"短尾鴗仅分布于牙买加，遍布全岛，从海岸到山区均有发现。","other":"短尾鴗的种群可能因栖息地破坏和獴类及农村儿童的捕猎而减少。"},{"name":"波多黎各短尾鴗","english_name":"Puerto Rican Tody","scientific_name":"Todus mexicanus","overview":"波多黎各短尾鴗（英文名：Puerto Rican Tody，学名：Todus mexicanus），是佛法僧目短尾鴗科短尾鴗属的鸟类。体型小巧、色彩鲜艳的鸟类，仅见于波多黎各岛的多样森林环境中。雄鸟和雌鸟外观相似，全身大部分覆盖着亮丽的绿色羽毛，拥有醒目的红色喉部斑块、白色颊纹、黄色胸侧和淡黄色胁部。由于最初被误认为来自墨西哥东部，故学名中带有墨西哥元素。","appearance":"波多黎各短尾鴗身长约为11厘米，体态丰满，背部和头部两侧为纯绿色，带轻微蓝色调。头部侧面颜色更鲜亮。白色下巴、颊纹和前颈，胸部呈灰色阴影，中央腹部为白色。喉咙呈现鲜艳的红宝石色，羽毛尖端有银白色点缀。翅膀边缘为白色，翼下覆羽和腋羽为硫磺黄色。翅膀短而圆，第五至第八主飞羽最长。尾巴长度约为翅膀的三分之二至四分之三，末端圆润，尾羽尖端宽圆。未成年个体缺乏红色喉部，胸部可能有暗灰色条纹，喙较短。","call":"波多黎各短尾鴗的声音特征明显，通常最先被其发出的响亮、嗡嗡声的‘zhip, zhip’叫声所吸引。","habits":"它们活跃于森林的低至中层，雨后阳光出现时最为活跃，此时较易观察到。以昆虫为主食，常从树叶下方捕获猎物。在非觅食时间，它们保持相对静止的状态。","breeding":"繁殖季节中，由于抚育后代的需求，梳理羽毛的时间减少，导致羽毛磨损。每年进行一次婚后的换羽过程。在Guánica国家森林中，秋季开始观察到身体和飞行羽毛的更换，一至两个月后飞行羽毛换羽完成，冬季中期（一月）完成身体换羽。但是，样本量有限，且Guánica的季节性比岛上其他地方更为显著。","identification":"波多黎各短尾鴗是岛上唯一的特有种，与其他短尾鴗科物种的区别在于其侧翼没有粉色，仅呈现黄色或黄绿色。它是波多黎各唯一主要呈现明亮绿色的小型鸟类，除蜂鸟外。","protection":"IUCN：LC（无危）","distribution":"波多黎各短尾鴗的分布局限于北美地区的波多黎各岛，包括沿海低地至山区。","other":"波多黎各短尾鴗的学名选择反映了早期分类学家对其地理起源的误解。"},{"name":"短尾翠鴗","english_name":"Tody Motmot","scientific_name":"Hylomanes momotula","overview":"短尾翠鴗（英文名：Tody Motmot，学名：Hylomanes momotula），是佛法僧目翠鴗科短尾翠鴗属的鸟类，也是该属的唯一物种。分布于中美洲南部至南美洲哥伦比亚西北部的热带湿润森林中。其体型小巧，具有绿色冠羽和锈色颈背，白色喉部，绿白相间的胸部条纹，以及白色腹部。","appearance":"短尾翠鴗体型短小紧凑，头大，尾部较短，中央尾羽仅比邻近的稍长约6-7毫米，外侧三对尾羽明显递减。雄鸟体重27-33克，雌鸟25-30克，长度约16.5-18厘米。冠羽绿色，颈背锈色，眉线蓝色，眼罩黑色带有白色下条纹；上体绿色，尾部全绿；喉部有白色或淡黄褐色羽毛簇，胸腹部绿白相间，腹面白色。喙黑色，基部下方常较浅色，嘴角毛短而弱；腿和脚棕色至黑色。幼鸟色彩较暗淡，顶冠和颈背灰褐。","call":"发出响亮、远传、粗哑的'kwa-kwa-kwa-kwa...'或'quah quah quah quah...'声，类似厚嘴拟啄木鸟的叫声，通常黎明时分最常听到，亦会发出间隔1.5秒一次的响亮、穿透力强、空洞的'whoop!'音节，或更快的类似棕鸺鹠的'whut whut whut...'声，音调可低沉或适度高音。","habits":"栖息于热带湿润常绿森林，尤其偏好溪谷地带，海拔高度可达1850米。以昆虫、蜘蛛和小型蜗牛为食，偶尔在空中捕捉蝴蝶和蜻蜓。不似多数其他翠鴗，未记录到吃水果，被认为是纯肉食性或大部分肉食性。食物在飞行中从植被中摘取。","breeding":"繁殖细节知之甚少。在伯利兹，6月观察到成鸟携带食物，7月初看到成鸟和幼鸟。在危地马拉，6月收集到一只幼鸟。在哥伦比亚，2月收集到正在产卵的雌鸟，5月在安蒂奥基亚省收集到处于繁殖状态的雌鸟。巢穴未被记录，可能位于土岸的洞穴中。","identification":"与其他翠鴗相比，体型最小，面部和下体图案独特，尾部无拍子状尖端，喙切割边缘无锯齿。幼鸟的顶冠和颈背灰褐色，区别于成鸟。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲南部至南美洲哥伦比亚西北部，包括墨西哥南部至洪都拉斯的大西洋斜坡，伯利兹、危地马拉、洪都拉斯、尼加拉瓜、哥斯达黎加等地。在特卡国家公园（危地马拉）有记录。","other":"在不同的栖息地范围内，短尾翠鴗的数量从非常罕见到常见不等，其具体繁殖生态学仍需更多研究。"},{"name":"蓝喉翠鴗","english_name":"Blue-throated Motmot","scientific_name":"Aspatha gularis","overview":"蓝喉翠鴗（英文名：Blue-throated Motmot，学名：Aspatha gularis），是佛法僧目翠鴗科蓝喉翠鴗属的鸟类。体型中等的翠鴗科鸟类，分布于中美洲的高海拔森林中，从墨西哥南部的瓦哈卡和恰帕斯州延伸到洪都拉斯。具有独特的头部图案，头部侧面呈赭色，带有黑色耳斑，以及显眼的蓝绿色喉咙。","appearance":"蓝喉翠鴗体长25.5至28厘米，体重介于56至67.3克之间。尾羽明显呈阶梯状排列，没有其他翠鴗常见的拍子尖端。喙部沿切割边缘有低矮且间隔均匀的锯齿，上颌骨仅基部有脊。雌雄两性的头部侧面均为赭色，带有黑色耳斑；背部主要为绿色，腹部颜色较淡；尾部深绿色，尖端略带蓝色；喉咙区域广泛覆盖着蓝色羽毛，下方边界处有一黑色胸斑；喙黑色，下部常呈现淡稻草色；腿和脚的颜色从稻草色到棕色不等。幼鸟的头部和上体颜色较为暗淡，泛橄榄色。","call":"蓝喉翠鴗通常会发出单个远传的‘hoot’或‘huuk’音符，这种叫声通常会在几秒后重复，有时也会连续发出10至20个类似‘hoodloodloodloodl...’或‘uut-a-uudauudauuda...’的呼叫声，有时声音带有一些模糊的质感，有时会以二重唱的形式发出。","habits":"蓝喉翠鴗栖息于中高海拔的湿润至半湿润的高山常绿林和松树林，海拔范围在墨西哥为1300至3000米，在洪都拉斯不低于1800米。它们几乎全年定居于挖掘的洞穴中，用于筑巢、繁殖和非繁殖季节的栖息。它们主要以昆虫为食，尤其是甲虫，偶尔也会吃一些水果，推测也会少量喂给幼鸟。","breeding":"蓝喉翠鴗在4月开始繁殖，在危地马拉有记录；在墨西哥南部，幼鸟在5月下半月被收集到。它们在土壁上挖掘巢穴，巢穴往往蜿蜒曲折，末端扩宽成椭圆形的巢室，顶部有低拱形的天花板。巢穴总长度可达1.8米。一窝产卵三枚，孵化期为21至22天，幼鸟身上会长出一层特有的长而柔软的绒毛，这是家族中的特例；离巢时间为29至31天。","identification":"蓝喉翠鴗与同科其他物种的区别在于其独特的头部图案、没有黑色眼罩和腿部的浅色。幼鸟与成鸟相比，头部和上体颜色更为暗淡，泛橄榄色。","protection":"IUCN：LC（无危）","distribution":"蓝喉翠鴗的分布区域从墨西哥南部的瓦哈卡和恰帕斯州，通过危地马拉和萨尔瓦多北部，一直延伸到洪都拉斯。","other":"蓝喉翠鴗是单型种，没有已知的近亲。"},{"name":"锈顶翠鴗","english_name":"Russet-crowned Motmot","scientific_name":"Momotus mexicanus","overview":"锈顶翠鴗（英文名：Russet-crowned Motmot，学名：Momotus mexicanus），是佛法僧目翠鴗科翠鴗属的鸟类。这一特征源自拉丁文中的‘红’。体长约30.5至35.5厘米，体重介于74至104克之间。","appearance":"锈顶翠鴗拥有红褐色的冠羽和颈背，背部和翅膀呈绿色，主翼羽蓝绿相间，胸部为淡绿色并带有黑色斑点，腹部颜色更浅。尾羽长而蓝，尾端中央羽轴裸露形成类似羽毛球拍的形状。喙略向下弯曲，边缘微锯齿状，黑色。眼红色，腿脚灰色。雌雄体型相似，但雌鸟尾羽较短，雄鸟的尾线长度范围为11至22毫米，雌鸟为10.6至15.1毫米。幼鸟眼睛棕色，羽毛色彩较暗淡。","call":"发出低沉的‘krrp’、‘krrup’或‘kru, krr-up’声，连续重复形成较长的叫声。也会偶尔发出类似的空洞‘ook’声，但带有一丝沙哑质感。","habits":"栖息于热带低地至海拔1800米的干旱至半干旱林地，包括次生林和开阔地带。以大型昆虫为主食，也会捕食小蛇。在地面、树叶或空中捕获猎物，返回栖木处进食。","breeding":"繁殖期在雨季，即4月至6月。在土坡、路边或河岸挖掘深度88至170厘米的巢穴，末端为裸土蛋室。每窝产4至5枚卵，孵化期约20天，幼鸟由双亲喂养，30至39天后离巢。","identification":"与亚马逊翠鴗相比，锈顶翠鴗体型较小，头部颜色不同，嘴缘锯齿更为细腻。不同亚种在羽毛色泽上有差异。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥西北部至危地马拉西南部的热带和亚热带干阔叶林及灌木丛。","other":"四个亚种中，M.m. castaneiceps在危地马拉中部的Motagua山谷中形成孤立种群，可能被视为独立物种。"},{"name":"蓝顶翠鴗","english_name":"Blue-capped Motmot","scientific_name":"Momotus coeruliceps","overview":"蓝顶翠鴗（英文名：Blue-capped Motmot，学名：Momotus coeruliceps），是佛法僧目翠鴗科翠鴗属的鸟类。色彩斑斓的翠鴗，广泛分布于墨西哥东北部的森林与林缘地带。其最显著的特点是拥有完全的天蓝色顶冠，这与中心黑色的雷氏翠鴗形成鲜明对比。该物种曾被视为多个物种的复合体之一，包括雷氏翠鴗、叫翠鴗、特岛翠鴗、亚马逊翠鴗和高原翠鴗，但现已被独立认定。","appearance":"蓝顶翠鴗体型较大，尾部长而具独特的“网球拍”状末端。羽毛总体呈绿色，头顶有一条宽阔的黑色线条，延伸至耳羽处，终止于延长的矛状羽毛。暗蓝色的羽毛覆盖前额至颈背，多数亚种中，这一蓝色带环绕着中央一小块黑色区域，但在最北端的亚种中，顶冠中心亦为蓝色。","call":"以双音节的咕咕叫声著称，类似猫头鹰的叫声，通常在黎明时分发出。","habits":"栖息于热带低地和丘陵地带的湿润森林中，常在阴凉处的树枝上栖息，尾巴像钟摆一样来回摆动，偶尔会飞扑捕食飞行中的昆虫。食性多样，包括小虫、蜥蜴及水果。","breeding":"像大多数翠鴗科鸟类一样，它们在河岸的土壁上挖掘隧道筑巢，每次产白色蛋约三到四枚。","identification":"与绿眉翠鴗相比，蓝顶翠鴗体型更大，尾羽中央的羽毛更长，背部中央为绿色而非红褐色，且喉部无蓝黑相间的条纹。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，主要在墨西哥东北部，从Nuevo León和Tamaulipas向南至北部Veracruz。","other":"与雷氏翠鴗的分布区相邻，二者可能有杂交现象，但杂交率尚未明确记录。"},{"name":"雷氏翠鴗","english_name":"Lesson's Motmot","scientific_name":"Momotus lessonii","overview":"雷氏翠鴗（英文名：Lesson's Motmot，学名：Momotus lessonii），是佛法僧目翠鴗科翠鴗属的鸟类。色彩斑斓的翠鴗，广泛分布于墨西哥南部至巴拿马西部的森林和林地。此物种曾与蓝顶翠鴗、呼啸翠鴗、特立尼达翠鴗、亚马逊翠鴗和安第斯翠鴗被视作同一物种。","appearance":"体长38至43厘米，体重77至148克，头部蓝冠中央有一大块黑色斑点，与蓝顶翠鴗纯蓝色的冠部不同。整体羽毛图案对比度不如绿眉翠鴗鲜明，尾羽末端的小拍状突起较小。喙略向下弯曲，上下颚边缘大部分长度都有粗糙锯齿。幼鸟外观类似成鸟，但整个冠部呈淡绿色，黑眼罩较小，颜色较暗，无胸斑和尾羽拍状突起，虹膜深棕色。","call":"发出独特的低沉双音节鸣叫，‘oot-oot’或‘hoop-hoop’，常在黎明前听到，有时会让人联想到猫头鹰的叫声。此外，也会发出空洞的‘kluk-kluk-kluk...’或‘klok-klok-klok...’声作为警报。","habits":"栖息于多种木本生境，包括热带雨林、干燥的树林（如伯利兹的松林）、林间峡谷、高大的次生林、树篱、树木茂密的花园和遮荫咖啡种植园，海拔可达2150米。以昆虫和其他无脊椎动物为主食，如蜗牛、蜈蚣和蚯蚓，偶尔捕食小型爬行动物、哺乳动物（如鼩鼱）、长舌蝠、阿尔法罗稻鼠，以及小型鸟类和雏鸟，还经常食用果实。善于跟踪行军蚁，捕食被其扰动的无脊椎动物。","breeding":"筑巢期在墨西哥南部为4月至6月，在哥斯达黎加为3月至5月，可能最早在巴拿马西部为2月至3月。巢穴通常挖掘于土堤中，如道路或溪流旁，长度变化很大，从1.5米到约4米不等，入口往往隐蔽。每窝产3至5枚白色蛋，孵化期约21天，幼鸟离巢时间在29至32天之间，最长记录为38天。","identification":"与蓝顶翠鴗的区别在于冠部图案（中央黑色带与蓝色王冠，缺乏绿色前额），胸部黑色标记更小，胸部和披肩的红褐色对比度较低。与叫翠鴗相比，体型更大，有更宽的王冠，腹部比胸部更绿，银色至蓝绿色的前部王冠中混有陶土色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，自墨西哥南部至巴拿马西部，包括热带雨林、干燥的树林等多种生境。","other":"适应部分退化的栖息地，即使在较小的树丛中也能生存，只要保留一些灌木层。在多个保护区中均有发现，如墨西哥南部的Montes Azules生物圈保护区。"},{"name":"叫翠鴗","english_name":"Whooping Motmot","scientific_name":"Momotus subrufescens","overview":"叫翠鴗（英文名：Whooping Motmot，学名：Momotus subrufescens），是佛法僧目翠鴗科翠鴗属的鸟类。自巴拿马东部至南美洲西北部的低地森林中皆可见到其身影。以其独特的‘呼’声闻名，是当地森林中常见的声音之一。","appearance":"叫翠鴗体型较大，背部及翅膀呈橄榄绿色，腹部为暗褐色。头部最显著的特征是深蓝色的冠羽，中央嵌有一块黑色斑点，周围环绕着一条明亮的天蓝色带。眼周有黑色的面纹，边缘点缀着青绿色。长长的尾羽末端呈蓝黑相间的球拍状。成鸟两性相似，体重平均约96克，范围在75至124克之间。","call":"发出单一的‘呼’声，音调低沉。","habits":"栖息于多种森林环境，包括常绿和落叶的低地原始森林、林缘以及次生林。生活习性相对静止，长时间静立于枝头，偶尔摇摆其尾羽。以大型节肢动物为主要食物，偶尔也会食用浆果和蜥蜴。","breeding":"繁殖期间，会在土岸挖掘长隧道筑巢。","identification":"在地理范围内，叫翠鴗是唯一一种具有天蓝色冠羽和黑色眼罩的翠鴗。与高原翠鴗相比，体型较小，下体颜色更偏橄榄绿，而高原翠鴗下体颜色更偏向棕色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，具体包括巴拿马中部、哥伦比亚北部、委内瑞拉北部、厄瓜多尔西部和秘鲁西北部。","other":"曾与蓝冠翠鴗（Momotus coeruleiceps）、特岛翠鴗、亚马逊翠鴗、雷氏翠鴗和高原翠鴗被视作同一物种，后因研究发现差异而被区分为独立种类。"},{"name":"特岛翠鴗","english_name":"Trinidad Motmot","scientific_name":"Momotus bahamensis","overview":"特岛翠鴗（英文名：Trinidad Motmot，学名：Momotus bahamensis），是佛法僧目翠鴗科翠鴗属的色彩斑斓的鸟类，仅分布于南美的特立尼达岛和多巴哥岛。以独特的橙、绿、蓝色羽毛图案和大体型令人难忘，拥有黑色面罩、胸斑、红宝石般的眼睛。当地唯一的翠鴗。","appearance":"特岛翠鴗是一种大型鸟类，具有粗壮的黑色喙和长长的尾羽，尾端呈球拍状。背部和翅膀一般为绿色，尾羽上表面蓝色，腹部深赤褐色。冠部中心黑色，环绕着宽广的蓝色带，前额至眼上方为淡蓝绿色，后颈处转为深蓝色。胸前有一条黑色条纹，边缘镶嵌着蓝绿色。胫部羽毛呈现绿色至蓝绿色。","call":"特岛翠鴗发出低沉的猫头鹰般的‘ooo-doot’叫声。","habits":"栖息于雨林中，通常处于较低的位置，有时会进入较为开阔的地带，只要那里有大树可供栖息。它们以小猎物为食，如两栖动物、小型哺乳动物、昆虫、蜘蛛、蚯蚓、蜥蜴、小蛇和雏鸟，也会吃水果。","breeding":"像大多数佛法僧目鸟类一样，特岛翠鴗在河岸的隧道中筑巢，产下大约三到四个白色蛋。","identification":"特岛翠鴗是特立尼达岛和多巴哥岛上唯一的翠鴗种类，其深赤褐色的腹部颜色和广泛的赤褐色分布，使其与‘蓝冠翠鴗’群中的其他成员区分开来。","protection":"IUCN：LC（无危）","distribution":"特岛翠鴗的分布局限于南美的特立尼达岛和多巴哥岛。","other":"特岛翠鴗出现在特立尼达和多巴哥5元纸币的正面。"},{"name":"亚马逊翠鴗","english_name":"Amazonian Motmot","scientific_name":"Momotus momota","overview":"亚马逊翠鴗（英文名：Amazonian Motmot，学名：Momotus momota），是佛法僧目翠鴗科翠鴗属的鸟类。广泛分布于南美洲安第斯山脉东侧的低地，以绿色羽毛搭配橙色腹部、黑色面罩和蓝色冠羽为显著特征。其独特的‘BOO-boop’叫声在黎明和黄昏时分尤为常见。","appearance":"亚马逊翠鴗拥有中等体型，背部和翅膀为绿色，腹部颜色从较浅的绿色到赭色不等。头部最显眼的是深蓝色的冠羽，顶部有一小块黑色，眼周被黑色羽毛形成的三角形面罩包围。尾部长而具特色，末端呈球拍状，通常为蓝色，尖端暗至黑灰色。","call":"亚马逊翠鴗的鸣唱为低沉的‘BOO-boop’声，重音在第一个音节，常在晨昏时分听到。","habits":"栖息于各种森林环境，包括湿润森林、半湿润森林及森林边缘地带，偏好在显眼的栖木上静坐，摆动尾巴。它们的饮食为杂食性，以昆虫、小型哺乳动物、爬行动物和果实为食。","breeding":"关于繁殖习性的资料有限，已知亚马逊翠鴗在土堤中挖掘长隧道筑巢，具体繁殖细节尚不清楚。","identification":"在分布范围内，亚马逊翠鴗是唯一具有蓝色冠羽的翠鴗。与高原翠鴗相比，体型较小，腹部颜色更绿，少有赭色色调。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲东部，涵盖亚马孙低地，从委内瑞拉东部延伸至巴西东部和阿根廷东北部。"},{"name":"高原翠鴗","english_name":"Andean Motmot","scientific_name":"Momotus aequatorialis","overview":"高原翠鴗（英文名：Andean Motmot，学名：Momotus aequatorialis），是佛法僧目翠鴗科翠鴗属的鸟类。即安第斯翠鴗，分布于南美洲安第斯山脉的潮湿山地森林，自哥伦比亚至玻利维亚。相较于亚马逊翠鴗，体型更大，下体更绿，缺乏土黄色调。","appearance":"体型大，具黑色喙和长尾，尾端呈拍状。全身绿色，翼和尾蓝色，冠中央黑色，环绕以蓝色带，眼周有黑线（面具）。下体绿色纯正，胸部中央有黑色羽毛，边缘带蓝。尾羽基部绿色，逐渐变为深蓝色。拍状尾尖深蓝色。","call":"发出类似猫头鹰的双重呼叫声，主要在黎明时分鸣叫。","habits":"栖息于潮湿的山地森林，常见于树木中层安静停歇。以昆虫和果实为食，可能偶尔捕食小型哺乳动物。","breeding":"在地面的长隧道末端筑巢，具体繁殖细节未知，但在9月观察到处于繁殖状态的雄鸟个体。","identification":"与亚马逊翠鴗相似但体型更大，下体颜色更纯，面具上方有垂直蓝条纹，拍状尾上部通常全蓝，无绿色或暗色尖端。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉，从哥伦比亚中北部至玻利维亚西部。在哥伦比亚，见于三大山脉；在厄瓜多尔、秘鲁和玻利维亚，仅见于安第斯山脉东侧。"},{"name":"棕翠鴗","english_name":"Rufous Motmot","scientific_name":"Baryphthengus martii","overview":"棕翠鴗（英文名：Rufous Motmot，学名：Baryphthengus martii），是佛法僧目翠鴗科棕翠鴗属的鸟类。以其独特的外观和行为而闻名。头部和胸部呈橙红色，带黑色面罩和胸部斑点，背部和长长的尾巴则是鲜艳的绿色。与体型较小的阔嘴翠鴗相似，但通过更大的体型、橙红色下巴和腹部更广泛的橙红色来区分。常见于中美洲和南美洲的森林中，通常位于树冠之下。","appearance":"棕翠鴗拥有醒目的黑色面罩和长而狭窄的渐变尾羽。尾羽末端在棕翠鴗 semirufus亚种上具有典型的羽毛球拍状，但在棕翠鴗 martii亚种中缺失。雌雄两性外观相似，头部和胸部为深橙红色，与绿蓝色的背部、翅膀和尾羽形成鲜明对比。雌鸟略小于雄鸟。","call":"棕翠鴗发出深沉的呼叫声，类似于'woo-doop'，有时作为单一叫声，有时则是一连串的持续笑声。","habits":"偏爱湿润的低地和山地森林环境，以各种果实、无脊椎动物乃至小型脊椎动物为食，有时会跟随行军蚁觅食。在觅食时，它会安静地坐在阴凉的水平树枝上，然后突然出击捕捉飞过的昆虫。","breeding":"关于繁殖和筑巢的细节较少。据信，如同其他翠鴗一样，它们会在土堤中挖掘或修整洞穴来筑巢。然而，具体的繁殖周期、蛋的描述、孵化期和离巢时间等信息尚不清楚。","identification":"与阔嘴翠鴗极为相似，但可通过体型更大、橙红色下巴以及腹部更广泛的橙红色来区分。此外，阔嘴翠鴗的喉部和下巴为绿色，而非橙红色。","protection":"IUCN：LC（无危）","distribution":"分布在中美洲东部至南美洲西南部，包括洪都拉斯至厄瓜多尔，以及亚马逊雨林西部。具体而言，从洪都拉斯东部至厄瓜多尔西南部，亚马逊雨林西部，以及哥伦比亚东部到巴西西部。","other":"尽管在部分范围内非常普遍，但关于其自然历史的许多方面，包括蛋的描述、孵化期和离巢时间等，仍有许多细节未知。"},{"name":"棕顶翠鴗","english_name":"Rufous-capped Motmot","scientific_name":"Baryphthengus ruficapillus","overview":"棕顶翠鴗（英文名：Rufous-capped Motmot，学名：Baryphthengus ruficapillus），是佛法僧目翠鴗科棕翠鴗属的鸟类。广泛分布于南美的巴西东南部、巴拉圭东部和阿根廷东北部。拥有独特的橙色头冠和黑色眼罩，身披蓝绿色羽衣。","appearance":"体长约42厘米，重约140至151克。成鸟上体呈蓝绿色，下体橄榄绿，具醒目的橙色头冠与颈背，黑色眼罩边缘环绕着浅蓝色。胸部带有黑斑，腹部中央有一条橙色带纹，下腹则为蓝绿色。幼鸟色泽较暗淡。","call":"通常在黎明与黄昏时分发出类似猫头鹰的连续‘hoo-oo-oo-oo-oo’叫声。","habits":"栖息于原始低地森林及沿水道的林廊，海拔高度可达1200米。以大型昆虫、蜘蛛、陆生软体动物、小型爬行动物、哺乳动物和鸟类为主食，偶尔加入混合物种觅食群。","breeding":"在潮湿土壤中挖掘巢穴，或利用其他动物如犰狳废弃的洞穴。繁殖季节可能为9月至10月，期间会喂养巢中幼鸟，双亲共同参与育雏。","identification":"与全地理隔离的Baryphtengus martii相比，棕顶翠鴗羽毛更显绿色，少红棕色，尾羽较短且末端无羽毛球状突起。","protection":"IUCN：LC（无危）；尽管种群数量大，分布广泛，且在多个保护区有记录，但因森林砍伐导致其数量正在减少。","distribution":"分布于巴西东南部（从巴伊亚至马托格罗索州南部和里奥格兰德州北部）、巴拉圭东部和阿根廷东北部（米西奥内斯省）。","other":"已知在多个国家公园和生态保护区中频繁出现，如阿根廷的伊瓜苏国家公园、乌鲁瓜伊省立公园，巴拉圭的圣拉斐尔国家公园和卡瓜祖国家公园，以及巴西的塞拉达卡纳斯特拉国家公园、索雷塔马生物保护区等。"},{"name":"隆嘴翠鴗","english_name":"Keel-billed Motmot","scientific_name":"Electron carinatum","overview":"隆嘴翠鴗（英文名：Keel-billed Motmot，学名：Electron carinatum），是佛法僧目翠鴗科隆嘴翠鴗属的鸟类。两者可能为同一物种。体型相似，叫声相近，但羽毛色彩有异。分布于中美洲，自墨西哥南部至哥斯达黎加北部，常栖息于热带湿润低地森林和山地森林，高度一般低于750米，偶尔可达1550米。","appearance":"隆嘴翠鴗身长30.5至38厘米，体重约68克。全身羽毛以绿色为主，腹部橄榄色至肉桂绿。额头呈红褐色，面部有黑色面罩，眼上有一蓝条纹。下巴为淡蓝色，胸部有黑色斑点。其喙长而宽阔，边缘有细小锯齿，尾部长且末端有拍状突起。","call":"鸣叫声与宽喙翠鴗极为相似，发出低沉、鼻音重的‘cuaet cuaet cadack’或‘ohhng’声，间隔时间约为3.5至5.5秒，较宽喙翠鴗更深沉。求偶时，两只雄鸟会向雌鸟发出‘ohn k-k-owhng k-k-k-owhng k-k-owhng’的鼻音。","habits":"隆嘴翠鴗偏爱热带湿润的常绿森林，尤其在有陡峭溪谷和溪流的区域。在哥斯达黎加仅见于丘陵森林和相邻的低地森林。以昆虫为主要食物，通过从栖木上进行空中扑捉的方式觅食。活动范围广泛，但迁徙情况未知。","breeding":"繁殖习性细节未详。雄鸟会在1月至3月间发出领地宣告声。已知的巢穴位于溪流岸边的陡峭河岸，或在伯利兹的未挖掘玛雅遗迹侧边。","identification":"与宽喙翠鴗相比，隆嘴翠鴗具有更宽的喙，更大的胸斑，不同的面部图案，以及较短的裸露尾羽。与阔嘴翠鴗相比，虽叫声相似，但后者头部和颈部有更多红褐色。","protection":"IUCN：VU（易危）","distribution":"分布于中美洲，自墨西哥南部至哥斯达黎加北部。在伯利兹、洪都拉斯、尼加拉瓜、危地马拉、伯利兹和哥斯达黎加均有记录。","other":"由于栖息地快速消失，尤其是森林被转换为农业用地，该物种面临威胁。"},{"name":"阔嘴翠鴗","english_name":"Broad-billed Motmot","scientific_name":"Electron platyrhynchum","overview":"阔嘴翠鴗（英文名：Broad-billed Motmot，学名：Electron platyrhynchum），是佛法僧目翠鴗科隆嘴翠鴗属的鸟类。广泛分布于中美洲东部至南美洲亚马逊西部，包括洪都拉斯至厄瓜多尔西南部。此物种拥有独特的橙红头部与胸部，配以黑色面罩和胸斑，绿色背部与腹部，尾羽长而末端呈蓝黑色。","appearance":"阔嘴翠鴗长约31-39厘米，体重约56-66克。头部、颈部和胸部呈橙红色，黑色面罩覆盖脸颊和耳羽区，胸中央有一黑色斑点。上体绿色，翅膀蓝色，腹部绿蓝色，尾部蓝色，尾羽末端黑色。喙宽扁，具锯齿边缘和上颌骨脊。两性相似，但幼鸟颜色较暗淡，下体大部分被深橄榄绿色取代，眼上方有短蓝绿色条纹，喙尖白色。","call":"最常听到的叫声是鼻音“cwaah”或“cwahnk”，通常在黎明时分发出，但整个白天也频繁鸣叫。有时会以较快的连续序列或二重唱形式发出。","habits":"栖息于湿润森林和较老的次生林地带，常见于低地和山脚，海拔高度可达1100米。主要以昆虫及其幼虫为食，也会捕食蜘蛛、蝎子、蜈蚣、小型蛙类、蜥蜴和蛇。偶尔食用果实，但仅占饮食极小部分。会跟随行军蚁群，捕食受其惊扰的猎物。","breeding":"繁殖期在哥斯达黎加为2月至5月。在哥伦比亚西部，幼鸟尾部缩短，由成鸟陪伴。巢穴位于土堤中，长约1米，入口宽8厘米，高6-7厘米。每窝产卵2-3枚，双亲共同孵卵，孵化期未确定，雏鸟离巢时间约为24-25天。","identification":"与更大的棕翠鴗相似，但体型较小，胸部黑色斑点较大，喉咙蓝绿色，翅膀更蓝。幼鸟颜色暗淡，喙尖白色，眼上方有蓝绿色条纹。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲东部至南美洲西部，具体包括洪都拉斯东部至厄瓜多尔西南部，亚马逊雨林西部。"},{"name":"绿眉翠鴗","english_name":"Turquoise-browed Motmot","scientific_name":"Eumomota superciliosa","overview":"绿眉翠鴗（英文名：Turquoise-browed Motmot，学名：Eumomota superciliosa），是佛法僧目翠鴗科绿眉翠鴗属的鸟类。常在热带低地的干燥森林边缘、半开放地带及花园中活跃。绿眉翠鴗以其独特的蓝绿色眉毛、黑色面部面具与蓝线以及鲜艳的尾羽而著称。","appearance":"绿眉翠鴗体长约34厘米，体重介于44-74克之间，雄鸟略大于雌鸟。它的尾羽极其特殊，中央尾羽长度约为相邻尾羽的两倍，带有极长的裸露羽轴（约75毫米），尾羽末端形成扇形的球拍状，宽度几乎是基部的两倍。羽毛上部主要为绿色，背部及腹部呈红褐色，翅膀和尾部上方为蓝绿色。喉咙和胸部橄榄绿色，中央有黑色毛茸茸的条纹，边缘镶以蓝绿色，腹部为肉桂色。喙黑色，腿和脚灰色。","call":"发出鼻音、嘶哑的‘wohh’或‘owhh’声，间隔3.5-4.5秒一次，声音比电子翠鴗更高更不响亮，还会有变化多样、空洞而略带沙哑的咕噜声，包括节奏感强的‘k'wok k'wok...’和更长的‘k'wok t'k'wok t'k'wok t'k'wok...’。","habits":"绿眉翠鴗栖息于落叶林、林缘、常绿树林、低矮灌木丛及半开放区域，也能在人工种植园和花园中找到。以昆虫、蜘蛛、千足虫、小型软体动物、蚯蚓、小蜥蜴和蛇为主要食物，偶尔食用少量水果。它在黄昏后的人造灯光下捕捉飞虫，以突然的冲刺捕食地面或植被上的猎物，或在空中捕获蝴蝶、蜜蜂和蜻蜓等。","breeding":"繁殖季节为5月第二周至7月中旬，有时在巢穴早期失败后会再次筑巢。在墨西哥的考古遗址中，36%的繁殖尝试因鼠蛇（Elaphe phaescens）的捕食而失败。绿眉翠鴗在土堤、低悬崖、人造废墟、渗井或淡水井的土层中挖掘巢穴，巢穴长度可变，平均130厘米，末端扩大成宽约20-23厘米、高约10厘米的巢室。每窝产卵2-6枚，通常为4枚，间隔约48小时产一枚，孵化期为18-20天，幼鸟离巢时间为24-31天。","identification":"绿眉翠鴗与其他翠鴗科鸟类的区别在于其极长的裸露尾羽轴、蓝绿色眉毛以及喉咙和胸部的图案。幼鸟颜色较暗淡，背部几乎没有红褐色，黑色与蓝绿色条纹也不明显。","protection":"IUCN：LC（无危）","distribution":"绿眉翠鴗分布在中美洲，从墨西哥东南部到哥斯达黎加西北部，包括尤卡坦半岛。在萨尔瓦多及尼加拉瓜，它是国鸟。","other":"绿眉翠鴗能够适应次生植被和半开放国家，利用人类活动创造的筑巢机会，甚至在人类频繁出入的地方筑巢。"},{"name":"赤须夜蜂虎","english_name":"Red-bearded Bee-eater","scientific_name":"Nyctyornis amictus","overview":"赤须夜蜂虎（英文名：Red-bearded Bee-eater，学名：Nyctyornis amictus），是佛法僧目蜂虎科夜蜂虎属的大型鸟类。其显著特征为全身绿色，喉部和顶冠呈鲜艳的红色，形成独特的‘胡须’状外观，尾羽下侧黄色。分布于东南亚的马来半岛、苏门答腊、邦加岛以及整个低地婆罗洲。","appearance":"赤须夜蜂虎体长27-31厘米，体重雄鸟68-92克，雌鸟61-70克。雄鸟上半身绿色，下半身较淡，顶冠呈现独特亮紫色，带有珍珠光泽；顶冠羽毛基部呈黄褐色或红色，从下方看羽毛尖端显红色而非紫色；喙基部周围有一圈浅蓝色细小、硬挺、向前弯曲的羽毛；喉部羽毛长而宽，基部灰色和深橄榄绿，仅末端长放射状的毛刺是红色；尾羽较硬，近端宽大，颜色为象牙白或浅黄色；尾羽上侧绿色，下侧黄色，末端黑色；喙强壮、拱形，强烈向下弯曲，黑色，下颌近端四分之一铅灰色；虹膜鲜橙色。雌鸟与雄鸟相似，但顶冠紫斑较小，额部和后顶冠分别呈朱红色和绿色，而非紫色。幼鸟通体绿色，翼下暖黄褐色，尾下黄色，喙基部周围有少量浅蓝羽毛。","call":"赤须夜蜂虎发出快速下降的系列粗哑音节“KA-Ka-ka-ka-ka-ko-kow”，强调前几个音节。有时只发出一次，有时则长时间间隔重复。此外，还会发出低沉的类似蛙鸣的声音“grwaa”或“ko-ko-grwaa”，以及粗哑的重复声“grow..grow..grow..”。","habits":"赤须夜蜂虎栖息于低地和山脚森林中的开阔地带，从高处叶间隐蔽的栖木飞出捕食飞行中的昆虫。它们单独或成对狩猎，而非群居，长时间几乎不动，然后突然移动到新的有利位置。","breeding":"繁殖期在8月、1月和2月，幼鸟出生在3月至6月；多数巢穴在2月被发现。在路边的土堤、密林旁的小溪沙土或锯木坑挖掘巢洞，洞长约1.2米。一窝产卵最多五枚，通常三枚，由双亲共同孵化。幼鸟孵化期为31-34天。","identification":"赤须夜蜂虎以其独特的绿色体羽、红色顶冠和喉部以及黄色尾下为辨识关键，与同属其他物种区分开来。","protection":"IUCN：LC（无危）。","distribution":"分布于远东的马来半岛、印尼苏门答腊岛、邦加岛（东部，印尼苏门答腊岛南部）和婆罗洲。","other":"赤须夜蜂虎主要以空中飞行的昆虫为食，包括黄蜂、大黄蜂、蜜蜂、木蜂、蝉、甲虫、蟋蟀和蚂蚁。"},{"name":"蓝须夜蜂虎","english_name":"Blue-bearded Bee-eater","scientific_name":"Nyctyornis athertoni","overview":"蓝须夜蜂虎（英文名：Blue-bearded Bee-eater，学名：Nyctyornis athertoni），是佛法僧目蜂虎科夜蜂虎属的鸟类。大型绿色林栖型蜂虎，以蓝色蓬松的胸羽著称。分布于喜马拉雅山脉、印度北部、中国南部含海南岛、东南亚等地，常栖息于海拔1800米以下的原始林和过伐林中。","appearance":"成年蓝须夜蜂虎体长31至35厘米，体重70至93克，外观草绿色，头部有淡蓝色的额头，喉咙处长而宽的羽毛形成似胡须的形状，颜色由深蓝色渐变为纯天蓝色。背部在新鲜状态下主要是绿色，但在冠顶、颈背、肩部和覆羽上会呈现蓝绿色。翼下有暖色的斑纹，腹部呈丰富黄褐色，带有宽阔的绿色条纹。喙灰色偏粉，眼周羽毛绿色，虹膜明亮橙色。印度种群通常上体颜色更清晰，脸颊较淡，下体条纹较少。","call":"发出粗犷、类似卷尾或犀鸟的复杂多样叫声，包括深沉喉音的咕噜声、低沉的咆哮声和干燥的嘶哑声。叫声在100至200米内可听见，但并不响亮。此外，还发出空洞鼻音的'KYao'叫声、咯咯笑声、短促压抑的咆哮声、低沉尖锐的啄木声和沙哑滚动的咕噜声。成对的蓝须夜蜂虎可能会持续几秒钟进行二重唱，交替使用各种叫声类型。","habits":"占据湿润落叶林和茂密次生常绿林的中层，也频繁出现在苔藓森林、林间空地、散布树木的花园和稀疏的落叶山顶丛林中。分布海拔从海平面至2200米，但多数低于1600米。主要以飞行昆虫为食，尤其是蜜蜂、木匠蜂、黄蜂、大型甲虫和蜻蜓。成对的鸟儿经常稳坐树边或高大的开花树顶，偶尔进行捕猎飞行。在尼泊尔、印度东部、缅甸和泰国东南部报道有季节性数量波动，可能是因为局部迁移或垂直迁徙所致。","breeding":"繁殖季节在阿萨姆邦为2月至5月及8月，在尼泊尔为4月至5月和10月，在缅甸为3月至10月，在泰国约4月至5月。单独筑巢，巢穴周围可能有4至12个隧道，可能是前一年的巢穴或“假启动”。在森林小径旁的河岸、沙质河岸、道路切割面或森林峡谷或滑坡的陡峭冲积悬崖面上挖掘巢穴。巢穴长度1.3至3米，直径75至95毫米，末端为无衬垫的卵室，宽20厘米，高13厘米。一窝最多六个卵，孵化期间由雄鸟喂养雌鸟。","identification":"蓝须夜蜂虎与其他夜蜂虎属物种的主要区别在于其特有的蓝色喉咙羽毛和蓬松的下垂胡须状结构。相较于其他小型蜂虎，它的飞行更为波浪形，尾巴末端方形，缺乏典型的小型蜂虎尾羽中央较长的‘电线’状结构。印度种群与印度支那种群在外貌上有细微差别，前者上体颜色更鲜明，脸颊更淡，下体条纹更少。","protection":"IUCN：LC（无危）","distribution":"在喜马拉雅山脉西部至科特加尔地区较为常见，在缅甸零星分布，南沿海岸至吉亚基亚米；在泰国不常见或局部存在；在印度中部的两个分离区域，一般不常见；在印度西部的西高止山脉，从古吉拉特的萨特普拉山和R塔普蒂至西马哈拉施特拉邦、卡纳塔克邦、泰米尔纳德邦的帕特尼山和喀拉拉邦，极为局部。在多个国家公园中均有记录，如印度的科比特、卡齐兰加、那木达帕和穆杜马莱，尼泊尔的奇旺，泰国的考三罗伊约特、多伊因塔农、那纳米奥和考艾，越南的Nam Bai Cat Tien，以及中国的迪丁、夏雷、榜良和西达明山自然保护区，广西的农岗国家自然保护区。","other":"已知寄生虫包括从该物种描述的Leucocytozoon nyctyornis血寄生虫和Brueelia属的羽毛寄生虫。"},{"name":"须蜂虎","english_name":"Purple-bearded Bee-eater","scientific_name":"Meropogon forsteni","appearance":"成年须蜂虎的体型约为25-26厘米，尾部的中央羽毛可额外延伸至6厘米左右。头部和王冠部分呈黑色，边缘带有深蓝色，脸颊和耳羽巧克力棕色或暗酒红色。雄鸟的紫色喉部羽毛宽大且长，几乎覆盖整个胸部，形成独特的视觉效果。雌鸟相似，但前腹部为红棕色而非紫色。幼鸟的头部和胸部主要为绿色，仅下喉部和上胸处的羽毛呈深蓝色，中央尾羽尚未形成流苏状。","call":"须蜂虎的叫声是一种相对低调的高音“seEep”，音调上扬，重复频率大约每2-3秒一次。","habits":"须蜂虎栖息于原始森林和次生林中的开阔地带和空地，海拔范围从海平面到1850米，包括低地、山地和苔藓森林边缘。它们偶尔也会出现在有大量大树的农田附近。须蜂虎在雨季会靠近海岸活动，而在旱季返回内陆繁殖。","breeding":"繁殖季节在3月、9月和11月，已知的筑巢记录出现在7月和9月。它们在陡峭的河岸、悬崖、滑坡、道路切割或森林小径旁挖掘巢穴，巢穴长度可达90厘米，入口宽90毫米，高35毫米。","identification":"须蜂虎的独特之处在于其紫色的喉部羽毛和中央尾羽的流苏状延长，这与其他蜂虎种类明显不同。","protection":"IUCN：LC（无危）","distribution":"须蜂虎主要分布在苏拉威西岛的北部、中部和东南部山区，包括Tangkoko和Ambang山保护区，Dumoga-Bone和Lore Lindu国家公园以及Morowali保护区。"},{"name":"黑头蜂虎","english_name":"Black-headed Bee-eater","scientific_name":"Merops breweri","overview":"黑头蜂虎（英文名：Black-headed Bee-eater，学名：Merops breweri），是佛法僧目蜂虎科蜂虎属的鸟类。体型较大的蜂虎，主要分布在非洲热带地区的森林边缘，包括安哥拉、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、加蓬、加纳、尼日利亚和南苏丹。其最显著的特征是黑色头部、绿色背部和翅膀、以及橙黄色腹部和胸部带有肉桂色胸带。","appearance":"成年黑头蜂虎体长约为28厘米（含尾羽流苏可达34厘米），体重约54克。头部呈黑色，背部和翅膀绿色，尾羽中央部分延长，上侧绿色，下侧暗淡肉桂色；腹部为丰富赭色，胸部有肉桂色胸带，胸带在中间较窄，两侧可能被翅膀遮掩；喙黑色，比同类物种除大体型的红蜂虎外都更为粗壮；眼睛鲜红，腿和脚为深灰色，脚底黄色，爪黑色。幼鸟类似成鸟，但尾羽中央部分不延长，前额、顶冠和颈背的黑色羽毛边缘宽泛绿边，有时有明显的绿色颊纹，缺乏肉桂色胸带，胸部为绿色。","call":"黑头蜂虎不常鸣叫，主要发出的叫声是重复而坚持的“wic”音，较短且声音低，还发出相对安静的“pfuruk’p’r’k”声在喂食巢穴时，以及在问候时发出低调的“churruk-churruk”或柔和的音乐般颤音。","habits":"黑头蜂虎通常单独或成对出现，偶尔以小群形式迁徙。它们主要栖息于森林边缘、开放的次生林、种植园、森林中的空地和居住区附近，尤其靠近河流和溪流；也见于木岛和河岸；画廊森林和沼泽森林，邻近干旱草原筑巢。它们主要以空中飞行的昆虫为食，如蜜蜂、黄蜂、金龟子、粪甲虫和其他甲虫、大型黄蜂、蜻蜓、蝉、天蛾、蝴蝶，可能也会给雏鸟提供幼虫。","breeding":"在北部范围内，黑头蜂虎于1月挖掘洞穴，2月产卵，3月至4月有雏鸟；在南部，8月末和9月产卵。它们单独或松散集群繁殖，巢穴通常位于斜坡上的软红土堆、白蚁丘或耕地上裸露或草地沙质地面，高度60至75厘米。洞穴向下倾斜约20°，圆形或椭圆形截面，高约55毫米，宽65毫米，入口直径70至90毫米，长度1.1至2.1米，末端急转弯形成一侧的卵室，长25厘米。每次产卵2至3枚白色卵，大小为23.3至25.5毫米×21.1至22.5毫米，雌鸟单独孵化，自最后一枚卵开始。","identification":"与同域内的其他蜂虎如黑蜂虎和蓝头蜂虎相比，黑头蜂虎具有不同的色彩和明显较大的体型。幼鸟的下巴和喉咙为黑色。","protection":"IUCN：LC（无危）。虽然黑头蜂虎在大部分地区被视为罕见，但由于人们捕杀成鸟或故意堵塞巢穴入口，以及栖息地的破坏，其种群被认为正在减少。在某些地区，如刚果西南部的Ménengué地区，由于种植桉树，可能会导致局部灭绝。","distribution":"黑头蜂虎分布于非洲的科特迪瓦、加纳、尼日利亚南部、中非共和国北部、加蓬至苏丹西部南部、刚果民主共和国中部、安哥拉西北部。","other":"在1966年，当沃尔塔湖淹没河流森林区域时，该物种在加纳的阿夫拉姆河沿岸消失。"},{"name":"蓝头蜂虎","english_name":"Blue-headed Bee-eater","scientific_name":"Merops muelleri","overview":"蓝头蜂虎（英文名：Blue-headed Bee-eater，学名：Merops muelleri），是佛法僧目蜂虎科蜂虎属的鸟类。生活在非洲热带雨林中的小型鸟类。其最显著的特征是头部的蓝色至蓝紫色，腹部和尾巴同样呈蓝色，喉咙为红色，面部呈深紫黑色，前额淡青色，背部呈红色。分布于喀麦隆南部至刚果民主共和国东部，以及肯尼亚西部。","appearance":"蓝头蜂虎体长约19厘米，体重24-33克。雄鸟具有尖锐的白色前额羽毛，浅蓝色的冠羽，蓝紫色的颈背，头部两侧黑色；红色的下巴羽毛细长而僵硬，上体和翅膀深栗色；尾部末端呈方形，闭合时显蓝色，内部黑色；下体蓝紫色；虹膜深红棕色。雌鸟与雄鸟相似，但某些个体胸部长有橄榄色斑点，蓝色部分带绿，下巴红色斑块较小，虹膜呈酒红色。幼鸟的栗色部位比成鸟更赭黄色，蓝色部分更接近暗绿色，冠羽、脸颊和肩部带有橄榄色。","call":"蓝头蜂虎较为沉默，其鸣唱由间隔开的音符组成，有的尖锐或刺耳，有的柔和而鼻音。叫声包括微弱的高音“tsee-sup”或更清脆的“trrri-wit！”以及连续的高音颤音“triiii...triiii”。","habits":"栖息于低地雨林，常在森林内部，但也出现在空地和林间空隙附近，沿着小径或森林边缘；在耕地上方，仅留下几棵枯树。在肯尼亚的卡卡梅加森林，主要分布在半落叶次生林，偶尔出现在有散落树木的邻近农田。以飞行中的昆虫为食，包括蜜蜂、胡蜂、蚂蚁、蝶类、蛾类、直翅目昆虫、甲虫和马蝇。","breeding":"繁殖季节可能在1月至5月期间，曾在加蓬观察到10月筑巢和2月幼鸟离巢的情况。可能有帮手参与，但缺乏近期证据。在小径旁的堤岸挖掘约60厘米长的洞穴。每窝产卵最多三个。","identification":"与黑蜂虎在森林内部昏暗光线下容易混淆，但蓝头蜂虎的前额为淡青色，而黑蜂虎的整个头部为黑色。","protection":"IUCN：LC（无危）","distribution":"分布于喀麦隆南部和加蓬北部至刚果民主共和国东部，以及肯尼亚西部。在肯尼亚，可能仅限于卡卡梅加和南南迪森林，现在较为罕见。","other":"蓝头蜂虎在肯尼亚的卡卡梅加森林受到投石儿童的骚扰，但更大的威胁来自于农业侵占和牛群践踏，后者现在在整个森林中放牧。"},{"name":"蓝须蜂虎","english_name":"Blue-moustached Bee-eater","scientific_name":"Merops mentalis","overview":"蓝须蜂虎（英文名：Blue-moustached Bee-eater，学名：Merops mentalis），是佛法僧目蜂虎科蜂虎属的鸟类。生活在西非和中非森林中的鸟类，常见于森林内部、边缘或树倒空隙。其头部、腹部和尾巴呈深蓝色至蓝紫色，喉部红色，眼线深色，背部呈红褐色。分布于塞拉利昂至喀麦隆西部和赤道几内亚的比奥科岛。","appearance":"体长约19厘米，体重17.4-30克，体型较小，全身暗色，不易引人注目。成鸟主要羽毛呈紫蓝色，胸背和翅膀为丰富的栗色，喉咙有小块鲜红色斑点被黑色环绕，光照下全身显暗色，翅膀略带赤褐色。喙黑色，眼睛红色，腿脚灰色。雄鸟颜色更鲜艳，背部更亮的肉桂色，腹部更深的蓝色，喉咙更深的红色，体型稍大于雌鸟。幼鸟整体较成鸟暗淡。与蓝头蜂虎区别在于前额、冠部和脸颊的深紫色到青绿色，下体颜色较浅，中央尾羽延长且末端呈球状。","call":"叫声包括罕见听到的两声组成的“ji-up！”。","habits":"栖息于常绿或半常绿雨林，偏好林间空隙或边缘地带，常见于丘陵和高原，有时出现在沼泽森林。活动高度可达地面以上15米，通常成对或小家庭群活动，以蝴蝶为主食，偶尔捕食蜜蜂和其他昆虫，从藤蔓和细枝上短暂飞扑捕食。","breeding":"繁殖季节不详，但在塞拉利昂和加纳观察到2月有幼鸟，3月在象牙海岸发现幼鸟。在喀麦隆和利比里亚的1月和3月初有发现鸟蛋。在路边土坡挖掘40-55厘米长的巢穴，每窝产2枚乳白色鸟蛋，大小约22.5-23.7毫米×18-20.1毫米。","identification":"与蓝头蜂虎相比，蓝须蜂虎具有深色的颊须区、没有白色的前冠部、深蓝色的冠部和绿色的尾巴，下体颜色较淡，中央尾羽较长且末端钝圆。","protection":"IUCN：NT（近危）国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"分布于塞拉利昂至西南加纳，南尼日利亚至西喀麦隆，以及赤道几内亚的比奥科岛。在加纳的阿特瓦山脉可达800米，利比里亚的宁巴山同样海拔，比奥科岛上可达1200米。","other":"在一些国家公园和保护区中有所记录，如科特迪瓦的塔伊森林、尼日利亚的克罗斯河、几内亚的丰峰森林保护区，以及加纳的多个森林保护区。"},{"name":"黑蜂虎","english_name":"Black Bee-eater","scientific_name":"Merops gularis","overview":"黑蜂虎（英文名：Black Bee-eater，学名：Merops gularis），是佛法僧目蜂虎科蜂虎属的鸟类。中等体型的鸟类，具有独特的黑色外观，鲜艳的红色喉部和蓝色腹部，主要分布在非洲中部和西部的热带雨林边缘及次生林地。","appearance":"黑蜂虎长约20厘米，体重25至34克。头部黑色，额部和眉纹蓝色，眼下方常有一条蓝色线。喉部羽毛鲜红，基部暗灰色，顶部形成10毫米长的非闭合状毛丛。背部黑色，臀部和上尾覆羽亮蓝色，如同某些翡翠鸟的色彩。翼羽深赤褐色，末端黑色。翼覆羽和次级飞羽边缘绿色到蓝色，三级飞羽顶端绿色到蓝色，随时间褪色或变蓝。胸部黑色，有蓝色条纹，腹部和下尾覆羽非常长，亮蓝色。雌雄同形同色。幼鸟下巴和喉咙油绿色，胸部较暗，腹部和下尾覆羽的蓝色不够鲜艳。亚种emaustralis/em缺少蓝色额部、眉纹和眼下方的蓝色，胸部有时可见红色羽毛尖端。","call":"黑蜂虎发出尖锐的“ji-lip！”叫声，不常听到。","habits":"黑蜂虎栖息于森林和森林边缘地带，以空中飞行的昆虫为食，如蜜蜂、黄蜂、蚂蚁、蝴蝶、蜻蜓、豆娘、双翅目昆虫、蛾类、蝽象、甲虫、少数蚱蜢和蟋蟀。它通过从高处观察并突然出击捕捉过往昆虫，之后滑翔回栖木，通过拍打猎物使其失去活力。","breeding":"关于黑蜂虎的繁殖信息未提供。","identification":"黑蜂虎在良好光照下很容易识别，其独特外观包括红色喉部和蓝色腹部，与同属其他物种有明显区别。亚种间差异主要体现在额头、眉纹的颜色和胸部羽毛的细节。","protection":"IUCN：LC（无危）。在西非的几内亚比绍、加纳、尼日利亚东部等地常见；刚果共和国的森林中频繁出现；乌干达的Bwamba森林、科特迪瓦的Taï森林、喀麦隆的Mount Kupé、加蓬的La Lopé和乌干达的Bwindi森林中也有分布；在塞拉利昂的Gola森林保护区出现。","distribution":"黑蜂虎分布于非洲的中部和西部，主要栖息在次热带雨林区域，包括塞拉利昂东部至尼日利亚东南部，向南延伸至刚果民主共和国东北部，直至安哥拉北部。","other":"黑蜂虎有两个亚种：M. g. gularis，分布于塞拉利昂至尼日利亚东南部；M. g. australis，分布于尼日利亚东南部至刚果民主共和国东北部，南至安哥拉北部。"},{"name":"燕尾蜂虎","english_name":"Swallow-tailed Bee-eater","scientific_name":"Merops hirundineus","overview":"燕尾蜂虎（英文名：Swallow-tailed Bee-eater，学名：Merops hirundineus），是佛法僧目蜂虎科蜂虎属的鸟类。以其深深分叉的蓝色尾巴而著称。分布广泛，从半沙漠灌木丛到稀树草原至森林边缘都有其踪迹。成鸟体色鲜艳，幼鸟色彩较暗淡。","appearance":"体长约23厘米，重约18-29克。上体绿色，臀部蓝色；眼纹黑色，下方镶以蓝白色；喉部黄色，下缘为蓝色领圈；胸部绿色，逐渐过渡至腹部和尾下覆羽的蓝色；翼羽主要为栗色，翼缘黑色；翼下浅栗色；三级飞羽暴露部分褪至灰蓝色；尾羽深叉，中间一对灰蓝，其余绿蓝，除中位和最外侧一对外，均在内缘具灰白尖端，亚端部暗色区双缘；尾外缘几乎直线，分叉端稍向内弯，分叉深度31-46毫米；虹膜橙红至鲜红。雌雄相似。幼鸟较暗淡，喉部绿白色，无领圈，虹膜深棕色。不同亚种在蓝色领圈宽度和尾腹蓝色程度上有差异。","call":"发出一系列柔和的滚动叫声“peerrr...peerrr...”和“trip...trip...”。飞行叫声为干燥的“prip....prip...”。群居时尤为嘈杂。","habits":"栖息于成熟的高大稀树草原林木，如Kalahari沙地上Baikiaea林木、Isoberlinia、Colophospermum、Brachystegia和Combretum林木、河流灌丛、高大的桉树防风林、灌木河岸平原、公园和半沙漠地带散生的Acacia。具有一定的游荡性和迁移性，会侵入最近烧过的地区。","breeding":"在北热带地区约于4-7月繁殖，南非洲则在9-12月。单独筑巢或有时两三对鸟邻近筑巢。在裸露沙土或路边堤岸、土豚(Orycteropus afer)巢穴挖掘长达80-100厘米的洞穴。每窝产2-4枚卵，孵化期和育雏期未知。","identification":"与其它蜂虎相比，燕尾蜂虎的尾部明显分叉，且色彩更加丰富，包括绿色、蓝色和黄色的组合。不同亚种在颜色细节上有细微差别。","protection":"IUCN：LC（无危）","distribution":"繁殖于非洲的稀树草原林地。在南非北部更为常见，但在赤道以南地区分布更广，从零星分布到局部常见。出现在多个国家公园，如科莫埃(象牙海岸)、Bamingui-Bangoran(中非共和国)、卡巴莱加瀑布(乌干达)、米库米(坦桑尼亚)、利翁德(马拉维)、瓦特伯格高原和埃托沙(纳米比亚)以及万基(津巴布韦)。"},{"name":"小蜂虎","english_name":"Little Bee-eater","scientific_name":"Merops pusillus","overview":"小蜂虎（英文名：Little Bee-eater，学名：Merops pusillus），是佛法僧目蜂虎科蜂虎属的鸟类。分布于撒哈拉沙漠以南的非洲国家。体长16-17厘米，体重13-19克，喉部黄色，与黄喉蜂虎有所区别。是非洲最小的蜂虎，常见于灌丛、草原地带，以昆虫为食。","appearance":"小蜂虎拥有绿色的冠羽和上体，宽阔的黑色眼纹，脸颊和喉部为黄色，被黑色颈环所环绕，下方有一条肉桂色带；其余下体为丰富淡褐色，翅膀带有赤褐色，次级飞羽尖端黑色；三级飞羽倾向蓝绿色，虹膜红色。成年个体性别相似，幼鸟缺乏黑色颈环，下巴和喉部为淡黄褐色，胸部轻绿，侧腹和腹部淡黄色，胸羽隐约斑点状或条纹，上胸染有棕色。种族间差异较小。","call":"小蜂虎的常见叫声为短促重复的“tsip”。群体中，其他个体可能以芦苇般的“drrreeee”声响应。在高强度问候展示中，还会发出高音的金属般短语。","habits":"小蜂虎栖息于草地环境，通常靠近水源，如沼泽、湖岸、河岸、溪边以及雨季时的耕作土地，有时出现在森林边缘的草地、灌木沙丘、草地岩露头和无树平原。它们在干燥季节偏好腰高草丛和夹杂着木棉树密集丛的半干沼泽。快速适应森林中被清理的土地，尤其是当惊慌草和其他草类入侵时。","breeding":"小蜂虎的繁殖记录遍及全年，最早在2月见到离巢的幼鸟，1月在马里发现蛋；尼日利亚的繁殖时间随纬度增加而延迟，从3月在中部尼日利亚到7月初在最北部，接近凉爽干燥季节的结束；东非全年都有繁殖记录，主要在9月左右的内罗毕附近；南部非洲，赞比亚为9月至10月，津巴布韦为9月至2月，南非主要为9月至11月（主要是10月）。它们挖掘单一的巢穴，长达100厘米，位于低矮沙崖、高峭壁、排水沟或犁沟的侧面，或是干燥的大动物蹄印侧边；在土豚（Orycteropus afer）常见的地区，巢穴常位于土豚洞穴入口处的斜坡顶上。每窝产4至6枚卵，平均数为4.4枚在尼日利亚。孵化期为18至20天，主要由雌鸟承担，自第一枚卵开始；前两枚卵几乎同时孵化，第三枚卵约19小时后，第四枚卵在第三枚后24小时。雏鸟期为23至24天。","identification":"小蜂虎与非常相似的的蓝胸蜂虎区别在于后者具有白色边框的黄色脸颊；与红胸蜂虎相比，小蜂虎体型更小，色彩不那么鲜艳，脸颊黄色边框几乎没有或完全没有白色。不同亚种间的差异较为轻微。","protection":"IUCN：LC（无危）","distribution":"小蜂虎广泛分布于撒哈拉沙漠以南的非洲国家，包括塞内加尔的萨卢姆三角洲、苏丹的丁德尔、埃塞俄比亚的阿瓦什、乌干达的鲁文佐里、肯尼亚的内罗毕、卢旺达的阿卡盖拉、坦桑尼亚的米库米、赞比亚的南卢安瓜、马拉维的利翁德和南非的克鲁格国家公园。"},{"name":"蓝胸蜂虎","english_name":"Blue-breasted Bee-eater","scientific_name":"Merops variegatus","overview":"蓝胸蜂虎（英文名：Blue-breasted Bee-eater，学名：Merops variegatus），是佛法僧目蜂虎科蜂虎属的鸟类。以其绿色背部、黄色喉咙和缓冲腹部为特征。胸部带的颜色随地理位置而变，最常见的是深蓝色，但在某些地区可能呈现黑色。该物种广泛分布于中非国家，如安哥拉、赞比亚、坦桑尼亚等地，主要栖息于湿润开阔的生境，如稀树草原边缘和森林边界。","appearance":"成年蓝胸蜂虎身长18至21厘米，体重20至25克。头部和上体呈绿色，宽阔的黑色眼纹，白色脸颊，黄色喉咙，深紫色至蓝色的胸部带下方有栗色胸带，其余下体为淡绿色至绿黄色。次级飞羽呈浅红褐色，主飞羽和次级飞羽尖端黑色；三级飞羽倾向于磨损或褪色成蓝色；尾巴红褐色，有黑色亚端斑和白色尖端，中央尾羽绿色。虹膜橙红色，喙黑色，腿和脚黑色。雌雄相似，幼鸟缺乏黑色胸部带，有淡黄色至黄绿色的下巴和喉咙，逐渐过渡到淡绿色的胸部，侧腹和腹部为淡黄绿色，胸部有斑点或条纹。","call":"鸣叫声包括短促的木制咔哒声，以及在求偶时更为扩展的三音节序列。","habits":"栖息于轻度树木覆盖的草地山坡、开放的杜松和冷杉林地，咖啡和桉树种植园的草缘，以及城市郊区环境。在埃塞俄比亚，与小蜂虎在同一区域内共存，但蓝胸蜂虎偏好永久湿润的开放环境。主要以空中的昆虫为食，如蜜蜂、花蜂、胡蜂和其他膜翅目昆虫，也吃甲虫、苍蝇、蝽、蚱蜢和蜻蜓。通常单独或成对出现，有时形成小型家庭群体。","breeding":"繁殖季节在喀麦隆和北扎伊尔为2月至3月，在坦桑尼亚为10月至12月，在加蓬为8月至9月，在赞比亚为9月至10月。单独筑巢，但相邻的繁殖对可能同步开始繁殖。在草地山坡或湖岸附近的斜坡挖掘隧道，长度45至75厘米，末端为无衬垫的蛋室，尺寸约为16.5至19.5×18至22厘米。产卵2至3枚，白色，大小约20.1至24毫米×14.8至18.1毫米。","identification":"与小蜂虎相比，蓝胸蜂虎略大，脸颊边缘更白；与红胸蜂虎相比，体型较小，次级飞羽和尾羽上表面更红褐色，绿色较少。幼鸟与成鸟的区别在于缺乏黑色胸部带。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部，从尼日利亚东南部至安哥拉和东非。在中国，指名亚种夏季繁殖于湖北及长江以南，海南岛为留鸟。","other":"历史上曾与较小的蓝胸蜂虎视为同一物种，但现已确认为独立种类。"},{"name":"双斑蓬头䴕","english_name":"Two-banded Puffbird","scientific_name":"Hypnelus bicinctus","overview":"双斑蓬头䴕（英文名：Two-banded Puffbird，学名：Hypnelus bicinctus），是䴕形目蓬头䴕科黄喉蓬头䴕属的鸟类。分布于南美洲的哥伦比亚和委内瑞拉北部，尤其是东北部的llanos地区，其特征为白脸斑、棕喉及胸部的多条带纹。曾被认为是黄喉蓬头䴕的一个亚种。","appearance":"成年双斑蓬头䴕的头部为深褐色，点缀着浅棕色斑点，脸部至眼周有淡黄色斑块，颊部有一片白色，下颌处有黑色斑纹。颈背有窄白环，上身呈暗棕色，带有白色斑点，闭合的翅膀为暗棕色，饰以白色波状纹。尾巴长而深棕色，羽毛边缘呈淡色。喉咙和上胸为红棕色，下颚处有两条黑色横带。腹部其余部分为红棕色，边缘有黑点，两肋为白色，点缀着大黑斑。亚种stoicus外观相似，但上体略显棕色，面部标记不那么明显，上胸带羽尖为黄色。","call":"发出节奏性的重复叫声'tak-ta-tóoo'，并伴有响亮的嘶哑声，有时在飞行中也会发出叫声。","habits":"栖息于开阔或半开阔的景观，如llanos草原、灌木丛、废弃农场和落叶林边缘，几乎完全位于海拔500米以下。它会从高处的开放位置或较低的阴凉处静候猎物，然后飞扑捕食，已知饮食中包含昆虫。季节性移动尚未被记录，但栖息地会经历季节性变化。","breeding":"繁殖季节可能包括5月和6月，具体细节不明。在树上的白蚁丘中挖掘洞穴作为巢穴，确切的窝卵数未知，但黄喉蓬头䴕通常产三枚蛋。","identification":"与黄喉蓬头䴕相比，双斑蓬头䴕总是展示两条或三条带纹（而不仅仅是一条），并且上部带纹环绕喉部。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的哥伦比亚东北部和委内瑞拉北部，包括llanos地区，几乎延伸到马拉开波湖西侧，东至接近圭亚那边境，南微入亚马逊州和玻利瓦尔州。亚种stoicus仅见于委内瑞拉海岸的玛格丽塔岛。","other":"过去被认为是黄喉蓬头䴕的一个亚种群，但现在被视为独立物种。"},{"name":"月胸蓬头䴕","english_name":"Crescent-chested Puffbird","scientific_name":"Malacoptila striata","overview":"月胸蓬头䴕（英文名：Crescent-chested Puffbird，学名：Malacoptila striata），是䴕形目蓬头䴕科须蓬头䴕属的鸟类。分布于南美的巴西东北部和东南部，栖息于多种半开放景观，如湿润低地森林边缘、砍伐过的森林及次生林。体长17.5至20厘米，体重约40至47克。","appearance":"月胸蓬头䴕的头部和背部为黑褐色，饰有淡褐色条纹。面部基部红棕色，嘴周有淡色或白色的\"胡须\"。翅膀为暗棕色，带有淡色斑点；尾巴呈均匀的深棕色。上胸部有一个白色新月形图案，其下有一条宽阔的黑色带状图案。下胸部为红棕色，腹部中央呈白色，而两侧则为淡棕色，饰有淡色斑点。M. s. minor亚种的胸部带状图案更为明亮，下体更白，无横纹。","call":"发出高音的口哨声，由10个以上的音符组成，类似小型暴鸟的声音，\"bieh, bieh, bieh…\"。","habits":"月胸蓬头䴕似乎主要为单独觅食，但也有报道指出它们会跟随军队蚁群，与其他鸟类一同觅食。饮食习惯记录不足，但推测以无脊椎动物为主。通常在开阔地带的边缘活动，如道路旁和空地边缘，较少进入森林内部。海拔分布范围从海平面至2,100米。","breeding":"繁殖期至少从10月至12月或1月。已知的两个巢穴是在土岸上挖掘的洞穴，但关于繁殖生态学的细节，巢穴本身以及蛋的信息尚缺乏。","identification":"与M. s. striata相比，M. s. minor明显较小，胸部带状图案更亮，下体更白且无横纹。通过体型、胸部颜色和下体特征可以区分。","protection":"IUCN：LC（较低关注）对于M. s. striata，但其估计种群数量超过72,000个成熟个体，且相信数量正在减少。M. s. minor被评估为Endangered（濒危），由于其范围内不断增加的森林砍伐，种群数量未知且相信正在减少。","distribution":"分布于南美洲巴西的东北部和东南部，具体包括巴伊亚、米纳斯吉拉斯、巴拉那、圣卡塔琳娜州以及东北部的马拉尼昂和皮奥伊州。"},{"name":"白胸蓬头䴕","english_name":"White-chested Puffbird","scientific_name":"Malacoptila fusca","overview":"白胸蓬头䴕（英文名：White-chested Puffbird，学名：Malacoptila fusca），是䴕形目蓬头䴕科须蓬头䴕属的鸟类。英文名形象地描述了这种鸟的外观特征，即拥有白色胸部斑块，尽管这一特征有时并不明显。主要分布在南美洲亚马孙雨林的北部和西北部地区。","appearance":"白胸蓬头䴕是一种棕色和白色条纹相间的鸟类，头部较大，喙呈黄橙色，微弯，尖端黑色。上身颜色深棕，背部有浅色条纹，而下体则为脏白色或淡黄色，带有模糊的暗棕色条纹。胸部有一窄窄的白色新月形斑纹，头部的颊纹和下巴为白色或淡黄色。成年鸟的总长度约为18厘米，体重约44克。","call":"其鸣唱为一连串柔和的颤音，音调逐渐下降，仅在近处可听见。叫声包括高音的下降哨声，重复间隔较长。","habits":"栖息于热带雨林的下层和中层，通常独居。在捕食时，它会从几米高的栖木上飞出，长时间静止不动后突然冲向地面或植被捕捉大型昆虫和小型脊椎动物。有时跟随行军蚁群。食性以昆虫为主，偶尔摄入小无脊椎动物。","breeding":"关于繁殖生态知之甚少，推测其筑巢于地面的洞穴中，如同其近亲白须蓬头䴕一样。","identification":"在大部分分布范围内，白胸蓬头䴕因背部长条纹和大部分橙色的喙而容易识别。与半领蓬头䴕相比，后者整体颜色较暗，颈部有宽大的栗色项圈。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊盆地的东部哥伦比亚、委内瑞拉西南部至厄瓜多尔东部、秘鲁中部至阿普里马克河谷，以及圭亚那低地至巴西的亚马逊州和帕拉州。栖息于海拔200米至1500米的热带常绿森林。"},{"name":"半领蓬头䴕","english_name":"Semicollared Puffbird","scientific_name":"Malacoptila semicincta","overview":"半领蓬头䴕（英文名：Semicollared Puffbird，学名：Malacoptila semicincta），是䴕形目蓬头䴕科须蓬头䴕属的鸟类。南美洲亚马逊雨林西部特有种。以独特的外观和习性而著称。","appearance":"该鸟体长约18厘米，体重约44克。头部和上体呈黑褐色，羽毛的浅色羽轴形成明显的条纹状。颈部后方有一圈红褐色的环状斑纹，如同佩戴了一条半领。下颏至喉部白色，两颊有白色的“胡须”。上胸有一细窄的白色新月形斑。下胸至两侧腹部有黑色条纹，其余下体部分呈白色。上喙基部除开之外全黑，下喙尖端黑色，其余橙黄色。眼睛深红色，周围环绕着一圈白环，脚趾淡绿粉色。","call":"它的叫声通常是一系列细弱、高音调、略带忧郁的下降式‘Fééeur’或‘pseuu’哨声，起初音节间隔较大，随后音调逐渐下降，呈现‘pseuu-uuu-uuu’的模式。","habits":"半领蓬头䴕主要栖息于亚马逊雨林的过渡地带，以及湿润热带常绿高地森林的边缘，从低层灌木到较低的中层林冠。海拔高度从近海平面至1,050米（3,400英尺）。其具体的觅食行为和饮食习惯尚未被详细记录。","identification":"与同属的白胸蓬头䴕相比，半领蓬头䴕具有更白的冠部条纹，红褐色的颈后环，更橙色的喙，上喙上的黑色区域更多但下喙上较少，眼睛颜色更深，眼周白色，脚趾颜色更浅。","protection":"IUCN：LC（无危）","distribution":"半领蓬头䴕分布于南美洲西部亚马逊地区，具体包括巴西极西部、秘鲁东南部和玻利维亚最北部的交汇处。","other":"该物种曾被认为与白胸蓬头䴕是同一物种，但现在被视为超种群。"},{"name":"黑纹蓬头䴕","english_name":"Black-streaked Puffbird","scientific_name":"Malacoptila fulvogularis","overview":"黑纹蓬头䴕（英文名：Black-streaked Puffbird，学名：Malacoptila fulvogularis），是䴕形目蓬头䴕科须蓬头䴕属的鸟类。分布于南美洲的哥伦比亚、厄瓜多尔、秘鲁和玻利维亚西北部，常单独或成对出现在湿润山地森林的中层。","appearance":"这是一种优雅的中型鸟，体长19至22厘米，重约65克，头部黑色带有细白条纹，眼前方有一白色斑点。上身深棕色，肩部有细白条纹，背部形成黄褐色三角形图案。翅膀呈褐色，覆羽上有黄褐色鳞片状斑点，尾巴实心棕色。喉咙和上胸橙黄色，下胸、上腹和侧翼黑白相间的条纹，腹部中央为淡污白色。喙黑色，眼睛深红色，周围有白色环圈，脚部暗色。","call":"其鸣声为非常尖锐的上升哨音，持续时间不到4秒。","habits":"黑纹蓬头䴕在森林的下层或中层栖息，从那里飞扑捕捉昆虫等无脊椎动物。有时跟随军队蚁群移动，加入混合物种觅食群。","breeding":"关于黑纹蓬头䴕的繁殖生态学信息尚未公布。","identification":"与其他蓬头䴕相比，黑纹蓬头䴕具有明显的黑白条纹和独特的鸣声。","protection":"IUCN：LC（无危）","distribution":"黑纹蓬头䴕分布于南美洲安第斯山脉东坡，从哥伦比亚中部至玻利维亚西北部，包括厄瓜多尔和秘鲁。在不同的海拔高度（500至2300米）的多种森林类型中均可找到，包括湿润原始森林、山地森林、开阔林地，甚至在玻利维亚的干燥和半落叶林。"},{"name":"棕颈蓬头䴕","english_name":"Rufous-necked Puffbird","scientific_name":"Malacoptila rufa","overview":"棕颈蓬头䴕（英文名：Rufous-necked Puffbird，学名：Malacoptila rufa），是䴕形目蓬头䴕科须蓬头䴕属的鸟类。广泛分布于南美洲亚马逊雨林的南部区域，从巴西亚马逊河口至玻利维亚北部和秘鲁东北部。偶尔会加入混合物种群，或在行军蚁群附近活动。","appearance":"成年棕颈蓬头䴕长约18厘米，重约39至46克。头部的冠羽和脸颊呈暗灰色，带有细窄的淡色条纹，具有显著的橙红色眉斑。颈部有一宽广的橙红色领圈，延伸至头部两侧，直至嘴基。背部为深棕色，翅膀和尾巴为暖棕色。下体颜色从深棕色到浅白色不等，胸部较深，腹部较浅。胸部上方有一白色新月形标记，边缘为黑色。喙为蓝灰色至黑色，眼色为深棕色或深红色，脚趾为淡灰棕色至淡橄榄灰色。幼鸟的颜色略淡且更暗淡。","call":"其鸣唱为一首长长的、下降的乐音颤音，与白胸蓬头䴕和半领蓬头䴕的歌声难以区分。叫声包括薄薄的哨声和激动的嘶哑连串声。","habits":"栖息于亚马逊雨林的下层，偶尔参与混合物种群，也会在行军蚁群附近活动。狩猎时从几米高的栖木上出击，捕食昆虫和其他无脊椎动物，可能还包括小型脊椎动物。偏好在地面隧道中的巢穴。","breeding":"关于棕颈蓬头䴕的繁殖生态知之甚少。已知它们会在地面的隧道中筑巢。","identification":"与白胸蓬头䴕和半领蓬头䴕相比，棕颈蓬头䴕的头部无明显条纹，具有橙红色的眉斑和领圈，且喙部颜色不同。","protection":"IUCN：LC（无危）","distribution":"南美：亚马孙雨林中南部，包括巴西南部亚马逊河以南地区、秘鲁东北部、玻利维亚东北部。"},{"name":"白须蓬头䴕","english_name":"White-whiskered Puffbird","scientific_name":"Malacoptila panamensis","overview":"白须蓬头䴕（英文名：White-whiskered Puffbird，学名：Malacoptila panamensis），是䴕形目蓬头䴕科须蓬头䴕属的鸟类。近似雀形目的鸟类，们栖息于中美洲东南部至南美洲厄瓜多尔的热带低地湿润常绿森林中，有时也在次生林和田野边缘的较矮植被中被发现。雄鸟和雌鸟在羽色上存在显著差异，雄鸟面部和胸部带有明显的赤褐色调。","appearance":"白须蓬头䴕体长约18厘米，重约43克。雄鸟上体呈棕到赤褐色，尾羽为赤褐色，头部两侧、颈侧为淡褐色，喉部和上胸为淡褐色至淡黄褐色，下体其余部分为淡黄色，胸部和侧腹有暗色条纹。雌鸟上体橄榄至褐色，冠部更灰，下体大部分为淡黄至肉桂色，腹部白色。幼鸟的下体条纹比成鸟更明显。两性均有大嘴基部的羽须和白色‘胡须’，实际上是羽毛簇。喙短而强壮，末端弯曲。","call":"其鸣声为高音下降的颤音，通常以强调的音符结尾，如tssiirrrrr-tsít。还有一种常见的叫声，为高而细、略带芦苇质感的拉长音tsssiiiw或tssssiiir，逐渐减弱。","habits":"白须蓬头䴕主要生活在热带低地湿润常绿森林中，偶尔出现在次生林和田野边缘的较矮植被中。它们常在距离地面6米左右的高度活动，以静候捕食策略为主，猎食大型无脊椎动物、小型蛙类和蜥蜴。有时会跟随行军蚁群或加入混合物种觅食群体。","breeding":"繁殖季节在哥斯达黎加从3月中旬持续到7月。巢建于斜坡上的洞穴中，洞深46至56厘米，直径约6厘米，巢室铺有干叶。雌鸟产2枚，有时3枚光滑的白色卵，两性共同孵化。","identification":"与须蓬头䴕最为相似，但后者胸部的肉桂色更广泛，下颌基部为蓝灰色而非黄绿色，下体条纹更为模糊。须蓬头䴕体型更大，通常出现在更高海拔。","protection":"IUCN：LC（无危）","distribution":"白须蓬头䴕分布于中美洲东南部至南美洲西部，从墨西哥东南部至厄瓜多尔。在北中美洲，分布海拔从海平面至750米，在哥斯达黎加的加勒比海一侧可达900米，太平洋一侧最高可达1200米。","other":"白须蓬头䴕能够适应次生林环境，但在森林砍伐导致的栖息地丧失面前仍处于脆弱状态。"},{"name":"须蓬头䴕","english_name":"Moustached Puffbird","scientific_name":"Malacoptila mystacalis","overview":"须蓬头䴕（英文名：Moustached Puffbird，学名：Malacoptila mystacalis），是䴕形目蓬头䴕科须蓬头䴕属的鸟类。此物种在南美洲安第斯山脉区域活动，包括哥伦比亚、委内瑞拉以及厄瓜多尔的北部地区。体型丰满的棕褐色鸟类，雄鸟与雌鸟的羽毛颜色有所不同。","appearance":"须蓬头䴕长约20至23厘米，体重约47至50克。雄鸟上部羽毛呈暗淡的棕色，背部和翼覆羽上有白色至黄白色的斑点，尾部棕色，带有小而浅色的标记。其脸部图案独特，眼圈和嘴角周围有白色的羽毛簇，形似胡须。雌鸟羽毛色调较灰，腹部条纹更重。幼鸟的颜色较深，胸羽上的锈红色较少，光亮的标记也不明显。","call":"须蓬头䴕的鸣声被描述为高而细的啾啾声，与同属的其他蓬头䴕相似。","habits":"该鸟主要栖息于湿润森林的下层植被中，偶尔在林缘和开阔的林地中发现，活动范围通常保持在地面以上6米之内。在海拔高度上，它们的分布范围从350到2100米不等。","breeding":"须蓬头䴕的繁殖期在委内瑞拉大约为5月至8月，在哥伦比亚则是2月至9月。它们在土壁上挖掘洞穴作为巢穴，但关于其繁殖生态的细节尚未完全了解。","identification":"与白须蓬头䴕和黑纹蓬头䴕形成超种群，但可通过其特有的羽毛特征和分布区域加以区分。雌鸟比雄鸟颜色更深，白须蓬头䴕一般出现在较低海拔，且下颌颜色为黄色而非灰色。","protection":"IUCN：LC（无危）","distribution":"须蓬头䴕分布于南美的安第斯山脉，具体包括哥伦比亚、委内瑞拉的西北部和北部，以及厄瓜多尔的中北部地区。","other":"须蓬头䴕在其范围内并无太多相似物种，需警惕与白须蓬头䴕混淆，后者通常出现在较低海拔，具有黄色下颌和腹部更多条纹。"},{"name":"矛蓬头䴕","english_name":"Lanceolated Monklet","scientific_name":"Micromonacha lanceolata","overview":"矛蓬头䴕（英文名：Lanceolated Monklet，学名：Micromonacha lanceolata），是䴕形目蓬头䴕科矛蓬头䴕属的唯一物种。分布于中美洲和南美洲，包括哥斯达黎加至玻利维亚北部，其范围广泛，但在某些区域可能较为罕见。","appearance":"体长13至15厘米，体重约19至22克。全身呈温暖的棕色，带有类似鳞片的淡褐色斑点。头部周围有白色的鼻须和胡须状羽毛，眼圈白色，翼部和尾羽上侧深棕色，尾羽下侧灰色。腹部大部分白色，带有黑色条纹，腹部中央无条纹，臀部略带赭色。","call":"发出1至5个高亢、细薄、哀怨的上升哨音，'sewee ... sewee sewee-sewee-sewee’swee’swee'，每次叫声略高于前一次。接触叫声为细而尖锐的'tsip tsip'。","habits":"栖息于中层和高层森林，偏好阴凉的开阔边界、边缘和自然树倒空地，包括原始森林、成熟次生林的小块区域和遮荫咖啡种植园，有时靠近水源，如小溪上方。活动高度通常在4至8米之间，以昆虫为主食，偶尔食用浆果，会跟随混群的小型鸟类觅食。","breeding":"繁殖期在哥斯达黎加为5月，厄瓜多尔西部为雨季晚期，玻利维亚有幼鸟喂食记录。已知巢穴为挖掘的隧道，长度40厘米，离地面73厘米，入口高6厘米宽5厘米，隧道弯曲向下至扩大的腔室，铺满干叶，每次产卵两个白色蛋，孵化期约15天。","identification":"与相似的Malacoptila属物种相比，体型较小，头部和喉部条纹较少。可通过体型、颜色模式和栖息行为加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加至巴拿马西部，南美洲的哥伦比亚西部、南部和中部，厄瓜多尔西部，巴西西部，秘鲁东部，以及玻利维亚北部。在亚马逊地区的巴西，仅限于Juruá河和Urucu河上游。在秘鲁，主要分布在Sucusary河流域附近。在玻利维亚，记录稀少，但在Pilón Lajas生物保护区和Cotapata国家公园有发现。","other":"尽管全球范围内不被视为受威胁，但因难以检测，在一些地区可能被低估了其数量。"},{"name":"锈胸小蓬头䴕","english_name":"Rusty-breasted Nunlet","scientific_name":"Nonnula rubecula","overview":"锈胸小蓬头䴕（英文名：Rusty-breasted Nunlet，学名：Nonnula rubecula），是䴕形目蓬头䴕科小蓬头䴕属的鸟类。主要分布在南美洲的亚马逊雨林以及巴西东南部，拥有独特的外观特征，如大而深色的眼睛和宽大的喙。其分布广泛，但在某些地区较为罕见。","appearance":"锈胸小蓬头䴕体型略显粗壮，长度约14至16厘米，体重介于17到20克之间。全身以灰棕色为主调，头部颜色偏灰，胸部呈淡褐色，腹部白色。喙部周围有白色眼圈，嘴基部至鼻羽有白色带纹，下颌线黑色，下巴白色。背部和翅膀暗灰棕色，尾部方尖，深棕色，下体从喉咙到腹部带有锈红色调。亚种间存在差异，例如东巴西的亚种更灰暗，而东南部亚种颜色更深，喉部至腹部橙红至浅橙色，中央腹部和臀部白色。幼鸟较暗淡，上体微带锈色边缘。","call":"其鸣唱主要在黎明和黄昏时发出，位于树冠层，歌声为一系列‘weeip, weeip, weeip’的叫声，音调和音量逐渐升高，有时会发出尖锐的‘tick’声，兴奋时对灰颊小蓬头䴕的播放回应尖叫。","habits":"常栖息于湿润的高地森林和河岸森林，也见于次生林和森林边缘，偏好砂土环境。活动于森林各层，主要在中层。食物以大型节肢动物为主，如甲虫、蟹类、竹节虫、螽斯和昆虫幼虫。偶尔短暂跟随混合物种群觅食。","breeding":"繁殖期在南美亚马逊和巴西米纳斯吉拉斯州观察到，巢筑于河岸洞穴或树洞中，至少一例观察到进入离地面约1.5米的树木白蚁巢。成鸟喂养两只已离巢的小鸟。巢的具体细节、卵数和其他繁殖生物学信息尚不清楚。","identification":"与其他小蓬头䴕属物种相比，锈胸小蓬头䴕具有明显的暗色眼圈和白色鼻羽带纹，以及锈红色的胸部和腹部特征。亚种间在结构和色彩上有细微差别。","protection":"IUCN：LC（无危）。虽然分布范围极广，但具体数量未知且被认为正在减少。在多个保护区中发现。","distribution":"锈胸小蓬头䴕主要分布在南美的亚马逊雨林区域以及巴西东南部，包括阿根廷、巴西、哥伦比亚、厄瓜多尔、圭亚那、巴拉圭、秘鲁、苏里南、委内瑞拉，可能还包括法属圭亚那。","other":"锈胸小蓬头䴕的系统分类仍有待解决，部分亚种可能代表独立的物种或并非有效分类单元。"},{"name":"褐颊小蓬头䴕","english_name":"Fulvous-chinned Nunlet","scientific_name":"Nonnula sclateri","overview":"褐颊小蓬头䴕（英文名：Fulvous-chinned Nunlet，学名：Nonnula sclateri），是䴕形目蓬头䴕科小蓬头䴕属的鸟类。是南美洲亚马逊雨林西部特有种。体型小巧，长约14至15.5厘米，体重介于15.4到19.9克之间。其显著特征为上体呈单调的褐色，脸颊为暗灰色，下巴处有一抹淡赤褐色，逐渐过渡至喉咙和胸部的红褐色。腹部中央为白色，两胁呈淡赭色。眼周有细窄的珊瑚红色或紫红色环。生活在低海拔（不超过300米）的湿润森林中。","appearance":"褐颊小蓬头䴕拥有略显沉重的黑色喙，喙基部有一块淡赤褐色的区域，头部侧面为暗灰色。上体和翅膀、尾巴为单调的褐色，下体从喉咙到胸为红褐色，腹部中间部分为白色。两胁淡赭色，足部为灰色或橄榄灰色。眼睛为棕色，周围有狭窄的珊瑚红或紫红色环。","call":"其鸣唱为一系列微弱的、类似猫叫的哨声：“wee weep weep weep weep weep”，音调逐渐上升，每秒约一音符。","habits":"栖息于亚马逊雨林的低地森林中，偏好上层湿润的‘terra firme’森林。通常单独或成对出现在灌木丛中，尤其是竹林附近。猎食行为尚不清楚，但推测主要以大型节肢动物为食，可能偶尔补充小型脊椎动物。","breeding":"繁殖习性了解甚少，据信在地面挖掘洞穴筑巢。近亲锈胸小蓬头䴕在斜坡上的浅坑中筑巢，用树枝和叶子覆盖，通常产四枚卵。","identification":"与棕顶小蓬头䴕的区别在于后者头部两侧和胸部为深灰色，与明亮的锈色冠羽、胸部和腹部形成鲜明对比。与锈胸小蓬头䴕相比，后者胸部颜色更接近赭色，且有明显的白色眼圈。","protection":"IUCN：LC（无危）。尽管其确切数量不明且被认为正在减少，但由于广泛分布而被列为无危。然而，由于人类活动导致的栖息地丧失或退化，所有亚马逊森林鸟类都面临潜在威胁。","distribution":"分布于南美洲亚马逊雨林西部，从秘鲁东部至玻利维亚北部，向东延伸至巴西西南部，直至马德拉河西岸。","other":"自然历史知之甚少，包括饮食和繁殖生物学。"},{"name":"褐小蓬头䴕","english_name":"Brown Nunlet","scientific_name":"Nonnula brunnea","overview":"褐小蓬头䴕（英文名：Brown Nunlet，学名：Nonnula brunnea），是䴕形目蓬头䴕科小蓬头䴕属的鸟类。分布于南美洲亚马孙雨林的西北部，包括南哥伦比亚、厄瓜多尔东部和秘鲁北部。具有独特的棕色上体和带状的淡褐色面部特征。","appearance":"该鸟体长约14至15厘米，头部和上体呈均匀的棕色，面部有一条从喙基延伸到眼睛的淡褐色带纹，眼周环绕着窄细的淡褐色眼环，脸颊为暗灰色至棕色。喉咙和两胁为深褐色，而下巴和胸部为浅褐色，腹部则呈现淡褐色。喙、眼睛和脚均为深色。","call":"其鸣唱为一系列约20至25个连续的‘treeu’音符，稳定重复，起始柔和，逐渐增强，最后再次减弱直至结束。","habits":"褐小蓬头䴕栖息于低地湿润的森林中，偏好森林下层至次生林密集区，通常不超出树冠层。在厄瓜多尔，主要分布于海拔400米以下，但有记录显示可达至700米左右。","breeding":"繁殖期未知，但已知会在地面挖掘洞穴作为巢穴，或利用树根下的隐蔽处筑巢。一个巢穴发现于秘鲁北部，内含一只幼鸟和一枚未孵化的白色卵；另在厄瓜多尔，巢穴建于地面的平坦区域，由精心排列的枝条和落叶构成。","identification":"与锈胸小蓬头䴕和灰颊小蓬头䴕有相似之处，但可通过其特有的面部带纹和颜色模式进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美亚马孙雨林的西北部，包括南哥伦比亚、厄瓜多尔东部和秘鲁北部。","other":"曾被认为与锈胸小蓬头䴕或灰颊小蓬头䴕同种，现在被确认为独立物种。"},{"name":"灰颊小蓬头䴕","english_name":"Grey-cheeked Nunlet","scientific_name":"Nonnula frontalis","overview":"灰颊小蓬头䴕（英文名：Grey-cheeked Nunlet，学名：Nonnula frontalis），是䴕形目蓬头䴕科小蓬头䴕属的鸟类。分布于哥伦比亚和巴拿马的森林地带。其特征为较丰满的体型，具大而略向下弯曲的喙。整体呈褐色，头顶温暖的赤褐色，脸颊灰色，喉部淡黄褐色，眼部周围有粉色眼环。性别相似，常单独或成对出现在森林较低至中层。","appearance":"长度约14至15厘米，体重介于14.5至19.5克。头顶深栗色，上体为单一的棕色，臀部颜色更亮；眼上方、脸颊和眼周为灰色，细长的暗色眼纹；尾羽长度约为全长的四分之一，末端平截，呈深棕色，尖端近黑色；颏部到下胸及两侧为赤褐色，腹部中央呈淡黄色，尾下覆羽白色；喙为银蓝色或灰色，顶部和切割边缘为黑色；虹膜深棕色，裸露的眼眶环为红色；脚为暗褐色或绿灰色。幼鸟色泽较淡，较为暗淡。亚种pallescens全身较淡，头顶非常暗淡，喉部和胸部为淡黄色；亚种stulta头顶非常暗，尾羽除外侧羽毛外几乎全黑，臀部颜色较为暗淡。","call":"发出哀婉、节奏均匀的长达20个音符的系列叫声，听起来像是“weeip weeip, weeip...”。","habits":"栖息于森林和林地，偏好有茂密灌木层的环境，活动范围涵盖从湿润的原始森林到次生林、河岸树林和灌丛。通常在森林较低层次活动，也可上升至次冠层。饮食以正翅目昆虫、毛虫、蠼螋（Dermaptera）、小型甲虫、蝉和蜘蛛为主，有时会加入由蚁鵙（Myrmotherula）、小型鵙（Tyrannidae）等组成的混合觅食群。","breeding":"繁殖季节从2月持续至6月，具体繁殖生态知之甚少。整个属的筑巢行为研究不足，但锈胸小蓬头䴕会在浅坑中筑巢，用树枝和树叶覆盖，通常产卵数量为四个。","identification":"在有限的分布范围内具有独特性，通过深色栗色的头顶、灰色脸颊、淡黄褐色的喉部和粉色眼环等特征与其他物种区分开来。亚种间主要在色泽深浅和某些部位颜色上有差异。","protection":"IUCN：LC（无危）。虽然其成熟个体估计少于50,000只且数量正在减少，但在哥伦比亚总体上仍相对常见。","distribution":"分布于中美洲和南美洲的巴拿马和哥伦比亚，亚种stulta分布在巴拿马中部至哥伦比亚西北部，亚种pallescens位于哥伦比亚北部的加勒比低地，指名亚种则在哥伦比亚北部内陆。"},{"name":"棕顶小蓬头䴕","english_name":"Rufous-capped Nunlet","scientific_name":"Nonnula ruficapilla","overview":"棕顶小蓬头䴕（英文名：Rufous-capped Nunlet，学名：Nonnula ruficapilla），是䴕形目蓬头䴕科小蓬头䴕属的鸟类。分布于南美洲的亚马逊雨林西部和南部，包括巴西、秘鲁和玻利维亚。该鸟具有独特的深栗色头顶，冷灰色的脸颊和胸部，上体为淡褐色，下体橙红至白色，是较为罕见的森林居民。","appearance":"棕顶小蓬头䴕体长约14厘米，体重14至22克。头部显著特征为深栗色的冠羽，脸颊、颈侧和胸部侧面呈冷灰色。背部颜色为单调的暗棕色，带有微弱的红褐色边缘。下巴至胸部为橙红色，两胁较浅的红褐色，腹部中央和尾下覆羽为白色。喙主要呈银蓝色，眼黑色，眼圈裸露呈红色，脚为暗褐灰色。幼鸟眼睑为黄褐色。三个亚种中，rufipectus亚种比指名亚种头部更暗，胸部更亮；nattereri亚种头部更暗，胸部更暗淡；inundata亚种比nattereri亚种更深、更暗。","call":"鸣唱为一系列尖锐、清晰、短促、音调上升的哨声，‘fwick!-fwick!...’，以每秒2-3次的均匀速度发出，整串叫声在开始和结束时略显柔和和低沉。","habits":"栖息于潮湿森林边缘、高地森林、次生林、河流边缘的竹林、沿溪流的密集低矮森林和igapó地带。通常单独或成对出现，偶尔加入混合物种群，特别是在跟随行军蚁时。在大多数分布范围内，与竹子（尤其是河岸竹林）有关联，但也出现在无竹子的环境中。在罗恩多尼亚的路边森林边缘发现领地，与丰富的藤蔓次生林相关；在秘鲁与Tessaria（早期演替洪水平原森林阶段）密切相关；在山林中，常沿溪流床活动。","breeding":"关于繁殖生态学的信息有限。在6月的玻利维亚和中巴西，收集到的4个成年个体并未处于繁殖状态。","identification":"与相似物种的区别在于更大胆的颜色模式和灰色脸颊斑块。亚种rufipectus、nattereri和inundata之间主要在头部颜色和胸部亮度上有细微差异。","protection":"IUCN：LC（无危）","distribution":"南美洲的亚马逊雨林西部和南部，包括巴西、秘鲁和玻利维亚。在巴西较为常见，秘鲁较少见，而在玻利维亚则为不常见至稀少。"},{"name":"栗头小蓬头䴕","english_name":"Chestnut-headed Nunlet","scientific_name":"Nonnula amaurocephala","overview":"栗头小蓬头䴕（英文名：Chestnut-headed Nunlet，学名：Nonnula amaurocephala），是䴕形目蓬头䴕科小蓬头䴕属的鸟类。主要分布于南美巴西西北部亚马逊州沿亚马逊河的一小片区域。","appearance":"该鸟体型小巧，全长约14至15厘米，体重介于15至16克之间。其头部、上背、胸部至腹部上部呈现鲜艳的栗色，背部、翅膀和尾巴颜色较暗，呈单调的棕褐色，臀部带有橄榄绿色调。腹部下部逐渐变为白色。喙大部分为黑色，眼虹膜红色，脚灰色。","habits":"生活在季节性淹没的igapó森林的下层，活动高度通常不超过3米，有时可达8米。它被观察到从栖木飞扑而出，推测是在捕食昆虫等无脊椎动物，但具体的觅食行为和饮食细节尚未发表。","identification":"与同属的其他物种相比，具有明显的特征，如较大的栗色鼻羽簇、亮栗色的头部至腹部上部，以及橄榄色臀部，易于区分。","protection":"IUCN：LC（无危）。虽然其分布范围极小，且估计数量正在减少，但其栖息地广泛且人类活动压力较小，可能因生性安静而未被充分记录。","distribution":"仅限于巴西西北部亚马逊州北部亚马逊河以北，内格罗河以西的小区域。","other":"属于蓬头䴕科中的单一物种，与灰颊小蓬头䴕和棕顶小蓬头䴕形成超种。"},{"name":"白脸䴕","english_name":"White-faced Nunbird","scientific_name":"Hapaloptila castanea","overview":"白脸䴕（英文名：White-faced Nunbird，学名：Hapaloptila castanea），是䴕形目蓬头䴕科白脸䴕属的鸟类。体型长约23至25厘米，重约75至84克。以独特的白色面部羽毛、黑色喙和红眼著称，广泛分布于哥伦比亚西部、厄瓜多尔东部至秘鲁西北部的安第斯山脉云雾林地带。","appearance":"白脸䴕体长23至25厘米，体重75至84克，具明显的白色鼻羽簇，喙大而黑色，边缘环绕着白色羽毛，形成额头上的显著白色斑块。头部灰褐色渐变为暗褐色的背部和脸部侧面，翅膀和尾巴颜色更深。下巴和喉咙白色，与鲜亮的栗色下体形成对比。下翼覆羽和初级飞羽基部呈锈色。喙全黑，虹膜红色，腿和脚灰色。雌雄外观相似，但雄鸟的下喙末端略向下弯曲，雌鸟下体可能略微淡一些。幼鸟胸部有灰色羽毛，喙和尾巴较短，其余部分与成鸟相似。","call":"白脸䴕的典型鸣声是一系列均匀间隔的、柔和的哨音，有时像猫头鹰的双声呼叫，有时会延伸成颤音或夹杂粗糙的音符。叫声哀婉，音调下滑，如'wuooooo'，或一系列加速后减速的吠叫声。","habits":"白脸䴕栖息于安第斯山脉的湿润至湿润森林和云雾林中，偏爱陡峭斜坡和溪谷的环境，常在中层到树冠层活动。它们主要以昆虫和其他节肢动物为食，偶尔也会捕食小型脊椎动物。白脸䴕偶尔加入混合物种的觅食群落。","breeding":"白脸䴕的繁殖季节在哥伦比亚为4月，在厄瓜多尔为5月末。巢穴通常挖掘在土质河岸上，由一对成鸟共同建造，内部铺垫小叶。巢穴隧道长38厘米，通向一个长23厘米、宽16厘米、高10厘米的室。每窝产两枚白色蛋，孵化期15至18天，幼鸟在37至38天后离巢。双亲共同承担筑巢、孵卵和喂养幼鸟的责任。","identification":"白脸䴕以其独特的白色面部羽毛、黑色喙缘和红眼易于识别，与同属其他物种有明显区别。","protection":"IUCN：LC（无危）","distribution":"白脸䴕分布在南美洲的哥伦比亚西部、厄瓜多尔东部至秘鲁西北部，主要栖息于海拔1500至2900米的安第斯山脉云雾森林中，特别是在哥伦比亚和厄瓜多尔，高度范围可低至750米；而在秘鲁，仅限于1800至2600米之间。","other":"白脸䴕在其分布范围内被认为是罕见至常见的局部物种，但在某些保护区如La Planada自然保护区、Munchique国家公园和Tatamá国家自然公园有所记录。"},{"name":"黑䴕","english_name":"Black Nunbird","scientific_name":"Monasa atra","overview":"黑䴕（英文名：Black Nunbird，学名：Monasa atra），是䴕形目蓬头䴕科黑䴕属的鸟类。广泛分布于南美洲北部，包括巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉等地。其最显著的特征是光泽蓝黑色的上部羽毛和暗灰色至浅灰色的下部羽毛，配以独特的珊瑚红色喙。在低地雨林中常可见到群体的黑䴕，通常生活在森林边缘、次生林和开阔地带。","appearance":"成年黑䴕长约25至29厘米，体重介于74至104克之间。其上半身呈光泽的蓝黑色，下半身为深灰色至中灰色，逐渐过渡。翼上的小覆羽为白色，形成明显的白色翼带。尾部宽大且圆润，喉咙的羽毛较长。下翼覆羽呈淡灰至白色。喙完全为红色，虹膜红至棕色，眼后有一块裸露的黑色皮肤。腿和脚为板岩黑色。幼鸟的上部颜色比成鸟更暗，下部则更偏褐色，眼睛颜色也更深。","call":"黑䴕发出的鸣唱为类似笛声的“whoo-doo-doo”和下降音调的“hyoo-hoo-hoo-oo-oo-oo”。群体中的叫声十分响亮，包括‘yawkl-diddl’或‘quee-didada’，往往由几只鸟一起发出，声音惊人地大。","habits":"黑䴕主要栖息于湿润的高地森林、河岸林和洼地森林，偏好靠近水源、森林边缘和较为开放的环境。它们在森林的各个层次活动，从林下层至树冠层均有发现。在海拔0至1000米的地方都能见到它们的身影。它们通常居住在固定的区域内，以昆虫为主食，包括正翅目、鞘翅目、半翅目等多种昆虫，以及蝎子、蜘蛛、大型蜈蚣和蜥蜴等。黑䴕通过突袭和悬停的方式捕捉猎物，有时跟随蚂蚁群寻找被冲刷下来的猎物。","breeding":"黑䴕的繁殖季节在委内瑞拉为3月至5月，在法属圭亚那则为8月至9月，可能也包括4月至5月。在巴西马瑙斯地区，一年中似乎有两个繁殖季节。它们的巢穴位于平地的洞穴中，但关于窝卵数、孵化期和离巢期的具体数据尚未记录。","identification":"黑䴕的黑色羽毛和珊瑚红色喙的组合是独一无二的。与黑额黑䴕和白额黑䴕相比，黑䴕的头部没有明显的白色或黑色标记。","protection":"IUCN：LC（无危）","distribution":"黑䴕分布于南美洲北部，包括委内瑞拉南部和东部、圭亚那、苏里南，穿过亚马逊雨林北侧，进入巴西北部和内格罗河以东地区。可能也在哥伦比亚极东部有分布，但在巴西马瑙斯附近非常常见。","other":"黑䴕在20世纪中叶被描述为圭亚那内陆最丰富的非群居森林鸟类之一，同时在海岸森林和草原地区也很常见。"},{"name":"黑额黑䴕","english_name":"Black-fronted Nunbird","scientific_name":"Monasa nigrifrons","overview":"黑额黑䴕（英文名：Black-fronted Nunbird，学名：Monasa nigrifrons），是䴕形目蓬头䴕科黑䴕属的鸟类。分布于南美洲的亚马逊盆地，包括哥伦比亚、厄瓜多尔、秘鲁和巴西，以及玻利维亚东部。偏好河流与湖泊边缘的森林地带。","appearance":"成鸟体长26至29厘米，体重68至98克。全身呈深灰黑色，头部颜色最深，身体后部为蓝灰色，尾巴蓝黑色。拥有醒目的红色喙，眼色深邃，腿为黑色。亚种canescens比指名亚种稍淡和灰。幼鸟为污浊的石板灰色，带有不规则的红褐色斑点。","call":"其鸣唱为一连串快速上扬的悦耳‘clerry’或‘curry’哨音，偶尔穿插下降的‘turra turra’颤音，通常以群体合唱形式呈现，持续数分钟。","habits":"栖息于亚马逊低地的河岸树、竹林、次生林、沼泽河岛、过渡森林及成熟的洪泛平原森林。主要捕食飞行中的昆虫，也会从地面和植被中觅食，食物包括节肢动物、小型蜥蜴和两栖动物。经常跟随猴群和行军蚁群，捕获被它们惊扰的猎物，有时加入混杂物种的觅食群。","breeding":"繁殖季节在4月至10月之间，具体时间因地理位置而异。在斜坡或平地的河岸挖掘洞穴筑巢，巢深可达约1米。每窝产三枚卵，孵化和雏鸟成长期尚未记录。","identification":"与白额黑䴕相比，黑额黑䴕具有黑色面部，常见于较年轻的森林和森林边缘而非成熟森林。","protection":"IUCN：LC（无危）","distribution":"分布于亚马逊盆地，包括哥伦比亚东南部、厄瓜多尔东部、秘鲁东部以及巴西大部分地区，向北延伸至亚马逊河以北直至里奥内格罗，向南至帕拉和阿拉戈斯州，再向南至马托格罗索州东部和圣保罗州西部。在玻利维亚仅限于东部。"},{"name":"白额黑䴕","english_name":"White-fronted Nunbird","scientific_name":"Monasa morphoeus","overview":"白额黑䴕（英文名：White-fronted Nunbird，学名：Monasa morphoeus），是䴕形目蓬头䴕科黑䴕属的鸟类。主要分布在中美洲至南美洲亚马逊雨林区域，从洪都拉斯至巴西东南部。具有独特的白色前额和下巴，橙红色的喙，全身呈暗灰黑色，下部稍显灰色。体重介于63-101克之间，长度在21-29厘米。常见于森林地带，偶尔出现在森林边缘或开阔地带。","appearance":"成年白额黑䴕体型较大，头部扁平，站立姿态挺拔。头部最显著的特征是白色的前额和下巴，喙部鲜亮的橙红色。性别间外观相似。幼鸟脸部呈现淡黄褐色，羽毛带棕色边缘，翼覆羽和体羽色调较暗。亚种在体型、羽毛颜色深浅及面部白色区域大小上有所差异。","call":"拥有多种多样的鸣叫声，包括模糊下降的哨音，带有短促的颤音“peeeur-r-r-r-r”，响亮而哀伤的‘how how how’，以及各种颤音、咕噜声和咔哒声。群体合唱时会发出响亮的咯咯声和吠叫声，持续时间可达20分钟，通常在一天的开始和结束时发生。","habits":"栖息于高大的湿润低地森林、山地雨林、树倒空隙、河滩边高树、画廊森林和成熟泛滥平原森林。活动范围低于300米，但在特定地区可高达1350米。主要以昆虫为食，包括蟋蟀、甲虫、蝉、蜘蛛、蜈蚣、蝎子、蛙类和小型蜥蜴，也吃果实。跟随蚂蚁群、猴子群落和鸟类群落觅食。","breeding":"繁殖季节在哥斯达黎加为12月至5月，在哥伦比亚为2月至5月。筑巢于地面斜坡或水平地面上的隧道末端，隧道长80-140厘米，宽约8厘米，巢室以树叶衬垫。每窝产卵2-3枚，由3-6只成鸟照料。","identification":"与黑额黑䴕的区别在于前额和下巴白色，体羽更显灰色，喙部更偏橙红色。亚种间存在大小、羽毛颜色深浅和面部白色面积的差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的洪都拉斯至南美洲亚马逊雨林区域，包括巴西东南部。常见于低海拔森林地带，最高可达1350米。","other":"白额黑䴕曾被分为多个物种，现已统一视为一个物种的多个亚种。"},{"name":"黄嘴黑䴕","english_name":"Yellow-billed Nunbird","scientific_name":"Monasa flavirostris","overview":"黄嘴黑䴕（英文名：Yellow-billed Nunbird，学名：Monasa flavirostris），是䴕形目蓬头䴕科黑䴕属的鸟类。分布于南美的亚马逊盆地，包括哥伦比亚东南部、厄瓜多尔东部、秘鲁北部、玻利维亚北部和巴西西部，直至普鲁斯河东岸。其显著特征为黄色的喙和肩部的白色斑块。","appearance":"黄嘴黑䴕整体呈煤黑色，翼下覆羽主要为白色，形成明显的肩部斑点，下腹部颜色较暗，接近深灰色。翅膀下覆羽白色，腋下和飞羽基部灰褐色，尾部长而略呈梯形，尾羽狭窄，颜色为绿黑色。喙黄色，比同属其他物种的喙短。虹膜深色，脚黑色。幼鸟比成鸟颜色稍淡，白色部位略显污浊。","call":"其鸣唱由完整的旋律长句组成，通常包含反复的“wheekit-wheeyk, wheekit-wheeyk...”的合唱。","habits":"黄嘴黑䴕主要栖息于亚马逊盆地的森林地带，偏好森林边缘和藤本植物密集区，也会在竹林中活动，尤其在高处的竹林上方的突出树木上停歇。它们通常以小群体形式觅食，主要食物为昆虫。","identification":"黄嘴黑䴕以其黄色的喙和白色的肩部斑点与同属其他物种明显区分。","protection":"IUCN：LC（无危）","distribution":"黄嘴黑䴕分布在南美洲亚马逊雨林西部，包括哥伦比亚东南部、厄瓜多尔东部、秘鲁、玻利维亚北部以及巴西西部至普鲁斯河东岸。"},{"name":"燕翅䴕","english_name":"Swallow-winged Puffbird","scientific_name":"Chelidoptera tenebrosa","overview":"燕翅䴕（英文名：Swallow-winged Puffbird，学名：Chelidoptera tenebrosa），是䴕形目蓬头䴕科燕翅䴕属的鸟类。分布于南美洲亚马逊盆地至安第斯山脉的山脚，以及巴西中部，其分布区还包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。","appearance":"该物种长度约14至15厘米，体重介于30至41.5克之间。全身大致呈炭黑色，带有部分蓝色金属光泽；背部下方至尾上覆羽为白色；翅膀细长尖锐，尾巴短小且黑色，新羽时尾羽尖端带白色，但很快磨损。下巴呈白色，喉咙灰色，胸前部炭黑渐变为灰色，腹部橙栗色。喙、眼、脚均为深色。","call":"发出类似啾啾声的歌唱，常在飞行中发出；叫声包括“tsi-tsi-tsi”和高音清脆的‘dí-didi dí-didi dí-didi…’。","habits":"偏好沙质土壤上的开阔地带，周围散落着灌木丛，同时也见于树和灌木草原、森林边缘、次生林、落叶林、河岸植被、湖泊边缘树木等环境。低地为主，高度低于1000米，偶尔可达1750米。以空中捕食缓慢飞行的小到中型昆虫为食，如膜翅目、鞘翅目、半翅目、直翅目、等翅目、双翅目昆虫。","breeding":"筑巢于倾斜的沙土中挖凿的隧道内，通常位于平坦的沙滩或土坡上，靠近河流。产卵1至2枚白色蛋，尺寸约为23.5毫米×20毫米，孵化期15天，离巢时间未详。","identification":"成鸟与幼鸟相似，但亚种间存在差异，如C. t. brasiliensis体型较大，下体有白色带纹，C. t. pallida下体较淡，具明显白色带纹。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲亚马逊盆地，包括委内瑞拉西北部、巴西东部、亚马逊雨林区域。在巴西，常见于亚马逊州、帕拉州和马托格罗索州；在秘鲁、玻利维亚、厄瓜多尔等地也有分布。","other":"人类活动如开辟牧场和道路建设可能对其有利，使其数量似乎在增加。"},{"name":"红顶拟啄木鸟","english_name":"Scarlet-crowned Barbet","scientific_name":"Capito aurovirens","overview":"红顶拟啄木鸟（英文名：Scarlet-crowned Barbet，学名：Capito aurovirens），是䴕形目须䴕科须䴕属的鸟类。广泛分布在南美洲的亚马逊雨林西部，从哥伦比亚南部的安第斯山麓延伸至巴西西北部的黑河、秘鲁中部的特费河和巴西中西部的阿克雷。这种鸟以其鲜明的红顶和橙黄色胸羽而著称，雄鸟红冠至颈背，雌鸟则以白色冠羽替代红冠，向后逐渐变为橄榄色。","appearance":"体长约19厘米，体重介于46至75克之间。整体呈绿橄榄色，拥有粗壮的喙。雄鸟头部顶部至颈背为红色，雌鸟的头部顶部则为白色，逐渐转变为橄榄色。喉咙至胸部为橙黄色，下体橄榄色，带有灰色和黄色。幼鸟色彩较暗淡，喉部黄色，冠羽颜色随性别而异，雄鸟有红斑，雌鸟为白色。","call":"发出一系列低沉的‘ttroup’或‘ttdoot’音符，类似青蛙或蟾蜍的叫声，部分音符更为嘶哑，以约每秒1.75次的速度持续可达9秒。两性会一起唱歌，一者节奏缓慢，音调嘶哑，另一者则更快更清晰。此外，还发出较快、短促、颤音‘twot-twot-’，每秒3至4个音符。","habits":"栖息于季节性洪水泛滥的瓦尔泽亚森林、泛滥平原低矮森林、森林沼泽、森林向旱地森林过渡地带以及次生森林，利用森林所有层次，从地面到树冠。偏好靠近水源的环境，海拔高度在低地至安第斯山脉山脚的500至600米间。以浆果、果实和少量昆虫为食，具体细节未知；偶尔加入混合物种觅食群。","breeding":"繁殖期在哥伦比亚和厄瓜多尔为1月至5月，在秘鲁为7月至8月，也可能从12月开始在巴西。有反唱行为，歌手在发声时抖动翅膀，向下指向喙，头部左右转动。巢穴、卵和其他繁殖数据尚未描述。在圈养条件下，寿命超过5年。","identification":"红顶拟啄木鸟的红顶和橙黄胸羽使其在同类中独具特色，雄鸟与雌鸟在冠羽颜色上明显不同，雌鸟头部顶部为白色，而非红色。幼鸟相比成鸟色彩较为暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于亚马逊盆地的中心区域，从哥伦比亚南部的安第斯山麓，穿过厄瓜多尔东部至秘鲁东中部，向东和向南延伸至巴西西北部的黑河、巴西中部的特费河上游和巴西中西部的阿克雷。","other":"红顶拟啄木鸟适应了不断变化的栖息地类型，包括许多未受干扰的河流岛屿。在多个保护区如库亚贝诺保护区（Ecuador）中存在。"},{"name":"红领须啄木鸟","english_name":"Scarlet-banded Barbet","scientific_name":"Capito wallacei","overview":"红领须啄木鸟（英文名：Scarlet-banded Barbet，学名：Capito wallacei），是䴕形目须䴕科须䴕属的鸟类。色彩鲜艳、仅分布于秘鲁中北部安第斯山脉以东偏远山区的云林鸟。其显著特征为红色冠羽和胸部环带，白色喉部，以及黄色胁部。通常成对或小群体活动，以森林树冠层的果实为食。","appearance":"体长约19.5厘米，体重65至78克。雄鸟具红色头冠，延伸至背部中间，白色眼上纹，黑色额纹，黑带穿过眼睛至颈部侧面；颈侧下方、喉部至胸部上部白色，宽阔的红色胸部环带，下胸至腹部金色至黄色，侧翼混合橄榄色、橙色或红色。雌鸟与雄鸟相似，但眼下方有白色斑点，肩羽外缘有黄白色条纹。幼鸟未知。","call":"鸣声为低沉的快速颤音，持续约两秒，类似远处啄木鸟的快速敲击声；亦发出粗糙的‘ggrrrakk’叫声。","habits":"栖息于湿润的苔藓覆盖的亚山地和山地森林，海拔1350至1500米。常在树冠层觅食，加入混群觅食队伍，以果实和种子为主食，可能也摄食昆虫。","breeding":"繁殖季节可能为3月至5月，但具体繁殖习性细节尚未公布。","identification":"与红领须啄木鸟相比，具有更深的喙，平均体型略大，侧翼颜色差异明显，黑色大腿羽毛尖端少有黄色，胸带更宽。雌鸟在外覆肩羽上有红色羽毛尖端，不同于其他须啄木鸟。","protection":"IUCN：VU（易危）","distribution":"仅限秘鲁中北部，已知分布于Contamana西北的孤立低高原，Huallaga河和Ucayali河之间，以及南塞罗斯德尔西拉（Ucayali）的东坡。","other":"1996年首次发现，2000年正式描述。'希拉须啄木鸟'曾被认为是其亚种，但现在被认为应视为独立物种。"},{"name":"希拉须啄木鸟","english_name":"Sira Barbet","scientific_name":"Capito fitzpatricki","overview":"希拉须啄木鸟（英文名：Sira Barbet，学名：Capito fitzpatricki），是䴕形目须䴕科须䴕属的鸟类。于2008年在秘鲁中部的Cerros del Sira山脉被发现。以鲜明的红色头部和胸部、灰白色的腹部以及独特的叫声而著称，被认为是红纹须鴷的姐妹种。","appearance":"成年希拉须啄木鸟体长约19.5至20厘米，体重介于70到79克之间。雄鸟的冠部和颈背为鲜亮的红色，肩部有一条较宽的白色带，延伸至尾部逐渐变窄。上半身其余部分为黑色，眼眉白色且宽阔，面部、喉咙、颈部和上胸部为白色。胸前有一条宽阔的红色带，沿侧腹延伸，与不同程度的黑色或灰色相接。下半身为白色。雌鸟的羽毛与雄鸟相似，但存在细微差异。其与红纹须鴷的区别在于体型、羽毛颜色，尤其是侧腹、下背部和大腿的颜色，以及更宽、更深的红色胸带。","call":"希拉须啄木鸟的鸣唱低沉而带有摩擦声，通常会发出类似Tityra的哼鸣声。它还会从栖息的洞穴中发出低沉的呻吟和咕哝声。","habits":"希拉须啄木鸟主要栖息于高大的山地森林顶层，那里生长着高达30米的树木，树上覆盖着附生植物和苔藓，林下植被稀疏。它们也出现在植被较为密集的较矮森林中。活动范围海拔高度可达1700米，但多数情况下位于950至1250米之间。这种鸟在森林树冠层和次冠层觅食，常被观察到成对或小群体活动，也会加入多种鸟类的觅食群。它们主要以果实为食，偶尔也会捕食少量昆虫。","breeding":"关于希拉须啄木鸟的繁殖信息尚未发表。","identification":"希拉须啄木鸟与红领须啄木鸟在形态和羽毛上有显著区别，特别是在侧腹、下背部和大腿的色彩上，以及更为宽阔和深色的红色胸带。DNA测序也证实了希拉须啄木鸟作为一个独立物种的地位。","protection":"IUCN：NT（近危）","distribution":"希拉须啄木鸟仅分布于秘鲁中部的Cerros del Sira山脉东坡，具体地点包括Río Shinipo和Río Tzipani河谷，以及Quebrada Quirapokiari地区。","other":"希拉须啄木鸟的种加词是为了纪念秘鲁鸟类专家John W. Fitzpatrick，同时也是Cornell Lab of Ornithology的主任。"},{"name":"斑冠拟啄木鸟","english_name":"Spot-crowned Barbet","scientific_name":"Capito maculicoronatus","overview":"斑冠拟啄木鸟（英文名：Spot-crowned Barbet，学名：Capito maculicoronatus），是䴕形目须䴕科须䴕属的鸟类。主要分布于中美洲至南美洲，具体包括巴拿马和哥伦比亚西北部的低地森林中。","appearance":"体长约16至18厘米，体重约44至66克，体形粗壮，具厚实的喙。雄鸟头顶有棕色与白色相间的斑点，上体黑色，喉部白色，上胸黄色至橙色，下胸和腹部白色带黑色斑点，侧翼有黄橙色斑块。雌鸟头部和胸部全黑。幼鸟颜色较暗淡。","call":"发出一系列刺耳的“kkaaak”音符，逐渐变为“kkkaakkk”声音，有时音符成双或成三，类似清喉咙声，有时两只鸟，可能是配偶，一起歌唱，一只发出典型缓慢歌曲，另一只使用柔和的“kk-ggkkk”声音。","habits":"栖息于低地森林的树冠层，偶尔在次生林中发现。以各种浆果、水果和昆虫为食，如蚱蜢。有时跟随行军蚁群，捕食逃离的昆虫。通常成对或小群体活动，最多可达10只，在果实丰富的树木上聚集。","breeding":"繁殖季节从12月至次年4月，3月在哥伦比亚和2月在巴拿马开始筑巢。已观察到由一只雄鸟和两只雌鸟照料的巢穴。雏鸟在6月初离巢。","identification":"与橙额拟啄木鸟相似，但可通过头顶的斑点和喉部颜色区分。雌雄之间主要通过头部和胸部的颜色差异辨识。","protection":"IUCN：LC（无危）","distribution":"繁殖区域与非繁殖区域均在中美洲的巴拿马和南美洲的哥伦比亚西北部。","other":"存在两个亚种，指名亚种C. maculicoronatus maculicoronatus和C. m. rubrilateralis，后者具有更多的白色冠羽和更红的侧翼标记。"},{"name":"橙额拟啄木鸟","english_name":"Orange-fronted Barbet","scientific_name":"Capito squamatus","overview":"橙额拟啄木鸟（英文名：Orange-fronted Barbet，学名：Capito squamatus），是䴕形目须䴕科须䴕属的鸟类。体型健壮，黑白相间，头部特征明显，橙色前额和白色冠羽是其显著标志。主要分布于南美洲哥伦比亚西南部及厄瓜多尔西部的低地和山麓雨林。","appearance":"橙额拟啄木鸟体长约16至18厘米，体重介于56至64克之间。雄鸟具有橙红到红色的前额斑块，白色冠羽，上体黑色，翼羽可见白色条纹，下体从下巴至腹部为黄白色，有时带橙色调，两胁有轻黑斑点，下腹至臀部黑色。雌鸟前额为黄橙色，头部、喉部和胸部为黑色，背部黑色并有细白纹。幼鸟色彩较暗淡。","call":"鸣唱为低沉、快速、柔和的嗡嗡颤音，持续约4秒；叫声为嘈杂的单声或多声“tyik”或“trrik”。在警戒状态或对抗蛇类时会发出一连串叫声。","habits":"栖息于湿热的低地和丘陵地带，常在原始森林、次生林及其边缘，以及农场、果园和树丛覆盖的开阔地带活动。以水果和浆果为主食，包括Cecropia物种和Castilla elastica，同时也会捕食甲虫和其他昆虫。通常成对觅食，会在植被的所有层次活动，加入混合物种觅食群。","breeding":"繁殖季节为7月至9月，可能更早。雄鸟会轮流在雌鸟附近歌唱。巢穴位于树木高处，由一对成鸟挖掘，曾报道在一棵4米高的死树上的一个可能的树洞中发现巢穴。已知的一对圈养鸟最多能养育4只幼鸟。","identification":"雄性橙额拟啄木鸟可通过白色下体、冠羽和颈背与五色拟啄木鸟区分开来。雌鸟背部有细白纹，喉部和胸部为黑色。","protection":"IUCN：LC（无危）。虽然其种群数量正在减少，估计数量在37,000至63,000之间，但因其分布范围广泛，目前未受全球威胁。","distribution":"分布于南美洲，具体包括厄瓜多尔的El Oro省向北延伸至哥伦比亚西南部的Nariño省。在海拔高度上，常见于海平面至800米（2,600英尺）之间，部分地区可达1,500米（4,900英尺）。","other":"属于限制范围物种，出现在Chocó EBA区域内。在小范围内，尽管面临森林破坏和人类殖民的压力，但似乎具有一定的适应能力，能在非森林环境中生存。"},{"name":"白背拟啄木鸟","english_name":"White-mantled Barbet","scientific_name":"Capito hypoleucus","overview":"白背拟啄木鸟（英文名：White-mantled Barbet，学名：Capito hypoleucus），是䴕形目须䴕科须䴕属的鸟类。特有于哥伦比亚北部，以其独特的黑白色调羽毛和强壮的喙闻名。通常成对活动，常在混合物种群中觅食。","appearance":"成年白背拟啄木鸟约18至19厘米长，雄鸟平均重74.6克，雌鸟平均重67.4克。上体黑色，具白色颈背和倒置的白色\"V\"字形斑纹，下体白色微带黄色，胸部有一淡褐色带。雄鸟额部和头顶红色，雌鸟下颌基部有黑色斑点。","call":"鸣唱由15至30个\"hoop\"音符组成，节奏逐渐加快，持续3至5秒。叫声为粗糙的\"drrrurtt\"，类似橙额拟啄木鸟的叫声，还有\"kek-ek\"和\"tteeaw\"的喋喋声。","habits":"栖息于海拔700至1600米的热带湿润山地森林、森林碎片、次生林、果园和咖啡种植园。主要以浆果、水果和昆虫为食，常在树冠层活动，偶尔下到开放地带的果树上觅食。","breeding":"繁殖期可能为4月至9月，已知会在4月底照料巢穴，5月开始换羽。筑巢、产卵等繁殖细节尚待研究。","identification":"与同属其他种类的区别在于喙色。雌鸟在白色颊区前部有黑色斑点。种族差异较小，carrikeri的背部和下体白色中带有更多黄色，extinctus的胸带略呈棕色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲哥伦比亚西北部的中马格达莱纳河谷，海拔200至1800米。","other":"由于栖息地丧失，其种群数量正在下降，被列为易危物种。"},{"name":"黑环拟啄木鸟","english_name":"Black-girdled Barbet","scientific_name":"Capito dayi","overview":"黑环拟啄木鸟（英文名：Black-girdled Barbet，学名：Capito dayi），是䴕形目须䴕科须䴕属的鸟类。在南美洲亚马逊雨林南部广泛分布的鸟类。其最显著的特征是黑色的腹部带纹，雄鸟头部顶冠鲜红，雌鸟则为黑色。体长约18厘米，体重介于56至74克之间。","appearance":"成年雄性黑环拟啄木鸟的头顶和颈背呈现鲜亮的红色，头部两侧黑色，背部除肩羽为白色或黄白色斑点外，其余部分黑色。下体上部白色或浅白色，逐渐过渡至淡黄绿色的腹部。两性相似，但雌鸟的顶冠和颈背为黑色。幼鸟整体较为暗淡，下体更白，背部的黑色较暗，尾下覆羽的红色较淡，且带有黄色条纹。","call":"黑环拟啄木鸟的鸣唱是一系列低沉而空洞的‘hooo’音符，逐渐加速至结尾，类似某些蚁鵙的歌声。","habits":"栖息于湿润森林的树冠层，包括森林边缘，常在果树林中出现。它通常伴随混合物种群，以水果为食，也会在卷曲的枯叶中寻找无脊椎动物。","breeding":"关于繁殖行为知之甚少，但已知主要繁殖期在8月至11月间，也可能在2月和6月繁殖。推测会在树洞中筑巢，但具体的巢穴和蛋尚未被描述。","identification":"黑环拟啄木鸟的黑白相间的羽毛在亚马逊地区的须䴕科中独一无二。与它相似的其他黑白色Capito属物种仅分布在南美洲西北部，且均不具备黑环拟啄木鸟特有的黑色腹部带纹。","protection":"IUCN：NT（近危）","distribution":"主要分布在南美亚马逊雨林的南部，具体包括巴西东南部的亚马逊州、帕拉州的大部分地区、马托格罗索州的西北半部以及朗多尼亚州东部，其分布略延伸至玻利维亚东北部的圣克鲁斯省。"},{"name":"棕胸拟啄木鸟","english_name":"Brown-chested Barbet","scientific_name":"Capito brunneipectus","overview":"棕胸拟啄木鸟（英文名：Brown-chested Barbet，学名：Capito brunneipectus），是䴕形目须䴕科须䴕属的鸟类。新世界特有的拟啄木鸟。体型中等，长约18厘米，雄鸟体重约58克。主要分布于巴西中央亚马逊盆地的低地湿润森林，常在树冠层活动。","appearance":"该鸟体态圆胖，喙部粗壮。雄鸟头部顶部呈暗金色，眼下方有一大片黑色斑纹；背部黑色，带有黄色线条；喉咙为黄白色，胸部有一圈肉桂色的带纹，腹部橄榄黄至黄色，有淡色条纹。雌鸟颜色较雄鸟暗淡，翅膀上黄色斑纹较多，喉咙处为黑点状的肉桂色。幼鸟特征尚未详细描述。","call":"发出极快速的一系列深沉‘呼’音组成的颤音，每秒由大约20个音符加速到40个，结尾时发出‘布噜噜噜噜’的声音。其叫声与Eubucco和红领须啄木鸟类似。","habits":"栖息于低地湿润森林，偏好树冠环境。以昆虫和其他节肢动物为主食，偶尔食用果实。通过攀爬藤蔓、跳跃于树枝和细枝上觅食。常加入多种鸟类混群觅食。","breeding":"繁殖季节可能从3月持续到6月，具体繁殖生态细节尚未公布。","identification":"与红喉拟啄木鸟和金胸拟啄木鸟在形态上有相似之处，但通过其独特的肉桂色胸部带纹和鸣叫声可以区分。","protection":"IUCN：LC（无危）。然而，其小范围分布和对其栖息地需求及繁殖习惯的未知，建议监测其种群动态，可能需要重新评估其保护状态。","distribution":"分布于南美洲巴西中北部，位于亚马逊河以南，介于马德拉河与塔帕若斯河之间，确切的南部界限未知。","other":"曾被认为与黑斑拟啄木鸟和金拟啄木鸟为同一物种，现已确认为独立种类。"},{"name":"红喉拟啄木鸟","english_name":"Black-spotted Barbet","scientific_name":"Capito niger","overview":"红喉拟啄木鸟（英文名：Black-spotted Barbet，学名：Capito niger），是䴕形目须䴕科须䴕属的鸟类。主要分布在南美洲亚马逊雨林东北部，包括巴西、圭亚那和委内瑞拉。以鲜明的红喉特征著称，广泛见于各种森林类型，从低地到山地森林。","appearance":"成年雄鸟长约16至19厘米，重41至68克。头部色彩丰富，额头红色，冠部和颈背黄色，具黑色带纹延伸至颈侧。上体黑色，肩羽边缘黄色，翼上有淡黄色条纹。喉部红色，胸部和腹部黄色，两胁橄榄色带黑斑。雌鸟类似，但标记更明显，上体具淡色斑点，下体斑点或条纹更重。幼鸟颜色较暗淡。","call":"其叫声为低沉的双重音‘wú-woot’，有时单发，重复成系列，持续20至40秒，节奏逐渐增强。","habits":"栖息于多种森林环境中，包括低地和低山森林，有时在城市区域出现。常成对出现，或加入混合物种群。以果实和昆虫为食，缓慢而有目的性地觅食。","breeding":"繁殖期从9月至次年5月，有时延续至7月。在树洞中筑巢，高5至12米，通常产3至4枚白色卵，由双亲共同孵化。雏鸟约34天离巢，之后仍可能被父母喂养3周左右。","identification":"与金胸拟啄木鸟相比，红喉拟啄木鸟具有更为明显的红色喉部，且雌鸟的标记更加显著。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉东部、圭亚那三国和巴西北部罗赖马州、帕拉州及阿马帕州的亚马逊河以北地区。","other":"曾被认为是金胸拟啄木鸟的一个亚种，现已确认为独立物种。"},{"name":"金胸拟啄木鸟","english_name":"Gilded Barbet","scientific_name":"Capito auratus","overview":"金胸拟啄木鸟（英文名：Gilded Barbet，学名：Capito auratus），是䴕形目须䴕科须䴕属的鸟类。属于须䴕科须䴕属，体型较大、色彩鲜明的鸟类。其最显著的特征是变化多端的喉部和胸部颜色，从黄色到红色不等，其余部分则为黄黑相间的斑纹。该鸟种广泛分布于南美洲低地热带雨林，包括亚马逊盆地和奥里诺科河流域。","appearance":"成年金胸拟啄木鸟体长约16至19厘米，体重介于47.5至77克之间。雄鸟具棕色金冠，黑色头部两侧和背部，黄色眉纹延伸至肩胛骨形成V字形标记，翼上有黄色斑点，尾羽尖端黄色，下背部和臀部橄榄黄色条纹，喉咙橙色，其余下体黄色，胸部两侧和胁部带有黑色斑点。雌鸟羽毛斑点更密集，上体淡色斑点边缘较多，下体斑点或条纹更为明显。幼鸟比雌鸟暗淡，斑点更多呈条纹状，头部颜色偏橙，喙灰色，眼睛灰至褐色。","call":"发出一系列双音节的低沉蛙鸣声“oo-doot”，强调每对音符的第二个音节，有时单个音节，持续时间5至60秒不等，通常6至20秒，声音类似亚马逊翠鴗的叫声，可能与黄喉拟啄木鸟的较高音调双音节鸣叫混淆。","habits":"栖息于低地和低山洪水森林、高地森林、河流森林、次生林、林缘、开阔地带和花园种植园，海拔高度可达1700米。以多样水果为主食，如无花果、芒果等，占饮食的80%，同时摄取昆虫如蚱蜢、蜘蛛，比例可达18%。常单独或成对活动，偶尔聚集于果实丰富的树上，加入混群觅食，与多种飞禽共同活动。","breeding":"繁殖季节从9月至次年5月或更晚至7月，哥伦比亚和厄瓜多尔为3月至11月，秘鲁至玻利维亚为6月至翌年2月。在咖啡种植园的遮阴树中发现筑巢。繁殖生态与近缘物种相似，但具体细节仍不详。","identification":"与红喉拟啄木鸟相似，但可通过喉部颜色和头部花纹区分，尤其是雌性金胸拟啄木鸟具有明显的黄色翼覆羽边缘和黄色耳羽斑点。不同亚种在喉部和头部颜色上有差异。","protection":"IUCN：LC（无危）。在部分地区常见，如秘鲁成熟森林中每100公顷有10.5对，过渡森林中15对，晚期河畔生境中高达20对。对森林生态系统具有重要作用，其洞穴被其他物种利用。","distribution":"分布于南美洲北部和西部的亚马逊雨林区域，包括巴西、哥伦比亚、委内瑞拉、厄瓜多尔、秘鲁和玻利维亚，主要栖息于奥里诺科河盆地和亚马逊盆地的低地森林。","other":"金胸拟啄木鸟在历史上曾被视为红喉拟啄木鸟的亚种，但现已独立为一物种。"},{"name":"五色拟啄木鸟","english_name":"Five-colored Barbet","scientific_name":"Capito quinticolor","overview":"五色拟啄木鸟（英文名：Five-colored Barbet，学名：Capito quinticolor），是䴕形目须䴕科须䴕属的鸟类。分布于南美洲的哥伦比亚西部至厄瓜多尔西北部低地雨林地带。雄鸟头部红色，背部黑色夹杂黄色，腹部金橙色，雌鸟则以黑色为主，带有金色条纹。","appearance":"成年五色拟啄木鸟体长17至18厘米，体重介于54至69克之间。雄鸟上身黑色，肩部有黄色V形斑，翼上有黄色条纹，冠羽鲜红，腹部从黄色渐变为金橙色，两侧有黑色斑点。雌鸟上体黑色，头部、耳羽和翼覆羽密集条纹，腹部颜色与雄鸟相似，但全身遍布黑色斑点。","call":"雄鸟会发出一系列低沉空洞的‘呼’音，每秒约1.5个音符，同时身体前倾，仿佛在呕吐。此外，还会发出一种粗犷的‘churr’叫声。","habits":"栖息于低地湿润森林、森林边缘及次生林，通常在海拔350米以下，局部可达600米。以果实为主食，兼食昆虫，觅食于树冠至中层，偶尔加入混群觅食队伍，穿梭于枝叶间。","breeding":"繁殖生态知之甚少，推测繁殖季节为4月至7月。曾见于成对或三鸟群，雄鸟在求偶时会低头、鼓喉、摇尾。一例报道中，一对五色拟啄木鸟在近溪流的老啄木鸟洞中孵卵。","identification":"雄鸟与雌鸟在色彩上有明显差异，雌鸟的条纹更显眼，且全身遍布黑色斑点。与白背拟啄木鸟和黑环拟啄木鸟在形态上有显著区别。","protection":"IUCN：NT（近危）","distribution":"分布于哥伦比亚西部，自乔科省向南延伸至厄瓜多尔最北西部省份埃斯梅拉达斯，主要栖息于低地湿润的原始和成熟次生林。","other":"尽管栖息地有限，五色拟啄木鸟也能适应次生林环境，显示其对未受干扰生境并非绝对依赖。"},{"name":"黄喉拟啄木鸟","english_name":"Lemon-throated Barbet","scientific_name":"Eubucco richardsoni","overview":"黄喉拟啄木鸟（英文名：Lemon-throated Barbet，学名：Eubucco richardsoni），是䴕形目须䴕科黄嘴须䴕属的鸟类。广泛分布于南美洲的亚马孙雨林西部，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔和秘鲁等地。其显著特征为雄鸟个体的红色冠羽和明亮的黄色喉部，而雌鸟则色彩较暗淡。","appearance":"成年黄喉拟啄木鸟长约15.5厘米，体重介于24.5至34克之间。雄鸟具有鲜亮的红冠，灰蓝色颈背，绿色上体，黄色喉部，橙红色胸部，腹部和两翼则带有绿色条纹。雌鸟颜色较雄鸟更为暗淡，头部呈现灰绿色，喉部为蓝灰色，胸部为橙金色，下体则带有深色条纹。幼鸟羽毛较为松散，颜色更暗淡，但仍显示出性别特征，雄鸟的前额有红色，雌鸟则在头部两侧有金色斑点。","call":"黄喉拟啄木鸟的鸣唱由柔和的双重或三重'hoo'音符组成，形成快速、类似颤音的系列，节奏快似马蹄声，每秒约4个复合音符，持续1.5至5秒。此外，它们还会发出各种哼哼和咆哮声。","habits":"主要栖息于低地森林、次生林、森林边缘和开阔地带，偶尔也会出现在热带山地森林中，高度可达1375米。它们偏好靠近河流和湖泊的成熟森林边缘地带。以水果和昆虫为主食，常加入混合物种觅食群。在觅食时，通常单独或成对活动，高度从树冠到离地面5米处都有可能。","breeding":"繁殖季节大约从2月或4月至11月。雄鸟会在树冠中反向鸣唱，每次约7首歌，每分钟可达7首。巢穴和蛋的细节尚未被描述。领域范围约为10公顷。关于繁殖行为的更多信息尚待研究。","identification":"与红头拟啄木鸟部分共域，但通过一系列特征易于区分，包括雄鸟的红色冠羽、蓝色颈背和绿色上体，以及雌鸟的灰绿色头部和橙金色胸部。不同亚种间也存在差异，如E. r. nigriceps雄鸟的黑色冠羽和蓝绿色背部。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲的亚马孙雨林西部，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔和秘鲁等地。在哥伦比亚可达海拔1375米，秘鲁则通常低于1000米。","other":"在多个保护区如Cuyabeno Faunal Reserve（厄瓜多尔）和Jaú National Park（巴西）中均有发现。"},{"name":"红头拟啄木鸟","english_name":"Red-headed Barbet","scientific_name":"Eubucco bourcierii","overview":"红头拟啄木鸟（英文名：Red-headed Barbet，学名：Eubucco bourcierii），是䴕形目须䴕科黄嘴须䴕属的鸟类。以其鲜艳的色彩著称，分布于中美洲至南美洲，包括哥斯达黎加至厄瓜多尔一带的山地森林中。","appearance":"雄鸟头部鲜红，背部绿色，腹部黄色，喙部粗壮呈黄色，具圆润体型，大头短尾。雌鸟与部分南美巴贝特相似，但其头部图案独特：蓝颊，橙色颈侧，黑色前额。雌鸟脸颊呈淡蓝色，颈后有金色项圈，喉部灰黄色，下有橙色带，腹部白色，两侧和下部橄榄黄色。雄鸟翼展平均71.3毫米，尾长平均49.9毫米，喙长平均19.2毫米，跗跖长平均20.4毫米；雌鸟相应数据略小。","call":"其鸣唱为响亮的喉音颤音，类似蛙鸣，具有回声效果，易于辨认。","habits":"常以成对形式出现，活跃于森林树冠层的混合群中，偶尔造访水果喂食器。主要食物为果实，亦会捕食昆虫和其他节肢动物，有时通过搜寻枯叶堆寻找食物。","breeding":"繁殖期未详，筑巢于树洞或腐朽树木自挖的洞穴中，窝卵数通常为2到5枚，雌鸟夜间孵卵，日间由双亲共同承担。","identification":"雄性红头拟啄木鸟的头部和前颈红色鲜明，雌鸟头部颜色多样，从暗橙到绿色不等，且有黑色前额和蓝颊，与雌性黄喉拟啄木鸟和雄性红巾拟啄木鸟存在差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，具体包括哥斯达黎加至厄瓜多尔的山地森林区域，海拔范围从400米至2400米。"},{"name":"红巾拟啄木鸟","english_name":"Scarlet-hooded Barbet","scientific_name":"Eubucco tucinkae","overview":"红巾拟啄木鸟（英文名：Scarlet-hooded Barbet，学名：Eubucco tucinkae），是䴕形目须䴕科黄嘴须䴕属的鸟类。色彩鲜艳的鸟类，分布于南美洲亚马逊盆地的东部秘鲁、西部巴西及西部玻利维亚交汇地带，主要栖息于河流附近。","appearance":"体长约17厘米，体重40至44克。雄鸟头部、喉咙及上背部为红色，眼周及喙部周围有黑色斑点，其余上体呈绿色，下胸橙黄色，侧身有一灰色斑块，两胁橄榄色条纹。雌鸟喉部黄色，上胸部具橙色带，其余部位与雄鸟相似。幼鸟特征未详述。","call":"鸣声为快速连续的'oop-oop-oop-'系列音符，每秒约6.5至7个音符，持续2至4秒，与非洲的斑胁拟啄木鸟类似，比黄喉拟啄木鸟的鸣声更快，有时每分钟可达5首歌。","habits":"偏好居住在距离河流和牛轭湖约150米内的竹林和Heliconia丛中，栖息于树下层密林，海拔高度从约150米到偶尔高达850米以上。以各种果实为主食，约占饮食的60%，包括无花果、Coussapoa、Cecropia、Psychotria等，以及Lauraceae科植物；也食用Inga、Quararibea、Combretum的花朵或花蜜，及多种昆虫和节肢动物，约占40%。觅食高度从地面到约11米，通过采集果实和探查枯叶簇寻找昆虫。","breeding":"在秘鲁的繁殖季节为7月，可能还包括其他月份。像所有新世界须䴕一样，它会在树中挖掘巢穴，但其繁殖生态学的细节尚不清楚。","identification":"雄鸟与雌鸟在下胸的色彩上有所不同，雌鸟下胸为橙黄色，有助于区分。与类似物种黄喉拟啄木鸟相比，雌性红巾拟啄木鸟缺乏红色下胸，这是辨识的关键。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊雨林西南部，具体包括秘鲁东部、巴西西部以及玻利维亚西部的La Paz地区。","other":"曾被认为与红头拟啄木鸟关系密切，甚至可能是同一种，但现在被视为独立物种，没有近亲，即使在其属内也是如此。"},{"name":"彩拟啄木鸟","english_name":"Versicolored Barbet","scientific_name":"Eubucco versicolor","overview":"彩拟啄木鸟（英文名：Versicolored Barbet，学名：Eubucco versicolor），是䴕形目须䴕科黄嘴须䴕属的鸟类。分布于南美洲的秘鲁和玻利维亚。这种鸟以其鲜艳多彩的羽毛著称，包括红色的头部和胸部，绿色到蓝绿色的背部，黄色的喉咙和带有绿色条纹的黄色腹部。体重和长度因亚种而异，大约在26至41克之间，体长约为16厘米。","appearance":"雄性彩拟啄木鸟通常具有绿色的上部，黄色的胸部，红色的腹部带和红色的头部。雌鸟的上部为绿色至蓝绿色，脸部为蓝色，身体更绿。两性都有淡绿色带黄色的喙。亚种间在颜色细节上有所差异，如喉部和颊部的颜色，以及耳羽周围的橙色量和强度。雌雄幼鸟的色彩可能较成鸟暗淡。","call":"彩拟啄木鸟发出一种音乐般的咕噜声，带有突出的起始音符：“PA-prrrrr”。","habits":"彩拟啄木鸟栖息于湿润的山地森林，常见于含有大量附生植物和苔藓的森林，有时也会出现在成熟的次生林中。它们的活动范围一般在海拔1000至2000米之间，最高可达2225米。它们单独或成对活动，有时会加入混合物种的觅食群。以水果、种子为主食，约占饮食的80%，其余部分主要是昆虫和其他节肢动物。觅食时，它们会在离地面10至25米的高度寻找食物，通过撕扯枯叶丛中的死叶来寻找猎物。","breeding":"繁殖季节似乎在7月至12月之间，确切的繁殖行为研究有限。已知的一窝中包含三个白色的蛋，尺寸约为16至17毫米 x 20至22毫米，位于树洞中，洞口直径32毫米，深度先水平延伸6厘米后向下弯曲18厘米，巢室直径约6厘米，铺有锯末状的衬垫。","identification":"彩拟啄木鸟与其他拟啄木鸟种类的区别在于其独特的颜色组合，尤其是喉部和颊部的颜色，以及耳羽周围的橙色量。亚种间的区别更为微妙，涉及色彩的细微变化。","protection":"IUCN：NT（近危）","distribution":"彩拟啄木鸟分布于南美洲，从秘鲁西部亚马逊斯至北部胡安科，中部秘鲁东坡至库斯科北部，以及秘鲁南部（库斯科，普诺）至玻利维亚东北部（科恰班巴）。","other":"关于彩拟啄木鸟的繁殖习性和需求所知甚少。由于其栖息地遭受农业和城市发展的威胁，以及亚马逊盆地森林砍伐的影响，该物种可能正在经历适度快速的人口下降。"},{"name":"厚嘴拟啄木鸟","english_name":"Prong-billed Barbet","scientific_name":"Semnornis frantzii","overview":"厚嘴拟啄木鸟（英文名：Prong-billed Barbet，学名：Semnornis frantzii），是䴕形目巨嘴拟䴕科巨嘴拟䴕属的鸟类。是中美洲特有种，分布于哥斯达黎加至巴拿马西部的云雾森林中。拥有橄榄色至淡褐色的均匀羽毛，以厚实的灰色喙和红色眼睛为显著特征。雄鸟头部后方有一簇黑色长硬羽。这种鸟通常成对或小群体出现，主要以果实为食，偶尔捕食昆虫。","appearance":"厚嘴拟啄木鸟体长约17-18.5厘米，体重约60-70克。具有橄榄棕色的上背，橄榄绿色的下背、臀部和尾羽覆盖。雄鸟头顶呈暗金色，雌鸟相似但无黑色顶冠羽毛。脸部、颊部和下巴为暗灰蓝黑色。下腹部为淡黄色，侧腹为灰白色，带微弱的黄斑。喙宽厚，银灰色至蓝色，尖端暗色，具独特的分叉。","call":"其叫声被描述为深沉的‘cwa-cwa-cwa-cwa’，重复多次，由一对或多只鸟发出，形成共鸣强烈的合唱。","habits":"厚嘴拟啄木鸟栖息于高湿度的山地常绿林中，海拔介于750-2450米之间。它们非迁徙性，成群活动，有时多达12只。主要食物为果实，也会吞食小型果实或仅吸取果肉，大果实则撕裂食用。","breeding":"繁殖季节开始于3月，此时鸟儿会成对筑巢，巢穴位于树洞中，距离地面3-18米。每窝产卵4-5枚，孵化期为14-15天，孵化和抚育雏鸟由双亲共同承担。","identification":"厚嘴拟啄木鸟以其独特的喙形状和色彩模式容易辨认，没有近似种类。雄鸟的黑色顶冠羽毛是辨识雄鸟和雌鸟的关键特征。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马西部，主要在云雾森林中。"},{"name":"巨嘴拟啄木鸟","english_name":"Toucan Barbet","scientific_name":"Semnornis ramphastinus","overview":"巨嘴拟啄木鸟（英文名：Toucan Barbet，学名：Semnornis ramphastinus），是䴕形目巨嘴拟䴕科巨嘴拟䴕属的鸟类。是新热带界特有的一种独特鸟类，属于巨嘴拟䴕科Semnornithidae。这种色彩斑斓的云雾林居民仅见于厄瓜多尔西北部和哥伦比亚西部，以其厚实的黄色喙尖带黑的喙和鲜艳的羽毛而闻名。","appearance":"巨嘴拟啄木鸟拥有约19至21厘米的体长，体重介于80至115克之间。其特征性的喙既粗壮又厚实，上颌黄色，下颌浅绿色，两端色深。头部黑色，带有灰色喉部和颈背，红胸和上腹部，下腹部黄绿色，翅膀和尾巴呈灰蓝色。雄鸟头顶有黑色羽冠，雌鸟略逊一筹，缺乏雄鸟的羽冠。幼鸟比成鸟暗淡，直到四个月大才发育出喙的钩状突起。","call":"巨嘴拟啄木鸟的鸣叫极具辨识度，由繁殖对发出的响亮尖叫组成，声音传播远，通常以二重唱的形式在繁殖季节中鸣唱，用于领土展示。叫声频率随季节变化，年初较为频繁，之后逐渐减少。","habits":"这种鸟类居住在海拔1400至2400米的湿润森林中，从厄瓜多尔西北部的安第斯山脉斜坡延伸到哥伦比亚西南部。它们偏好旧的月桂科树木，用于筑巢。巨嘴拟啄木鸟以水果为主食，偶尔也会吃昆虫、小爬行动物、花蜜、树液和花瓣。它们在白天12小时内于领地内觅食，通常形成3至6只的小群体，有时加入多种物种的混合群。","breeding":"巨嘴拟啄木鸟采用合作繁殖模式，有几只辅助鸟帮助主导繁殖对孵化和抚养幼鸟。繁殖季节从2月至10月，一对可能每年育有两个甚至三个窝。它们在枯死的树木中用强大的喙挖掘巢穴，孵化期为15天，雏鸟45天后离巢。","identification":"巨嘴拟啄木鸟与其他鸟类明显不同，尤其是其厚实的喙和独特的羽毛图案。与同属的厚嘴拟啄木鸟相比，后者体型相似，但喙较厚，羽毛几乎全为橄榄色，分布于哥斯达黎加和巴拿马高地。","protection":"IUCN：NT（近危）","distribution":"巨嘴拟啄木鸟的分布局限于南美洲的哥伦比亚西部至厄瓜多尔西部，具体而言是从哥伦比亚西部到厄瓜多尔西部的安第斯山脉斜坡。","other":"巨嘴拟啄木鸟面临的主要威胁是非法捕捉以供笼鸟贸易，以及栖息地丧失。"},{"name":"韦氏绿巨嘴鸟","english_name":"Wagler's Toucanet","scientific_name":"Aulacorhynchus wagleri","overview":"韦氏绿巨嘴鸟（英文名：Wagler's Toucanet，学名：Aulacorhynchus wagleri），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。分布于墨西哥西南部的巨嘴鸟科鸟类。其鲜艳的颜色和大型喙部使其在热带森林中独具特色。","appearance":"韦氏绿巨嘴鸟身长29至37厘米，体重约160至200克。两性外观相似，但雌鸟通常较小，喙部略短。喙部黑色，有黄色条纹沿中脊，基部有橙棕色竖条。羽毛主要为绿色，下部颜色较浅。头部前冠黄白色，渐变为橄榄色至后冠，颈部淡色。眼周暗红色，被更深的裸露皮肤环绕。下脸和喉咙白色，过渡至蓝色的下体。尾羽上部基部绿色，逐渐变为蓝色，末端有栗色尖端。","call":"其主要鸣叫声为低沉、类似蛙鸣的重复音节，如'rronk- rronk- rronk'或'wup-wup-wup'，偶尔夹杂更强调的音符，打破单调的重复。飞行时，翅膀发出呼啸声。","habits":"韦氏绿巨嘴鸟栖息于墨西哥西南部的湿润山地森林，同时也出现在次生林、灌木丛、牧场和种植园等较开放的环境中。它们非迁徙性，群体活动，常聚集多达10只。食性广泛，包括各种水果、昆虫、小型脊椎动物如鸟类、蛋、蜥蜴和蛇。","breeding":"繁殖季节从3月持续到7月。它们在树洞中筑巢，洞穴可能是自然形成或啄木鸟弃置的。巢位高度可达27米。每窝产卵数通常为3至4枚，范围从1至5枚。双亲共同孵卵，雌鸟承担更多孵化任务。孵化期16天，幼鸟离巢时间为42至45天。","identification":"韦氏绿巨嘴鸟与同属物种的区别在于其独特的颜色模式，尤其是喙部的黄色和橙棕色条纹，以及胸部和尾部下方的白色和栗色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲墨西哥的西南部，主要在瓜埃拉州和瓦哈卡州西部的Sierra Madre del Sur山区。","other":"现为绿巨嘴鸟亚种。"},{"name":"绿巨嘴鸟","english_name":"Emerald Toucanet","scientific_name":"Aulacorhynchus prasinus","overview":"绿巨嘴鸟（英文名：Northern Emerald Toucanet，学名：Aulacorhynchus prasinus），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。中美洲湿润山地森林中的小型巨嘴鸟，也是分布最北的巨嘴鸟，向北可达墨西哥东部。通体以翠绿为主，喉部呈白色或蓝色，尾下覆羽及尾端栗色。本种地理变异显著，现存最多8个亚种，喉部颜色及喙部花纹差异明显。常见于小群活动，以果实及小型脊椎动物为食，在树洞中筑巢。","appearance":"体长30–37厘米，雌雄同色。成鸟通体翠绿，头顶微带铜色，上背泛铜黄；尾羽末端深蓝，具宽阔栗色端斑，中央尾羽端斑较窄或缺失；喉及颊部白色，胸腹渐转为绿色，尾下覆羽栗色。幼鸟羽色暗淡，尾羽端斑窄小且颜色较暗。喙长而侧扁，上喙黄色为主，下喙黑色，亚种间差异显著。跗蹠及趾橄榄绿至灰蓝色，足底暗黄。","call":"鸣声低沉似蛙鸣，连续发出“rronk-rronk-rronk”或“wup-wup-wup”，常夹杂更响亮的音节；另有远传的干涩“rrip rrrip”或“curré curré”声，可持续数分钟。群内交流时发出柔和“eeaaah”，惊飞时发出尖锐断续的“咯咯”或吠声。飞行时翼可发出轻微呼呼声。","habits":"留居于海拔250–3000 m的湿润山地森林、林缘、次生林、种植园及散树空地。主要在林冠中层至顶层觅食，偶尔下降至地面。以113种植物的果实为主，兼食蜘蛛、蜈蚣、直翅目、甲虫、鳞翅目幼虫等无脊椎动物，以及雏鸟、卵、小型蜥蜴和蛇。飞行直接，翼拍急促带嗡声，末端常短滑翔。","breeding":"繁殖期3–8月，因地而异。巢筑于距地2–27 m的树洞中，入口椭圆，高约80 毫米。每窝1–5枚卵，多为3–4枚；卵白色椭圆，平均32.1×23.9 毫米。双亲共同孵卵16天，雌鸟夜间为主；育雏期42–45天，双亲共同喂以果实及动物性食物。","identification":"在其分布区内为唯一绿色巨嘴鸟，不会与其他巨嘴鸟混淆。与南邻的白喉巨嘴鸟亚种griseigularis喉部浅灰，而本种最南端亚种cognatus喉部深蓝，可资区分。亚种间差异主要在于喉部颜色（白或蓝）及喙部黄黑比例。","protection":"IUCN: LC（无危）。全球种群被认为正在下降，但因分布广泛而总体安全。墨西哥法律将其列为需特别保护物种。","distribution":"繁殖区：墨西哥东南部（圣路易斯波托西至瓦哈卡）、尤卡坦、伯利兹、北危地马拉；非繁殖区：同域留居。亚种prasinus分布于墨西哥韦拉克鲁斯至瓦哈卡；virescens自恰帕斯至洪都拉斯、尼加拉瓜；caeruleogularis在哥斯达黎加山系至西巴拿马；cognatus在巴拿马东部达连省至哥伦比亚西部乔科省。","other":"绿巨嘴鸟复合体约含15个分类单元，物种划分从1到8种不等，争议源于不同物种概念的运用。韦氏绿巨嘴鸟与蓝喉巨嘴鸟被视为其亚种。"},{"name":"蓝喉巨嘴鸟","english_name":"Blue-throated Toucanet","scientific_name":"Aulacorhynchus caeruleogularis","overview":"蓝喉巨嘴鸟（英文名：Blue-throated Toucanet，学名：Aulacorhynchus caeruleogularis），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。广泛分布于中美洲的哥斯达黎加到南美洲哥伦比亚西北部一带，其显著特征为拥有大而醒目的喙以及深蓝色的喉咙。","appearance":"成年蓝喉巨嘴鸟体长约29至37厘米（11至15英寸），体重约120至185克（4.2至6.5盎司）。雌雄外观相似，但雌鸟体型通常较小，喙也较短。喙为黑色，带有宽黄色条纹和白色竖直条纹。头部主要呈绿色，下方略浅，冠部有青铜色光泽，颈背带黄铜色，眼周环绕着深色裸露皮肤，脸部下部和喉咙呈深蓝色。尾羽上端基部绿色，向末端渐变为蓝色，尾羽尖端为栗色。幼鸟颜色较灰，尾羽尖端的栗色更小且偏棕色。","call":"蓝喉巨嘴鸟的主要叫声为响亮且传播远的‘rrip rrrip rrip rrip’或‘curré curré curré’…经常连续几分钟不断，飞行时翅膀会发出呼呼的声音。","habits":"蓝喉巨嘴鸟为留鸟，群居，常见以10只左右的小群体聚集。栖息于海拔800至3000米（2600至9800英尺）的湿润山地森林，也会出现在次生林、灌木地、牧场和种植园等较为开阔的环境中。以多种果实、昆虫、鸟类、蛋、蜥蜴和蛇等为食。","breeding":"繁殖季节从3月持续至8月，它们在树洞中筑巢，可能是自然形成的或是啄木鸟弃置的洞穴，巢位可达27米（89英尺）高。一窝产卵3至4枚，孵化期为16天，雏鸟在孵化后42至45天离巢。","identification":"蓝喉巨嘴鸟与同属其他物种的区别在于其深蓝色的喉咙和特定的叫声。两个已知亚种之间，A. c. caeruleogularis与A. c. cognatus在外观上有细微差异，如后者冠部和颈背几乎纯绿色。","protection":"IUCN：LC（无危）","distribution":"蓝喉巨嘴鸟分布于中美洲哥斯达黎加至南美洲哥伦比亚西北部，具体覆盖了哥斯达黎加大部分地区，西部巴拿马直至Veraguas省，以及中央和东部巴拿马与哥伦比亚Chocó省的部分区域。","other":"蓝喉巨嘴鸟的分类历史复杂，曾是绿巨嘴鸟的多个亚种之一，后被独立为新种。现为绿巨嘴鸟亚种。"},{"name":"白喉巨嘴鸟","english_name":"White-throated Toucanet","scientific_name":"Aulacorhynchus albivitta","overview":"白喉巨嘴鸟（英文名：Southern Emerald Toucanet，学名：Aulacorhynchus albivitta），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。分布于安第斯山脉的中型巨嘴鸟，体型30-37厘米，全身翡翠绿为主，具白喉、栗色尾下覆羽及尾端。地理变异显著，依喉部颜色与喙纹分为7个亚种，见于哥伦比亚至玻利维亚的湿润山地森林。","appearance":"成鸟体羽主色为亮丽翡翠绿，头顶稍带铜绿，上背泛青铜黄，眼周具蓝色小斑，下体较上体淡。尾羽末端呈栗色，中央羽对栗端窄或缺；喉、颊及颏白色，向下渐变为绿色；胁亮黄绿至绿黄；尾下覆羽栗色。雌雄同色，雌鸟略小。幼鸟羽色黯淡，呈灰绿，尾羽更尖、栗端缩减且色暗。喙长而侧扁，上喙大部黄色、下喙黑色，基具白色纵纹及栗斑；跗跖与趾橄榄绿，足底暗黄。","call":"叫声因地区略有差异，被描述为连续的短促“took”、“churt”或“grá-val”声，每秒约2-3次；亦作快速“rek-rek-rek”或带犬吠质感的“grra grra”连串音。飞行时翼可发出呼呼声。","habits":"主要栖息于海拔200-3100 m的湿润山地森林，也见于林缘、次生林、种植园及疏林空地。在哥伦比亚、委内瑞拉、厄瓜多尔、秘鲁和玻利维亚均有分布，南秘鲁及玻利维亚种群可下至低地200 米。常成小群活动，在林冠及中层觅食，偶至地面。以果实为主，兼食昆虫及小型脊椎动物，记录到的果实包括榕属、Cecropia、Prunus等，亦跟随行军蚁群。","breeding":"繁殖期依纬度和海拔不同：哥伦比亚与委内瑞拉为1-9月，厄瓜多尔9-11月，秘鲁5-9月。巢筑于树洞中，其余繁殖信息不详，推测与北方翡翠巨嘴鸟相似。","identification":"与同属其他种区别：本种具黄色上喙；栗色尾下覆羽及尾端；体型小于绯腰巨嘴鸟、黄额巨嘴鸟及蓝斑巨嘴鸟，且后者具红色或蓝色臀斑。与沟嘴巨嘴鸟亚种calorhynchus相比，后者尾下覆羽及尾端无栗色，且上、下喙均具更多黄色。与绿巨嘴鸟最南种群无重叠，喉色亦不同。","protection":"IUCN: Least Concern（无危）","distribution":"繁殖地与非繁殖地重叠：自哥伦比亚北部（圣玛尔塔山、佩里哈山及三大安第斯山脉）与委内瑞拉安第斯山，向南延伸至玻利维亚圣克鲁斯。太平洋坡仅见于哥伦比亚；自厄瓜多尔向南则局限于安第斯山东坡。","other":"曾被归入广义的“翡翠巨嘴鸟复合体”，该复合体内物种划分长期存在争议，依据不同物种概念可划分为1-8种。目前系统发育研究显示本种与绿巨嘴鸟互为姊妹群，构成Aulacorhynchus属的基部类群。"},{"name":"黑喉巨嘴鸟","english_name":"Black-throated Toucanet","scientific_name":"Aulacorhynchus atrogularis","overview":"黑喉巨嘴鸟（英文名：Black-throated Toucanet，学名：Aulacorhynchus atrogularis），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。分布于南美洲的玻利维亚、巴西、厄瓜多尔和秘鲁。","appearance":"黑喉巨嘴鸟拥有明亮的色彩和大喙，成鸟长度介于33到38厘米之间，体重约120至210克。雌雄外观相似，但雌鸟通常较小，喙部也较短。喙部颜色在不同亚种间有所不同，带有黄色条纹或仅在上喙尖端有黄色。所有亚种的喙基部都有白色垂直条纹，羽毛主要是绿色，略浅于背部，喉咙颜色在亚种间有黑色或蓝色的变化。","call":"其鸣声被描述为一系列磨砺般的低沉哼声或犬吠般的‘yak yak yak yak yak’声。飞行时，翅膀发出呼啸声。","habits":"黑喉巨嘴鸟是非迁徙性鸟类，群居，常聚集在小型群体中。它们在森林中层到上层觅食，以各种果实、陆生无脊椎动物和小型脊椎动物为食。","breeding":"关于其繁殖生态知之甚少，但在秘鲁的繁殖季节为5月至9月。它们像家族中的其他成员一样，在树洞中筑巢。","identification":"与其他绿巨嘴鸟属物种的区别在于喉咙的颜色和喙部的细节差异。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从中部厄瓜多尔延伸至西部玻利维亚。","other":"2008年，国际鸟类学家委员会（IOC）将其从更广泛的绿巨嘴鸟（ sensu lato）中分离出来，创建了包括黑喉巨嘴鸟在内的七个新物种。现为白喉巨嘴鸟亚种。"},{"name":"沟嘴巨嘴鸟","english_name":"Groove-billed Toucanet","scientific_name":"Aulacorhynchus sulcatus","overview":"沟嘴巨嘴鸟（英文名：Groove-billed Toucanet，学名：Aulacorhynchus sulcatus），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。外形酷似犀鸟，主色为绿色，背部和翅膀颜色较深，尾巴带有红色斑点。喙巨大而轻巧，上半部分靠近基部呈紫红色，重量不足30克。栖息于哥伦比亚东北部和委内瑞拉北部的山林中，生活在海拔1,000至3,600米之间。","appearance":"沟嘴巨嘴鸟的喙构造独特，外层为薄壳，内部由多孔的海绵状组织构成，充满了空气，使它虽大却不重。体长约33至37厘米，体重介于130至200克。喙大部分为酒红色至棕红色，有黑色斜纹，底端有白色线条。羽毛整体绿色，下体较淡，尾下覆羽黄绿色。雌鸟比雄鸟略小，喙也较短。","call":"发出一系列冗长、不和谐的喉音，类似蛙鸣和狗吠，还伴有干涩的咔哒声。","habits":"栖息于海拔1,000至3,600米的山林中，偏好树梢地带。主要在腐朽树木上凿洞为巢，杂食性，食用果实、种子和昆虫，偶尔掠食小鸟的巢穴。","breeding":"一次产卵2至4枚，光滑白蛋直接置于巢穴中，大约16天孵化。雏鸟出生时全身裸露，至少需3周才能睁开眼睛，约45天后开始独立生活。","identification":"与绿巨嘴鸟和绯腰巨嘴鸟相比，沟嘴巨嘴鸟的尾下覆羽和臀部为绿色，尾端蓝色。亚种A. s. erythrognathus与指名亚种相似，但面部金色较少。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚东北部和委内瑞拉北部，包括圣玛尔塔山脉和佩里亚山脉，向东延伸至委内瑞拉西部，最东可达拉腊州西南部。","other":"亚种A. s. calorhynchus曾被认为是独立物种，称为\"黄嘴巨嘴鸟\"，但自2012年起被归入沟嘴巨嘴鸟。"},{"name":"栗斑巨嘴鸟","english_name":"Chestnut-tipped Toucanet","scientific_name":"Aulacorhynchus derbianus","overview":"栗斑巨嘴鸟（英文名：Chestnut-tipped Toucanet，学名：Aulacorhynchus derbianus），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。中型攀禽，主要分布于南美洲安第斯山脉东坡，从哥伦比亚东南部至玻利维亚中部。体羽以绿色为主，具白色领环和喉部，尾羽尖端呈栗色，喙部极大，基部有一条显眼的红色。曾与怀氏巨嘴鸟被视为同一物种。","appearance":"体长33至41厘米，体重介于141至262克。全身以绿色为主，翼和尾颜色更深，具有白色的颈圈和喉部，尾羽尖端栗色。喙极大，基部有鲜艳的红色，重量不足30克，结构独特，由一层薄壳包裹，内部为多孔的海绵状组织，充满空气。喙部仅在上颌有沟纹，尖端尤其钩曲。","call":"发出一系列冗长的‘grrrrump’到‘kwuk’音符，每秒1.2至1.55次，音符较长且音调均匀。此外还发出‘ggg-rgg’、‘ngg-ngg’和‘bbdt-bbdt’的干涩卡嗒声。","habits":"居于海拔600至2,000米的山林中，主要栖息于云雾林，偶尔出现在热带高谷森林。通常在树冠层活动，以水果、种子和昆虫为食，有时会掠食小鸟的巢穴。成对或小群体（最多10只）觅食。","breeding":"繁殖季节从5月持续至10月，其余繁殖生物学细节未知。巢筑于树洞内，一次产卵2至4枚，孵化期约16天，雏鸟孵化后至少3周才能睁开眼睛，约45天后开始独立生活。","identification":"与沟嘴巨嘴鸟相比，栗斑巨嘴鸟尾羽尖端为栗色，喙基部深红色，缺乏上颌沟纹。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉东坡，从极端南部的哥伦比亚至玻利维亚中部（Cochabamba）。","other":"在一些有限区域内常见，但在厄瓜多尔总体上罕见至不常见，在秘鲁则较为罕见。"},{"name":"怀氏巨嘴鸟","english_name":"Tepui Toucanet","scientific_name":"Aulacorhynchus whitelianus","overview":"怀氏巨嘴鸟（英文名：Tepui Toucanet，学名：Aulacorhynchus whitelianus），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。主要分布在南美洲的特普伊高地，包括委内瑞拉南部、巴西、圭亚那和苏里南。其独特的小型绿色身躯和鲜明的红黑相间喙部使它在同类中独树一帜。","appearance":"怀氏巨嘴鸟体长33至41厘米，体重约117至160克。其喙深红色与黑色相间，带有独特的垂直白色线条和上颌沟槽。全身主要呈绿色，喉部白色，下尾覆羽黄绿色，眼周有蓝色。尾羽端部锈色，雌雄外观相似，但雌鸟体型较小，喙较短。幼鸟颜色较暗淡，黄色较少，面部蓝色减少。","call":"发出低沉的吼叫声，节奏感强，通常以'grank, graank, graank...'的形式连续发出，每秒略多于一声，持续时间较长，间歇短暂。","habits":"生活在热带湿润山地云雾林中，海拔800至1800米，偶尔下降至更低高度。通常单独或成对活动，有时加入混合物种觅食群，主要在森林较低层到亚冠层之间活动，以果实为主食，偶尔在果树林中聚集。","breeding":"繁殖季节从2月持续至7月，但具体繁殖生态细节未知。","identification":"在特普伊地区范围内无其他绿巨嘴鸟属物种共享生境，可通过其独特的体型、喙部特征和分布地辨别。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲特普伊高地，包括委内瑞拉南部、圭亚那南部，以及巴西和苏里南的部分地区。","other":"怀氏巨嘴鸟与栗斑巨嘴鸟曾被视为同一物种，自2011年起被主要分类系统分离。"},{"name":"绯腰巨嘴鸟","english_name":"Crimson-rumped Toucanet","scientific_name":"Aulacorhynchus haematopygus","overview":"绯腰巨嘴鸟（英文名：Crimson-rumped Toucanet，学名：Aulacorhynchus haematopygus），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。外形与犀鸟相似，主要分布于南美洲的委内瑞拉西部至厄瓜多尔东部，体羽以绿色为主，具有独特的红臀部，是其显著的外部特征之一。","appearance":"绯腰巨嘴鸟体长约40至45厘米，体重介于141至232克之间。它们拥有草绿色的体羽，胸部带有青绿色光泽，翅膀和背部颜色较深，尾部有一明显的红色斑块。鸟喙呈褐色并带有黑色斑点，基部有一条白色线条，喙形扁平，侧面有脊状突起，底部的白色线条在腹面加宽并在下颚基部最宽。雄鸟的蓝斑覆盖眼周、眼下以及胸部两侧；雌鸟的喙稍短。幼鸟的羽毛较暗淡，臀部橙色，喙主要为红色，没有白色基线。","call":"绯腰巨嘴鸟的鸣声通常为一系列变化多端、粗糙的吠叫声，从“daakk”到“gggruk”，可持续长达两分钟或更久，比绿巨嘴鸟的叫声更低沉、节奏更慢。伴侣间会合唱，雄鸟发出更深沉、类似咆哮的声音，雌鸟声音更为清晰。","habits":"绯腰巨嘴鸟生活在海拔300至2200米的低地和山地常绿森林中，偶尔可达2750米高度。它们在森林冠层活动，单独或成对出现，或组成小群体。主要以果实为食，如Cecropia和月桂科植物的果实，棕榈果仁，也可能摄食昆虫和鸟蛋。在圈养条件下，它们会捕捉并食用小型鸟类和昆虫，甚至在繁殖季节喂食死鼠。它们通过水生植物中积存的水源饮水。","breeding":"繁殖期一般从1月持续至5月，但在厄瓜多尔南部和哥伦比亚南部可能早在11月就开始。建立伴侣关系前，双方会唱歌、鸣叫、追逐，直至形成稳定的伴侣。双亲共同参与求偶喂食、互相梳理羽毛等活动。雄鸟会摇摆尾巴，竖立胸部羽毛。唱歌时，鸟喙指向水平线下方，尾部随着歌声节奏摆动。在繁殖期间，巢通常位于旧的啄木鸟洞中，去除腐烂的木质部分。圈养条件下，每次产卵数可达4枚；雌鸟承担大部分孵化任务，孵化周期约为16至17天；刚孵化的雏鸟全身裸露，粉色，以昆虫、果实和幼鸟为食；巢穴由双亲共同保持清洁；幼鸟发育缓慢，约3周后眼睛才睁开，此时开始长出羽毛；大约6周时，除飞行羽外，已基本完全长出羽毛；约7周后离巢；幼鸟可能会返回与父母同巢过夜，直到下一个繁殖季节。","identification":"绯腰巨嘴鸟与绿巨嘴鸟的区别在于其全黑色的喙与红色臀部。雄鸟与雌鸟在外表上相似，但雌鸟的喙较短。幼鸟的羽毛较为暗淡，臀部呈橙色，喙主要为红色，没有白色的基线。","protection":"IUCN：LC（无危）","distribution":"绯腰巨嘴鸟主要分布在南美洲，包括委内瑞拉西部至厄瓜多尔东部，具体分布于哥伦比亚、厄瓜多尔和委内瑞拉的部分地区。","other":"绯腰巨嘴鸟在哥伦比亚的La Planada自然保护区和Río Ñambí自然保护区中常见，且在Ecuador的Podocarpus国家公园也有分布。它们似乎具有较强的适应性，能够在次生林中生存，即使在小片林地中也能找到它们的身影。圈养状态下，繁殖成功。"},{"name":"黄额巨嘴鸟","english_name":"Yellow-browed Toucanet","scientific_name":"Aulacorhynchus huallagae","overview":"黄额巨嘴鸟（英文名：Yellow-browed Toucanet，学名：Aulacorhynchus huallagae），是䴕形目巨嘴鸟科绿巨嘴鸟属的罕见鸟类。仅见于秘鲁北部安第斯山脉东坡的偏远地区，由于其栖息地难以接近，这一物种知之甚少。体色以绿色为主，尾部末端和臀部呈红色，喉咙白色，胸部有一条淡蓝色带。与蓝斑巨嘴鸟的区别在于眼上方的黄色条纹而非白色，以及喙基部明显的垂直白色线条。","appearance":"黄额巨嘴鸟体型介于小型到中型之间，总长38至44厘米。全身羽毛主要为绿色，头部和翅膀颜色较深，更接近纯绿色。尾巴上表面绿色，中央一对尾羽带有蓝色，内侧两对尾羽尖端呈栗色。胸腹部黄色绿色，下腹部金黄色。下胸部有一亮蓝色横带。喙大部分为蓝灰色，逐渐变浅至灰白色，尖端白色，基部有明亮的白色竖线。眼睛周围有黑色裸露皮肤。","call":"黄额巨嘴鸟的典型叫声被描述为一系列20到30个类似蛙鸣的‘krik’音符，也有人形容为一系列刺耳的哼哈声：‘rehh rehh rehh...’。","habits":"黄额巨嘴鸟栖息于海拔2000至2600米的湿润山地森林中，以果实和种子为主要食物来源，偶尔也会捕食昆虫和其他小型动物。它们在树梢活动，偏好在朽木上凿洞筑巢。","breeding":"繁殖季节可能从10月持续到次年2月或3月，推测与同属其他物种一样，在树洞中筑巢。每次产卵2至4枚，孵化期约为16天。雏鸟孵化出来时全身赤裸，需至少3周后才能睁开眼睛，大约45天后开始独立生活。","identification":"黄额巨嘴鸟与蓝斑巨嘴鸟最为相似，但后者的眼上条纹为白色而非黄色，喙基部没有白色线条。此外，蓝斑巨嘴鸟的喉咙延伸至上颌基部两侧为白色，下腹覆羽为黄绿色。","protection":"IUCN：NT（近危）","distribution":"黄额巨嘴鸟的分布局限于秘鲁北部，具体地点包括亚马逊南部、圣马丁和拉利伯塔德东北部。其确切分布范围可能比目前所知更为广泛，但由于该区域缺乏道路，发现机会有限。","other":"黄额巨嘴鸟的生存受到其栖息地转变为古柯种植的威胁，尽管这一地区的大部分森林砍伐发生在较低海拔地区。"},{"name":"蓝斑巨嘴鸟","english_name":"Blue-banded Toucanet","scientific_name":"Aulacorhynchus coeruleicinctis","overview":"蓝斑巨嘴鸟（英文名：Blue-banded Toucanet，学名：Aulacorhynchus coeruleicinctis），是䴕形目巨嘴鸟科绿巨嘴鸟属的鸟类。近似攀禽的鸟类，属于巨嘴鸟科。其特征为喙极大但轻巧，具蓝喉，背部灰绿，翅膀翠绿，腹部嫩绿。分布于秘鲁中部至玻利维亚东南部的湿润山地森林。","appearance":"体长40-44厘米，体重173-257克。喙蓝灰色，具白色和蓝色眉纹，喉部白色，胸部有蓝色带，尾羽中央有锈色尖端。尾下覆羽绿黄，雌雄相似，幼鸟较暗淡。","call":"发出一系列低沉的、摩擦声般的“grrok”音符，节奏均匀。","habits":"栖息于湿润的山地森林和云雾林，海拔1470-3050米。单独、成对或小群活动，常与混种群如啄木鸟和树叶觅食者相伴。以果实、昆虫和其他节肢动物为食。","breeding":"繁殖季节可能从1月持续到4月或更晚，具体细节未知。","identification":"与黄额巨嘴鸟的区别在于喙基部更窄，无白色线，侧面更硬，尾下覆羽更绿。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁中部至玻利维亚东南部，包括安第斯山脉东坡的几个孤立山区。","other":"蓝斑巨嘴鸟为单型种，对其繁殖生态学的研究尚需加强。"},{"name":"绿簇舌巨嘴鸟","english_name":"Green Aracari","scientific_name":"Pteroglossus viridis","overview":"绿簇舌巨嘴鸟（英文名：Green Aracari，学名：Pteroglossus viridis），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的中型攀禽，外形略似犀鸟。上体墨绿色，腰部深红色，头部栗色，眼睛周围有一圈青绿色，下体以黄绿色为主。分布于南美洲东北部低地森林，包括东北亚马逊盆地、圭亚那盾地和委内瑞拉东部奥里诺科河流域。","appearance":"雄鸟的冠部呈黑色，而雌鸟为红褐色至锈色。长喙呈现出多种色调搭配，以黑色与黄色为主，有少许橙色、红色等。喙缘一般成明显的锯齿状，外表为黑色或象牙色，看上去有几分像牙齿。绿簇舌巨嘴鸟的嘴尽管很大，但是重量不足30克，喙骨构造特别，轻巧且充满空气。","call":"发出‘bridididit’的敲击声，每秒1-6次，声音类似缓慢的摩托车引擎声，还有柔和的叽叽喳喳声、咕噜声和哀鸣声。","habits":"栖息于暖林及边缘地带，喜栖于树梢。以果实、种子和昆虫为食，有时掠夺小鸟巢穴，吃掉卵和雏鸟。在果实丰富的树木、开阔地和河边成小群活动，从树冠到下层林间觅食。","breeding":"繁殖期通常为2月至6月，筑巢于树洞中，产2-4枚光滑的白色蛋，孵化期约为17天，幼鸟孵化后约45天开始独立生活。","identification":"与黑颈簇舌巨嘴鸟相比，绿簇舌巨嘴鸟腹部无条纹，喙更为多彩，分布更限于高大的雨林。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉东部至亚马逊河口，包括圭亚那、苏里南、法属圭亚那和巴西东北部。"},{"name":"巴西簇舌巨嘴鸟","english_name":"Lettered Aracari","scientific_name":"Pteroglossus inscriptus","overview":"巴西簇舌巨嘴鸟（英文名：Lettered Aracari，学名：Pteroglossus inscriptus），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的中型攀禽。主要分布在南美洲亚马逊雨林的西部和南部区域，包括巴西、哥伦比亚、秘鲁等地。这种鸟以其独特的外观著称，拥有墨绿色的上体、深红色的腰部，以及栗黑色或黄色的头部。下体大部分呈黄色，长喙则呈现黑色与象牙白的双色搭配。","appearance":"巴西簇舌巨嘴鸟是一种中等体型的巨嘴鸟，上体墨绿色，腰部鲜红，头部通常为栗黑色，下体主色为黄色。其喙部独特，由黑色与象牙白色组成，边缘具明显的锯齿状，外层薄壳内含轻质海绵状组织，充满空气，使整个喙部虽大却不显沉重。雌雄异形明显，雏鸟四周大时即可通过体羽辨别性别。","call":"这种鸟的鸣叫声被描述为一系列连续的粗哑音符，如‘cha’音，快速的‘kkik’或‘kkuk’音，以及类似电击的哼鸣声。此外，它们还会发出单个的‘chak’或‘kak’音，以及在争斗中可能使用的‘bdddt’的喙摩擦声。","habits":"巴西簇舌巨嘴鸟栖息于低地热带雨林的树冠层，偏好温暖的林区及边缘地带。它们通常以小群形式活动，可能是由家庭成员组成的小群体。以水果为主要食物，但也摄取小型节肢动物，甚至会掠夺其他鸟类的巢穴以获取鸟蛋和雏鸟。","breeding":"繁殖季节横跨12月至翌年7月（西部区域）和8月至次年3月（东部巴西）。巢穴通常建在树洞中，每次产卵2至4枚，孵化期约为16天。雏鸟出生时全身裸露，至少需三周后才能睁开眼睛，大约45天后开始独立生活。","identification":"在它的分布范围内，巴西簇舌巨嘴鸟因全身黄色下体而不会与其他种类混淆。与之相似的绿簇舌巨嘴鸟在地理上并不重叠。东部亚种偶尔被认为是单独的物种，但与指名亚种在亚马逊中部的马德拉河区域有杂交现象。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊盆地的广阔区域，包括巴西、哥伦比亚、秘鲁等地的低地热带雨林。在巴西东北部的佩尔南布科和阿拉戈斯有少量孤立种群。西部亚种分布在哥伦比亚南部、厄瓜多尔东部、玻利维亚西北部以及巴西西部靠近亚马逊河的区域。","other":"巴西簇舌巨嘴鸟与绿簇舌巨嘴鸟形成超种概念，但两者地理上不重叠。"},{"name":"红颈簇舌巨嘴鸟","english_name":"Red-necked Aracari","scientific_name":"Pteroglossus bitorquatus","overview":"红颈簇舌巨嘴鸟（英文名：Red-necked Aracari，学名：Pteroglossus bitorquatus），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。又名: 红颈簇舌鵎鵼，中型攀禽。拥有红色臀部、颈背和胸部带状区域，绿色翅膀和尾巴，黄色腹部。雄鸟有黑色冠羽，雌鸟冠羽偏棕色，喉部黑色较少，黄色胸带较窄。分布于南美洲亚马逊雨林南部，从巴西南部至玻利维亚，包括低地和丘陵的热带湿润森林。","appearance":"长约36厘米，体重112-171克。上体呈棕黑色，腰部深红色，头部通常为栗色。下体以黄色为主，带有黑色或红色斑纹，形成显著的胸斑。长喙呈现黑色与黄色两种色调，边缘锯齿状，外观为黑色或象牙色。喙部虽大，但重量不足30克，由薄壳包裹，内部为多孔海绵状结构，充满空气，减轻了重量。雌雄差异明显，雌鸟比雄鸟体色更暗淡，喉部黑色较少，黄色胸带较窄。雏鸟四周大时即可通过体羽辨别性别。","call":"发出一系列‘tik’音符，节奏约为每秒13个音，通常成组出现，每组约6个音，组间短暂停顿。叫声还包括‘ttak’或‘tyat’，更丰富多变，少机械感，以及摩擦音、单一‘ik’音、‘tweah’声和类似咆哮的‘dcheeeaah’叫声。","habits":"栖息于低地和丘陵的热带湿润森林，也见于次生林、竹林和溪流旁的密集树木。海拔范围从海平面至约800米。主要以各种无花果、肉桂和Cecropia的果实为食，可能也吃昆虫、小型脊椎动物如雏鸟、鸟蛋和蜥蜴。在中层林冠活动，单独、成对或小群体觅食。","breeding":"繁殖季节在大部分地区为2月至8月，部分地区为4月至9月，玻利维亚为7月至12月。巢穴位于树洞内，具体细节未知。每次产卵2-4枚，孵化期约16天，雏鸟孵化后至少三周才能睁开眼睛，约45天后开始独立生活。","identification":"与红颈簇舌巨嘴鸟相比，P. sturmii体型更大，黄色胸带更宽，黑色部分在下喙基部与白色交汇，形成2-5个黑色点。雌雄差异在于冠羽颜色和黄色胸带宽度。","protection":"IUCN：EN（濒危）","distribution":"分布于南美洲亚马逊雨林南部，具体包括巴西南部亚马逊河以南区域，从马德拉河至塔帕若斯河，向南至罗萨尼亚，东至玻利维亚东部本尼和圣克鲁斯东北部，中部马托格罗索（巴拉圭河流域，几乎到达Xingu河）。","other":"在Noel Kempff Mercado国家公园（玻利维亚）有记录。物种面临栖息地丧失威胁，但对环境退化有一定容忍度。"},{"name":"白嘴簇舌巨嘴鸟","english_name":"Ivory-billed Aracari","scientific_name":"Pteroglossus azara","overview":"白嘴簇舌巨嘴鸟（英文名：Ivory-billed Aracari，学名：Pteroglossus azara），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。体型较小的巨嘴鸟，主要分布在南美洲的亚马逊地区。其羽毛与红颈簇舌巨嘴鸟非常相似，但与绿簇舌巨嘴鸟类群的亲缘关系更近。白嘴簇舌巨嘴鸟有三个亚种，它们在各自的分布区域有杂交现象，这在巨嘴鸟分类学中具有重要意义。其主要栖息于亚马逊西部的季节性洪泛林和高地森林，从哥伦比亚东南部向南至玻利维亚北部，东至马德拉河。这种鸟通常单独、成对或以小群（最多五只）活动，以各种水果为食，尤其是无花果和 Cecropia 的花序，也会捕食飞行昆虫。","appearance":"体长 36–45 厘米，体重 100–200 克，通常在 120–160 克。雄性指名亚种的头部黑色，其余头部和喉部栗色，喉部下方有黑色带，上背至后颈几乎完全为深红色，红色臀部；宽阔的红色上胸带，宽阔的黑色下胸带，腹部黄色，大腿主要为绿色；黄色的喙，喙侧有深红色至棕色的线条，基部宽阔，逐渐变细至黑色尖端，切缘“牙齿”红色、黑色和象牙色；眼周区域黑色至灰色，通常被栗色至红色的面部皮肤包围。雌性喙较短，头顶暗棕色，喉部下方的黑色线条较窄。幼鸟羽毛较为松散，黑色区域呈棕色，红色区域更橙色，黄色较浅，有斑驳，喙模糊标记，没有切缘“牙齿”或基线。亚种主要在喙的颜色上有所不同：flavirostris 亚种的上喙黄色至黄绿色或象牙色，鼻孔下方有橙色斑点，切缘“牙齿”黑色和白色，下喙黄色或象牙色，中央有一条细长的橙棕色线；mariae 亚种的上喙黄色至象牙色，切缘“牙齿”黑色和白色，黑色有时形成切缘线，下喙主要橙棕色，尖端黄色或象牙色，基部黄色基线后方有时有小的淡黄色区域，眼周区域可能更窄的灰蓝色，因此红色面部区域更大。","call":"可能的歌声是一系列 2–6 个哀怨的“twaaa-a-a”或“tweee-ee”或“traaa-at”音符，每个音符长 0.2–0.5 秒，最多约每秒 1 个，随着系列的进行逐渐放慢速度，有时以更嘶哑的“treee-awk”音符开始；有时发出“ttaaaaw”音符；还会发出类似嘎嘎声的接触音、鼻音“nyek”、类似咕噜声的音符、“kyeek”警报声、纯嘎嘎声“bddddt”以及在互动中发出的响亮的翅膀噪音。","habits":"栖息于季节性洪泛林和高地湿地森林，分布在低地至山地较低坡地，有时可达云雾林；也出现在竹林和其他河滨植被、河岸森林、林地、沿溪流的森林、草原中的次生林、树木种植园和边缘地带。在湖泊和溪流的早期和中期演替阶段数量最多，后期演替阶段个体较少，最后的过渡阶段和高地森林中数量最少；在亚马逊-索利莫斯系统中，岛屿和移动河流的占据可能是导致亚种跨河杂交的原因之一。主要分布在海拔 600 米以下，但在厄瓜多尔和玻利维亚之间的东安第斯山脉可达 900 米，局部地区可达 1400 米。通常在上层和林冠觅食，但也在底层被雾网捕获。在大型簇舌巨嘴鸟（曲冠簇舌巨嘴鸟）的鸣叫群体接近时，会从结果树上飞走。","breeding":"根据标本数据，繁殖季节在东北部为 12 月至次年 5 月，在西部和西南部为 2 月至 8 月。在野外观察到求偶喂食行为；未报告其他求偶行为。巢未被描述，可能使用旧啄木鸟洞；曾被看到进入一棵树上 18 米高的洞穴。每次产卵 2–3 枚或 4 枚；没有进一步信息。","identification":"与红颈簇舌巨嘴鸟相似，但分布区域不重叠。与绿簇舌巨嘴鸟类群的亲缘关系更近。亚种之间主要通过喙的颜色区分：flavirostris 亚种的上喙黄色至黄绿色或象牙色，鼻孔下方有橙色斑点；mariae 亚种的上喙黄色至象牙色，下喙主要橙棕色。此外，mariae 亚种与 P. humboldti 在巴西西部（茹鲁阿河）有杂交现象，杂交后代最初被认为是一个独立的物种，命名为‘P. olallae’。","protection":"IUCN: LC（无危）","distribution":"分布于南美洲的亚马逊地区。指名亚种分布于巴西的亚马逊地区，位于内格罗河西岸和索利莫斯-亚马逊河北岸；flavirostris 亚种分布于哥伦比亚东南部、委内瑞拉南部和巴西西北部（内格罗河以西，索利莫斯河北岸），向东至厄瓜多尔东部和秘鲁东北部；mariae 亚种分布于亚马逊河南部，从秘鲁东部和巴西西部（向东至马德拉河）向南至玻利维亚中部。在中国大陆地区没有分布。","other":"该物种有时被错误地命名为 P. flavirostris，这可能是由于优先权的混淆。褐嘴簇舌巨嘴鸟现在为其亚种。"},{"name":"褐嘴簇舌巨嘴鸟","english_name":"Brown-mandibled Aracari","scientific_name":"Pteroglossus mariae","overview":"褐嘴簇舌巨嘴鸟（英文名：Brown-mandibled Aracari，学名：Pteroglossus mariae），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。是攀禽中的一种中型鸟类，外形与犀鸟相似。上体呈黑色，腰部为深红色，雄鸟头部栗色，项和咽喉有独特的黑色或红色斑纹，羽色排列成类似“王”字的图案。臀部红色，颌部为柑橘色，长喙象牙色，边缘具锯齿状结构，似牙齿。分布在南美洲亚马孙雨林西南部，从东部秘鲁至巴西西部的亚马逊河以南，直至玻利维亚中部。","appearance":"褐嘴簇舌巨嘴鸟长约36至45厘米，重120至160克。成年雄鸟特征明显，有黑色顶冠、栗色头颈、红色颈背、绿色下背及红色臀部，喉下有黑色窄带，胸上部有宽红带，胸下部有黑带，腹部黄色，大腿绿色。雌鸟顶冠暗棕色，喉下黑色窄带比雄鸟更细。两性喙色独特，上喙黄至象牙色，边缘有黑色和白色标记，下喙橙棕色，尖端象牙色或黄色，基部有垂直黄色线。","call":"其鸣唱特征为一系列2至6个哀婉的‘twaaa-a-a’或‘tweee-ee’或‘traaa-at’音符，另有咔哒声、咕哝接触音、鼻音‘nyek’、嗡嗡音、警报声‘kyeek’以及纯咔哒声‘bddddt’。","habits":"褐嘴簇舌巨嘴鸟栖息于多种森林环境，偏好早期至中期演替森林而非成熟森林，常见于海拔600米以下，偶尔可达900米。它们全年在其范围内居住，主要在森林上层和树冠活动，通常成对或小群觅食，饮食以水果为主，辅以节肢动物。","breeding":"繁殖季节从2月至8月，推测在树洞中筑巢，每窝产2至4枚光滑白蛋，孵化期约16天，雏鸟孵化后至少3周才能睁眼，约45天后开始独立生活。","identification":"与白嘴簇舌巨嘴鸟相比，褐嘴簇舌巨嘴鸟主要通过喙的颜色区分，且两物种在分布区重叠时会相互杂交。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从东部秘鲁至巴西西部的亚马逊河以南，延伸至玻利维亚中部，栖息于各种森林景观。","other":"簇舌巨嘴鸟属中少数两性差异显著的种类，雏鸟四周大即可通过体羽辨别性别。现为白嘴簇舌巨嘴鸟亚种。"},{"name":"黑颈簇舌巨嘴鸟","english_name":"Black-necked Aracari","scientific_name":"Pteroglossus aracari","overview":"黑颈簇舌巨嘴鸟（英文名：Black-necked Aracari，学名：Pteroglossus aracari），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。属于中型攀禽，外形类似犀鸟。分布于南美洲东北部和东部，包括巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉。此鸟以黑色头部、橄榄绿背部和双色喙著称，喙上方淡色下方黑色。","appearance":"成年黑颈簇舌巨嘴鸟体长43至46厘米，体重介于177至325克之间。雄鸟和雌鸟的羽色和喙色相同，但雌鸟的喙较短。头部、颈部和喉部呈黑色，耳羽呈栗黑色。上体主要是绿色，臀部鲜红，下体黄色，下胸部有一宽大的红带，大腿绿褐色。喙的上半部象牙色，下半部黑色，基部有一条垂直的白色线。幼鸟的黑绿色羽毛比成鸟暗淡，红色和黄色部分颜色较浅，喙色偏棕色，没有‘牙齿’状的结构，也没有白色的基部线条。","call":"黑颈簇舌巨嘴鸟的常见叫声为'tsee-eet'到'sneet'，有时延长为'tseeeeeee-it'，也会发出像是'bdd-dddit'的响声，可能是叫声或是喙碰撞的声音。","habits":"黑颈簇舌巨嘴鸟栖息于多种半开放的景观，包括湿热森林、沙丘森林、次生林、木地、cerrado、草原中的画廊森林以及果园（如木瓜）。它们在低地森林的边缘和空旷地带活动，高度多在海平面至约600米，但在委内瑞拉和东南部地区可达更高海拔。这种鸟以群居形式生活在小群中，数量可达六只，偶尔更多，它们主要以各种水果为食，偶尔捕食昆虫，甚至幼鸟。","breeding":"繁殖季节在大部分地区为11月至8月，南部地区则为9月至2月。成对繁殖，繁殖期间的展示行为包括摇臀、甩头、鞠躬和翘尾。巢建于旧啄木鸟洞中，有时会自行挖掘。每窝产卵2至4枚，由双方共同孵化，孵化期16至17天。刚孵化的雏鸟裸身、灰色，坐在跗跖垫和泄殖腔上。雏鸟由双方父母喂养，有时父母会在接近巢穴时反刍食物，幼鸟约在40天左右离巢，之后家庭群体会离开巢穴。","identification":"与栗耳簇舌巨嘴鸟相比，黑颈簇舌巨嘴鸟的头部至上胸和上背几乎全黑，喙更白，少橙黄色，上喙较少黑色。雌鸟与雄鸟相似，但喙较短。幼鸟的羽毛颜色暗淡，红色和黄色较淡，喙色偏棕色，没有明显的‘牙齿’状结构和白色的基部线条。","protection":"IUCN：LC（无危）","distribution":"黑颈簇舌巨嘴鸟广泛分布于南美洲东北部和东部，包括巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉。在低地森林中，它们通常在海拔600米以下活动，但在委内瑞拉和东南部地区，它们的分布可高达1000米。","other":"黑颈簇舌巨嘴鸟在一些地方被猎杀，曾经有人一天内猎杀了150只个体。尽管如此，它们在多个保护区中得到保护，例如委内瑞拉的Imataca森林保护区和El Dorado，以及巴西的Rio Doce州立公园、Sooretama生物保护区和Parque Estadual da Pedra Talhada。"},{"name":"栗耳簇舌巨嘴鸟","english_name":"Chestnut-eared Aracari","scientific_name":"Pteroglossus castanotis","overview":"栗耳簇舌巨嘴鸟（英文名：Chestnut-eared Aracari，学名：Pteroglossus castanotis），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。属于巨嘴鸟科，体型中等，分布于南美洲西部至巴西东南部的热带雨林区，以其独特的外观和生活方式著称。","appearance":"成年栗耳簇舌巨嘴鸟长度介于43至47厘米之间，体重在220至310克范围内。雄鸟具有黑色冠至颈背，头侧棕色至栗色，下喉黑色；背部暗绿色，臀部红色。下体主要为黄色，腹部带有红带，形成显著的腰斑。喙色彩丰富，基部橙黄，上颌主要黑色，边缘呈锯齿状，似牙齿。雌鸟色泽较淡，喉部黑色带较窄，喙更短。幼鸟色彩较暗淡，喙的图案不明显。","call":"主要鸣叫声为刺耳的‘sneeep’至更长的‘psheee-eeep’，以每秒约2次的频率发出，高亢而尖锐；还发出单音‘tekk’，低沉的‘eeee-eee’，四声哨音‘weet’，以及‘pyeee-tyee-tyee-tyee-tyet’。","habits":"栗耳簇舌巨嘴鸟栖息于热带雨林，偏好森林边缘和年轻森林，常在果园和人类居住地附近出现。以水果为主食，如Cecropia、Coussapoa、Ficus、Ocotea等，偶尔摄取花朵、花蜜和昆虫。也会猎捕巢中幼鸟和寻找鸟蛋，已知会攻击黄腰酋长鹂的巢穴，成功率约为24%。在觅食时，它们会探查树洞和裂缝。","breeding":"繁殖季节因地区而异，北部和西部为2月至9月，玻利维亚为6月至1月，东南巴西、东北阿根廷和东部巴拉圭为9月至2月。巢穴通常位于旧啄木鸟的洞中，可能需要扩大洞口。每窝产卵2枚，最多可达4枚，孵化期和育雏期未知。","identification":"与其他Aracari相比，栗耳簇舌巨嘴鸟拥有蓝色眼周皮肤和黄色腹部上的单一红带。雌雄差异体现在色彩和喙的长度上。亚种P. c. australis颜色更浅，脸颊和上喉部锈色，胸带红混有锈色。","protection":"IUCN：LC（无危）","distribution":"分布于南美亚马逊盆地的西部和南部，包括哥伦比亚南部和东部、厄瓜多尔东部、秘鲁东南部、巴西沿亚马逊河至里奥内格罗和阿克雷、亚马逊州，以及巴西南部、玻利维亚北部、巴拉圭东部、阿根廷东北部的米西奥内斯省至巴西东南部的米纳斯吉拉斯、圣保罗州和里奥格兰德杜苏尔。","other":"在一些地方，栗耳簇舌巨嘴鸟被认为是较为普遍的物种，尤其是在哥伦比亚和秘鲁。它适应性强，能够容忍环境变化，比其更依赖森林的近亲更为适应。"},{"name":"多斑簇舌巨嘴鸟","english_name":"Many-banded Aracari","scientific_name":"Pteroglossus pluricinctus","overview":"多斑簇舌巨嘴鸟（英文名：Many-banded Aracari，学名：Pteroglossus pluricinctus），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。常见于南美洲亚马孙雨林西北部。以独特的腹部条纹和鲜明的黑黄红三色喙尖为显著特征。","appearance":"体长43至46厘米，体重215至302克。雄鸟头部、喉部及颈部黑色，眼后具一小片栗色区域；背部暗绿色，臀部红色；腹部黄色，上胸带红色，前腹带黑色，后腹带黑红相间；大腿部栗色、绿色和黄色混杂。喙基橙黄色，上喙橙黄带宽黑脊和黑色基部；眼周皮肤蓝绿至绿色；眼睛黄色。雌鸟喙较短，胸部栗色较少或无，平均黑色胸带更宽。幼鸟羽毛较松散，颜色较暗淡，尤其是黄色部分；大腿部绿色；喙灰色、棕色、角质色和黑色，无成年鸟的色彩模式，无喙齿和基线。","call":"发出\"seeent\"、\"seeet\"或\"see-yeet\"音调，常成对或快速连发，功能不明，可能作为联系、攻击和警报信号；尾音可能粗糙，类似\"bbbrt\"，与“无斑”的簇舌巨嘴鸟和红颈簇舌巨嘴鸟的部分叫声相似。","habits":"栖息于低湿的原始森林，较少见于várzea和画廊森林。活动于低地到海拔500-750米的湿润热带森林，沿安第斯山脉可达900米。成对或小群体在树冠层觅食，以各种水果为主食，偶尔食用节肢动物。","breeding":"繁殖季节可能在哥伦比亚和厄瓜多尔为11月至3月，在其余范围内为3月至10月。其繁殖生态细节尚不清楚。","identification":"与其他巨嘴鸟区别在于腹部的条纹图案。雌鸟与雄鸟的主要区别在于喙的长度和胸部栗色区域的有无。幼鸟与成鸟相比，颜色较为暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于东北哥伦比亚、西北及东南委内瑞拉，向南延伸至东北秘鲁（南至Ucayali河，但大多位于Marañón河以北）和巴西西北部（亚马逊河北岸，东至Roraima州、白兰哥河和上Japurá河）。"},{"name":"领簇舌巨嘴鸟","english_name":"Collared Aracari","scientific_name":"Pteroglossus torquatus","overview":"领簇舌巨嘴鸟（英文名：Collared Aracari，学名：Pteroglossus torquatus），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。分布于中美洲至南美洲的墨西哥至委内瑞拉地区。其显著特征为黑色或墨绿色的上体，腰部深红，以及黄色为主的下体，带有独特的黑色与红色斑纹。长喙色彩斑斓，由黑、黄、红三色组成。","appearance":"领簇舌巨嘴鸟是一种中型攀禽，体长38至41厘米，体重175至250克。其上体黑色或墨绿色，腰部有醒目的深红色，头部黑色，下体主要为黄色，带有黑色与红色的斑纹，形成一大块胸斑。长喙呈现黑、黄、少许红色，边缘具明显的锯齿状结构，表面黑色或象牙色，喙骨轻巧，中间充满空气，减轻了重量。雌雄羽色相似，但雌鸟的喙较短，雏鸟外观较暗淡，缺乏成鸟的鲜艳色彩。","call":"领簇舌巨嘴鸟发出的叫声多样，包括尖锐的‘seek’、‘pseek’、‘pink’或‘penk’声，两音节的‘pi-cheet’或‘squi-zeek’声，还有‘purr’声和激昂的‘grhhrr’声，甚至有非发声的‘bddddddt’颤音。","habits":"领簇舌巨嘴鸟栖息于暖林及边缘地带，偏好树梢生活，常成群活动，群体规模可达6至15只，有时与其他巨嘴鸟混群。它们的饮食以水果为主，但也食用大型昆虫、其他鸟类的卵与雏鸟以及小型脊椎动物。觅食时，它们从树冠至林下各层次活动，以喙伸展、弯曲甚至倒挂的方式摘取果实。","breeding":"繁殖季节通常从1月至5月，领簇舌巨嘴鸟在树洞中筑巢，通常利用啄木鸟挖掘的洞穴或自然形成的空洞。每窝产卵2至5枚，孵化期约为16至17天，期间双亲共同孵化。幼鸟孵化后需26至30天离巢，期间由双亲及最多三位辅助成鸟喂养，初期以昆虫为主食。","identification":"与其他巨嘴鸟相比，领簇舌巨嘴鸟具有明显的红色颈环，这是其独特标识。与其他亚种的区别在于胸部黑斑的大小和喙基部白色线的宽度。","protection":"IUCN：LC（无危）。虽然领簇舌巨嘴鸟的分布范围广泛，但其种群数量被认为正在减少，对森林砍伐较为敏感，且受到土著居民的猎杀威胁。","distribution":"分布于中美洲的墨西哥至南美洲的哥伦比亚和委内瑞拉，栖息于从海平面至约1000米的海拔高度。","other":"领簇舌巨嘴鸟属于巨嘴鸟科中少数具有明显两性异形的种类之一。"},{"name":"斑嘴簇舌巨嘴鸟","english_name":"Stripe-billed Aracari","scientific_name":"Pteroglossus sanguineus","overview":"斑嘴簇舌巨嘴鸟（英文名：Stripe-billed Aracari，学名：Pteroglossus sanguineus），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的中型攀禽。上体黑色，腰部深红色，头部通常为黑色，下体以蓝色为主，眼角处有一块红色斑纹。长喙色彩斑斓，由黑色、黄色、象牙白、橙色、红色等多种色调构成，重量不足30克。分布于哥伦比亚西部、厄瓜多尔西北部以及巴拿马东部。","appearance":"斑嘴簇舌巨嘴鸟总长约40.5至43厘米，喙长11.5至12.5厘米。体重介于175至250克之间。雄鸟和雌鸟的颜色相似，但雌鸟喙较短。成鸟的喙基部有窄的垂直白色条纹，上喙黄色，下缘有黑色条纹，上喙顶部黑色，下喙黑色。上体多为光泽黑，腰、臀及上尾覆羽亮红，头、喉及上胸绿黑，下胸、腹及下尾覆羽黄，胸带可变红，中心有黑点，上腹有红黑带，大腿棕色。幼鸟比成鸟暗淡，头部和胸部呈烟灰黑色，上体橄榄棕色，红色臀部和黄色下体较淡，胸点、腹带和喙图案模糊。","call":"其典型叫声为高亢、尖锐、类似尖叫的“ksisik”或“ksiyik!”。","habits":"斑嘴簇舌巨嘴鸟常结群旅行，群体由六至十五只组成，有时会与其他巨嘴鸟混群。它们栖息于热带雨林内部和边缘，成熟次生林以及咖啡、可可和水果种植园。它们主要以水果为食，但也捕食大型昆虫、其他鸟类的卵和幼鸟，以及小型脊椎动物。觅食活动主要在森林中层至冠层进行，偶尔也会在林下层觅食水果。","breeding":"繁殖季节为12月至次年5月。它们在树洞中筑巢，通常利用木啄鸟挖掘的洞穴或自然形成的洞穴，有时会扩大巢穴。巢穴高度可达30米。每窝产卵数量通常是三枚，但最多可达五枚。孵化期为16至17天，双亲共同孵化。幼鸟孵化后26至30天离巢。父母及多达三只成年辅助鸟提供食物，主要喂食幼鸟昆虫。","identification":"斑嘴簇舌巨嘴鸟与其他巨嘴鸟的区别在于其独特的色彩组合，尤其是腰部的深红色，以及下体的黄色。喙的锯齿状边缘和色彩搭配也是辨识要点。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体包括哥伦比亚西部、厄瓜多尔西北部以及巴拿马东部的Darién省，向南至哥伦比亚西部及厄瓜多尔Esmeraldas和Imbabura省份。","other":"虽然能够适应次生林环境，但仍然对森林砍伐极为敏感。现为淡嘴簇舌巨嘴鸟亚种。"},{"name":"淡嘴簇舌巨嘴鸟","english_name":"Pale-mandibled Aracari","scientific_name":"Pteroglossus erythropygius","overview":"淡嘴簇舌巨嘴鸟（Pale-mandibled Aracari，Pteroglossus erythropygius）是簇舌巨嘴鸟属最北端的成员之一，分布于墨西哥韦拉克鲁斯中部至委内瑞拉北部、厄瓜多尔西部。其为中型专食果实的鸟类，主要活动于海拔1000米以下的湿润低地原生林、次生林、林缘碎片及咖啡、可可、水果种植园。常结成3-10只的小群在林冠及亚林冠层活动，飞行或鸣叫时极易被发现，安静觅食或巢边活动时可被忽略。","appearance":"淡嘴簇舌巨嘴鸟体长38–43厘米，体重雄鸟平均228.7克，雌鸟216.4克。成鸟上体及头、喉、上胸为光泽黑色，后颈有一条不显眼的肉桂栗色领环；腰、尾上覆羽鲜红；下体黄色，胸部中央具黑色圆斑，胸羽带红色晕染；腹部有一条细窄红黑相间的横带；胫羽肉桂栗色。裸露的面部皮肤红色。嘴形细长，上嘴基部有一条白色垂直细线，上嘴淡灰角质或稍带白色，具黑色脊棱及尖端，基部常带红色；下嘴黑色。雌鸟与雄鸟极似，仅耳羽基部有一小栗斑或领环色略深，且嘴略短。幼鸟全身色暗淡，头胸烟黑，背褐橄榄，腰羽红色较暗，胸斑及腹带模糊，嘴纹不显。","call":"常见叫声为高而尖的“seek、pseek、penk”或双音节“pi-cheet、squi-zeek”。亦可连续发出逐渐升高、逐渐衰弱的“peetch”，同时左右摆头。另有攻击或起飞前的颤音“bdddtdt”。其他声音包括“purrr”常与颤音或“seek”结合，以及粗哑攻击声“grhhrr”。飞翔时翼振声清晰可闻；成鸟有时以嘴敲击巢口发出声响，也可能通过舌在嘴内颤动产生机械声。","habits":"栖息于低地常绿林、林缘、成熟次生林及种植园，在哥伦比亚北部与委内瑞拉局部干旱区亦见于河岸林。海拔分布从海平面至墨西哥1300米、哥斯达黎加1000-1200米、哥伦比亚800米、委内瑞拉1000米、厄瓜多尔1500米，但通常低于1100米。为留鸟，飞行快速，振翅与短滑交替。常6-15只成群活动于中上层树冠，沿枝干跳跃前进，亦会在树洞积水处洗浴，侧躺枝条上晒太阳。觅食以树冠结果树为主，偶尔下降至下层食果实。食性以果实为主，已知取食多种榕果、棕榈果及热带果树；也吃大型昆虫、小型脊椎动物并掠食其他鸟类的卵和雏鸟。进食时多次吞咽与回吐整粒种子，以清除果肉。","breeding":"繁殖期在大部分分布区为1–5月，哥伦比亚全年均可，厄瓜多尔西部始于12月。巢筑于由大型啄木鸟凿出的树洞或天然洞，距地6–30米。巢口平均9.75×6.75厘米，洞深平均138厘米。每窝2–5枚纯白卵，多为3枚，卵大小33–35×24毫米。双亲轮流孵化16–17天；育雏期43–46天。育雏时前期以昆虫为主，后期增加果实。曾有记录显示一巢由多达5只成鸟共同喂养，表明存在巢中帮手。巢洞至少可连续两年被重复利用。","identification":"在大部分分布区内，淡嘴簇舌巨嘴鸟是唯一的簇舌巨嘴鸟属成员，不会与体型更大的黑嘴巨嘴鸟、 厚嘴巨嘴鸟和乔科巨嘴鸟混淆。太平洋沿岸的哥斯达黎加及巴拿马西北部由红嘴簇舌巨嘴鸟取代，两者羽色极似，但红嘴簇舌巨嘴鸟胸斑更大，腹带全红且宽，上嘴呈深橙至朱红色。与同属其他亚种的区别在于上嘴无黑纵纹，下嘴除尖端外大部为黄白色。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：墨西哥南部（除尤卡坦半岛）经中美洲至哥伦比亚西北角及厄瓜多尔西部；分布连续但避开哥斯达黎加西南与巴拿马西部，由红嘴簇舌巨嘴鸟取代。太平洋坡自墨西哥南部经西哥伦比亚至厄瓜多尔埃尔奥罗，偶见于秘鲁通贝斯。","other":"淡嘴簇舌巨嘴鸟常与同属的 sanguineus 在厄瓜多尔皮钦查省杂交，形成中间类型。因森林砍伐，局部范围已出现收缩。注意当前描述包括领簇舌巨嘴鸟（AviList 中为独立种），而斑嘴簇舌巨嘴鸟为本种亚种。"},{"name":"红嘴簇舌巨嘴鸟","english_name":"Fiery-billed Aracari","scientific_name":"Pteroglossus frantzii","overview":"红嘴簇舌巨嘴鸟（英文名：Fiery-billed Aracari，学名：Pteroglossus frantzii），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。分布于中美洲，包括哥斯达黎加和巴拿马西部。以鲜艳的橙色上喙和红色腹部条纹为显著特征。","appearance":"红嘴簇舌巨嘴鸟长约45厘米，体重介于225至280克。雄鸟拥有黑色头、喉部，栗色颈环，蓝绿色背部与红色臀部；下体黄红相间，胸部有黑斑，腹部有红色条纹。喙部特征明显，基部有象牙色线条，下喙黑色，上喙主要为红色，尖端黄色，基部绿意盎然，上喙缘黑色，锯齿状不明显；眼周皮肤红色，眼眶上方区域黑色。雌鸟与雄鸟相似，但颈环颜色更深，喙稍短。幼鸟色泽较暗淡，喙的图案模糊。","call":"发出高音调的'pseep'到'sis-sik'系列叫声，与领簇舌巨嘴鸟类似。也会发出低沉的叫声和柔和的颤音。","habits":"栖息于湿润的原始森林和次生林内部及边缘，海拔范围从海平面至1200米，偶尔可达1800米。以水果为主食，辅以大型昆虫、其他鸟类的蛋和雏鸟以及小型脊椎动物。通常成群活动，数量可达10只，主要在树冠层觅食，但也会在低矮的灌木丛中觅食浆果。","breeding":"繁殖季节为1月至4月，可能在巴拿马会更晚。成对或三只一起繁殖，亚成鸟占群体多数。通过击打喙部的方式进行“决斗”，并以喂食浆果和大果实碎片进行求偶。利用旧的啄木鸟巢或驱逐啄木鸟占据新巢。每窝产卵2枚，孵化期未知，由父母和帮手轮流孵化，孵化期间覆盖卵约65%的白天时间，平均每次15至27分钟。雏鸟最初以昆虫为食，随后转为以水果为主。离巢期未知，两只幼鸟间隔3天离巢。刚离巢的幼鸟会被引导回巢休息。","identification":"与领簇舌巨嘴鸟相似，但可通过上喙尖端的黄色和绿色基部，以及更不显眼的锯齿状特征和更红的腹部条纹来区分。","protection":"IUCN：LC（无危）。红嘴簇舌巨嘴鸟的种群估计至少有50,000只成熟个体，虽然数量可能正在减少，但在哥斯达黎加至少有两个保护区内出现。","distribution":"分布于中美洲，具体而言，从哥斯达黎加的尼科亚湾向南至巴拿马的奇里基省西部。曾经向东延伸至巴拿马的维拉瓜斯省。","other":"其特定种名纪念德国自然学家Alexander von Frantzius。"},{"name":"曲冠簇舌巨嘴鸟","english_name":"Curl-crested Aracari","scientific_name":"Pteroglossus beauharnaisii","overview":"曲冠簇舌巨嘴鸟（英文名：Curl-crested Aracari，学名：Pteroglossus beauharnaisii），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。以其独特的卷曲、光泽的黑色头冠和鲜明的红绿黄配色羽毛闻名。分布于亚马逊雨林西南部，主要在巴西、秘鲁和玻利维亚的热带湿润森林。","appearance":"体长42至46厘米，体重164至280克。特征为相对短的喙和非常长的尾巴。头部顶部有卷曲、改良的亮黑色羽毛，上背部和臀部红色，其余上体暗绿色。喉咙淡色，带有黄色白色羽毛，尖端有闪亮的黑色斑点，有时延伸至黄色胸部，下胸带红色，腹部黄色，下覆羽黄色，可能显现出红色。喙基部棕色橙色线，下颌象牙色，逐渐变橙至尖端，橙色鼻脊扩展至尖端，然后转为黄色，上颌有紫红色条纹，两侧逐渐变窄，上方绿色或蓝色，切缘‘牙齿’象牙白。眼周蓝色皮肤，眼睛上方和后面红宝石色，常被羽毛遮盖，虹膜红色。雌鸟喙比雄鸟短。幼鸟色泽较暗。","call":"叫声不如其他簇舌巨嘴鸟响亮，包括一系列深沉的‘rrek’音符，柔和的‘rrr’到硬朗甚至似咕噜的‘grenk’音符。也有较轻柔的‘et-et’声当它们安顿在栖息处时，另一资料源还提到低沉、粗糙的‘cha-cha-cha cha wruh cha--’。","habits":"栖息于低地湿热森林，包括排水良好和沼泽地带，森林边缘和空地，也见于较低的山地森林，通常海拔低于500米，但在靠近安第斯山脉时可达约900米。以群体形式觅食，通常3至12只一起，主要在树冠层，但也会在开阔地带的灌木丛低至1.2米处觅食。饮食以果实为主，如无花果和Ocotea的果实，偶尔会吃其他鸟的蛋和幼鸟，尤其是繁殖期间需要蛋白质时。已知会猛烈攻击并摧毁黄臀霸鹟的巢穴。","breeding":"繁殖季节主要在5月至8月，偶尔延至11月或2月。记录显示6月在马托格罗索和帕拉州有交配行为。可能在群体中繁殖。展示行为包括深鞠躬和叫声，伴随追逐跳跃。巢和蛋的详细信息未知。","identification":"与其他簇舌巨嘴鸟相比，面部图案更为模糊，头部灰色覆盖着柔软的卷发。下腹部有一单一的红色带。雌鸟比雄鸟喙短。幼鸟色彩较暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于亚马逊盆地南部，从秘鲁北部（位于马拉尼翁河以南）和巴西西部（东至马德拉河口，更南至上辛古河；帕拉州西南部有孤立记录）至玻利维亚北部和中部（潘多省、科恰班巴）以及巴西北马托格罗索。","other":"系统发育历史中，曲冠簇舌巨嘴鸟与同属物种明显不同，过去曾被单独归入单型属或亚属Beauharnaisius；但遗传数据显示该物种嵌入Pteroglossus中，与红颈簇舌巨嘴鸟（含sturmii）为姐妹种。"},{"name":"橘黄巨嘴鸟","english_name":"Saffron Toucanet","scientific_name":"Pteroglossus bailloni","overview":"橘黄巨嘴鸟（英文名：Saffron Toucanet，学名：Pteroglossus bailloni），是䴕形目巨嘴鸟科簇舌巨嘴鸟属的鸟类。以其独特的金黄色和橄榄色羽毛，红色臀部和两色的长喙而闻名，喙的上半部为淡绿色，下半部蔚蓝，基部有红色。分布于巴西东南部、巴拉圭东部和阿根廷东北部的亚热带湿润森林。","appearance":"雄性橘黄巨嘴鸟呈现鲜明的金黄色、橄榄色和红色臀部，喙部颜色丰富，由绿色、灰色和黄色构成。雌鸟相似但更偏橄榄色，且喙部较短。幼鸟羽毛较为灰暗，喙部斑驳，眼睛棕色。体长约35至39厘米，体重介于129.8至168.6克之间。","call":"拥有丰富的声音库，包括一系列节奏加快的‘teeee-up’音符，类似Pteroglosslus azara的鸣唱，以及类似啄木鸟的‘yeep’或‘yi’音符，还有低沉的‘eeeeee’音符和柔和的‘uh’或‘perp’音。","habits":"栖息于亚热带湿润森林的斜坡和溪流旁，偶尔出现在次生林和被选择性砍伐的森林边缘。以水果为主食，如Cecropia、Ficus等，偶尔吃年轻鸟类和鸟蛋。活动于海拔1550米以下，通常在400至600米高度。以小群体活动，有时会访问人工喂食站。","breeding":"繁殖季节在北部地区为6月至7月，大部分地区为12月至4月。巢穴通常在旧的啄木鸟洞中挖掘。雌雄双方共同参与孵化2至3枚白色卵，孵化期约为16天。","identification":"与同属物种相比，橘黄巨嘴鸟的金黄色和两色喙是其显著特征。幼鸟与成鸟在颜色上有明显差异。","protection":"IUCN：NT（近危）；CITES: II级。在巴西、巴拉圭和阿根廷的多个保护区中有所分布。","distribution":"分布在巴西东南部（包括佩南布科、巴伊亚、埃斯皮里图桑托和邻近的米纳斯吉拉斯至圣卡塔琳娜和里奥格兰德杜苏尔的极北端）、巴拉圭东部和阿根廷东北部（北米西奥内斯）。","other":"面临的主要威胁包括笼鸟贸易、狩猎和栖息地丧失。物种对森林碎片化高度敏感，可能因农业和牧场耕作而遭受损失。"},{"name":"黄耳小巨嘴鸟","english_name":"Yellow-eared Toucanet","scientific_name":"Selenidera spectabilis","overview":"黄耳小巨嘴鸟（英文名：Yellow-eared Toucanet，学名：Selenidera spectabilis），是䴕形目巨嘴鸟科小巨嘴鸟属的鸟类。攀禽，以其金黄色的耳羽和独特的羽色图案著称，分布于中美洲至南美洲的森林地带，从洪都拉斯至哥伦比亚西南部。雄鸟具有鲜明的黑身配亮黄色颊斑，雌鸟则有栗色的头部和蓝绿眼周裸皮。","appearance":"黄耳小巨嘴鸟体长36-38厘米，体重175-245克。雄鸟拥有黑色的冠至颈背，黄色耳羽，绿色背部和上尾覆羽，黑色尾巴，腹部黑色至黄色侧腹斑，红棕色大腿，红色下尾覆羽。雌鸟额至颈背为栗色，无黄色耳羽，喙较短。幼鸟色彩较为暗淡，羽毛质地松散，喙的图案模糊。喙长且轻，外层为角质鞘，内部中空，有细骨质支撑。面部和下颌裸露皮肤颜色鲜艳。","call":"发出一系列短至长的双音节鸣叫“tik-ett”，常伴随喙的咔哒声，频率为每秒1.1-1.8个音符。有时成对同时歌唱，也会发出长或短的咔哒声。","habits":"栖息于海拔300至1,100米的湿润森林斜坡和山脊，偶尔降至海平面，最高可达1,500米。通常成对或小群体在森林中层至树冠觅食，以水果为主食，亦食用昆虫、蜘蛛和蜥蜴。","breeding":"繁殖季节大致在4月至8月，可能最早在2月开始。求偶时，成鸟边唱歌边摇晃头部和尾巴。窝卵数估计为2至4枚，其余繁殖细节未知。","identification":"与其他Selenidera属物种相比，体型更大，喙部图案独特，缺乏黄色领圈，尾羽无栗色尖端。雌鸟与雄鸟的区别在于无黄色耳羽，喙更短。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从东北部洪都拉斯至哥伦比亚西南部，包括西北部厄瓜多尔（埃斯梅拉达斯）。"},{"name":"圭亚那小巨嘴鸟","english_name":"Guianan Toucanet","scientific_name":"Selenidera piperivora","overview":"圭亚那小巨嘴鸟（英文名：Guianan Toucanet，学名：Selenidera piperivora），是䴕形目巨嘴鸟科小巨嘴鸟属的鸟类。攀禽，体型较小，长度介于30至35厘米之间。该鸟以独特的外观和巨大的红黑相间鸟喙著称，雄鸟具有黑色头部和金色项圈，而雌鸟的羽色较为灰暗。分布于南美洲亚马逊雨林东北部，包括巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉。","appearance":"圭亚那小巨嘴鸟的雄鸟体重约129至159克，雌鸟约132至165克。其最显著的特征是长长的红黑相间的鸟喙，上颌和下颌大部分为黑色，基部有红色。雄鸟拥有黑色的冠、颈、喉、胸和腹部，背部上方有一圈金色的项圈，其余部分为绿色，尾部绿色带红棕色尖端，尾下覆羽为红色。雌鸟则有黑色的冠，颈背至背部为栗色，下体灰至绿灰色，腹部带有绿色。幼鸟较成鸟暗淡，黑色部位偏褐色，鸟喙模式不鲜明。","call":"该鸟的叫声多样，但发出的频率较低。其叫声包括一系列低沉、似蛙鸣的“arrouk”音符，基本的叫声为连续的颤音“trrrr-trrrr-trrrr...”，伴随上升的嘶叫，有时类似公鸡啼鸣的“kaaaaaaiiiiii”。还会有长啸声和各种柔和的颤音，用于不同的社交情境。","habits":"圭亚那小巨嘴鸟主要栖息于低地雨林，偶尔出现在稀树草原的画廊森林中，海拔高度通常不超过600米，但在委内瑞拉和苏里南可高达900米。它们被认为是留鸟，以水果为主食，包括辣椒、Cecropia和其他果实，偶尔食用昆虫。它们与Oenocarpus bacaba棕榈树有共进化关系，每次仅取少量果实。在森林的中层至次冠层活动，通常成对或小群体觅食。","breeding":"繁殖期在委内瑞拉和圭亚那为3月至5月，在巴西为4月至7月。雄鸟会向雌鸟喂食并进行求偶喂养，选择啄木鸟洞作为巢穴，例如波斑啄木鸟的巢洞。每窝产卵2至3枚，白色，孵化期约16天，但野外具体数据未知。雏鸟孵化后至少三周才能睁开眼睛，45天后离巢飞行。","identification":"与同类物种相比，圭亚那小巨嘴鸟的体型较小，雄鸟和雌鸟的颜色差异明显。雄鸟具有醒目的金色项圈和黑色头部，而雌鸟上体颜色较暗，呈栗色，下体灰至绿灰色。在野外可通过其叫声和活动范围加以识别。","protection":"IUCN：LC（无危）","distribution":"该物种分布于南美洲东北部，包括委内瑞拉东南部、圭亚那、苏里南、法属圭亚那和巴西北部，南至亚马逊河与Rio Negro之间的Amapá州。","other":"在一些地区，圭亚那小巨嘴鸟被认为是对果园有害的鸟种，因其食果习性。"},{"name":"金领小巨嘴鸟","english_name":"Golden-collared Toucanet","scientific_name":"Selenidera reinwardtii","overview":"金领小巨嘴鸟（英文名：Golden-collared Toucanet，学名：Selenidera reinwardtii），是䴕形目巨嘴鸟科小巨嘴鸟属的鸟类。为巨嘴鸟科小巨嘴鸟属的攀禽，体长30-35厘米，拥有独特的墨绿色身体和翅膀，红色腹部，蓝绿色眼周裸皮，最显著特征是颈部一圈金黄色羽毛。雄鸟具黑色冠羽，雌鸟羽色偏棕色，雏鸟四周大时可辨性别。分布于南美洲亚马逊雨林西部。","appearance":"雄鸟头部至肩部黑色，黄绿耳羽，绿色背部和尾部带栗色尖端，腹部黑色，金黄色或橙金色侧腹，红色尾下覆羽。雌鸟胸部棕色代替黑色，耳羽暗淡，侧腹较淡黄色，上背黄色带窄。幼鸟整体较暗，尾下覆羽锈橙色，性别特征早期显现。鸟喙庞大，实际轻盈，角质鞘包裹中空结构，内部有骨质支撑。喙缘锯齿状，喙基无口须，脸和下颚裸露皮肤色彩鲜艳。","call":"发出一系列约4-14个‘ggrraawk’音符，每分钟60-85次，音符长于高氏小巨嘴鸟和点嘴小巨嘴鸟，节奏接近点嘴小巨嘴鸟。还包括‘eh’、‘uh’、‘kik’和其他柔和声音。在争斗时会大声摩擦鸟喙。","habits":"栖息于低地和较低山地森林，偶尔出现在泛洪平原森林和várzea，更偏好干燥的上层森林和山脊。常在森林边缘活动，但不进入次生林。海拔范围一般在约1000米，秘鲁可达1500米，玻利维亚西北部可达1300米。以果实、种子和昆虫为主食，有时损害果园。","breeding":"繁殖季在哥伦比亚和厄瓜多尔为3月至7月，在秘鲁、玻利维亚和巴西西部为6月至12月。雄鸟向雌鸟展示喂食行为，巢建于树洞中，洞深17厘米至2米。每窝产卵至少3枚，孵化期约16天。雏鸟孵化后需3周才能睁眼，45天后离巢飞翔。","identification":"与金领小巨嘴鸟相比，S. langsdorffii眶区更绿，侧腹更橙色，主要区别在于喙的颜色：上喙主要黑色，下喙前端黑色，其余部分绿色至灰绿色，‘牙齿’奶油色至白色，或几乎全黑，或有2-4条垂直或倾斜的黑色线在上喙切缘上方，类似于点嘴小巨嘴鸟的模式。喙略宽。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊雨林西部，具体包括南哥伦比亚、东厄瓜多尔、北秘鲁、西巴西至普鲁斯河和马德雷河，南至玻利维亚西部。","other":"在哥伦比亚普遍稀少，在厄瓜多尔不常见至相当常见。在秘鲁局部地区报告为相当常见，但在森林中的密度仅约1对/100公顷。"},{"name":"褐须小巨嘴鸟","english_name":"Tawny-tufted Toucanet","scientific_name":"Selenidera nattereri","overview":"褐须小巨嘴鸟（英文名：Tawny-tufted Toucanet，学名：Selenidera nattereri），是䴕形目巨嘴鸟科小巨嘴鸟属的攀禽。分布于南美洲亚马逊雨林的中北部，具有独特的蓝斑红喙特征。雄鸟头部、项喉至胸部为黑色，雌鸟相应部位为栗褐色。成年个体长约32-33厘米，体重约148-165克。","appearance":"体长32-33厘米，重148-165克。上身绿色，腹部红色，尾羽中央三对有栗色尖端。雄鸟头部、颈、喉至腹部黑色，雌鸟相应部位栗褐色。两性均有黄色至锈色耳羽和金黄至锈色腰带。雄鸟面部裸皮天蓝色，雌鸟较淡。喙基有垂直红线，喙顶绿色至黄绿，其余部分红至褐红，具蓝斑和白色“牙齿”。","call":"发出缓慢、深沉的系列‘ggrawnk’至‘ggrraaw’音符，类似蛙鸣，容易被忽视。","habits":"栖息于低地雨林，偏好砂土环境，常靠近溪流。海拔分布400-1000米，杂食性，以果实、种子和昆虫为食，有时被视为果园害鸟。飞行特点不详。","breeding":"繁殖季节可能为3月至5月，也可能持续到11月。巢穴选在良好木质的树洞中，深度17厘米至2米。巢内无衬垫，卵产于木屑上，孵化期约16天，雏鸟45天后离巢。","identification":"可通过蓝斑红喙、雄鸟的黑头和雌鸟的栗褐色头部加以辨识。与同属其他物种的区别在于体型较小，耳羽颜色和面部裸皮颜色。","protection":"IUCN：LC（无危）","distribution":"分布于南美亚马逊雨林中北部，具体包括哥伦比亚东部、委内瑞拉南部、巴西西北部，以及可能的圭亚那地区。","other":"其饮食习惯和繁殖行为的细节尚需进一步研究。"},{"name":"高氏小巨嘴鸟","english_name":"Gould's Toucanet","scientific_name":"Selenidera gouldii","overview":"高氏小巨嘴鸟（英文名：Gould's Toucanet，学名：Selenidera gouldii），是䴕形目巨嘴鸟科小巨嘴鸟属的鸟类。小型、多彩的攀禽，名称纪念英国鸟类学家John Gould。雄鸟头部至肩部为黑色，雌鸟相应部位为栗色。广泛分布于巴西中东部亚马逊河以南地区，直至玻利维亚东部和马托格罗索州，栖息于热带湿润森林。","appearance":"高氏小巨嘴鸟长约33厘米，雄鸟体重介于138至209克，雌鸟稍轻，约131至183克。雄鸟头部至肩部黑色，耳羽金黄色，背部绿色，尾羽绿色带栗色尖端，腹面黑色，翼下覆羽红色，雌鸟黑色部位变为栗色。喙具独特三色分区：黑色、象牙白基部、橙黄色尖端，喙上有‘牙齿’状突起。面部裸露部分绿黄至蓝色，雌鸟颜色较暗淡。幼鸟色泽较为暗淡，喙部图案模糊。","call":"高氏小巨嘴鸟发出一系列深沉缓慢的‘ggrawnk’至‘ggrraaw’音节，易于被忽视。","habits":"栖息于低地湿润森林、季节性泛滥森林、廊道森林及老生次生林。觅食高度从中层至树冠，常在结果实的树木中活动。食物包括水果、可能的小型鸟类或爬行动物。","breeding":"繁殖季节估计在5月至9月间，具体筑巢、产卵、孵化和育雏信息尚不清楚。","identification":"与金领小巨嘴鸟和点嘴小巨嘴鸟在喙部色彩上相似，但分布区域不同。雌雄异色，雄鸟黑色，雌鸟栗色。","protection":"IUCN：LC（无危）","distribution":"分布于巴西中东部亚马逊河以南地区，从马代拉河东至马拉尼昂和塞阿拉北部，南至玻利维亚东部（马莫雷河、贝尼河和圣克鲁斯东北部），以及马托格罗索中部，可达巴拉圭河上游支流。","other":"能够利用次生林的能力有助于其生存。"},{"name":"点嘴小巨嘴鸟","english_name":"Spot-billed Toucanet","scientific_name":"Selenidera maculirostris","overview":"点嘴小巨嘴鸟（英文名：Spot-billed Toucanet，学名：Selenidera maculirostris），是䴕形目巨嘴鸟科小巨嘴鸟属的鸟类。攀禽，身长30-35厘米，以黑色和深蓝色羽毛为主，下腹部红色，具柑橘黄色标记。雄鸟头、颈、胸和腹黑色，雌鸟相应部位呈棕色。广泛分布于巴西东南部至巴拉圭东部和阿根廷东北部的亚热带湿润森林。","appearance":"点嘴小巨嘴鸟具有橄榄绿背部，眼周蓝裸皮，红腹，尾部中央三对羽毛带栗尖端。雄鸟头部和下体黑色，雌鸟相应部位褐色。幼鸟较暗淡，缺乏黄色颈带，喙色柔和。喙部灰白，具三道黑色条纹，尖端绿黄至象牙白，中央鼻嵴黑色，上喙有3-5垂直黑纹，下喙前端有小黑斑。喙型独特，轻巧，内部中空，支撑结构复杂。","call":"发出粗犷、嘶哑的‘ggrooaw’至‘kkrowk’音节，每分钟约75-90次，持续约15秒。两性通常交替鸣叫，偶尔同时发声，但不紧随其后。互动时发出相似音符，以及低沉‘tut’音，颤音，低哼，喙击声。","habits":"栖息于亚热带湿润原始森林、被选伐的森林、次生林、棕榈树林和灌木林，海拔可达1000米。以Euterpe、Cecropia等果实为主食，捕食昆虫和小型脊椎动物，偶见于开阔地带的孤立果树。饮水来自树隙。单个、成对或小群体活动。","breeding":"繁殖季节为北区12月至翌年6月，南区10月至翌年1月。巢建于树洞，双方共同筑巢。产卵2-3枚，孵化期约15天，雏鸟喂食果实和死鼠，发育缓慢，约25天可辨性别，31天体重达120克，6-7周离巢，成鸟哺育至约55天。","identification":"与高氏小巨嘴鸟区别在于喙部图案和颜色。雌雄差异明显，雄鸟黑头黑下体，雌鸟相应部位棕色。","protection":"IUCN：LC（无危）；CITES II级；巴西多个保护区存在，如伊瓜苏周边，但局部受森林损失威胁。","distribution":"分布于巴西东南部（巴伊亚至圣卡塔琳娜，可能至里奥格兰德杜苏尔）、东巴拉圭和阿根廷东北部（米西奥内斯省）。","other":"在野外，曾观察到一对点嘴小巨嘴鸟收养了两只2日龄的绿簇舌巨嘴鸟，并成功抚养。"},{"name":"灰胸山巨嘴鸟","english_name":"Grey-breasted Mountain Toucan","scientific_name":"Andigena hypoglauca","overview":"灰胸山巨嘴鸟（英文名：Grey-breasted Mountain Toucan，学名：Andigena hypoglauca），是䴕形目巨嘴鸟科山巨嘴鸟属的鸟类。属于巨嘴鸟科，中型攀禽，拥有极具特色的巨大而轻盈的喙，喙上色彩鲜艳，嘴缘带有锯齿。分布于南美洲的哥伦比亚中部至秘鲁，常在高海拔的湿润山地云雾林中出没。","appearance":"灰胸山巨嘴鸟体长41至48厘米，体重介于244至370克之间。其特征为黑色头冠、脸部和颈背，灰蓝至灰色的腹部，以及绿色调的棕色背部。雄鸟有明亮的黄色臀部，黑色至深褐色的尾巴，末端几对中央羽毛呈栗色，侧面和大腿部分为淡灰蓝色和栗色，尾下覆羽为红色。喙基部呈黄色至绿黄色，近基部有一黑色环带，上颌外侧2/3部分为红色，与黄色部分斜向相接，下颌外半部分为黑色。雌鸟喙较短，通常颜色较为暗淡。幼鸟羽毛较为暗淡，喙为棕色至黑色，无明显标记。","call":"灰胸山巨嘴鸟发出低沉的‘gweeeeeeeat’声，是已知最长的皮鸡目音符之一，缓慢重复，每分钟约24至36次，伴有偶尔的喙击声。此外，还发出‘wek’声，单独或连续，以及‘kek’声，用于警戒或攻击，频率可达每分钟160至180次。","habits":"生活在湿温带山地森林，包括云雾林、树线附近的矮树丛、边缘和次生林。栖息高度一般在2200至3650米之间，偶尔低至1500米。以水果、浆果为主食，包括Rubus、Cecropia和Ceroxylon quindiuense等植物的果实，也可能喂食幼鸟动物性食物。单个或小群体觅食，最高可达六个成员，通常保持安静并不显眼。在觅食时能倒挂。可能加入由金翅雀、鸫和新世界黑鸟组成的混群觅食。","breeding":"繁殖季节在哥伦比亚为12月至2月，在厄瓜多尔和秘鲁为6月至11月。关于繁殖行为、巢穴和卵的信息未知，可能占据大面积的家园或领地。","identification":"与冠山巨嘴鸟相比，灰胸山巨嘴鸟具有黑色喉部、暗色虹膜、红色缺失的喙和缺乏中央尾羽的栗色尖端；与黑嘴山巨嘴鸟的区别在于全黑的喙和较大的白色喉部。不同亚种间，如A. h. lateralis，有较浅的黄色臀部、浅黄色至灰白色的侧翼斑点和黄色到绿色的眼睛。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体包括哥伦比亚中部至秘鲁，栖息于湿温带山地森林，包括云雾林、精灵森林和次生林。在秘鲁，栖息高度通常在2200至3650米之间，但在部分地区可低至1500米，在厄瓜多尔则可低至1700米。","other":"在多个保护区中出现，包括厄瓜多尔的Las Cajas国家休闲区和Podocarpus国家公园。由于森林砍伐、农业扩张、采矿和伐木等活动，面临栖息地丧失的威胁，尤其是在哥伦比亚。"},{"name":"扁嘴山巨嘴鸟","english_name":"Plate-billed Mountain Toucan","scientific_name":"Andigena laminirostris","overview":"扁嘴山巨嘴鸟（英文名：Plate-billed Mountain Toucan，学名：Andigena laminirostris），是䴕形目巨嘴鸟科山巨嘴鸟属的鸟类。中型攀禽，以巨大而轻盈的喙著称，长度几乎占到体长的三分之一。分布于南美安第斯山脉的云雾森林，从哥伦比亚西南部至厄瓜多尔南部。其嘴上独特的黄色平板是其显著特征。","appearance":"体长约46至51厘米，体重275至355克。头部黑色，背部呈铜褐色，下体蓝灰色，侧翼有黄色斑块，大腿处呈栗色，尾羽黑色并带有栗色尖端。最显著的特征是其黑色的喙，上颌基部有红色，上颌近基部覆盖着突出的黄色平板。面部皮肤上方蓝色，下方黄色，眼睛棕红色。雌鸟比雄鸟略小，幼鸟喙色灰黑，黄色平板仅微现。","call":"发出一系列响亮的‘kyeeowp’至‘kyewp’声，每分钟35至42次，前有喙的咔哒声，逐渐变为‘eeeowp’音，失去咔哒元素。雌鸟的叫声音调更高。此外，还发出吱吱声，‘ddrak’可能作为联系叫声，‘ek-ek’叫声当伴侣接近时响起。","habits":"栖息于湿润的山地森林，海拔1300至2500米，偶尔下降至300米，罕见至3600米。以水果为主食，偶尔食用昆虫、鸟蛋和小型哺乳动物。在哥伦比亚，会撕开鸟巢捕食雏鸟。成群活动，高度可达2至30米。","breeding":"繁殖季节为3月至10月，筑巢于死树、树桩或电线杆中，巢入口圆形至椭圆形，直径约8厘米，深度约2米。每次产卵2至3枚，孵化期约16至17天。幼鸟4周左右睁开眼睛，46至60天离巢，主要在49至51天之间。父母喂养幼鸟2至3周。","identification":"与灰胸山巨嘴鸟和冠山巨嘴鸟的区别在于喙的图案和缺乏蓝色颈背。喙上的黄色平板是其独特标志。","protection":"IUCN：NT（近危）","distribution":"分布于南美洲西部，从哥伦比亚西南部（Patia峡谷，Nariño）至厄瓜多尔中部，可能远至Chanchan河。","other":"在哥伦比亚，非法捕捉用于宠物贸易。在厄瓜多尔，常见于多个私人生态旅游地产和研究站。"},{"name":"冠山巨嘴鸟","english_name":"Hooded Mountain Toucan","scientific_name":"Andigena cucullata","overview":"冠山巨嘴鸟（英文名：Hooded Mountain Toucan，学名：Andigena cucullata），是䴕形目巨嘴鸟科山巨嘴鸟属的鸟类。中型攀禽，外形类似犀鸟，拥有极大的喙，但重量相对较轻，喙边缘带有锯齿，颜色鲜艳。主要分布在南美的安第斯山脉云雾森林，具体包括秘鲁东南部至玻利维亚中部。这种鸟以其醒目的外观和群居习性而著称。","appearance":"冠山巨嘴鸟的体长在48至50厘米之间，体重介于222至380克。它们的喙大多呈现黄绿色，带有黑色尖端和基部附近的黑斑。头部呈暗蓝到黑色，眼周有浅蓝色裸露皮肤，颈部后方有一圈灰蓝色项圈。上背呈栗色，逐渐变为绿色和黄色臀部。尾巴为黑色，翅膀为绿色，下体主要为烟灰色至蓝灰色，大腿锈色，尾下覆羽红色。面部皮肤呈现浅蓝色调，喙基部三分之二为黄色，靠近基部有黑点。","call":"冠山巨嘴鸟的叫声包括缓慢的一系列'peeeeah'音符，持续约1.5秒，以1至5秒间隔的规律或不规律序列发出；还发出一系列'ik'或'tik'音符，每秒约2次；同时伴有喙击声。","habits":"冠山巨嘴鸟主要栖息在湿温带和亚热带森林，通常在海拔2,400至3,300米之间活动，偶尔低至2,000米。它们通常是定居的，但个体可能会在常规下限之下游荡。它们单独或小群体活动，可能由扩大家庭组成，从林下层到树冠觅食。已知饮食包括多种水果。","breeding":"繁殖季节大致从2月持续到6月，但可能早在11月就开始。巢建在高树洞内，一次产2-4枚光滑的白色蛋，大约16天孵化。雏鸟出生时全身赤裸，至少需3周才能睁开眼睛，孵化后约45天开始独立生活。","identification":"与灰胸山巨嘴鸟和扁嘴山巨嘴鸟的区别在于主要为绿黄色的喙，缺乏黄色臀部斑块，尾羽无栗色尖端，头部黑色更多。","protection":"IUCN：LC（无危）","distribution":"分布于南美安第斯山脉，从秘鲁东南部（普诺）到玻利维亚西部和中部（拉巴斯至科恰班巴）。"},{"name":"黑嘴山巨嘴鸟","english_name":"Black-billed Mountain Toucan","scientific_name":"Andigena nigrirostris","overview":"黑嘴山巨嘴鸟（英文名：Black-billed Mountain Toucan，学名：Andigena nigrirostris），是䴕形目巨嘴鸟科山巨嘴鸟属的鸟类。是巨嘴鸟科山巨嘴鸟属的中型攀禽，拥有三个亚种。其特征鲜明，喙极大但相对较轻，嘴边缘具锯齿，色彩鲜艳。羽色以黑色为主，配以白色胸脯、栗色背部和翅膀，以及黄色和天蓝色的面部羽毛点缀，构成一幅多彩画面。分布于南美洲，自委内瑞拉西部至秘鲁北部的云雾林、亚热带至温带山地森林。","appearance":"黑嘴山巨嘴鸟的喙长占体长的三分之一，上半部黄色偏淡绿，下半部深蓝色，嘴形似刀。头部黑色，脸部环绕着黄色和天蓝色的羽毛，胸部白色，背部和翅膀栗色。成年雄鸟的喙全黑，雌鸟的喙稍短。亚种之间主要区别在于喙的颜色，以及大腿颜色的细微差异。","call":"该鸟发出鼻音般的“gwaaak”声，音调可变，有时拉长，有时似吠叫，每分钟约25至45声。同时伴有响亮的拍翅声和喙的咔嗒声。","habits":"黑嘴山巨嘴鸟群居，常栖息于树冠层，偏好海拔1,700至2,700米的地带，偶尔降至1,200米，最高可达3,245米。主要以果实、种子和昆虫为食，偶尔掠食小鸟的卵和雏鸟。活动时声音喧闹，能发出隆隆巨响和刺耳嗄声。","breeding":"繁殖季节为8月至11月在委内瑞拉，3月至8月在哥伦比亚，推测厄瓜多尔相似或更早。筑巢于树洞内，每次产卵2至4枚光滑的白蛋，孵化期约16天，雏鸟孵化后至少3周才睁眼，约45天后开始独立生活。","identification":"与灰胸山巨嘴鸟区别明显，具有全黑的喙和白色的喉部。亚种间喙色和大腿颜色有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉西部至秘鲁北部，包括哥伦比亚和厄瓜多尔的部分地区。在繁殖区域和非繁殖区域都有记录。","other":"黑嘴山巨嘴鸟的巢通常位于高树洞内，吃食时会仰头将食物抛向空中再接入口中，以减少‘吞’的时间消耗。"},{"name":"红胸巨嘴鸟","english_name":"Red-breasted Toucan","scientific_name":"Ramphastos dicolorus","overview":"红胸巨嘴鸟（英文名：Red-breasted Toucan，学名：Ramphastos dicolorus），是䴕形目巨嘴鸟科巨嘴鸟属的鸟类。又名: 红胸鵎鵼，中型攀禽，分布于南美洲巴西东南部至阿根廷东北部。体羽以黑色为主，胸腹部显眼的红色与黄色，以及绿色的喙是其显著特征。","appearance":"红胸巨嘴鸟长约42至48厘米，重约265至400克。全身羽毛主要为黑色，胸部呈现带有柑橘色调的黄色，腹部覆盖着醒目的红色羽毛。喙为绿色，基部有一圈黑色斑纹，鼻孔隐蔽于喙基下方。喙长而轻，外层为薄角质鞘，内部中空，由细骨质支撑构成，边缘呈锯齿状。","call":"发出一系列嘈杂的‘grrekk’音符，比类似物种的叫声更高调，节奏多变，每分钟约31次，偶尔达到每秒2次。","habits":"主要栖息于低地雨林，也出现在有稀疏树木的开阔地带。常见于100至1500米海拔，偶尔高达2070米。以水果、种子、昆虫为主要食物，有时捕食小鸟的卵和雏鸟。","breeding":"繁殖季节在南半球为10月至2月，北部地区为1月至6月。在树洞中筑巢，偏好洞口宽度适中的树洞，深度17厘米至2米。一窝产2至4枚光滑白蛋，孵化期约16天，雏鸟孵化后需50天以上才能独立。","identification":"与同类相比，红胸巨嘴鸟的雌鸟喙较短，喙主要呈绿到黄绿色，具有独特的红、象牙色的喙齿及绿色条纹。面部皮肤红、蓝、黄绿色相间。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东南部、巴拉圭东部和阿根廷东北部，从南托坎廷斯至南里奥格兰德州，东至帕拉圭和阿根廷的东部省份。","other":"在某些地区因捕食小鸟和破坏果园水果而遭到猎杀，但在多个保护区得到保护。"},{"name":"凹嘴巨嘴鸟","english_name":"Channel-billed Toucan","scientific_name":"Ramphastos vitellinus","overview":"凹嘴巨嘴鸟（英文名：Channel-billed Toucan，学名：Ramphastos vitellinus），是䴕形目巨嘴鸟科巨嘴鸟属的鸟类。又称橙喉巨嘴鸟，是巨嘴鸟属中分布最广的“蛙鸣型”成员，见于哥伦比亚西北部至巴西亚马孙及东南部大西洋森林的湿热低地。体长46–56厘米，通体以黑为主，具醒目巨喙，上颚具特征性纵沟，面部裸皮、喉胸斑及尾上覆羽的色彩因五个亚种而异。","appearance":"成鸟通体背面及腹部黑色，眼周裸皮颜色因亚种呈蓝或红；喉胸部具大型浅色斑块，外围橙或白，下方接一条红色胸带；尾上覆羽红或金黄，尾下覆羽鲜红。喙巨大，黑色为主，基部具彩色横带，上颚具纵向深沟。雌雄同色，雄鸟略大。亚种间差异主要体现在喙基颜色、裸皮色、喉胸斑及尾上覆羽色：指名亚种vitellinus裸皮蓝色，胸斑橙心白边，尾上覆羽红；ariel裸皮红色，胸斑橙黄边；culminatus胸斑几乎纯白，尾上覆羽金黄；citreolaemus胸斑淡黄，尾上覆羽淡黄；pintoi介于culminatus与ariel之间。幼鸟羽色暗淡，面部色浅，喙较短而钝，色彩不鲜明。","call":"鸣声为连续的“蛙鸣”式低沉咕噜或双音节“cree-op”声，每秒约1次，雌雄可同时鸣唱，雌鸟音调略高且节奏稍慢。不同亚种的鸣声在质量上相似，均缺乏白喉巨嘴鸟那种尖锐的“yelp”。","habits":"栖息于海拔1700 m以下的原始潮湿低地及丘陵森林、林缘、沼泽林、河谷林及稀树草原中的林片，偏好近水源地带。通常单独或成对活动，果期可与其他巨嘴鸟混群。在树冠层觅食，偶至地面捡食落果或捕食小动物。以棕榈果、榕果等水果为主，兼食昆虫、蜘蛛、蜥蜴、蛙类、雏鸟、鸟卵及悬挂的蝙蝠；亦跟随行军蚁捕捉被惊扰的小动物。","breeding":"繁殖期因地而异：北哥伦比亚1–3月已见繁殖个体，雏鸟2–7月可见；巴西中西部8–3月，东南部10–4月；特立尼达3–6月；委内瑞拉11–7月；圭亚那延至11月。巢于天然树洞，入口小，距地3.5 m以上，重复使用成功巢址。每窝2–4枚（圈养2–5枚）白色卵，双亲共孵16–18天，雏鸟37–46天出飞，约60日龄可自行取食，每巢常2–3雏。","identification":"与白喉巨嘴鸟重叠分布且相似，可通过鸣声（凹嘴为“蛙鸣”，白喉为尖锐“yelp”）及比例较小的喙区分；在东部亚马孙，vitellinus与ariel亚种的胸斑橙色、喙无黄色纵脊，而白喉亚种tucanus胸斑近白且喙具红色块。与黑嘴巨嘴鸟在哥伦比亚安第斯山麓重叠时，后者具更宽的黄喙脊、纯黄胸斑及白色尾上覆羽，且分布海拔较高。在巴西东南部，ariel亚种与体型较小的红胸巨嘴鸟同域，后者具全绿色短喙。","protection":"IUCN: LC（无危）。整体被CITES附录II所列。按亚种分别评估：citreolaemus和ariel均为近危（NT），前者因安第斯山麓森林消失而数量下降，后者为特有亚种，缺乏具体数据但推测下降；culminatus群和指名亚种vitellinus为无危（LC），虽仍常见但呈下降趋势。","distribution":"繁殖区：哥伦比亚西北部、委内瑞拉、特立尼达、圭亚那、苏里南、法属圭亚那、亚马孙盆地（巴西、秘鲁、玻利维亚）、巴西东南部大西洋森林至圣卡塔琳娜州。非繁殖区：无季节性迁徙，偶见扩散。特立尼达和格林纳达有引入种群。","other":"曾被拆分为多个独立种，因接触带存在广泛渐变及杂交，现归并为单一物种下的五个亚种，并记录与红胸巨嘴鸟杂交。"},{"name":"淡黄喉巨嘴鸟","english_name":"Citron-throated Toucan","scientific_name":"Ramphastos citreolaemus","overview":"淡黄喉巨嘴鸟（英文名：Citron-throated Toucan，学名：Ramphastos citreolaemus），是䴕形目巨嘴鸟科巨嘴鸟属的鸟类。外形酷似犀鸟，长度可达60公分。其体羽主要为黑色，脸部、喉咙、胸部呈现白色至柠檬黄色，尾巴腹面带有鲜红色。主要分布在南美洲的哥伦比亚北部和委内瑞拉西北部的低地雨林中。","appearance":"淡黄喉巨嘴鸟的嘴主要是黑色，但在基部有蔚蓝色和黄色的圈纹，成鸟的鼻孔隐藏于喙基下面。鸟喙轻盈，表面覆盖一层薄薄的角质鞘，内部中空，有细骨质支撑杆交错排列。舌长，喙缘呈锯齿状，喙基周围皮肤裸露并色彩鲜艳。","call":"淡黄喉巨嘴鸟的鸣叫声嘶哑低沉，类似一系列蛙鸣般的‘cree-op’音符。","habits":"淡黄喉巨嘴鸟主要栖息于低地雨林中，偶尔出现在有稀疏树木的空旷地带，海拔高度一般不超过1,700米。它们是杂食性动物，以果实、种子和昆虫为主要食物来源，有时会捕食小鸟的巢穴，吞食鸟卵和雏鸟。","breeding":"淡黄喉巨嘴鸟以树洞为巢，偏好洞口宽度恰好能让成鸟进入的树洞，深度在17厘米到2米之间。一次产卵2-4枚，孵化期约16天，雏鸟出生时全身赤裸，睁开眼睛需至少3周，完全独立则需50天以上。","identification":"与其他巨嘴鸟相比，淡黄喉巨嘴鸟的喉部和胸部的柠檬黄色以及尾部腹面的鲜红色是其显著特征。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体包括哥伦比亚北部和委内瑞拉西北部的低地雨林。","other":"淡黄喉巨嘴鸟在哥伦比亚被认为是不常见的，在受保护的区域内可见，而在委内瑞拉则被视为稀有和局部分布，尤其是Maracaibo盆地周围的安第斯山麓森林正迅速消失。现为凹嘴巨嘴鸟亚种。"},{"name":"乔科巨嘴鸟","english_name":"Choco Toucan","scientific_name":"Ramphastos brevis","overview":"乔科巨嘴鸟（英文名：Choco Toucan，学名：Ramphastos brevis），是䴕形目巨嘴鸟科巨嘴鸟属的鸟类。中型攀禽，主要分布在南美洲的哥伦比亚西北部至厄瓜多尔西南部。体羽以黑色为主，脸部、喉咙、胸部呈现柠檬黄色，尾部腹面鲜红，喙部则以黑色和柠檬黄色为主色调。喙基周围无口须，成鸟鼻孔隐藏于喙基之下。","appearance":"乔科巨嘴鸟长约46至48.5厘米，体重介于365至482克之间。头部到上背带有微红棕色调的黑色，背部黑色，尾上覆羽白色；喉部和胸部黄色，下方有一狭窄的红色条纹，腹部黑色，下尾覆羽红色；上喙黄色，有绿色的冠突和中央侧面，与黑色的上喙基部相遇，上喙上有灰色斑点；下喙黑色，有时尖端黄色；面部皮肤黄色至橄榄绿色，虹膜绿色带黄色至灰色色调。雌鸟喙较短，更显块状。","call":"乔科巨嘴鸟发出一系列的沙哑叫声，‘tree-aak’到‘tyook’或‘tyeerp’，每分钟约40至55声（有时高达100声），声音在系列开始时更长且类似咆哮，持续数分钟；雄鸟的叫声更深沉、更咆哮；还有更多号叫声的变体，以及仅近距离可闻的柔和音调；同时会敲击喙部，闭合喙时发出刮擦和拍打的声音。","habits":"乔科巨嘴鸟栖息于低地森林和安第斯山脉较低坡地的森林中，以及相邻的有果树林或种植园的牧场。以果实为主食，可能也摄入昆虫和小型脊椎动物。在觅食时会跟随行军蚁群，以获取它们惊扰的动物猎物。在树冠层觅食，能将头倒置进食。不进行迁徙，但成对或群体广泛游荡，上山可达约1550米。","breeding":"乔科巨嘴鸟的繁殖季节主要在6月至8月，可能在哥伦比亚更早开始。配偶间通过摇摆头部并发出叫声展示求偶行为。巢建于树洞中，偏好质地良好的木材，开口宽度适中，深度17厘米至2米。一次产卵2至4枚，孵化期约为16天。雏鸟孵化后全身赤裸，至少三周后才能睁眼，幼鸟需50天以上才能独立。","identification":"与非常相似的Ramphastos ambiguus swainsonii相比，乔科巨嘴鸟体型较小，叫声不同，雌鸟的喙比雄鸟短且更显块状。与‘胸下颌栗色’的黄色巨嘴鸟（R. a. swainsonii）相比，主要通过声音区分。","protection":"IUCN：LC（无危）。乔科巨嘴鸟在哥伦比亚和厄瓜多尔的部分保护区中出现，但因森林砍伐数量明显下降，可能受到进一步的栖息地碎片化威胁。其巢穴可能受限，因为物种可能需要大的、安全的自然洞穴。被用于食物和传统医药。","distribution":"乔科巨嘴鸟主要分布在南美洲的哥伦比亚西北部至厄瓜多尔西南部，包括低地雨林和安第斯山脉较低坡地的森林。","other":"乔科巨嘴鸟曾被视为黑嘴巨嘴鸟的亚种，但因其独特的叫声和其他特征而被分类为独立物种。与凹嘴巨嘴鸟是姐妹物种。"},{"name":"厚嘴巨嘴鸟","english_name":"Keel-billed Toucan","scientific_name":"Ramphastos sulfuratus","overview":"厚嘴巨嘴鸟（英文名：Keel-billed Toucan，学名：Ramphastos sulfuratus），是䴕形目巨嘴鸟科巨嘴鸟属的鸟类。又名: 彩虹巨嘴鸟或厚嘴鵎鵼，是南美洲色彩斑斓的巨嘴鸟，为伯利兹的国鸟。这种中型攀禽以其巨大、彩虹色的鸟嘴著称，体羽藏蓝黑，胸黄，尾红，脚蓝。广泛分布于中美至南美的热带雨林，自墨西哥南部至哥伦比亚北部和委内瑞拉西北部。","appearance":"厚嘴巨嘴鸟体长约42至55厘米，体重380至500克。其标志性特征是大型、多彩的鸟嘴，平均长12至15厘米，由轻质的角质鞘覆盖，内部中空，具细骨质支撑。体羽藏蓝黑色，胸部亮黄，尾腹面鲜红，脚蓝，鼻孔隐藏于喙基下。喙缘锯齿状，喙基有黑色线斑，脸和下颚皮肤色彩鲜艳。","call":"鸣叫声嘶哑低沉，常在森林中回荡。","habits":"主要栖息于低地雨林，偶尔出现在有稀疏树木的开阔地带，海拔1700米以上罕见。杂食性，食谱包括水果、种子、昆虫，甚至小鸟的卵和雏鸟。飞行缓慢起伏，由快速拍打翅膀接滑翔组成。","breeding":"以树洞为巢，偏好木质好、入口适中的树洞，深度17厘米至2米。雌鸟产2至4枚白色卵，雄雌轮流孵卵，孵化期15至20天。雏鸟孵化时无毛，闭眼，由双亲轮流喂养，约两个月成熟，留巢8至9个月直至喙完全长成。","identification":"与同属的Chestnut-mandibled Toucan相比，体型较小，鸟嘴颜色独特，是辨别的重要特征。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲和南美洲，从墨西哥东部至委内瑞拉西北部，主要在低地雨林中，偶尔在邻近有树木的开阔地带，最高见于海拔1700米以上。"},{"name":"巨嘴鸟","english_name":"Toco Toucan","scientific_name":"Ramphastos toco","overview":"巨嘴鸟（英文名：Toco Toucan，学名：Ramphastos toco），是䴕形目巨嘴鸟科巨嘴鸟属的鸟类。又名鞭笞鵎鵼、鞭笞巨嘴鸟、托哥巨嘴鸟，是最具辨识度的南美热带鸟类之一，以其巨大的橙色喙著称，喙端带有黑色斑点。分布于南美洲，从圭亚那至阿根廷北部，偏好草原边缘和低湿草地，避免湿润森林地带。是最大的巨嘴鸟种类，黑体白喉，红色腹下羽毛和醒目的红橙色大喙是其显著特征。食性广泛，以果实为主，偶尔捕食昆虫和鸟巢中的雏鸟。","appearance":"巨嘴鸟是最大的巨嘴鸟种类，平均长度约56厘米。全身主要为光泽的黑色，喉部和胸部上方为白色，有时带淡黄色晕染，与黑色胸部分界处有一窄红带。臀部白色，尾下覆羽红色。眼睛棕色，周围有蓝环，其余眼周皮肤为硫磺黄至橙色。喙极为醒目，顶部红色最浓，两侧有不规则的橙褐色条纹，长度可达200毫米，基部黑色，顶端有大黑斑。喙虽看似沉重，实则轻盈，内部大部分为空腔，舌长约与喙相等，扁平。雌雄外观相似，仅体型大小有异。幼鸟色泽较淡，喙较短。","call":"发出一系列嘶哑、粗犷或鼻音的叫声，类似于蟾蜍的叫声，包括“groomkk”、“grunt”、“grunnkkt”等，可单独发出或连串，一分钟内可达50个音节。此外，还有幼鸟发出的‘te-te-te’和‘ehh-ehh’的呢喃声。","habits":"生活在南美洲，分布广泛，从圭亚那南部至阿根廷北部，偏好半开放生境，如林边、湿地、灌木丛、果园等。以果实为主要食物来源，也会捕食昆虫、鸟蛋和雏鸟。在树冠活动，群体觅食，飞行时振翅有力，滑翔能力较强。","breeding":"季节性繁殖，筑巢于树洞中，每窝产卵2至4枚，双亲共同孵化，孵化期17至18天。雏鸟孵化后全身裸露，发育缓慢，约43至52天后离巢。","identification":"与其他巨嘴鸟种类相比，巨嘴鸟的喙更大，颜色更鲜明，且有独特的黑色顶端。叫声比红胸巨嘴鸟更深沉，节奏更慢。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的东北部、中部和东南部，从圭亚那至阿根廷北部，包括巴西的cerrado、Pantanal湿地等。","other":"在人类活动频繁的区域，如机场周边和新道路附近也能发现巨嘴鸟的踪迹。"},{"name":"红嘴巨嘴鸟","english_name":"White-throated Toucan","scientific_name":"Ramphastos tucanus","overview":"红嘴巨嘴鸟（英文名：White-throated Toucan，学名：Ramphastos tucanus），是䴕形目巨嘴鸟科巨嘴鸟属的鸟类。又名: 红嘴鵎鵼，分布于南美洲亚马逊盆地，包括周边的Tocantins和Araguaia河排水区。偏好热带湿润森林，偶尔在林地和河流森林中可见。","appearance":"红嘴巨嘴鸟是一种中型攀禽，体长53-58厘米，体重515-830克。雄鸟的长喙较雌鸟大，腹下部和尾巴黑色，咽喉和胸部白色，肛尾和胸部红色。尾巴掩蔽处黄色，眼周皮肤蓝色，喙基部黄色和蓝色，喙尖至基部有一黄色条纹。喙轻盈，表面角质，内部中空，有骨质支撑。喙缘锯齿状，喙基周围无口须。","call":"发出嘶哑低沉的鸟鸣声。","habits":"栖息于低地雨林，偶尔出现在有稀疏树木的开阔地带，海拔1700米以上少见。杂食性，以果实、种子和昆虫为主食，偶尔掠夺小鸟巢穴，食用卵和雏鸟。","breeding":"以树洞为巢，一次产2-4枚光滑白蛋，直接放置于未衬里的巢穴中，孵化期约16天。雏鸟赤裸，孵化后需3周睁眼，50天以上离开巢穴。","identification":"与凹嘴巨嘴鸟相似，但体型略大，喙更长，通过鸣叫声辨别，红嘴巨嘴鸟发出yelping 'keeow-yelp-yelp-'叫声。","protection":"IUCN：LC（无危）","distribution":"南美亚马逊雨林区域，包括委内瑞拉东部、圭亚那、巴西东北部等地。","other":"曾被列为Vulnerable（易危），因亚马逊盆地的森林破坏和狩猎压力而受到威胁。"},{"name":"黑嘴巨嘴鸟","english_name":"Yellow-throated Toucan","scientific_name":"Ramphastos ambiguus","overview":"黑嘴巨嘴鸟（英文名：Yellow-throated Toucan，学名：Ramphastos ambiguus），是䴕形目巨嘴鸟科巨嘴鸟属的大型鸟类。其最显著的特征是拥有巨大的双色喙，上部黄色下部暗色或栗色，脸部及喉咙呈现明亮的黄色。分布于南美地区，从洪都拉斯东南部至厄瓜多尔西部，再到委内瑞拉西部直至秘鲁中部。","appearance":"黑嘴巨嘴鸟体型庞大，总长度约47到61厘米，体重介于584至746克之间。整体羽毛以黑色为主，带有少许红褐色调于后颈和背部上端。脸部、喉咙及上胸部为鲜亮的黄色，胸前有白色与深红色条纹。尾下覆羽呈鲜艳的红色。喙部特征明显，上喙大多为黄色，带有绿黄色条纹，基部有细黑线，下喙颜色因亚种而异，有的黑色，有的为红棕色。","call":"其叫声为一系列响亮、传得远的吠叫声，节奏和音节数量略有变化，被当地人描述为“Díos te dé te dé”，意为‘上帝赐予你’。","habits":"黑嘴巨嘴鸟主要栖息于低地热带雨林，偶尔出现在有零星树木的开阔地带，一般不在海拔1,700米以上的区域活动。它们以水果为主食，辅以昆虫、小蜥蜴、其他鸟类的蛋和雏鸟。通常在森林冠层活动，单独、成对或小群体觅食。","breeding":"繁殖季节随纬度而变，大致在3月至6月间。雄鸟会对雌鸟进行喂食求偶。它们在腐朽的树洞中筑巢，通常位于地面9至30米的高度，每次产卵2至3枚，孵化期和雏鸟成长时间尚不明确，双方父母共同守护巢穴和照顾幼鸟。","identification":"与厚嘴巨嘴鸟和乔科巨嘴鸟的区别在于较大的体型、双色喙以及独特的吠叫声音。与乔科巨嘴鸟相比，黑嘴巨嘴鸟喙部较宽且长，颜色差异更明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美，具体包括从洪都拉斯东南部至厄瓜多尔西部，委内瑞拉西部至秘鲁中部。在哥伦比亚和厄瓜多尔，常见于低地至海拔1,000米左右的森林。","other":"尽管能容忍一定程度的人类干扰和森林环境改变，黑嘴巨嘴鸟仍受栖息地丧失的影响，农业和牧场扩张是主要威胁之一。"},{"name":"火簇拟啄木鸟","english_name":"Fire-tufted Barbet","scientific_name":"Psilopogon pyrolophus","overview":"火簇拟啄木鸟（英文名：Fire-tufted Barbet，学名：Psilopogon pyrolophus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。分布于马来半岛和苏门答腊的热带湿润低地和山地森林。由Salomon Müller于1836年首次描述。","appearance":"该鸟主要呈绿色，具有棕红色颈背，灰色面颊，前额有一白色带纹，喉咙绿色，接着是明亮的黄色带纹，然后是一条黑色带纹，如同佩戴项链。喙呈淡褐色，中央有黑色竖向条纹。雄鸟的上部羽簇为鲜艳的橙色。成年个体长约28厘米。","call":"其鸣声类似蝉鸣，持续3至8秒，音调逐渐加快，从每秒1-2个音符加速到12-14个音符，形成渐强后稍弱的旋律。还发出清脆的'茨尼克'声和尖锐的'特恩克'声。","habits":"常栖息于海拔1070至2010米的常绿阔叶林中，以无花果、其他水果、大型节肢动物和昆虫为食。成对或家庭群觅食，有时加入混合物种觅食群。会驱赶较小的拟啄木鸟，如。","breeding":"繁殖期为1月至9月中旬，成对繁殖。雄鸟进行对抗鸣叫，可能在地上相互抓咬。双方共同在离地面4米以上的枯树或枝干中挖掘巢穴。巢中可能有两枚卵，孵化期未知。亲鸟轮流喂养幼鸟，直至幼鸟独立。离巢后5-8天，幼鸟开始独立觅食。","identification":"雄鸟具有醒目的橙色上部羽簇，而雌鸟则缺乏这一特征。幼鸟较暗淡，喉部斑纹不明显，冠部和胸带呈灰黑色，鼻部羽簇主要为白色。","protection":"IUCN：LC（无危）","distribution":"分布于马来半岛山区和印尼苏门答腊岛，最近在泰国极南端也有报道。在爪哇西部可能为逃逸的笼养个体。","other":"其科学名称由Salomon Müller在1836年提出，描述了来自苏门答腊的拟啄木鸟。"},{"name":"大拟啄木鸟","english_name":"Great Barbet","scientific_name":"Psilopogon virens","overview":"大拟啄木鸟（英文名：Great Barbet，学名：Psilopogon virens），是䴕形目拟啄木鸟科火簇拟䴕属的大型鸟类，广泛分布在印度次大陆至东南亚的森林地带，最高可达3,000米海拔。其显著特征为蓝头、大黄喙、棕绿条纹体及红尾下覆羽。数量虽不多，但已被纳入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","appearance":"大拟啄木鸟体长32–35厘米，重164–295克，为最大型的拟啄木鸟，具有庞大的黄喙。成鸟头色暗蓝带绿，身披棕色与绿色条纹，下腹黄斑点缀，尾下覆羽鲜红。幼鸟相似但色彩较暗，尾下覆羽粉红。存在一些黄色调变异个体。","call":"鸣声独特响亮，连续的'kee-aar'至'peeao'音符，雌雄会相互应答。雄鸟发出慢长音，雌鸟音调快短。另有尖锐'karr-r'声，展示时翼振嘈杂。","habits":"栖息于落叶与常绿森林，海拔800至2400米间，冬季会迁往低地。以多样水果为主食，如无花果、浆果等，也摄食花蜜与昆虫。集群可达40只。","breeding":"繁殖期为2月至8月或9月，一季可能有两至三窝。营巢于死树或枝干，深可达60厘米。产卵2至5枚，主要3至4枚，双亲共孵，孵化期13至15天，雏鸟期超38天。","identification":"与同类相比，大拟啄木鸟体型最大，具独特的蓝头、黄喙与红尾下覆羽。不同亚种颜色深浅与黄色条纹有异。","protection":"IUCN：LC（无危）","distribution":"繁殖于喜马拉雅山脉中下部，分布于北印度、巴基斯坦北部、尼泊尔、不丹、孟加拉国及东南亚部分地区，远至中国东南部与缅甸。在中国大陆，分布于东南部山区。","other":"适应性强，能在残存森林中生存，如山谷栽培区。在多个保护区可见，如印度的Namdapha国家公园、香港的Tai Po Kau自然保护区及泰国的Nam Nao、Doi Inthanon和Kaeng Krachan国家公园。"},{"name":"红臀拟啄木鸟","english_name":"Red-vented Barbet","scientific_name":"Psilopogon lagrandieri","overview":"红臀拟啄木鸟（英文名：Red-vented Barbet，学名：Psilopogon lagrandieri），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。原生于东南亚的亚洲拟啄木鸟，主要分布在老挝、越南和柬埔寨的热带低地森林与山地森林中。其最显著的特征为头部棕色，两侧及喉部带灰色，眼上有一条蓝色线纹，尾下覆羽鲜红色。","appearance":"红臀拟啄木鸟体长约为29至34厘米，整体羽毛呈现绿色到青铜色，头部颜色偏棕，喉部和两侧有灰色斑块，眼睛上方有蓝色线条。尾下部有红色斑块，喙大而钝，尖端黄色，边缘锋利。未成年个体色泽较为暗淡，棕色更重，喙基部有橙色羽毛簇。","call":"发出响亮的‘kyaa’、‘kyow’或‘yowt’音调的鸣叫声，单个或以每分钟30至75个音符连续鸣叫，持续时间可达10秒以上。报警声为‘grrrik-grrrik’。","habits":"栖息于从低地至山地的森林中，偏好在树冠深处的隐蔽枝头发出规律的柔和哨声。饮食包括果实（如无花果）、昆虫和其他小型动物，如蜘蛛和蜥蜴。","breeding":"繁殖季节可能从1月至7月，成对的雄鸟和雌鸟会共同鸣叫以维护领地。在越南南部观察到的巢穴位于阔叶树干的死木中，高度从9.5米到16米不等，洞口呈瓶状，带有弯曲的入口通道。大约14天大的雏鸟几乎裸露，初级飞羽平均长度约9毫米，仍无法自行抬头，由双亲喂食并清理粪便。","identification":"与多数其他拟啄木鸟相比，红臀拟啄木鸟的头部为棕色和灰色，面部点缀着蓝色、红色和黄色斑点，使其独具特色。喙基部的红褐色羽毛簇是识别成年个体的标志之一。","protection":"IUCN：LC（无危）","distribution":"主要分布在老挝和越南的热带低地和山地森林中，包括Nam Bai Cat Tien National Park、Bach Ma National Park和Cuc Phuong National Park。","other":"红臀拟啄木鸟在其有限的分布范围内常见，但在生态学和生物学方面了解甚少，需要进一步研究以明确其保护状况。"},{"name":"棕头绿拟啄木鸟","english_name":"Brown-headed Barbet","scientific_name":"Psilopogon zeylanicus","overview":"棕头绿拟啄木鸟（英文名：Brown-headed Barbet，学名：Psilopogon zeylanicus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。原生于亚洲的拟啄木鸟，广泛分布于印度次大陆的热带和亚热带湿润森林。其头部带有明显的淡黄色纵纹，颈部及胸部呈棕色，其余羽毛为绿色，体长约27厘米。该物种在印度、尼泊尔南部特莱地区和斯里兰卡都有发现。","appearance":"成鸟具有显著的棕色头部，颈部和胸部带有细密的条纹，眼周环绕着黄色的眼圈。其余羽毛呈现绿色，拥有大头、短颈和短尾巴。喙部颜色从浅黄色到红橙色不等，依据繁殖季节而变化。幼鸟外观相似但色泽较为暗淡。亚种inornatus体型较大，色调偏淡，棕色延伸至背部和腹部；亚种caniceps同样体型较大且色彩较浅，但棕色仅限于前部，条纹清晰可见。","call":"发出重复的'kutroo...kutroo...kutroo'叫声，但冬季较为沉默。当一只开始鸣叫时，其他个体也会加入，形成合唱。","habits":"主要栖息于花园、林地、路边树木，偏好既不太湿也不太干的环境。以水果为食，尤其喜爱无花果、Syzygium果实和浆果，也包括咖啡果、番茄和园艺水果。同时，它们还会食用花萼、花蜜和动物性食物，如甲虫、螳螂、蚂蚁、白蚁及各种大小的蜥蜴。常在城市公园中被观察到，适应力强。","breeding":"繁殖期从二月持续至十月。筑巢由双方共同完成，通常在树干或树枝上挖洞，洞深可达46厘米。每窝产卵2至4枚，孵化和育雏周期未知。雌鸟负责夜间孵卵和抚育幼鸟，白天则由双亲共同承担喂养任务。雏鸟离巢时，成鸟会通过停止喂食的方式鼓励其离开。","identification":"与斑头绿拟啄木鸟相比，棕头绿拟啄木鸟的翼覆羽上有白色斑点，喉咙呈棕色，胸前的白色条纹更窄，面部裸露皮肤面积更大，周围有深色羽毛环绕。幼鸟色泽较为暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于印度次大陆，从尼泊尔南部的特莱地区向南直至斯里兰卡，覆盖了印度半岛大部分地区。","other":"尽管在咖啡种植园中被认为是轻微的害鸟，但最近的研究表明，它们捕食茎蛀虫Xylotrechus quadripes，因此对生态平衡有一定正面影响。"},{"name":"斑头绿拟啄木鸟","english_name":"Lineated Barbet","scientific_name":"Psilopogon lineatus","appearance":"体型介于25至30厘米，重量在115至205克之间。全身绿色，头部有明显的灰棕色条纹，喉咙和下巴趋向白色，其余部分羽毛绿色。喙的颜色可为黄色、粉色或角质色，繁殖季节时变为奶油粉色，基部黄色。眼周皮肤黄色或金色，腿黄色。幼鸟颜色较为暗淡，偏米色。","call":"其领地性歌曲通常包含重复的“woo-kohw”声，有时也会发出一种哼鸣式的颤音。","habits":"居住于落叶森林及其边缘地带，包括公园和花园。以各种果实为主食，尤其是无花果，亦食花蜜、昆虫幼虫、白蚁、青蛙、雏鸟和可能的鸟蛋。在果实丰富的树上聚集，与其他拟啄木鸟共享资源。","breeding":"繁殖期在多数地区为1月至7月，在马来半岛为9月至5月，在爪哇和巴厘岛为1月至7月及9月至10月。成对挖掘树干、枯枝中的巢穴，高度2至12米，洞深可达50厘米。产卵数2至4枚，双亲共同孵化和喂养幼鸟，孵化期约14至15天，其余繁殖细节尚不清楚。","identification":"与Megalaima zeylanicus相比，斑头绿拟啄木鸟具有更粗大的白色条纹，喉咙苍白，翼盖无斑点，眼周裸皮面积较小。幼鸟颜色较暗淡，偏米色。","protection":"IUCN：LC（无危）。在尼泊尔、印度、不丹、孟加拉国及东南亚广泛分布，适应力强，存在于多个保护区。","distribution":"分布于印度西北部至马来半岛、爪哇岛和巴厘岛。","other":"在新加坡，引入的斑头绿拟啄木鸟数量逐渐增多，已稳定建立种群。"},{"name":"小绿拟啄木鸟","english_name":"White-cheeked Barbet","scientific_name":"Psilopogon viridis","overview":"小绿拟啄木鸟（英文名：White-cheeked Barbet，学名：Psilopogon viridis），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。仅见于南印度森林地带，其特征为头部深褐色，面部有独特的白色图案：耳羽周围有白色斑块，眼上方有一条白线，喉部白色。颈和胸部棕色，带有宽大的白色条纹。幼鸟颜色较暗淡，面部图案不如成鸟明显。在咖啡种植园和果园中被视为害鸟，但在某些地区亦能控制害虫。","appearance":"身长约16.5至18.5厘米，头部呈暗褐色并有白色条纹，有时看起来像是戴着一顶帽子。喙为浅粉色。北方个体体型较大，南方个体较小。绿色为主色调，坐姿静止，直立，不易察觉。","call":"发出连续的‘kutrook-kutrook-kutrook’叫声，尤其是在正午时分。叫声与棕头绿拟啄木鸟相似，难以区分。在炎热的下午，会发出单音节的‘wut’声。","habits":"栖息于原生林和次生林，包括湿润落叶林和常绿林，也常见于公园、咖啡园和花园中的果树。主要在树冠和次树冠层活动，偶尔落地。以榕树、无花果和其他果实为主食，也会吸食花蜜，捕食昆虫及其幼虫，如蝴蝶、蜻蜓、螳螂、蝉、甲虫和飞蚁。白天主要在早晨和傍晚觅食。","breeding":"繁殖期从12月持续到7月，筑巢在枯枝或树洞中，由雄鸟为主挖掘，雌鸟辅助，巢穴深度平均32.2厘米。每次产2至4枚白色卵，平均3枚，孵化期14至15天。雏鸟以昆虫喂养，约5天后转为水果。幼鸟在36至38天后离巢，离巢前2至3天停止喂食。","identification":"与棕头绿拟啄木鸟相比，体型较小，有明显的白色颊斑。在干燥森林中，两物种可能共同出现。","protection":"IUCN：LC（无危）","distribution":"主要分布于印度西部和西南部，从马哈拉施特拉邦的托兰马尔保护区到帕尔尼山、尼尔吉里山、班加罗尔地区和泰米尔纳德邦西部。","other":"在几个保护区中被发现，如拉吉夫甘地国家公园、巴拉姆比克拉姆野生动物保护区、普尔纳野生动物保护区、穆杜马莱、佩里亚尔和英迪拉甘地国家公园。"},{"name":"黄纹拟啄木鸟","english_name":"Green-eared Barbet","scientific_name":"Psilopogon faiostrictus","overview":"黄纹拟啄木鸟（英文名：Green-eared Barbet，学名：Psilopogon faiostrictus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。头部条纹，耳羽绿色，体型丰满，颈短头大，尾部短小，主要分布于东南亚的低地森林中，包括中国南部、柬埔寨、老挝、泰国和越南。以果实为食，偶尔捕食昆虫。","appearance":"该鸟长约24.5至27厘米，头部呈褐色，带有白色条纹，耳羽区绿色，腹部黄色并有绿色条纹。全身羽毛以绿色为主，雄鸟与雌鸟及幼鸟外观相似。喙部大部分为暗色，眼圈深色而非黄色，与斑头绿拟啄木鸟相比，体型较小，具有独特的绿色耳羽，喙色较深。","call":"鸣声为一系列快速的复合音符，如‘twa-ta-ta-tat’或‘too-er-took’，每秒约2.5个音节，也有缓慢的单音‘tawt’或‘toook’，以及颤音叫声。","habits":"黄纹拟啄木鸟栖息于常绿和混交林或开阔的落叶林中，高度可达900米，偏好在树冠层活动，以果实如无花果、Trema和Eugenia的果实及浆果为食，可能也会捕食昆虫，但具体细节尚不清楚。","breeding":"繁殖季节通常在2月至7月间，确切时间未知。在枯枝或枯立木上挖掘巢穴，已知会产下两枚卵，关于孵化期、育雏期及父母角色的信息缺乏。","identification":"与斑头绿拟啄木鸟相比，黄纹拟啄木鸟体型更小，喙色更深，具有绿色耳羽，背部全绿色，雌鸟胸部红色斑点不如雄鸟明显或仅存痕迹。","protection":"IUCN：LC（无危）。在中国、泰国和印度支那普遍，但在某些地区如中国报告为罕见。由于其偏好在难以察觉的常绿森林树冠活动，使得定位较为困难。需要持续监测及对其习性、生态和繁殖生物学的研究。","distribution":"主要分布在东南亚的低地森林，包括中国南部、柬埔寨、老挝、泰国和越南，海拔可达900米，有时可达1035米。","other":"在多个保护区中可见，如中国的弄岗国家级自然保护区、泰国的Kaeng Krachan和Khao Yai国家公园以及越南的Nam Bai Cat Tien国家公园。"},{"name":"褐喉拟啄木鸟","english_name":"Brown-throated Barbet","scientific_name":"Psilopogon corvinus","overview":"褐喉拟啄木鸟（英文名：Brown-throated Barbet，学名：Psilopogon corvinus），是䴕形目拟啄木鸟科火簇拟䴕属的独特大型物种。仅分布于爪哇岛西部山区，以叶绿色为主，头部呈深褐色。","appearance":"体长约27厘米，体重可达130克。两性均具有不带斑纹的褐色头、颈及上胸，通常在颈背处有黄色金色标记，上体绿色有时带有蓝色调，喙为黑色。幼鸟色泽较淡，喙色较浅。","call":"鸣声为一系列持续约20秒的3至4音节响亮叫声，每复合音节长约0.9秒，声音类似“too-ta-ta-toot”。此外，还发出短而快的颤音，可能作为鸣唱前奏，以及缓慢短促的颤音和嘎嘎的警报声。","habits":"栖息于海拔800至2000米的湿润山地森林，活动缓慢且难以察觉，常在结果的树木上发现，无论是单独还是小群活动，可能为家庭单位，与其它食果鸟种共同觅食。主要食物为果实，尤其是无花果，偶尔也会摄取昆虫。通常在树冠层觅食。","breeding":"繁殖季节推测为每年的1月至6月，也有报告在8月和10月繁殖，可能是部分双窝。据报道，会在树洞中产下两枚卵，但巢穴和其他繁殖细节尚未有具体描述。","identification":"与其他拟啄木鸟的区别在于其独特的褐色头部和颈背的黄色金色标记，以及体型较大。","protection":"IUCN：LC（无危）。虽然范围受限，但在其极小的分布区内局部较为常见，确切的种群数量和栖息地面积未知，需更多关于其繁殖生态学和栖息洞穴需求的信息，以备必要时采取保护措施。","distribution":"分布于爪哇岛西部山区，特别是在Gunung Gede-Pangrano国家公园内。"},{"name":"金须拟啄木鸟","english_name":"Golden-whiskered Barbet","scientific_name":"Psilopogon chrysopogon","overview":"金须拟啄木鸟（英文名：Golden-whiskered Barbet，学名：Psilopogon chrysopogon），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。其最显著的外部特征是脸部两侧的亮黄色颊须，如同太阳般耀眼，以及头部红蓝交织的色彩。广泛分布于马来半岛、苏门答腊岛和婆罗洲的低地和山脚森林。","appearance":"金须拟啄木鸟体型较大，约30厘米长，体重介于110至215克之间，拥有绿色的羽毛，色调多样。雄鸟的前额红色，前冠黄色，后冠红色，眼纹宽厚呈棕色，颊部黄色，喉咙灰白边缘蓝色。雌鸟与雄鸟相似，但喙部颜色较淡。幼鸟色彩较为暗淡，红色部分不明显，喙部呈角质色，眼周皮肤奶油色或黄褐色。不同亚种在颜色上有细微差异。","call":"金须拟啄木鸟的鸣唱为一系列快速而响亮的双音节‘too-tuk’，每分钟可达70至150次，持续时间从短到长达几分钟。另一种叫声为长达约20秒的快速低沉颤音，常以系列形式出现，速度在颤音间逐渐减慢。颤音有时会过渡到‘too-tuk’的歌曲，单音与颤音类似，只是播放速度较慢。","habits":"金须拟啄木鸟栖息于热带和亚热带湿润阔叶林及山地森林，常见于海拔250米以上的山脚，特别是在750至1000米的高度，最高可达约1500米。它们主要在树冠层活动，以果实如无花果和浆果为主食，也可能捕食昆虫，经常在枯木上啄食，推测是在寻找蚂蚁或白蚁巢穴中的食物。","breeding":"金须拟啄木鸟的繁殖季节从2月持续到8月，每窝产两枚蛋。","identification":"金须拟啄木鸟与其他拟啄木鸟相比，其独特的黄色颊须和多彩的头部颜色是主要的辨识特征。不同亚种间的差异主要体现在颊部颜色和头部羽毛的红色程度上。","protection":"IUCN：LC（无危）","distribution":"金须拟啄木鸟分布于马来半岛、印尼苏门答腊岛和婆罗洲的低地和山地森林，偶尔出现在次生林和可可种植园。","other":"该物种有三个已识别的亚种。"},{"name":"花彩拟啄木鸟","english_name":"Red-crowned Barbet","scientific_name":"Psilopogon rafflesii","overview":"花彩拟啄木鸟（英文名：Red-crowned Barbet，学名：Psilopogon rafflesii），是䴕形目拟啄木鸟科火簇拟䴕属的大型热带鸟。分布于东南亚，包括缅甸南部、泰国、马来西亚、新加坡、印度尼西亚和文莱等地的低地森林和种植园。其独特的红冠和复杂的面部图案使其易于识别。","appearance":"体长约24.5至27厘米，体重介于99至150克之间。全身以绿色为主，头顶红色，眼下方有红色斑点，颈部侧面有一红色标记，脸部呈黑黄相间，喉部蓝色，有宽广的眉纹。雄雌相似，但幼鸟颜色较淡，喙基部浅色。","call":"歌曲开始时为低沉的“took”音节，每秒一次，逐渐加快至约每秒三次的“tuk”音节，持续5至15秒，部分歌曲以快速颤音“-dattttttttt”结束，单调重复，每分钟2至3次。","habits":"栖息于低地的原始森林和次生林，偶尔出现在橡胶和榴莲种植园中。几乎仅限于低海拔区域，最高不超过600米，但在婆罗洲可能高达800米。以多样化的果实如无花果、一些栽培水果以及昆虫为食，后者通过其强大的喙从树皮中挖掘。","breeding":"繁殖季节为1月至7月，苏门答腊为11月至5月。筑巢于树干1至5米高处，已知至少产2枚卵，无更多繁殖信息。","identification":"与其他类似物种如金须拟啄木鸟和丽色拟啄木鸟的区别在于完全红色的头顶、眼上方的蓝线和黄色脸部斑块。","protection":"IUCN：NT（近危）","distribution":"分布于南缅甸（下丹那沙林）、泰国半岛、新加坡、苏门答腊东部、邦加岛、勿里洞岛以及婆罗洲。","other":"在一些城市化地区如新加坡仍可见到，但在泰国和马来西亚由于森林砍伐，其栖息地受到严重威胁。"},{"name":"丽色拟啄木鸟","english_name":"Red-throated Barbet","scientific_name":"Psilopogon mystacophanos","overview":"丽色拟啄木鸟（英文名：Red-throated Barbet，学名：Psilopogon mystacophanos），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。为东南亚热带地区的特有种，广泛分布在马来半岛、苏门答腊岛及婆罗洲等地。雄鸟拥有独特的黄色额部、红色头冠、喉部及胸前斑点，而雌鸟仅呈现蓝色与红色面部斑块，展现出显著的雌雄异型。","appearance":"体长约23厘米，体重介于60至95克之间，属于中等体型的绿色拟啄木鸟。雄鸟头部特征明显，具黄色额部小斑、红色头冠、喉部及胸前标记，辅以蓝色颊部和下喉部，黑色眼纹，喙大且黑。雌鸟略大于雄鸟，颜色较淡，具窄淡黄色额部、红色眼下方斑点，小红冠斑被蓝色环绕，蓝眼上区、脸颊及下颚颜色较淡。幼鸟喙色较浅，主要呈暗绿灰，鲜艳色彩较弱，红色最后显现。","call":"有两种鸣唱模式，其一为一系列单至四声的\"tyuk\"、\"tuk\"或\"tyowp\"音符，间歇不一，有时长达数秒；另一模式为快速颤音序列，逐渐减慢并变短，最终可能分解成单音，过渡到第一种鸣唱模式。雄鸟在展示行为中对雌鸟发出低沉\"hoot\"叫声，且在对抗鸣唱时会运用两种鸣唱。","habits":"栖息于各种低地森林环境，从原始森林到公园花园皆可见其踪迹。听其独特鸣叫，如持续的吞咽声、简洁的呼噜声，或一系列颤音最终放缓成呼噜声，音符具有\"敲击\"质感，不同于更响亮的花彩拟啄木鸟。","identification":"与同属其他种类相比，红喉拟啄木鸟的两性异形最为显著，雄鸟的面部色彩丰富，而雌鸟仅限于蓝色和红色。亚种ampalus的特征在于更大的喙，形状更为方正，雌鸟的红冠斑更大，喉部颜色更深。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛、苏门答腊岛和婆罗洲。"},{"name":"黑斑拟啄木鸟","english_name":"Black-banded Barbet","scientific_name":"Psilopogon javensis","overview":"黑斑拟啄木鸟（英文名：Black-banded Barbet，学名：Psilopogon javensis），是䴕形目拟啄木鸟科火簇拟䴕属的大型鸟类。其最显著的特征是拥有巨大的凿状喙。全身以叶绿色为主，具有红色喉部、黑色面罩和黄色冠羽及喙基部圆形黄斑。仅分布于爪哇岛和巴厘岛，栖息于低地和山脚森林。","appearance":"成年黑斑拟啄木鸟体长约26厘米，雄鸟体重约115克。全身覆盖绿色羽毛，头部有黑色、蓝色和红色标记；黑色眼纹和耳羽，连接至黑色胸带；红色喉部和胸部侧面有红色标记。喙色黑色。幼鸟色彩较暗淡，明亮部位颜色减弱，喙色较浅。","call":"鸣唱多变，通常是一系列加速的双音节‘too-took’声，持续10到45秒，有时长达60秒，有时伴有停顿，有时节奏不规则。偶尔发出单个‘too’声，每秒约3次，或加快的‘tyaap’和‘tap’声。尚不清楚两性是否都会唱歌。","habits":"黑斑拟啄木鸟栖息于低地和山脚森林，包括柚木林，偏好非密林环境，也可见于森林斑块，最高可达海拔约1500米。通常活动缓慢，难以在树冠层中观察。以果实如无花果和昆虫为食。","breeding":"繁殖期自2月到9月，也有报道12月繁殖，可能一年两次繁殖。据说会在树洞中产下两枚卵，但无更多细节。","identification":"与同类物种相比，黑斑拟啄木鸟具有独特的黄色冠羽和黑色胸带，以及红色喉部标记。","protection":"IUCN：LC（无危）。虽然广泛分布且常见，但生境高度破碎化。低地森林遭受严重破坏，高海拔地区的存在对保护尤为重要。需要繁殖和觅食数据，以及巴厘岛上种群估计和其他信息。有时被捕获用于笼鸟贸易。在几个保护区，包括Aas Purwo国家公园（东爪哇），有其分布。","distribution":"分布于爪哇岛和巴厘岛的低地和山脚森林。","other":"生态旅游者常因其而前往爪哇。"},{"name":"黄额拟啄木鸟","english_name":"Yellow-fronted Barbet","scientific_name":"Psilopogon flavifrons","overview":"黄额拟啄木鸟（英文名：Yellow-fronted Barbet，学名：Psilopogon flavifrons），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。在斯里兰卡的森林环境中，特别是在低地和山脚下的湿润地带，以绿色为主调的羽毛，黄色前额和颊须，蓝色面颊和喉咙，斑驳的下体，引人注目的鸟类。其别名为mukalang kottoruwa，在当地语言中称为මූකලන් කොට්ටෝරුවා。","appearance":"中等体型，长度约为21-22厘米，体重在57-60克之间。头部的前额和脸颊前方呈金色，其余头部侧面为蓝色，下巴和喉咙也是蓝色。颈部有淡色条纹，胸部有淡色斑点。幼鸟色泽较为暗淡。","call":"鸣唱表现为重复而有力的‘ke-cheer’声，叫声包括滚动上升的‘pup-pup-pup-pup’。","habits":"主要栖息于西南部山地森林、花园和树种植园，较少出现在湿润的低地森林和干燥东部地区的溪流旁，偶尔在干燥北部地区的溪流附近发现。通常独居或成对出现，活动范围可达海拔约2000米。以多种果实、浆果（包括无花果）、番石榴和木瓜为食，偶尔捕食昆虫和小型蜥蜴。","breeding":"繁殖期可能全年皆有，高峰期在3月至5月和8月至9月。在软木树如Bombax或Doona中挖掘巢穴，高度主要在1.8至3米之间，洞口直径5厘米，挖掘至约20厘米深，若连续多年使用，深度可达60厘米以上。每次产卵2至3枚，孵化和育雏期资料不详，雏鸟大小不一，推测孵化自首枚蛋开始，或两枚蛋之间间隔较长。","identification":"通过黄色前额和颊须、蓝色面部和斑驳的下体来区分于其他本地拟啄木鸟。","protection":"IUCN：LC（无危）。黄额拟啄木鸟在斯里兰卡普遍常见且适应性强，但在某些地区被视为果园害鸟，因造成作物损失。在斯里兰卡多个保护区如Bellanwila-Attidiya Sanctuary、Kelani River Forest Reserve、Ingiriya Forest Reserve和Sinharaja Forest Reserve内均有分布。","distribution":"黄额拟啄木鸟仅分布于斯里兰卡，主要在该国的西南部山地森林、花园、树种植园以及湿润的低地森林。","other":"黄额拟啄木鸟的形象曾出现在斯里兰卡5卢比的邮票上。"},{"name":"金喉拟啄木鸟","english_name":"Golden-throated Barbet","scientific_name":"Psilopogon franklinii","overview":"金喉拟啄木鸟（英文名：Golden-throated Barbet，学名：Psilopogon franklinii），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。是亚洲的一种大型绿色拟啄木鸟。广泛分布于东南亚，栖息于海拔900至2700米的森林中，偏好陡峭且植被茂盛的山谷环境。IUCN列为无危（Least Concern），因其分布范围广阔且种群稳定。","appearance":"体长20.5-23.5厘米，体重50-101克。头部特征明显，有宽大的黑色眼带，灰白的脸部和黄黑相间的冠羽。喉部有一小块黄色橙色斑块，容易被忽视。雄鸟具深金色上喉，下喉较淡；雌鸟翼部色调偏蓝或紫。幼鸟色彩暗淡，绿色更浓，明亮色彩和黑色细节模糊。","call":"鸣唱多变，开始于颤音，可能持续为全颤音歌，或颤音后接以每秒一次的“tuk”音，或双音节或三音节的‘tu-KEE-ow’，每分钟58-65次。歌声在繁殖季节可整天单调重复。","habits":"主要以果实为食，特别喜爱无花果、浆果和番石榴，偶尔食昆虫。活动隐秘，多在树冠层觅食，偶尔降下至下层林间。有时成群访问结果树，最多可达30只。","breeding":"繁殖期在3月至8月，筑巢于腐朽的树木或树桩中，高2-6米，巢室直径约8厘米。每窝产卵2-5枚，大小介于25-29.2毫米×18.8-22毫米。双亲共同孵卵及喂养雏鸟，孵化期和育雏期未知。","identification":"与其他拟啄木鸟相比，金喉拟啄木鸟的翼部颜色和喉咙斑块是其显著特征。与马来拟啄木鸟和蓝喉拟啄木鸟相比，它在海拔上更高。","protection":"IUCN：LC（无危）","distribution":"分布于尼泊尔中部至越南北部，马来半岛。在中国大陆，常见于云南、西藏等地的高山森林。","other":"在多个自然保护区内有记录，如泰国的Doi Inthanon和Kaeng Krachan国家公园。"},{"name":"斑喉拟啄木鸟","english_name":"Necklaced Barbet","scientific_name":"Psilopogon auricularis","overview":"斑喉拟啄木鸟（英文名：Necklaced Barbet，学名：Psilopogon auricularis），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。主要分布于老挝东南部和越南南部的亚热带低地热带湿润森林和山地森林，海拔可达2700米。其命名源自1919年赫伯特·C·罗宾逊和C·博登·克洛斯在越南南部朗边高原采集到的标本。","appearance":"这种色彩鲜艳的拟啄木鸟长约22.5厘米，体型粗壮，羽色以绿色为主，翅膀常带有蓝或紫色调。头部特征明显，额头和颈背红色，头顶金色，喉咙处有醒目的黄色，一条细薄的黑色线从眉纹后方环绕头部至颈部，形成独特的“项链”。与近缘种金喉拟啄木鸟极为相似，但两者分布区域不重叠。","call":"其叫声具有回声效果，类似蛙鸣，易于通过声音识别。","habits":"斑喉拟啄木鸟栖息于山地和丘陵森林中，偏好密集树冠下的环境，通常较难直接观察到。它们的饮食习惯可能与近缘种相似，曾有观察记录显示其捕食蝉。","breeding":"关于其繁殖生态的信息目前尚未详细记载。","identification":"与相对较大且曾为同种的金喉拟啄木鸟相比，斑喉拟啄木鸟的颈背红斑较小，耳覆羽带有紫色，整个喉咙呈深黄色，腹部下方的黄色较少，中央头顶有一条狭窄的淡黄白色带。","protection":"IUCN：LC（无危）。全球种群数量未量化，但在其分布范围内被认为是常见至局部频繁的物种，估计分布面积约为42,800平方公里。","distribution":"分布于老挝东南部和越南南部，主要栖息于亚热带低地热带湿润森林和山地森林，海拔可达2700米。"},{"name":"马来拟啄木鸟","english_name":"Black-browed Barbet","scientific_name":"Psilopogon oorti","overview":"马来拟啄木鸟（英文名：Black-browed Barbet，学名：Psilopogon oorti），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。体型略小的亚洲拟啄木鸟，分布于马来半岛山区和苏门答腊岛的亚热带森林中，主要栖息于海拔600至2,000米处。其头部拥有独特的蓝红黄黑四色组合，是该物种显著的外部特征之一。","appearance":"马来拟啄木鸟长约21.5厘米，体重约为62克，整体呈绿色，头部色彩丰富，具有黑色眉毛，蓝色脸颊，黄色喉部带蓝色边缘，红色点缀额头、喉部及颈侧。雌雄差异不大，仅在标本中观察到雄鸟可能有红色或橙红色眼睛。亚成鸟颜色较为暗淡，红色部分更小且模糊。","call":"马来拟啄木鸟的叫声为tok?tr?trrrrrt的呼唤，约每分钟20次，重音落在第三个音节，形成连贯的三音节短语。","habits":"马来拟啄木鸟是典型的冠栖拟啄木鸟，常栖息于海拔1,000至2,000米的亚热带森林中。它们主要以水果为食，辅以昆虫，尤其在繁殖季节会增加昆虫的摄取量。活动范围主要在树冠层，偶尔会降至较低位置。","breeding":"繁殖季节在苏门答腊为2月至11月，在马来半岛为3月至6月。它们会在树干上挖掘巢穴，通常位于地面以上2至10.5米处，具体繁殖细节未知。","identification":"马来拟啄木鸟与其他拟啄木鸟的区别在于体型略小，黑色眉毛，蓝色脸颊，黄色喉部带红点。在中国，原分布于海南和广西的亚种已被分立为黑眉拟啄木鸟，而原分布于台湾的亚种被归类为台湾拟啄木鸟。","protection":"IUCN：LC（无危）。马来拟啄木鸟在其分布范围内常见，尤其是在苏门答腊。然而，关于其种群和繁殖生物学的信息不足，需要进一步研究。目前在多个保护区可见，如Kerinci-Seblat国家公园和Sungai Penuh保护区。","distribution":"马来拟啄木鸟分布在马来半岛山区和苏门答腊岛，通常在海拔600至2,000米的亚热带森林中，包括蒙塔纳和上层龙脑香林。在苏门答腊，高度分布通常在600米以上，在马来半岛则从750米起，最高可达2,400米。","other":"马来拟啄木鸟在历史上曾被归类于不同的属名，如Bucco和Megalaima。分子系统发育研究表明，该物种属于Psilopogon属，与火簇拟啄木鸟同属一系。"},{"name":"中南拟啄木鸟","english_name":"Indochinese Barbet","scientific_name":"Psilopogon annamensis","overview":"中南拟啄木鸟（英文名：Indochinese Barbet，学名：Psilopogon annamensis），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。主要栖息于热带和亚热带森林，分布于老挝南部、越南中南部以及柬埔寨东部。曾被视为黑眉拟啄木鸟的亚种。","appearance":"体长约21.5至23.5厘米，是一种山地绿色拟啄木鸟。头部前额、眼上和颈背有少量红色，喉部呈黄色并带有宽广的蓝色边缘，头顶为淡黄色，胸侧有微小的红色斑点。黑色的眼纹延伸过眼至耳羽，耳羽为蓝色并与喉部的蓝色边框相连。喙基部下方有较多的灰色角质色，某些个体的喙则全黑。翼长而尾短，与其他同类物种有明显区别。","call":"其鸣声比黑眉拟啄木鸟略高音，每组重复的叫声或节拍尾部音符较多，使得声谱上看起来几乎连续。","habits":"通常生活在阔叶常绿林中，海拔高度一般在750米以上，在越南的记录高达2400米。","identification":"与其他马来拟啄木鸟物种群成员的区别在于较长的翼和较短的尾，以及独特的头部颜色和喙的基部色彩。","protection":"IUCN：LC（无危）。在大部分分布范围内常见，但关于种群数量和繁殖生态学的信息不足，需进一步研究。该物种存在于多个保护区，如越南的Bach Ma国家公园。","distribution":"分布于老挝东南部、越南中南部以及柬埔寨东部。在繁殖季节和非繁殖季节的分布信息一致。"},{"name":"黑眉拟啄木鸟","english_name":"Chinese Barbet","scientific_name":"Psilopogon faber","overview":"黑眉拟啄木鸟（英文名：Chinese Barbet，学名：Psilopogon faber），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。又名: 五色鸟，俗称: “花和尚”，色彩斑斓的热带森林冠层栖息者，身长约20-23厘米，以翠绿的身体、蓝色的头部、黄色的额头和喉部、红色的眼前和前颈以及黑色的眼部至耳羽上方为显著特征。叫声独特，类似敲击木鱼的声音，因此也有‘花和尚’的俗名。在中国南部和海南岛的亚热带或热带湿润山地森林中广泛分布。","appearance":"黑眉拟啄木鸟体长约为20至23厘米，具有鲜明的色彩组合：翠绿色的身体，蓝色的头部大部分区域，黄色分布于额头和喉部，眼部至耳羽上方为黑色，带有小部分红色于眼前和前颈，喙基上黑色嘴须发达，脚呈铅灰色。雄雌及幼鸟的羽毛特征相似，没有明显差异。","call":"叫声单调而响亮，类似于敲击木鱼的“郭、郭郭郭郭……”声，这是识别它们的重要特征之一。","habits":"栖息于亚热带和热带湿润的低地森林及山地森林，海拔高度通常在250米以上，最高可达2000米。属于留鸟，可能具有定居习性，但确切的迁徙行为尚未完全明确。偏好成熟的原生森林，是森林质量的指标物种。","breeding":"繁殖季节可能为2月至5月，特别是在海南岛上。繁殖期间会出现对唱行为。关于繁殖生态的细节了解甚少，但可能与近缘种台湾拟啄木鸟相似。","identification":"与同属其他种类相比，黑眉拟啄木鸟拥有黑色的冠部，胸部有更多的红色，以及独特的红、黄、蓝、黑、绿五色组合。与台湾拟啄木鸟(Megalaima oorti)的区别在于黑眉拟啄木鸟的冠部为黑色，胸部红色更多，而亚种sini的耳羽更偏紫色，上体颜色更接近和马来拟啄木鸟。","protection":"IUCN：LC（无危）","distribution":"主要分布于中国南部，包括海南岛，生活在亚热带和热带湿润的低地森林及山地森林中。","other":"曾被认为是台湾拟啄木鸟(Megalaima oorti)的亚种，现已提升为独立物种。"},{"name":"台湾拟啄木鸟","english_name":"Taiwan Barbet","scientific_name":"Psilopogon nuchalis","overview":"台湾拟啄木鸟（英文名：Taiwan Barbet，学名：Psilopogon nuchalis），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。台湾特有种，属于拟啄木鸟科。其显著特征为鲜艳的彩虹色脸部，由红、蓝、黄三色组成，身体主要为亮丽的绿色。分布于台湾的森林、公园及花园，自低地至海拔2800米处均有其踪迹。","appearance":"台湾拟啄木鸟长约21.5厘米，体重介于67至123克之间。成鸟头部具有红色眼纹，黄色金喉部带有蓝色边缘，胸部呈红色，眼上和眼后有一条黑色条纹，上颊区亦为黑色，耳羽蓝色。幼鸟颜色较为暗淡，色彩不如成鸟鲜明。头顶在红色额部之后呈黄色，逐渐过渡至青绿色，与其它同类物种相比，缺乏明显的红色颈背斑块。","call":"台湾拟啄木鸟发出的声音包括类似青蛙的呱呱声或沸腾的气泡声，以及空洞的气泡般的呼呼声。","habits":"台湾拟啄木鸟栖息于各种类型的森林，最低可达海平面，但通常在300米以上，最高可达2800米。它们在树冠层和次冠层活跃，以水果为主要食物，但在繁殖期间会摄取较多昆虫。已知的食物包括多种植物的浆果和各种昆虫，如甲虫、半翅目、膜翅目、螳螂目、蜻蜓目、鳞翅目、直翅目、蜚蠊目等。","breeding":"繁殖季节可能主要集中在6月至8月，但也有记录显示筑巢活动最早在1月和4月进行。雄鸟主要负责巢穴的挖掘，巢穴通常位于离地面2至10.5米高的树木中。平均产卵数量为3枚白色卵（2至4枚），尺寸约27.5至31毫米 x 21至22毫米，孵化期平均13.8天，由双亲共同孵化，雏鸟期平均27.5天。研究发现，总体孵化至飞翔的成功率仅为32.8%，失败原因多样。","identification":"台湾拟啄木鸟与马来拟啄木鸟、中南拟啄木鸟和黑眉拟啄木鸟的区别在于缺乏醒目的红色颈背斑块，以及特有的红色胸带和黄色头顶，逐渐过渡至青绿色。","protection":"IUCN：LC（无危）","distribution":"台湾拟啄木鸟仅分布于台湾，涵盖从低地到山地的各种森林环境，包括海平面至海拔2800米的高度。","other":"台湾拟啄木鸟在台湾有多个地方名称，如五色鸟和多彩僧，反映了其多彩的羽毛和独特的叫声。"},{"name":"蓝喉拟啄木鸟","english_name":"Blue-throated Barbet","scientific_name":"Psilopogon asiaticus","overview":"蓝喉拟啄木鸟（英文名：Blue-throated Barbet，学名：Psilopogon asiaticus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。中型拟啄木鸟，分布于喜马拉雅山麓至东南亚。其头部特征显著，前额至头顶为鲜红色，中间有一黑色横带，头侧、颏、喉为蓝色，下喉两侧各有红色点斑。主要栖息于海拔2000米以下的热带森林，常见于低地和山脚地带。","appearance":"体长约22-23厘米，体重61-103克。具有短尾，全身绿色，喉部和面部为蓝色。雄鸟的红色帽状顶部边缘为黑色，额部被黄色和黑色或蓝色的带状条纹中断；雌鸟可能缺乏红色侧胸斑。幼鸟颜色较暗淡，头部图案不鲜明，红色部分呈橙色，蓝色和黑色部分较暗，背部和腹部的绿色较暗淡。","call":"发出重复的三到四音节的‘took-o-rrook！’叫声，歌声柔和，不如棕头绿拟啄木鸟和斑头绿拟啄木鸟那样嘈杂。","habits":"栖息于原始和次生的常绿和落叶山地森林，也出现在果园、种植园和花园，甚至进入城镇和城市中的果树区域。通常居住在150至2000米的高度，偶尔可达2450米。主要以榕树果和其他水果、浆果为食，也食用花朵、昆虫幼虫、螳螂、蟋蟀和蜈蚣。","breeding":"繁殖期从3月至7月，也可能在南方和低海拔地区延至更晚，有时会双窝繁殖。巢穴由双方挖掘，位于1.5至8米高的枯木或树枝上，巢室宽约10至15厘米。每窝产卵2至5枚，主要是3至4枚，白色，大小约为26.7至31毫米×19.3至23毫米，孵化期大约14天，幼鸟成长迅速。","identification":"与休氏拟啄木鸟的区别在于冠部图案和全蓝色的面颊和喉咙，没有黑色条纹。幼鸟与成鸟的颜色差异明显。","protection":"IUCN：LC（无危）。在中国西南部分地区和南部广西分布，需加强保护。","distribution":"分布于巴基斯坦东北部至越南中部，缅甸，主要在中低山地、丘陵、沟谷和山脚平原地带的常绿阔叶林中，也出现于林缘和村边乔木树上。","other":"蓝喉拟啄木鸟适应性强，常见于多个国家公园，如印度的Corbett、Kaziranga和Nameri，尼泊尔的Chitwan，泰国的Doi Pha Hom Pok、Phu Suan Sai、Nam Nao和Kaeng Krachan，以及Mchao和Kamlang野生动物保护区。"},{"name":"绿喉拟啄木鸟","english_name":"Turquoise-throated Barbet","scientific_name":"Psilopogon chersonesus","overview":"绿喉拟啄木鸟（英文名：Turquoise-throated Barbet，学名：Psilopogon chersonesus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。是亚洲的一种树栖鸟类，主要分布在泰国南部的山地森林中。其鲜艳的色彩和蓝喉拟啄木鸟极为相似，但两者的分布区域并不重叠。绿喉拟啄木鸟头部具有独特的黑色眼后线和较为淡色的喉咙。","appearance":"绿喉拟啄木鸟体长约22至23厘米，属于中等体型的绿色巴比特，拥有蓝色的喉咙和面部。与蓝喉拟啄木鸟相比，本物种头部颜色更淡，尤其是喉咙部分，黑色眼后线更为明显，下巴可能带有黄色或白色，头顶大部分为蓝色，仅小部分红色位于颈背。喙稍长，幼鸟色泽较暗淡，红色和白色减少。","call":"鸣叫声与蓝喉拟啄木鸟类似，发出空洞的敲击声序列，如'bu-goh-goh-goh, bu-goh-goh-goh'。也会发出类似的空洞颤音，有时会转化为歌曲。","habits":"绿喉拟啄木鸟通常为留鸟，活动范围有限，主要生活在泰国南部的山地森林中。它们的活动模式和食物来源尚未详细记录，但预计与蓝喉拟啄木鸟相似，以水果和昆虫为食。","breeding":"关于繁殖行为的信息稀缺，只知道晚九月时曾收集到幼鸟标本，且在六月末和九月末观察到可能是繁殖后的换羽。推测其繁殖生态与蓝喉拟啄木鸟相近。","identification":"与蓝喉拟啄木鸟的区别在于，绿喉拟啄木鸟头部色彩更淡，有明显的黑色眼后线，下巴可能呈现黄色或白色，而红色仅限于颈背小片区域。","protection":"IUCN：LC（无危）。尽管分布范围极小（约850平方公里），但在其范围内并不罕见。部分分布区被Khao Luang和Tai Rom Yen国家公园保护。","distribution":"绿喉拟啄木鸟主要分布在泰国南部的山地森林，具体位置包括Khao Luang和Tai Rom Yen国家公园。"},{"name":"山拟啄木鸟","english_name":"Mountain Barbet","scientific_name":"Psilopogon monticola","overview":"山拟啄木鸟（英文名：Mountain Barbet，学名：Psilopogon monticola），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。外观略显暗淡，主要分布在婆罗洲北中部的山脉地带，常见于海拔600至1200米的山地森林及其边缘。","appearance":"体长20至22厘米，雄鸟体重65至110克，雌鸟体重83至112克。体型较小而圆润，上部草绿色，下部浅绿色。头部呈淡蓝色，喉部黄白色，头部后方有一条红色条纹。雄鸟前额蓝黄色，头顶后部和颈背红色，边缘部分蓝色，喉部带有黄色晕染，斑点灰色，有时可见蓝色痕迹，上胸两侧有红色标记。雌鸟类似雄鸟，但体型较大。幼鸟颜色较暗淡，头顶后部和颈背橙红色斑块。","call":"鸣唱为一系列快速音符组成的重复乐句，‘tu-tu-tu-tu-tuk’到更快的‘tu-t-t-t-tuk’，每句话中的音符数量可变，最多可达每秒六句话，其间有不规则的短暂停顿，整首歌可持续数分钟。","habits":"栖息于婆罗洲山区的山地和亚山地森林及其边缘，以果实为主食，同时捕食各类昆虫，如蚂蚁、蝉、蜻蜓、蟋蟀、蝗虫、甲虫、蛾子和螳螂。","breeding":"筑巢于树洞中，雌鸟通常产2至4枚卵，孵化期为13至15天。","identification":"与雌性丽色拟啄木鸟相似，但嘴型较小，上喙基部两侧的‘胡须’无红色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于婆罗洲山区，从基纳巴卢山向南至卡普阿斯和卡扬山脉。"},{"name":"休氏拟啄木鸟","english_name":"Moustached Barbet","scientific_name":"Psilopogon incognitus","overview":"休氏拟啄木鸟（英文名：Moustached Barbet，学名：Psilopogon incognitus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。中型的亚洲拟啄木鸟，属于火簇拟啄木鸟科。以绿色为主色调，面部色彩鲜明，具有独特的蓝色脸颊和喉咙，黑色的眼纹和颊部线条增添了其魅力。分布于东南亚的缅甸、泰国、柬埔寨、老挝和越南的山地与低地常绿森林。","appearance":"体长约22至23厘米，体态丰满，颈短头大，尾短。头部特征明显，冠部绿色，额部有非常细小的红色斑点，颈背有红色斑块，眼纹黑色。脸颊和喉咙蓝色，喉部被黑色线条分割。雌雄相似，幼鸟色彩较暗淡，尤其是鲜艳部位颜色减弱，胸侧斑点可能较小或缺失。不同亚种间存在细微差异。","call":"鸣声独特，由单个\"tuk\"音开始，逐渐转变为双音或三音的\"tuk-uk\"或\"tuk-a-tuk\"，有时以三音节结尾的颤音结束。鸣叫通常短暂，每秒约一个音节，持续10至12秒，但在互动或对唱时，鸣唱会更长且节奏更快。","habits":"栖息于海拔600至700米的常绿阔叶林，以各种无花果和其他树种如Macaranga和Trema的果实为食，繁殖期间也食用昆虫，如天牛甲虫和竹节虫。昆虫会被敲碎后喂给幼鸟。","breeding":"在树洞中筑巢","identification":"与蓝喉拟啄木鸟相比，面部色彩较淡，喉部有黑色的亚口线。亚种eurous有较大的红色后冠和颈背斑，喉部颜色更浅，偏绿蓝。elbeli亚种的颈背斑与指名亚种类似，但喉部颜色更绿蓝。","distribution":"分布于东南亚的缅甸、泰国、柬埔寨、老挝和越南的山地与低地常绿森林。"},{"name":"黄顶拟啄木鸟","english_name":"Yellow-crowned Barbet","scientific_name":"Psilopogon henricii","overview":"黄顶拟啄木鸟（英文名：Yellow-crowned Barbet，学名：Psilopogon henricii），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。美丽的、色彩柔和的拟啄木鸟，属于Megalaimitdae家族。以蓝喉、眼周的暗色‘眼影’和鲜亮的黄色额部及眉纹著称。其蓝色的冠羽和颈背的红色痕迹有时难以察觉。该鸟种栖息于低地森林，面临因栖息地丧失而受到的威胁。","appearance":"成年黄顶拟啄木鸟体长21.5至22.5厘米，体重65至83克。全身绿色，喙粗壮，喉部呈粉末蓝，头部顶部有大量的黄色。雌雄两性的标本（指名亚种）中央后冠呈蓝色，从额部到头顶广泛延伸，覆盖眼睛上方，呈金黄色；眼窝黑色，眼线黑色，颊部淡绿色，眼上有一条淡绿色线条；颈部两侧有窄的红带，胸部靠近喉部的边界处有红色标记。幼鸟颜色较暗淡，鲜艳的颜色更浅，仅额头为黄色，喙基部灰白色。brachyrhynchus亚种喙较小，色彩不那么鲜艳，蓝色区域更接近紫蓝色，耳羽的绿色更偏黄，头部顶部的黄色较少金色。","call":"其鸣唱通常是一系列长句子，每个句子由2至7个“tuk”音符组成，前面或后面有时跟着短暂的颤音，‘ttrrrt’；每个句子持续2至3秒，有时可能缺少颤音。","habits":"栖息于低地森林，以果实为主食，尤其是无花果（Ficus）。一只被监测四天的个体在7.5公顷范围内活动，75%的时间都在结果实的无花果树（Ficus binnendykii）附近或树上；其主要活动是从这棵树到它栖息的一棵40米高的树的树冠。关于其进食习惯的其他信息尚缺。","identification":"黄顶拟啄木鸟可以通过其蓝喉、大量的黄色头部特征以及颈部侧面的红色带子与其它类似物种区分开来。","protection":"IUCN：NT（近危）","distribution":"分布在东洋界，包括马来半岛、印度尼西亚的苏门答腊岛和婆罗洲。"},{"name":"蓝顶拟啄木鸟","english_name":"Flame-fronted Barbet","scientific_name":"Psilopogon armillaris","overview":"蓝顶拟啄木鸟（英文名：Flame-fronted Barbet，学名：Psilopogon armillaris），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。是亚洲的一种特有拟啄木鸟，分布于爪哇岛和巴厘岛的山区。拥有绿色羽毛，鲜明的黄色至橙色前额，蓝色颈背，以及橙色胸带。体长约19.5-23厘米，重约61-79克。","appearance":"小型而体格健壮的绿拟啄木鸟，具有粗壮的喙和显著的黄色到橙色前额。雄鸟和雌鸟的指名亚种都有黄色橙色的前额和前冠，蓝色的中冠至颈背，眼睛前方有黑色线条，下颌前方黑色，颈部两侧有金色至橙色标记，上胸部呈金橙色。幼鸟颜色较暗淡，黄色橙色和蓝色部分更淡，面积较小。巴厘亚种（baliensis）体型略大，前额颜色偏红橙或棕橙，颈部和胸部侧边也有类似倾向。","call":"发出一系列短暂的颤音，'t-t-t-rrrt'，反复连续；同时发出单一的嗡嗡声'tirrr'。","habits":"栖息于低地和山地的原始森林，边缘地带，附近花园和种植园中的结果树；海拔高度可达约2500米，常见于600米以上。全年留居且定居。以水果为主食，包括咖啡果实，也会摄取一些昆虫；有记录显示其会捕食蜘蛛。在圈养环境中，雏鸟食用粉虫、蟋蟀和小鼠。","breeding":"繁殖期为2月至7月，也可能延续至9月至1月；可能有二次繁殖。在高大的树木中挖掘巢穴；在圈养条件下，成年鸟双方共同挖掘深度达35厘米的巢洞，耗时1个月完成。每窝产卵2枚；在圈养条件下，孵化由双亲共同承担，孵化期13-15天，孵化后母鸟对公鸟表现出攻击性，雏鸟由双亲喂养，当一方在外敲击时另一方会离开；人工饲养的雏鸟大约14天后睁开眼睛，17天后开始长出羽毛，首次飞行发生在大约37天时。一对圈养的蓝顶拟啄木鸟成功产下3窝各含2枚卵的蛋，人工喂养后培育出3只健康的幼鸟。","identification":"通过其独特的黄色至橙色前额，蓝色颈背和橙色胸带与同类物种区分开来。巴厘亚种与其他亚种的区别在于体型略大，前额颜色的差异，以及颈部和胸部侧边的色彩倾向。","protection":"IUCN：LC（无危）。蓝顶拟啄木鸟在爪哇和巴厘岛普遍分布，是当地最常见的拟啄木鸟种类之一。在Gunung Gede-Pangrano国家公园和Aas Purwo国家公园（爪哇）有其分布记录，但在后者中较为罕见。","distribution":"分布于爪哇岛山区和巴厘岛，主要在海拔600米以上的地区，最高可达约2500米。"},{"name":"金枕拟啄木鸟","english_name":"Golden-naped Barbet","scientific_name":"Psilopogon pulcherrimus","overview":"金枕拟啄木鸟（英文名：Golden-naped Barbet，学名：Psilopogon pulcherrimus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。是东南亚特有种，主要分布在婆罗洲的山脉中，从北部的基纳巴卢山和特鲁斯马迪山向南至穆鲁和穆鲁德。引人注目的绿宝石色鸟，具有荧光蓝色的冠和喉部，而其标志性的金色颈背只有在特定角度下才可见。这种鸟的分布范围限于海拔1000米以上的高山森林。","appearance":"体长20-21.5厘米，体重55-76克，是一种中等体型的绿拟啄木鸟，体态结实。雄鸟头部从额到颈后呈蓝色，喉部蓝色，上背边缘有一块金色斑点，眼周黑色边缘蓝色，面部绿色，眼上方呈绿金色。雌鸟可能颜色更淡。幼鸟通常较暗淡，缺乏金色特征。","call":"以声音最佳检测，发出两声明亮的空洞音节后接短暂的上升颤音，其歌声由三音节短语组成，速度为每分钟18-25个短语，以双音结尾。","habits":"栖息于山地原始森林和次生森林，苔藓覆盖的森林，边缘及部分砍伐的区域。海拔高度从1000米至3100米，通常高于1500米，比婆罗洲拟啄木鸟和山拟啄木鸟的分布更高。食物以果实、浆果为主，偶尔会吃绿色嫩芽，常在林中层和树冠层觅食。","breeding":"繁殖季节据标本数据推测为12月至3月，具体细节未知。","identification":"与黄顶拟啄木鸟外观相似，但两者在海拔分布上不重叠。","protection":"IUCN：LC（无危）","distribution":"分布于婆罗洲北部和中部山区，从基纳巴卢山和特鲁斯马迪山向南至穆鲁和穆鲁德，最近在东加里曼丹的Menyapa山脉也有发现。","other":"已知在基纳巴卢山和Gunung Mulu国家公园（婆罗洲）出现，虽然目前无立即威胁，但由于其狭窄的高地分布范围，需要更多关于其生态和生物学的数据，以备未来可能的保护措施。"},{"name":"黄耳拟啄木鸟","english_name":"Yellow-eared Barbet","scientific_name":"Psilopogon australis","overview":"黄耳拟啄木鸟（英文名：Yellow-eared Barbet，学名：Psilopogon australis），是䴕形目拟啄木鸟科火簇拟䴕属的小型鸟类，仅见于爪哇和巴厘岛。其最显著的特征为头部天蓝色斑块和眼下鲜亮的黄色斑点。栖息于低地至山脚森林，偶尔可见于再生林、竹林、落叶林以及果园和花园。","appearance":"体长约16-17厘米，体重26-39克。整体呈叶绿色，头部天蓝，具黑色喉带，黄色耳羽和脸颊，由黑色眼纹和髭纹框饰。成年个体的头冠和前额全蓝，喉咙天蓝，胸前有黄色金色横带。幼鸟颜色较暗淡，头部主要为绿色，缺乏成鸟的鲜艳色彩，嘴和眼周皮肤颜色较淡。","call":"鸣声多样，包括类似昆虫的一系列四音节的歌曲，有时以鸽子般的‘ooooooo’结尾，或单音节快速歌唱，每分钟180个音符。还有所谓的‘警哨’歌曲，颤音但带嘶哑的‘ttirrr, ttirrr,-’。在遭遇时发出刺耳的声音，不规则的‘teeow’音符串，以及类似乞食叫声的嘁嘁喳喳声和快速的颤音。","habits":"常居留于低地和山脚森林及其边缘地带，主要栖息于常绿森林，但也可能移入再生林、斑驳森林，访问种植园、花园、竹林和落叶林。海拔高度可达2000米。一般领域性强，但在繁殖季后会移动到有果实的食物源，包括那些非繁殖地。","breeding":"繁殖季节为2月至10月在爪哇。具体繁殖细节未知。","identification":"与蓝顶拟啄木鸟容易混淆，但黄耳拟啄木鸟可通过全蓝色的头冠（缺少橙色前额和前头冠）、蓝色喉咙、喉咙后方的黑色带以及眼下的黄色标记来区分。","protection":"IUCN：LC（无危）。在分布区内常见，显示出一定的适应性。","distribution":"分布于爪哇岛和巴厘岛。"},{"name":"蓝耳拟啄木鸟","english_name":"Blue-eared Barbet","scientific_name":"Psilopogon cyanotis","overview":"蓝耳拟啄木鸟（英文名：Blue-eared Barbet，学名：Psilopogon cyanotis），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。生活在东南亚大陆的拟啄木鸟科鸟类，广泛分布于尼泊尔东部、印度东北部至泰国及中南半岛的低地和山脚地带的茂密阔叶林中。该物种拥有鲜艳的绿色羽毛，蓝色的脸部图案，以及复杂的黑、红、橙、黄斑纹。","appearance":"蓝耳拟啄木鸟体长约16至17厘米，体型圆润，颈部短，头部大而尾部短小。其羽毛以绿色为主，脸部有独特的蓝色耳罩和红色斑点，喉咙处有一条黑色带状标记。雄鸟具有黑色前额，雌鸟的头部图案较为暗淡，带有更多的橙色色调。幼鸟的头部为绿色，耳罩和喉咙部分带有蓝色。喙部呈深色。","call":"蓝耳拟啄木鸟的领地叫声为响亮的重复声调，有时也会发出类似警笛的哨音。","habits":"这种鸟主要栖息在低地和山脚地区的浓密森林中，偶尔也会出现在果园和高大的树木残余林中。它偏好高树冠层，活动范围广泛，以水果为食，也会捕食昆虫。蓝耳拟啄木鸟在树洞中筑巢。","breeding":"关于蓝耳拟啄木鸟的具体繁殖信息记录较少，但已知它们会在树洞中筑巢，进行繁殖。","identification":"蓝耳拟啄木鸟与同属的其他种类如黑耳拟啄木鸟和黄耳拟啄木鸟在头饰上有明显差异，尤其是蓝色耳罩和黑色前额的组合使其易于区分。","protection":"IUCN：LC（无危）","distribution":"蓝耳拟啄木鸟主要分布在尼泊尔东部至印度东北部，向南延伸至泰国和中南半岛，包括缅甸南部地区。在中国大陆，主要见于云南西南部的热带雨林。","other":"尽管蓝耳拟啄木鸟与黑耳拟啄木鸟在泰国-马来西亚边境有疑似杂交现象，但目前没有确凿证据表明存在稳定的杂交后代。"},{"name":"加里曼丹拟啄木鸟","english_name":"Bornean Barbet","scientific_name":"Psilopogon eximius","appearance":"体型小而健壮，约15至16厘米长，喙短而强。头部图案复杂，雄鸟具有黑色前额至前冠，红色后冠，蓝线从眼窝延伸过眼睛，眼下方有黄色斑点，耳羽常有细黑边，脸颊后方有红色，黑色喉咙，胸部有红色。雌鸟较暗淡，可能额头有蓝色。幼鸟更暗淡，红色部分淡化或缺失，喉咙呈蓝黑色带白色斑点。","call":"快速连续发出类似‘tiuk’的单音节叫声，每秒3至6声，持续可达40秒以上，另有一种快速颤音叫声。","habits":"栖息于湿润的山地森林，主要活动于树冠层，通常在海拔900至1387米之间，偶尔低至370米。居民性，可能为定居物种，以无花果和其他果实为食，主要在树冠觅食。","breeding":"可能在5月至10月或更晚繁殖。唱歌时会膨胀喉咙并转动头部。","identification":"独特的短黑喙、明亮的黄色脸部斑点、黑色喉咙和红黑相间的冠部组合使其在所处生境中与其他拟啄木鸟区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于婆罗洲的山区，包括基纳巴卢山和穆鲁国家公园等较高海拔地区。","other":"虽然数量不多，且知之甚少，但在婆罗洲的山地部分比岛上的其他两种特有山地拟啄木鸟（山拟啄木鸟和）更为广泛。"},{"name":"斯里兰卡拟啄木鸟","english_name":"Crimson-fronted Barbet","scientific_name":"Psilopogon rubricapillus","overview":"斯里兰卡拟啄木鸟（英文名：Crimson-fronted Barbet，学名：Psilopogon rubricapillus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。是亚洲特有的拟啄木鸟，仅见于斯里兰卡的热带湿润低地森林，海拔可达1,300米。这种鸟体型较小，长约15厘米，以绿色为主，头部带有醒目的红色额部，侧面有蓝色条纹，黑眼线后方有黑色半月形标记。","appearance":"该鸟体长16至17厘米，体重32至39.5克，体色以绿色为主。雄鸟额头鲜红，眼周有金色斑纹，眼线下有一条黑色纹路，后部黑色边缘环绕，脸部后侧有蓝色延伸至颊部；喉部金橙色，胸部有橙红色斑点。雌鸟的橙红色胸部不如雄鸟鲜艳。幼鸟色彩较暗淡，缺乏鲜明的标记，喉咙颜色较浅，下体全绿。","call":"鸣唱为一系列连续的‘pop-pop-pop-pop’声，每秒约6个音节，中间有短暂停顿，有时持续5分钟以上，易与黄额拟啄木鸟的前奏混淆，但其短促的乐句更明显。此外，还发出缓慢的单一、极短、上扬的‘Whup’音符，速率低于每秒1次，音质比赤额拟啄木鸟柔和。","habits":"栖息于常绿林、林缘、果园和城市花园，甚至出现在农田树丛中，偏好有树木的农业区。在低地湿润区最为常见，局部可见于干燥地带，最高可达海拔1300米左右。以无花果为主食，也吃其他果实、浆果及小型昆虫，如毛虫、蛀虫幼虫、蚂蚁和飞蚁。群体聚集于果树上，数量可达30只以上，进食无花果时会反复啄食而非一口吞下。","breeding":"繁殖季节从12月至次年9月。选择腐朽的椰子树作为筑巢地点，巢穴可能被其他物种破坏。繁殖生态研究有限，与近缘种马拉巴拟啄木鸟相比，两者的繁殖周期可能相似。","identification":"与黄额拟啄木鸟的区别在于体型更小和红色的额头，与赤胸拟啄木鸟的区别在于腹部无条纹。雌雄之间主要通过胸部橙红色的亮度差异辨识。","protection":"IUCN：LC（无危）。在斯里兰卡湿润低地常见，干燥区较为零散。适应性强，但栖息地退化和破坏是潜在威胁，尤其是在法律执行和国家公园保护不力的情况下。存在于多个保护区，如Sinharaja森林保护区和Uda Walawe国家公园。","distribution":"仅分布于斯里兰卡，包括低地湿润森林及局部干旱区域，海拔上限约为1300米。","other":"在斯里兰卡当地被称为heen kottoruwa。"},{"name":"马拉巴拟啄木鸟","english_name":"Malabar Barbet","scientific_name":"Psilopogon malabaricus","overview":"马拉巴拟啄木鸟（英文名：Malabar Barbet，学名：Psilopogon malabaricus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。广泛分布于印度西南部，包括从果阿南部至喀拉拉邦和泰米尔纳德邦西部的地区。该鸟拥有醒目的红脸、额头、喉部和胸部，全身主要呈绿色。","appearance":"这种鸟体型粗壮，全身以绿色为主，面部、额头、喉部及胸部覆盖着红色羽毛。头部两侧和胸部有淡蓝色条带，一条黑色横带将蓝色部分与红色区分开来。幼鸟的绿色较暗淡，脸部图案不明显，头部蓝色被灰色替代，红色部位带有黄色，腹部呈均匀绿色，与成鸟显著不同。","call":"马拉巴拟啄木鸟的叫声为快速连贯的‘kuk-kuk-kuk’声，与赤胸拟啄木鸟相似，但节奏略快。","habits":"栖息于印度西部的湿润森林、果树种植园和残存林区，延伸至农田树荫处和花园，最高可达海拔约1200米。偏好较小的无花果种类，动物性食物约占其饮食的20%。","breeding":"繁殖季为12月至次年5月，50%的配对会连续两次筑巢，首次离巢后4-6天再次筑巢。巢穴由双方挖掘，通常位于离地面8-20米高的细枝下方，平均深度17厘米，直径7.25厘米，有时长达1.5米。每窝产卵2-3枚，平均孵化期14-15天，幼鸟在35-37天后离巢。","identification":"与赤胸拟啄木鸟相比，马拉巴拟啄木鸟的面部红色更显著，叫声更快，栖息地更为湿润。","protection":"IUCN：LC（无危）","distribution":"主要分布在印度西南部，包括从果阿南部到喀拉拉邦和泰米尔纳德邦西部的区域。","other":"在某些地区，马拉巴拟啄木鸟能适应人类改变的环境，如咖啡种植园和农田。"},{"name":"赤胸拟啄木鸟","english_name":"Coppersmith Barbet","scientific_name":"Psilopogon haemacephalus","overview":"赤胸拟啄木鸟（英文名：Coppersmith Barbet，学名：Psilopogon haemacephalus），是䴕形目拟啄木鸟科火簇拟䴕属的鸟类。以其类似铜匠打铁的节奏鸣叫而闻名。亚洲地区的拟啄木鸟，头部鲜红，脸颊黄色，喉部亦呈黄色，背部常显现出灰黑条纹。分布广泛，自巴基斯坦至中国南部、菲律宾、苏门答腊、爪哇及巴厘岛，国内可见于云南西部和南部。该物种已列入国家林业局2000年8月1日发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","appearance":"赤胸拟啄木鸟体长约15至17厘米，体重30至52.6克，全身绿色，头部以红色为主，颊部黄色，喉部黄色，下胸有一红色斑块，雌鸟较雄鸟颜色稍暗淡，幼鸟初期缺乏红色，喉部条纹模糊，喙色较浅。不同亚种间存在色彩深浅、斑块宽度及黑色冠带的差异。","call":"赤胸拟啄木鸟以响亮、金属质感的‘tuk…tuk…tuk’声著称，如同铜匠敲击金属的声音，这种叫声持续且有节奏，每分钟可达80至200次，但在冬季它们保持沉默。","habits":"偏好开阔地带，如森林边缘、种植园、村庄花园甚至城市环境，活动于低地和山脚区域，有时高达1500米，偶尔在更高山区出现。以多样水果为主食，包括无花果、芒果等，也吃昆虫如蟋蟀、白蚁、甲虫等。在果实丰富的树上，多达70只鸟会聚集觅食，偶尔与非洲绿拟啄木鸟和斑拟啄木鸟共同进食。","breeding":"繁殖期因地区而异，一般在印度次大陆和东南亚为1月至10月，斯里兰卡为11月至5月，东南亚东部和菲律宾为2月至7月。繁殖期间，双方共同挖掘巢穴，通常位于腐朽或死亡的树木、枝干或栅栏柱中，高度从1.5米到15米不等。巢穴入口直径3.8至5厘米，深度15至80厘米。每窝产卵2至4枚，通常为三枚，白色，孵化期约12至14天，由双亲共同孵化。幼鸟由双亲喂养，孵化后约35天离巢。","identification":"与其他拟啄木鸟相比，赤胸拟啄木鸟更偏爱开放环境，其头部红色和黄色的鲜明对比，以及独特的金属质感鸣叫是辨识关键。不同亚种间在颜色深浅、斑块宽度及黑色冠带的细节上有所区别。","protection":"IUCN：LC（无危）","distribution":"广泛分布于东洋界，包括巴基斯坦至中国南部、菲律宾、苏门答腊、爪哇及巴厘岛。在中国，主要分布于云南西部和南部。","other":"该物种在部分地区的繁殖成功率可能受到非洲绿拟啄木鸟的竞争影响，后者可能会驱逐赤胸拟啄木鸟或破坏其巢穴。"}];
